    def _write_csv_rows(self, path: Path, rows: list[dict[str, Any]]) -> None:
        path.parent.mkdir(parents=True, exist_ok=True)
        fieldnames = list(rows[0].keys()) if rows else []
        with open(path, "w", encoding="utf-8", newline="") as handle:
            if not fieldnames:
                handle.write("")
                return
            writer = csv.DictWriter(handle, fieldnames=fieldnames)
            writer.writeheader()
            for row in rows:
                out_row = dict(row)
                for key, value in list(out_row.items()):
                    if isinstance(value, (list, dict)):
                        out_row[key] = json.dumps(self._json_safe(value), ensure_ascii=False)
                writer.writerow(out_row)

    def _compute_cut_td_export(
        self, cut_id: int
    ) -> tuple[np.ndarray, dict[str, Any], dict[str, Any]] | None:
        cut = self.cuts.get(int(cut_id))
        if cut is None:
            return None
        params = self._cut_td_params(int(cut_id))
        dynamic_geometry = self._dynamic_cut_geometry_samples(
            int(cut_id),
            int(params["t_ini"]),
            int(params["t_fin"]),
            int(params["stride"]),
        )
        td, meta = compute_td(
            self.cube,
            cut,
            int(params["t_ini"]),
            int(params["t_fin"]),
            int(params["stride"]),
            int(params["width"]),
            str(params["weighting"]),
            dynamic_geometry=dynamic_geometry or None,
        )
        return np.asarray(td, dtype=np.float32), dict(meta), dict(params)

    def _write_experiment_stack_csv_tables(
        self,
        experiment: dict[str, Any],
        root_dir: Path,
        master_rows: list[dict[str, Any]],
    ) -> tuple[dict[int, str], dict[int, str], str]:
        csv_root = root_dir / "csv_tables"
        master_csv_path = csv_root / "master_events.csv"
        self._write_csv_rows(master_csv_path, master_rows)

        def _write_group(
            folder_name: str, stack_ids: list[int]
        ) -> dict[int, str]:
            paths: dict[int, str] = {}
            for stack_id in stack_ids:
                stack = self.stacks.get(int(stack_id))
                if stack is None:
                    continue
                cut_id_set = {
                    int(cut_id)
                    for cut_id in (stack.get("cut_ids") or [])
                    if int(cut_id) in self.cuts
                }
                rows = [
                    dict(row)
                    for row in master_rows
                    if int(row.get("cut_id", -1)) in cut_id_set
                ]
                slug = self._safe_export_slug(str(stack.get("name") or f"stack_{int(stack_id):03d}"))
                path = csv_root / folder_name / f"stack_{int(stack_id):03d}_{slug}.csv"
                self._write_csv_rows(path, rows)
                paths[int(stack_id)] = str(path)
            return paths

        displacement_paths = _write_group(
            "displacements",
            [int(stack_id) for stack_id in (experiment.get("displacement_stack_ids") or [])],
        )
        rotation_paths = _write_group(
            "rotates",
            [int(stack_id) for stack_id in (experiment.get("rotation_stack_ids") or [])],
        )
        return displacement_paths, rotation_paths, str(master_csv_path)

    def _write_experiment_td_fits(
        self,
        experiment: dict[str, Any],
        root_dir: Path,
    ) -> tuple[dict[int, str], dict[int, str], str, str]:
        if not bool(experiment.get("save_options", {}).get("save_td_fits", True)):
            return {}, {}, "", ""

        def _write_stack_cube(
            folder_name: str,
            stack_kind: str,
            stack_ids: list[int],
        ) -> tuple[dict[int, str], str]:
            stack_paths: dict[int, str] = {}
            stack_cubes: list[np.ndarray] = []
            max_members = 0
            max_t = 0
            max_s = 0
            valid_stack_count = 0

            for stack_id in stack_ids:
                stack = self.stacks.get(int(stack_id))
                if stack is None:
                    continue
                cut_ids = [
                    int(cut_id)
                    for cut_id in (stack.get("cut_ids") or [])
                    if int(cut_id) in self.cuts
                ]
                member_tds: list[np.ndarray] = []
                member_meta: list[dict[str, Any]] = []
                stack_value = float("nan")
                varying_key = "angle_deg" if stack_kind == "displacement" else "offset_value"
                constant_key = "offset_value" if stack_kind == "displacement" else "angle_deg"
                constant_unit = "px" if stack_kind == "displacement" else "deg"
                varying_unit = "deg" if stack_kind == "displacement" else "px"

                for member_index, cut_id in enumerate(cut_ids, start=1):
                    result = self._compute_cut_td_export(int(cut_id))
                    if result is None:
                        continue
                    td, meta, params = result
                    cut = self.cuts.get(int(cut_id))
                    if cut is None:
                        continue
                    cell = next(
                        (
                            dict(candidate)
                            for candidate in self._experiment_cells(experiment)
                            if int(candidate.get("cut_id", -1)) == int(cut_id)
                        ),
                        {},
                    )
                    if not np.isfinite(stack_value):
                        stack_value = float(cell.get(constant_key, float("nan")))
                    member_tds.append(td)
                    member_meta.append(
                        {
                            "member_index": int(member_index),
                            "cut_id": int(cut_id),
                            "cut_name": str(cut.name),
                            "offset_idx": int(cell.get("offset_idx", 0)),
                            "offset_value": float(cell.get("offset_value", float("nan"))),
                            "angle_idx": int(cell.get("angle_idx", 0)),
                            "angle_deg": float(cell.get("angle_deg", float("nan"))),
                            "varying_value": float(cell.get(varying_key, float("nan"))),
                            "varying_unit": varying_unit,
                            "td_shape": [int(td.shape[0]), int(td.shape[1])],
                            "cut_length_px": float(meta.get("cut_length", float("nan"))),
                            "t_indices": self._json_safe(meta.get("t_indices", [])),
                            "distances": self._json_safe(meta.get("distances", [])),
                            "td_params": {
                                "t_ini": int(params["t_ini"]),
                                "t_fin": int(params["t_fin"]),
                                "stride": int(params["stride"]),
                                "width": int(params["width"]),
                                "weighting": str(params["weighting"]),
                            },
                        }
                    )
                    max_t = max(max_t, int(td.shape[0]))
                    max_s = max(max_s, int(td.shape[1]))

                if not member_tds:
                    continue

                cube = np.full(
                    (len(member_tds), max((td.shape[0] for td in member_tds), default=0), max((td.shape[1] for td in member_tds), default=0)),
                    np.nan,
                    dtype=np.float32,
                )
                for member_idx, td in enumerate(member_tds):
                    cube[member_idx, : td.shape[0], : td.shape[1]] = td

                slug = self._safe_export_slug(str(stack.get("name") or f"stack_{int(stack_id):03d}"))
                path = root_dir / folder_name / f"stack_{int(stack_id):03d}_{slug}_td.fits"
                path.parent.mkdir(parents=True, exist_ok=True)
                header = fits.Header()
                header["EXPTYPE"] = ("EXHSTK", "Exhaustive stack TD cube")
                header["EXPID"] = (int(experiment["experiment_id"]), "Experiment id")
                header["STKTYP"] = (str(stack_kind).upper(), "Stack family")
                header["STACKID"] = (int(stack["stack_id"]), "Stack id")
                header["STKNAME"] = (str(stack.get("name") or ""), "Stack name")
                header["STACKBY"] = (str(stack_kind).upper(), "Stack grouped by")
                header["STKVAL"] = (float(stack_value), f"Constant {constant_key}")
                header["STKUNIT"] = (constant_unit, "Constant stack unit")
                header["VARIES"] = (varying_key.upper()[:8], "Value changing inside stack")
                header["NMEMBER"] = (int(len(member_tds)), "Members in stack")
                header["MAXT"] = (int(cube.shape[1]), "Padded time axis length")
                header["MAXS"] = (int(cube.shape[2]), "Padded distance axis length")
                header["PADVAL"] = ("NaN", "Padding value")
                header["DMIN"] = (float(experiment.get("displacement_min", float("nan"))), "Study displacement min [px]")
                header["DMAX"] = (float(experiment.get("displacement_max", float("nan"))), "Study displacement max [px]")
                header["DSTEP"] = (float(experiment.get("displacement_step", float("nan"))), "Study displacement step [px]")
                header["AMIN"] = (float(experiment.get("angle_min", float("nan"))), "Study angle min [deg]")
                header["AMAX"] = (float(experiment.get("angle_max", float("nan"))), "Study angle max [deg]")
                header["ASTEP"] = (float(experiment.get("angle_step", float("nan"))), "Study angle step [deg]")
                header["CTYPE1"] = ("DIST", "Axis 1 = distance sample")
                header["CUNIT1"] = ("pixel", "Axis 1 unit")
                header["CTYPE2"] = ("TIME", "Axis 2 = time sample")
                header["CUNIT2"] = ("frame", "Axis 2 unit")
                header["CTYPE3"] = ("MEMBER", "Axis 3 = stack member")
                header["TDWIDTH"] = (int(experiment.get("td_width", 1)), "TD sampling width")
                header["WEIGHT"] = (str(experiment.get("td_weighting") or "uniform"), "TD weighting")
                fits.PrimaryHDU(data=cube, header=header).writeto(path, overwrite=True)

                stack_paths[int(stack["stack_id"])] = str(path)
                stack_cubes.append(cube)
                max_members = max(max_members, int(cube.shape[0]))
                valid_stack_count += 1

            if not stack_cubes:
                return stack_paths, ""

            group_cube = np.full(
                (valid_stack_count, max_members, max_t, max_s),
                np.nan,
                dtype=np.float32,
            )
            for stack_index, cube in enumerate(stack_cubes):
                group_cube[
                    stack_index,
                    : cube.shape[0],
                    : cube.shape[1],
                    : cube.shape[2],
                ] = cube

            group_path = root_dir / f"{folder_name}_cube.fits"
            group_path.parent.mkdir(parents=True, exist_ok=True)
            group_header = fits.Header()
            group_header["EXPTYPE"] = ("EXHGRP", "Exhaustive grouped TD cube")
            group_header["EXPID"] = (int(experiment["experiment_id"]), "Experiment id")
            group_header["STACKBY"] = (str(stack_kind).upper(), "Outer stack axis meaning")
            group_header["NSTACK"] = (int(valid_stack_count), "Number of stacks")
            group_header["NMEMMAX"] = (int(max_members), "Padded member axis length")
            group_header["MAXT"] = (int(max_t), "Padded time axis length")
            group_header["MAXS"] = (int(max_s), "Padded distance axis length")
            group_header["PADVAL"] = ("NaN", "Padding value")
            group_header["CTYPE1"] = ("DIST", "Axis 1 = distance sample")
            group_header["CUNIT1"] = ("pixel", "Axis 1 unit")
            group_header["CTYPE2"] = ("TIME", "Axis 2 = time sample")
            group_header["CUNIT2"] = ("frame", "Axis 2 unit")
            group_header["CTYPE3"] = ("MEMBER", "Axis 3 = stack member")
            group_header["CTYPE4"] = ("STACK", "Axis 4 = stack index")
            group_header["DMIN"] = (float(experiment.get("displacement_min", float("nan"))), "Study displacement min [px]")
            group_header["DMAX"] = (float(experiment.get("displacement_max", float("nan"))), "Study displacement max [px]")
            group_header["DSTEP"] = (float(experiment.get("displacement_step", float("nan"))), "Study displacement step [px]")
            group_header["AMIN"] = (float(experiment.get("angle_min", float("nan"))), "Study angle min [deg]")
            group_header["AMAX"] = (float(experiment.get("angle_max", float("nan"))), "Study angle max [deg]")
            group_header["ASTEP"] = (float(experiment.get("angle_step", float("nan"))), "Study angle step [deg]")
            group_header["TDWIDTH"] = (int(experiment.get("td_width", 1)), "TD sampling width")
            group_header["WEIGHT"] = (str(experiment.get("td_weighting") or "uniform"), "TD weighting")
            fits.PrimaryHDU(data=group_cube, header=group_header).writeto(
                group_path, overwrite=True
            )
            return stack_paths, str(group_path)

        displacement_paths, displacement_group_path = _write_stack_cube(
            "displacements",
            "displacement",
            [int(stack_id) for stack_id in (experiment.get("displacement_stack_ids") or [])],
        )
        rotation_paths, rotation_group_path = _write_stack_cube(
            "rotates",
            "rotation",
            [int(stack_id) for stack_id in (experiment.get("rotation_stack_ids") or [])],
        )
        return (
            displacement_paths,
            rotation_paths,
            displacement_group_path,
            rotation_group_path,
        )

    def _write_experiment_stack_payloads(
        self,
        experiment: dict[str, Any],
        root_dir: Path,
        cells_rows: list[dict[str, Any]],
        master_rows: list[dict[str, Any]],
        novelty_rows: list[dict[str, Any]],
        important_rows: list[dict[str, Any]],
        trace_rows: list[dict[str, Any]],
    ) -> tuple[dict[int, str], dict[int, str], str]:
        if not bool(experiment.get("save_options", {}).get("save_stack_json", True)):
            return {}, {}, ""

        experiment_summary = {
            "experiment_id": int(experiment["experiment_id"]),
            "name": str(experiment.get("name") or ""),
            "base_cut_id": int(experiment.get("base_cut_id")) if experiment.get("base_cut_id") is not None else None,
            "base_cut_name": str(experiment.get("base_cut_name") or ""),
            "base_frame_idx": int(experiment.get("base_frame_idx", 0)),
            "stack_group_mode": str(self._experiment_stack_mode(experiment)),
            "full_cube_angles": bool(experiment.get("full_cube_angles", False)),
            "dynamic_length": bool(experiment.get("dynamic_length", False)),
            "min_cut_length_px": float(
                experiment.get("min_cut_length_px", MIN_EXPERIMENT_CUT_LENGTH_PX)
            ),
            "displacement_step": float(experiment.get("displacement_step", float("nan"))),
            "displacement_min": float(experiment.get("displacement_min", float("nan"))),
            "displacement_max": float(experiment.get("displacement_max", float("nan"))),
            "full_sweep": bool(experiment.get("full_sweep", False)),
            "angle_min": float(experiment.get("angle_min", float("nan"))),
            "angle_max": float(experiment.get("angle_max", float("nan"))),
            "angle_step": float(experiment.get("angle_step", float("nan"))),
            "td_width": int(experiment.get("td_width", 1)),
            "td_weighting": str(experiment.get("td_weighting") or "uniform"),
            "status": str(experiment.get("status") or ""),
            "updated_at": str(experiment.get("updated_at") or ""),
        }
        cells_by_cut = {
            int(row["cut_id"]): dict(row)
            for row in cells_rows
            if int(row.get("cut_id", -1)) in self.cuts
        }
        events_by_cut: dict[int, list[dict[str, Any]]] = {}
        novelty_by_cut: dict[int, list[dict[str, Any]]] = {}
        important_by_cut: dict[int, list[dict[str, Any]]] = {}
        traces_by_cut: dict[int, list[dict[str, Any]]] = {}
        for row in master_rows:
            events_by_cut.setdefault(int(row.get("cut_id", -1)), []).append(dict(row))
        for row in novelty_rows:
            novelty_by_cut.setdefault(int(row.get("cut_id", -1)), []).append(dict(row))
        for row in important_rows:
            important_by_cut.setdefault(int(row.get("cut_id", -1)), []).append(dict(row))
        for row in trace_rows:
            traces_by_cut.setdefault(int(row.get("cut_id", -1)), []).append(dict(row))

        def _stack_payload(stack: dict[str, Any], kind: str) -> dict[str, Any]:
            cut_ids = [
                int(cut_id)
                for cut_id in (stack.get("cut_ids") or [])
                if int(cut_id) in self.cuts
            ]
            cut_id_set = set(cut_ids)
            cuts_payload: list[dict[str, Any]] = []
            for member_index, cut_id in enumerate(cut_ids, start=1):
                cut = self.cuts.get(int(cut_id))
                if cut is None:
                    continue
                cuts_payload.append(
                    {
                        "member_index": int(member_index),
                        "cut_id": int(cut_id),
                        "cut_name": str(cut.name),
                        "cell": dict(cells_by_cut.get(int(cut_id), {})),
                        "events": [dict(row) for row in events_by_cut.get(int(cut_id), [])],
                        "novelty": [dict(row) for row in novelty_by_cut.get(int(cut_id), [])],
                        "important": [dict(row) for row in important_by_cut.get(int(cut_id), [])],
                        "traces": [dict(row) for row in traces_by_cut.get(int(cut_id), [])],
                        "velocity_traces": self._session_analysis_state_payload(
                            self._cut_analysis_snapshot(int(cut_id))
                        ).get("velocity_traces", []),
                        "analysis_state": self._session_analysis_state_payload(
                            self._cut_analysis_snapshot(int(cut_id))
                        ),
                    }
                )
            return {
                "experiment": dict(experiment_summary),
                "stack": {
                    "kind": str(kind),
                    "stack_id": int(stack["stack_id"]),
                    "stack_name": str(stack.get("name") or ""),
                    "cut_ids": cut_ids,
                    "cut_count": int(len(cut_ids)),
                },
                "cells": [
                    dict(row)
                    for row in cells_rows
                    if int(row.get("cut_id", -1)) in cut_id_set
                ],
                "events": [
                    dict(row)
                    for row in master_rows
                    if int(row.get("cut_id", -1)) in cut_id_set
                ],
                "novelty": [
                    dict(row)
                    for row in novelty_rows
                    if int(row.get("cut_id", -1)) in cut_id_set
                ],
                "important": [
                    dict(row)
                    for row in important_rows
                    if int(row.get("cut_id", -1)) in cut_id_set
                ],
                "traces": [
                    dict(row)
                    for row in trace_rows
                    if int(row.get("cut_id", -1)) in cut_id_set
                ],
                "cuts": cuts_payload,
            }

        def _write_stack_group(
            folder_name: str,
            stack_ids: list[int],
        ) -> tuple[list[dict[str, Any]], dict[int, str]]:
            payloads: list[dict[str, Any]] = []
            paths: dict[int, str] = {}
            stack_kind = "rotation" if folder_name == "rotates" else "displacement"
            for stack_id in stack_ids:
                stack = self.stacks.get(int(stack_id))
                if stack is None:
                    continue
                payload = _stack_payload(stack, stack_kind)
                slug = self._safe_export_slug(str(stack.get("name") or f"stack_{int(stack_id):03d}"))
                path = root_dir / folder_name / f"stack_{int(stack_id):03d}_{slug}.json"
                payload["stack"]["json_path"] = str(path)
                path.parent.mkdir(parents=True, exist_ok=True)
                with open(path, "w", encoding="utf-8") as handle:
                    json.dump(self._json_safe(payload), handle, indent=2)
                payloads.append(dict(payload))
                paths[int(stack_id)] = str(path)
            return payloads, paths

        displacement_payloads, displacement_paths = _write_stack_group(
            "displacements",
            [int(stack_id) for stack_id in (experiment.get("displacement_stack_ids") or [])],
        )
        rotation_payloads, rotation_paths = _write_stack_group(
            "rotates",
            [int(stack_id) for stack_id in (experiment.get("rotation_stack_ids") or [])],
        )
        root_bundle_path = root_dir / "stacks_bundle.json"
        with open(root_bundle_path, "w", encoding="utf-8") as handle:
            json.dump(
                self._json_safe(
                    {
                        "experiment": experiment_summary,
                        "displacements": displacement_payloads,
                        "rotates": rotation_payloads,
                    }
                ),
                handle,
                indent=2,
            )
        return displacement_paths, rotation_paths, str(root_bundle_path)

    def _finalize_experiment_outputs(
        self,
        experiment_id: int,
        *,
        summary: str = "",
    ) -> None:
        experiment = self.experiments.get(int(experiment_id))
        if experiment is None:
            return
        root_dir = self._experiment_output_root(experiment)
        stack_outputs = dict(experiment.get("stack_outputs") or {})
        if stack_outputs:
            ordered_stack_ids = self._experiment_stack_ids_for_processing(experiment)
            cells_rows: list[dict[str, Any]] = []
            master_rows: list[dict[str, Any]] = []
            trace_part_paths: list[str] = []
            displacement_rows: list[dict[str, Any]] = []
            rotation_rows: list[dict[str, Any]] = []
            for stack_id in ordered_stack_ids:
                info = dict(
                    stack_outputs.get(str(int(stack_id)))
                    or stack_outputs.get(int(stack_id))
                    or {}
                )
                if not info:
                    continue
                cells_path = str(info.get("cells_table_path") or "")
                master_path = str(info.get("master_table_path") or "")
                trace_path = str(info.get("trace_table_path") or "")
                if cells_path and Path(cells_path).exists():
                    loaded_cells = self._read_json_file(Path(cells_path))
                    if isinstance(loaded_cells, list):
                        cells_rows.extend(
                            dict(row) for row in loaded_cells if isinstance(row, dict)
                        )
                if master_path and Path(master_path).exists():
                    loaded_master = self._read_json_file(Path(master_path))
                    if isinstance(loaded_master, list):
                        master_rows.extend(
                            dict(row) for row in loaded_master if isinstance(row, dict)
                        )
                if trace_path and Path(trace_path).exists():
                    trace_part_paths.append(trace_path)
                summary_row = {
                    "experiment_id": int(experiment["experiment_id"]),
                    "stack_id": int(info.get("stack_id", stack_id)),
                    "stack_name": str(info.get("stack_name") or ""),
                    "cut_count": int(info.get("cell_count", 0) or 0),
                    "stack_json_path": str(info.get("stack_json_path") or ""),
                    "stack_csv_path": "",
                    "stack_fits_path": str(info.get("td_fits_path") or ""),
                }
                if str(info.get("stack_kind") or "") == "rotation":
                    rotation_rows.append(summary_row)
                else:
                    displacement_rows.append(summary_row)

            self._annotate_curated_group_rows(master_rows)
            novelty_rows = self._build_experiment_novelty_rows(experiment, master_rows)
            novelty_map = {
                (int(row["cut_id"]), int(row["event_id"])): row for row in novelty_rows
                if row.get("event_id") is not None
            }
            for row in master_rows:
                novelty = novelty_map.get((int(row["cut_id"]), int(row["event_id"])), {})
                row["novelty_class"] = str(novelty.get("classification", ""))
                row["novelty_score"] = float(novelty.get("novelty_score", float("nan")))
                row["novelty_match_cut_id"] = novelty.get("matched_cut_id")
                row["novelty_match_event_id"] = novelty.get("matched_event_id")

            cell_lookup = {
                int(row.get("cut_id", -1)): dict(row)
                for row in cells_rows
                if int(row.get("cut_id", -1)) in self.cuts
            }
            velocity_trace_rows: list[dict[str, Any]] = []
            for cut_id, cell in sorted(cell_lookup.items()):
                state = self._cut_analysis_snapshot(int(cut_id))
                for trace in state.get("velocity_traces") or []:
                    if not isinstance(trace, dict):
                        continue
                    velocity_trace_rows.append(
                        {
                            "experiment_id": int(experiment["experiment_id"]),
                            "experiment_name": str(experiment["name"]),
                            "cut_id": int(cut_id),
                            "cut_name": str(self.cuts[int(cut_id)].name),
                            "cell_id": str(cell.get("cell_id") or ""),
                            "offset_idx": int(cell.get("offset_idx", 0)),
                            "offset_value": float(cell.get("offset_value", 0.0)),
                            "angle_idx": int(cell.get("angle_idx", 0)),
                            "angle_deg": float(cell.get("angle_deg", 0.0)),
                            **dict(trace),
                        }
                    )

            trace_rows_estimate = int(
                sum(
                    int(info.get("trace_count", 0) or 0)
                    for info in stack_outputs.values()
                    if isinstance(info, dict)
                )
            )
            write_trace_bundle = trace_rows_estimate <= MAX_EXPERIMENT_TRACE_BUNDLE_ROWS
            write_important_images = bool(
                len(master_rows) <= MAX_EXPERIMENT_AUTO_IMPORTANT_IMAGE_SOURCE_ROWS
            )
            important_rows = self._build_experiment_important_rows_from_saved_outputs(
                experiment,
                master_rows,
                novelty_rows,
                cells_rows,
                write_images=write_important_images,
            )

            self._write_table_bundle(root_dir / "master_table", master_rows)
            self._write_table_bundle(root_dir / "cells_table", cells_rows)
            trace_bundle_rows = 0
            if write_trace_bundle:
                trace_bundle_rows = self._merge_table_parts_to_bundle(
                    root_dir / "trace_table",
                    trace_part_paths,
                )
            self._write_table_bundle(root_dir / "velocity_trace_table", velocity_trace_rows)
            self._write_table_bundle(root_dir / "novelty_table", novelty_rows)
            self._write_table_bundle(root_dir / "important_zones_table", important_rows)
            if displacement_rows:
                self._write_table_bundle(root_dir / "displacements" / "summary", displacement_rows)
            if rotation_rows:
                self._write_table_bundle(root_dir / "rotates" / "summary", rotation_rows)
            self._write_json_file(
                root_dir / "manifest.json",
                {
                    "experiment": experiment,
                    "stack_outputs": stack_outputs,
                    "summary": {
                        "master_rows": len(master_rows),
                        "cells_rows": len(cells_rows),
                        "trace_parts": len(trace_part_paths),
                        "trace_rows_estimate": trace_rows_estimate,
                        "trace_bundle_rows": trace_bundle_rows,
                        "trace_bundle_written": bool(write_trace_bundle),
                        "velocity_trace_rows": len(velocity_trace_rows),
                        "important_rows": len(important_rows),
                        "important_images_written": bool(write_important_images),
                        "novelty_rows": len(novelty_rows),
                        "stack_group_mode": self._experiment_stack_mode(experiment),
                        "full_cube_angles": bool(experiment.get("full_cube_angles", False)),
                    },
                    "master_csv_path": str(root_dir / "master_table.csv"),
                    "velocity_trace_table_path": str(root_dir / "velocity_trace_table.csv"),
                },
            )
            finalize_notes: list[str] = []
            if not write_trace_bundle:
                finalize_notes.append(
                    f"trace bundle skipped ({trace_rows_estimate} rows)"
                )
            if not write_important_images and bool(
                experiment.get("save_options", {}).get("save_important_images", True)
            ):
                finalize_notes.append(
                    f"important images skipped ({len(master_rows)} source events)"
                )
            summary_text = summary or f"Completed with {len(master_rows)} event row(s)."
            if finalize_notes:
                summary_text += " " + "; ".join(finalize_notes) + "."
            experiment["status"] = "completed"
            experiment["nuwt_status"] = (
                "completed"
                if str(experiment.get("nuwt_status") or "pending") != "pending"
                else experiment.get("nuwt_status", "pending")
            )
            experiment["wavelet_status"] = (
                "completed"
                if str(experiment.get("wavelet_status") or "pending") != "pending"
                else experiment.get("wavelet_status", "pending")
            )
            experiment["tables_status"] = "completed"
            experiment["updated_at"] = self._timestamp_now()
            experiment["completed_at"] = self._timestamp_now()
            experiment["last_run_summary"] = summary_text
            self._write_experiment_metadata_files(experiment)
            with open(root_dir / "run_log.txt", "a", encoding="utf-8") as handle:
                handle.write(
                    f"{self._timestamp_now()} | finalize_staged | master={len(master_rows)} "
                    f"important={len(important_rows)} novelty={len(novelty_rows)} "
                    f"trace_bundle={'yes' if write_trace_bundle else 'no'} "
                    f"important_images={'yes' if write_important_images else 'no'}\n"
                )
            self._record_session_change()
            self.refresh_all()
            self._set_status(
                (summary_text or f"Exhaustive study completed for {experiment['name']}.")
                + f" Folder: {root_dir}"
            )
            return
        master_rows = self._experiment_curated_rows(experiment)
        novelty_rows = self._build_experiment_novelty_rows(experiment, master_rows)
        novelty_map = {
            (int(row["cut_id"]), int(row["event_id"])): row for row in novelty_rows
        }
        for row in master_rows:
            novelty = novelty_map.get((int(row["cut_id"]), int(row["event_id"])), {})
            row["novelty_class"] = str(novelty.get("classification", ""))
            row["novelty_score"] = float(novelty.get("novelty_score", float("nan")))
            row["novelty_match_cut_id"] = novelty.get("matched_cut_id")
            row["novelty_match_event_id"] = novelty.get("matched_event_id")
        cells_rows = self._experiment_cells_table_rows(experiment)
        trace_rows: list[dict[str, Any]] = []
        for row in master_rows:
            event = self._wavelet_event_ref_by_cut(
                int(row["cut_id"]),
                int(row["event_id"]),
            )
            if event is None:
                continue
            for trace_row in self._event_trace_rows(int(row["cut_id"]), event):
                trace_rows.append(
                    {
                        "experiment_id": int(experiment["experiment_id"]),
                        "experiment_name": str(experiment["name"]),
                        "cut_id": int(row["cut_id"]),
                        "event_id": int(row["event_id"]),
                        "cell_id": str(row.get("experiment_cell_id") or ""),
                        "offset_idx": int(row.get("experiment_offset_idx", 0)),
                        "offset_value": float(row.get("experiment_offset_value", 0.0)),
                        "angle_idx": int(row.get("experiment_angle_idx", 0)),
                        "angle_deg": float(row.get("experiment_angle_deg", 0.0)),
                        **trace_row,
                    }
                )
        cell_lookup = {
            int(cell.get("cut_id", -1)): dict(cell)
            for cell in self._experiment_cells(experiment)
            if int(cell.get("cut_id", -1)) in self.cuts
        }
        velocity_trace_rows: list[dict[str, Any]] = []
        for cut_id, cell in sorted(cell_lookup.items()):
            state = self._cut_analysis_snapshot(int(cut_id))
            for trace in state.get("velocity_traces") or []:
                if not isinstance(trace, dict):
                    continue
                velocity_trace_rows.append(
                    {
                        "experiment_id": int(experiment["experiment_id"]),
                        "experiment_name": str(experiment["name"]),
                        "cut_id": int(cut_id),
                        "cut_name": str(self.cuts[int(cut_id)].name),
                        "cell_id": str(cell.get("cell_id") or ""),
                        "offset_idx": int(cell.get("offset_idx", 0)),
                        "offset_value": float(cell.get("offset_value", 0.0)),
                        "angle_idx": int(cell.get("angle_idx", 0)),
                        "angle_deg": float(cell.get("angle_deg", 0.0)),
                        **dict(trace),
                    }
                )
        important_rows = self._build_experiment_important_rows(
            experiment,
            master_rows,
            novelty_rows,
            cells_rows,
        )
        displacement_csv_paths, rotation_csv_paths, master_csv_path = (
            self._write_experiment_stack_csv_tables(
                experiment,
                root_dir,
                master_rows,
            )
        )
        (
            displacement_fits_paths,
            rotation_fits_paths,
            displacement_group_fits_path,
            rotation_group_fits_path,
        ) = self._write_experiment_td_fits(
            experiment,
            root_dir,
        )
        displacement_stack_paths, rotation_stack_paths, stack_bundle_path = (
            self._write_experiment_stack_payloads(
                experiment,
                root_dir,
                cells_rows,
                master_rows,
                novelty_rows,
                important_rows,
                trace_rows,
            )
        )

        displacement_rows: list[dict[str, Any]] = []
        for stack_id in experiment.get("displacement_stack_ids") or []:
            stack = self.stacks.get(int(stack_id))
            if stack is None:
                continue
            displacement_rows.append(
                {
                    "experiment_id": int(experiment["experiment_id"]),
                    "stack_id": int(stack["stack_id"]),
                    "stack_name": str(stack["name"]),
                    "cut_count": int(len([cut_id for cut_id in (stack.get("cut_ids") or []) if int(cut_id) in self.cuts])),
                    "stack_json_path": str(displacement_stack_paths.get(int(stack["stack_id"]), "")),
                    "stack_csv_path": str(displacement_csv_paths.get(int(stack["stack_id"]), "")),
                    "stack_fits_path": str(displacement_fits_paths.get(int(stack["stack_id"]), "")),
                }
            )
        rotation_rows: list[dict[str, Any]] = []
        for stack_id in experiment.get("rotation_stack_ids") or []:
            stack = self.stacks.get(int(stack_id))
            if stack is None:
                continue
            rotation_rows.append(
                {
                    "experiment_id": int(experiment["experiment_id"]),
                    "stack_id": int(stack["stack_id"]),
                    "stack_name": str(stack["name"]),
                    "cut_count": int(len([cut_id for cut_id in (stack.get("cut_ids") or []) if int(cut_id) in self.cuts])),
                    "stack_json_path": str(rotation_stack_paths.get(int(stack["stack_id"]), "")),
                    "stack_csv_path": str(rotation_csv_paths.get(int(stack["stack_id"]), "")),
                    "stack_fits_path": str(rotation_fits_paths.get(int(stack["stack_id"]), "")),
                }
            )

        self._write_table_bundle(root_dir / "master_table", master_rows)
        self._write_table_bundle(root_dir / "cells_table", cells_rows)
        self._write_table_bundle(root_dir / "trace_table", trace_rows)
        self._write_table_bundle(root_dir / "velocity_trace_table", velocity_trace_rows)
        self._write_table_bundle(root_dir / "novelty_table", novelty_rows)
        self._write_table_bundle(root_dir / "important_zones_table", important_rows)
        if displacement_rows:
            self._write_table_bundle(root_dir / "displacements" / "summary", displacement_rows)
        if rotation_rows:
            self._write_table_bundle(root_dir / "rotates" / "summary", rotation_rows)
        with open(root_dir / "manifest.json", "w", encoding="utf-8") as handle:
            json.dump(
                self._json_safe(
                    {
                        "experiment": experiment,
                        "summary": {
                            "master_rows": len(master_rows),
                            "cells_rows": len(cells_rows),
                            "trace_rows": len(trace_rows),
                            "velocity_trace_rows": len(velocity_trace_rows),
                            "important_rows": len(important_rows),
                            "novelty_rows": len(novelty_rows),
                            "stack_group_mode": self._experiment_stack_mode(experiment),
                            "full_cube_angles": bool(experiment.get("full_cube_angles", False)),
                        },
                        "stack_bundle_path": stack_bundle_path,
                        "master_csv_path": master_csv_path,
                        "velocity_trace_table_path": str(root_dir / "velocity_trace_table.csv"),
                        "displacement_group_fits_path": displacement_group_fits_path,
                        "rotation_group_fits_path": rotation_group_fits_path,
                    }
                ),
                handle,
                indent=2,
            )
        with open(root_dir / "status.json", "w", encoding="utf-8") as handle:
            json.dump(
                self._json_safe(
                    {
                        "experiment_id": int(experiment["experiment_id"]),
                        "status": "completed",
                        "updated_at": self._timestamp_now(),
                        "summary": summary or f"Completed with {len(master_rows)} event row(s).",
                    }
                ),
                handle,
                indent=2,
            )
        with open(root_dir / "run_log.txt", "a", encoding="utf-8") as handle:
            handle.write(
                f"{self._timestamp_now()} | finalize | master={len(master_rows)} "
                f"important={len(important_rows)} novelty={len(novelty_rows)}\n"
            )
        experiment["status"] = "completed"
        experiment["nuwt_status"] = "completed"
        experiment["wavelet_status"] = "completed"
        experiment["tables_status"] = "completed"
        experiment["updated_at"] = self._timestamp_now()
        experiment["completed_at"] = self._timestamp_now()
        experiment["last_run_summary"] = summary or f"Completed with {len(master_rows)} event row(s)."
        self._record_session_change()
        self.refresh_all()
        self._set_status(
            (summary or f"Exhaustive study completed for {experiment['name']}.")
            + f" Folder: {root_dir}"
        )

    def _export_selected_experiment_tables(self) -> None:
        self._run_selected_experiment("tables")

    def _td_window_wavelet_event_final_mode(self, event: dict[str, Any]) -> str:
        origin = str(event.get("origin", "") or "")
        if event.get("split_children_ids") or origin == "manual-split":
            return "split"
        if origin == "manual-trim":
            return "trim"
        if event.get("manual_decision") is not None or event.get("customized"):
            return "manual"
        return "auto"

    def _td_window_wavelet_event_qa_flags(self, event: dict[str, Any]) -> list[str]:
        analysis = event.get("analysis") or {}
        params = dict(event.get("current_params") or event.get("base_params") or {})
        flags: list[str] = []
        point_count = int(np.asarray(analysis.get("wave_t_idx", []), dtype=np.float64).size)
        min_points = max(
            min(
                int(params.get("min_points_segment", 3)),
                int(params.get("min_points_cut_seg", 3)),
            ),
            3,
        )
        if point_count <= min_points + WAVELET_QA_LOW_POINTS_MARGIN:
            flags.append("few_points")
        peak_period = float(analysis.get("peak_period_s", float("nan")))
        p_min = float(params.get("p_min", float("nan")))
        p_max = float(params.get("p_max", float("nan")))
        if (
            np.isfinite(peak_period)
            and np.isfinite(p_min)
            and np.isfinite(p_max)
            and p_max > p_min
        ):
            edge_margin = max((p_max - p_min) * WAVELET_QA_EDGE_FRACTION, 1e-6)
            if (peak_period - p_min) <= edge_margin or (p_max - peak_period) <= edge_margin:
                flags.append("period_edge")
        residual = float(
            analysis.get(
                "fit_rms_over_amp",
                analysis.get("rms_amp_ratio", float("nan")),
            )
        )
        rms_limit = float(params.get("rms_amp_ratio_max", float("nan")))
        if (
            np.isfinite(residual)
            and np.isfinite(rms_limit)
            and residual >= rms_limit * WAVELET_QA_RESIDUAL_WARN_FRAC
        ):
            flags.append("high_residual")
        return flags

    def _curated_group_key(
        self,
        cut_id: int | None,
        event_id: int | None,
        link_group_id: str | None,
    ) -> str:
        group_id = str(link_group_id or "").strip()
        if group_id:
            return group_id
        return f"CUT{int(cut_id or -1):04d}:EVENT{int(event_id or -1):04d}"

    def _curated_row_rank_value(self, value: Any) -> float:
        try:
            number = float(value)
        except Exception:
            return float("-inf")
        return number if np.isfinite(number) else float("-inf")

    def _collect_curated_event_rows(self) -> list[dict[str, Any]]:
        rows: list[dict[str, Any]] = []
        for cut_id in sorted(self.cuts.keys()):
            cut = self.cuts.get(cut_id)
            if cut is None:
                continue
            state = self._cut_analysis_snapshot(cut_id)
            crest_params, wavelet_params = self._merge_crest_and_wavelet_params(
                state.get("crest_params"), state.get("wavelet_params")
            )
            panels = self._panels_for_cut(cut_id)
            primary_panel = panels[0] if panels else None
            memberships = self._stack_memberships_for_cut(cut_id)
            experiment_refs = self._experiment_memberships_for_cut(cut_id)
            primary_experiment = experiment_refs[0] if experiment_refs else {}
            dynamic_enabled = self._cut_dynamic_enabled(cut_id)
            dynamic_reference_frame = self._cut_dynamic_reference_frame(cut_id)
            dynamic_keyframes = self._cut_dynamic_keyframes(cut_id)
            for event in state.get("wavelet_events") or []:
                self._ensure_wavelet_event_fields(event)
                analysis = event.get("analysis") or {}
                qa_flags = self._td_window_wavelet_event_qa_flags(event)
                confidence_score, confidence_label = self._wavelet_event_confidence_details(
                    event
                )
                link_refs = self._wavelet_event_link_refs(event)
                rows.append(
                    {
                        "panel_id": int(primary_panel.panel_id) if primary_panel is not None else None,
                        "panel_name": primary_panel.name if primary_panel is not None else "",
                        "primary_panel_id": int(primary_panel.panel_id) if primary_panel is not None else None,
                        "primary_panel_name": primary_panel.name if primary_panel is not None else "",
                        "panel_ids": [int(panel.panel_id) for panel in panels],
                        "panel_names": [str(panel.name) for panel in panels],
                        "panel_count": int(len(panels)),
                        "cut_id": int(cut.cut_id),
                        "cut_name": cut.name,
                        "event_id": int(event.get("event_id", -1)),
                        "parent_event_id": (
                            int(event.get("parent_event_id"))
                            if event.get("parent_event_id") is not None
                            else None
                        ),
                        "final_mode": self._td_window_wavelet_event_final_mode(event),
                        "status": self._td_window_wavelet_event_status(event),
                        "counted": bool(self._td_window_wavelet_event_is_counted(event)),
                        "origin": str(event.get("origin", "")),
                        "manual_decision": event.get("manual_decision"),
                        "reason": self._td_window_wavelet_event_reason(event),
                        "qa_flags": qa_flags,
                        "qa_flags_text": ",".join(qa_flags),
                        "confidence_score": confidence_score,
                        "confidence_label": confidence_label,
                        "review_locked": bool(event.get("review_locked")),
                        "review_notes": str(event.get("review_notes", "")),
                        "history_count": len(event.get("history") or []),
                        "history": self._clone_wavelet_payload(event.get("history") or []),
                        "link_group_id": event.get("link_group_id"),
                        "propagation_class": str(event.get("propagation_class") or ""),
                        "link_count": self._wavelet_event_link_count(event),
                        "link_refs": self._clone_wavelet_payload(link_refs),
                        "stack_ids": [int(item["stack_id"]) for item in memberships],
                        "stack_names": [str(item["stack_name"]) for item in memberships],
                        "stack_positions": [
                            f"{int(item['stack_index'])}/{int(item['stack_size'])}"
                            for item in memberships
                        ],
                        "stack_refs": self._clone_wavelet_payload(memberships),
                        "experiment_ids": [
                            int(item["experiment_id"]) for item in experiment_refs
                        ],
                        "experiment_names": [
                            str(item["experiment_name"]) for item in experiment_refs
                        ],
                        "experiment_refs": self._clone_wavelet_payload(experiment_refs),
                        "experiment_id": primary_experiment.get("experiment_id"),
                        "experiment_name": str(primary_experiment.get("experiment_name") or ""),
                        "experiment_cell_id": str(primary_experiment.get("cell_id") or ""),
                        "experiment_offset_idx": int(primary_experiment.get("offset_idx", 0)),
                        "experiment_offset_value": float(primary_experiment.get("offset_value", 0.0)),
                        "experiment_angle_idx": int(primary_experiment.get("angle_idx", 0)),
                        "experiment_angle_deg": float(primary_experiment.get("angle_deg", 0.0)),
                        "dynamic_enabled": bool(dynamic_enabled),
                        "dynamic_reference_frame": int(dynamic_reference_frame),
                        "dynamic_keyframe_count": int(len(dynamic_keyframes)),
                        "dynamic_keyframe_frames": [int(frame_idx) for frame_idx in sorted(dynamic_keyframes.keys())],
                        "preset_name": str(state.get("preset_name", "custom")),
                        "thread_index": int(analysis.get("thread_index", -1)),
                        "seg_id": int(analysis.get("seg_id", -1)),
                        "wseg_id": int(analysis.get("wseg_id", -1)),
                        "peak_period_s": float(analysis.get("peak_period_s", float("nan"))),
                        "freq_mhz": float(analysis.get("freq_mhz", float("nan"))),
                        "fit_amp_arcsec": float(analysis.get("fit_amp_arcsec", float("nan"))),
                        "fit_amp_km": float(analysis.get("fit_amp_km", float("nan"))),
                        "velocity_amp_km_s": float(analysis.get("velocity_amp_km_s", float("nan"))),
                        "accel_amp_km_s2": float(analysis.get("accel_amp_km_s2", float("nan"))),
                        "specific_energy_j_kg": float(analysis.get("specific_energy_j_kg", float("nan"))),
                        "energy_flux_w_m2": float(analysis.get("energy_flux_w_m2", float("nan"))),
                        "duration_s": float(analysis.get("duration_s", float("nan"))),
                        "power_ratio": float(analysis.get("power_ratio", float("nan"))),
                        "fit_rms_over_amp": float(
                            analysis.get(
                                "fit_rms_over_amp",
                                analysis.get("rms_amp_ratio", float("nan")),
                            )
                        ),
                        "point_count": int(np.asarray(analysis.get("wave_t_idx", []), dtype=np.float64).size),
                        "source_start_frame": (
                            float(np.asarray(event.get("source_t_idx", []), dtype=np.float64)[0])
                            if np.asarray(event.get("source_t_idx", []), dtype=np.float64).size
                            else float("nan")
                        ),
                        "source_end_frame": (
                            float(np.asarray(event.get("source_t_idx", []), dtype=np.float64)[-1])
                            if np.asarray(event.get("source_t_idx", []), dtype=np.float64).size
                            else float("nan")
                        ),
                        "wave_start_frame": (
                            float(np.asarray(analysis.get("wave_t_idx", []), dtype=np.float64)[0])
                            if np.asarray(analysis.get("wave_t_idx", []), dtype=np.float64).size
                            else float("nan")
                        ),
                        "wave_end_frame": (
                            float(np.asarray(analysis.get("wave_t_idx", []), dtype=np.float64)[-1])
                            if np.asarray(analysis.get("wave_t_idx", []), dtype=np.float64).size
                            else float("nan")
                        ),
                        "cad": float(crest_params["cad"]),
                        "res": float(crest_params["res"]),
                        "grad": float(crest_params["grad"]),
                        "min_tlen": int(crest_params["min_tlen"]),
                        "max_dist_jump": int(crest_params["max_dist_jump"]),
                        "max_time_skip": int(crest_params["max_time_skip"]),
                        "invert": bool(crest_params["invert"]),
                        "gauss": bool(crest_params["gauss"]),
                        "p_min": float(wavelet_params["p_min"]),
                        "p_max": float(wavelet_params["p_max"]),
                        "power_ratio_thresh": float(wavelet_params["power_ratio_thresh"]),
                        "segment_power_frac": float(wavelet_params["segment_power_frac"]),
                        "min_points_segment": int(wavelet_params["min_points_segment"]),
                        "min_amp_arcsec": float(wavelet_params["min_amp_arcsec"]),
                        "max_jump_pix": float(wavelet_params["max_jump_pix"]),
                        "min_points_cut_seg": int(wavelet_params["min_points_cut_seg"]),
                        "rms_amp_ratio_max": float(wavelet_params["rms_amp_ratio_max"]),
                        "km_per_arcsec": float(wavelet_params["km_per_arcsec"]),
                        "density_kg_m3": float(wavelet_params["density_kg_m3"]),
                        "phase_speed_km_s": float(wavelet_params["phase_speed_km_s"]),
                    }
                )
        groups: dict[str, list[dict[str, Any]]] = {}
        for row in rows:
            group_key = self._curated_group_key(
                row.get("cut_id"),
                row.get("event_id"),
                row.get("link_group_id"),
            )
            groups.setdefault(group_key, []).append(row)
        for group_key, members in groups.items():
            representative_amp = max(
                members,
                key=lambda row: (
                    self._curated_row_rank_value(row.get("fit_amp_arcsec")),
                    self._curated_row_rank_value(row.get("confidence_score")),
                    self._curated_row_rank_value(row.get("duration_s")),
                ),
            )
            representative_conf = max(
                members,
                key=lambda row: (
                    self._curated_row_rank_value(row.get("confidence_score")),
                    self._curated_row_rank_value(row.get("fit_amp_arcsec")),
                    self._curated_row_rank_value(row.get("duration_s")),
                ),
            )
            class_labels = sorted(
                {
                    str(member.get("propagation_class") or "").strip()
                    for member in members
                    if str(member.get("propagation_class") or "").strip()
                }
            )
            resolved_class = (
                class_labels[0]
                if len(class_labels) == 1
                else ",".join(class_labels)
                if class_labels
                else ("local" if len(members) == 1 else "same-wave")
            )
            for row in members:
                row["group_key"] = group_key
                row["group_member_count"] = int(len(members))
                row["is_group_representative_amp"] = bool(row is representative_amp)
                row["is_group_representative_conf"] = bool(row is representative_conf)
                row["resolved_propagation_class"] = resolved_class
        return rows

    def _export_curated_results(self) -> None:
        rows = self._collect_curated_event_rows()
        default_name = self.cube_path.stem + "_wavelet_curated.csv"
        save_path = self.filedialog.asksaveasfilename(
            title="Export curated results",
            initialdir=str(Path(__file__).resolve().parent.parent),
            initialfile=default_name,
            defaultextension=".csv",
            filetypes=[("CSV", "*.csv"), ("JSON", "*.json"), ("All files", "*.*")],
        )
        if not save_path:
            return
        save_path_obj = Path(save_path).expanduser().resolve()
        save_path_obj.parent.mkdir(parents=True, exist_ok=True)

        if save_path_obj.suffix.lower() == ".json":
            payload = {
                "cube_path": str(self.cube_path),
                "rows": self._json_safe(rows),
                "summary": {
                    "event_count": len(rows),
                    "counted_event_count": sum(1 for row in rows if row["counted"]),
                },
            }
            with open(save_path_obj, "w", encoding="utf-8") as f:
                json.dump(payload, f, indent=2)
        else:
            fieldnames = list(rows[0].keys()) if rows else [
                "panel_id",
                "panel_name",
                "cut_id",
                "cut_name",
                "event_id",
                "final_mode",
                "status",
                "counted",
                "qa_flags_text",
            ]
            with open(save_path_obj, "w", encoding="utf-8", newline="") as f:
                writer = csv.DictWriter(f, fieldnames=fieldnames)
                writer.writeheader()
                for row in rows:
                    out_row = dict(row)
                    for key, value in list(out_row.items()):
                        if isinstance(value, list) and key == "qa_flags":
                            out_row[key] = ",".join(str(item) for item in value)
                        elif isinstance(value, (list, dict)):
                            out_row[key] = json.dumps(self._json_safe(value), ensure_ascii=False)
                    writer.writerow(out_row)
        self._set_status(f"Curated results exported to {save_path_obj}")

    def _export_curated_report(self) -> None:
        rows = self._collect_curated_event_rows()
        default_name = self.cube_path.stem + "_wavelet_report.pdf"
        save_path = self.filedialog.asksaveasfilename(
            title="Export curated report",
            initialdir=str(Path(__file__).resolve().parent.parent),
            initialfile=default_name,
            defaultextension=".pdf",
            filetypes=[("PDF", "*.pdf"), ("PNG", "*.png"), ("All files", "*.*")],
        )
        if not save_path:
            return

        save_path_obj = Path(save_path).expanduser().resolve()
        save_path_obj.parent.mkdir(parents=True, exist_ok=True)
        counted_rows = [row for row in rows if row["counted"]]
        flagged_rows = [row for row in rows if row["qa_flags"]]
        linked_rows = [row for row in rows if int(row.get("link_count", 0)) > 0]
        locked_rows = [row for row in rows if bool(row.get("review_locked"))]
        fig = self.Figure(figsize=(11.0, 8.5), dpi=160)
        grid = fig.add_gridspec(3, 2, height_ratios=[0.95, 1.0, 1.0], hspace=0.38, wspace=0.25)
        text_ax = fig.add_subplot(grid[0, :])
        axes = (
            fig.add_subplot(grid[1, 0]),
            fig.add_subplot(grid[1, 1]),
            fig.add_subplot(grid[2, 0]),
            fig.add_subplot(grid[2, 1]),
        )

        grouped: dict[tuple[str, str], list[dict[str, Any]]] = {}
        for row in counted_rows:
            key = (str(row["panel_name"]), str(row["cut_name"]))
            grouped.setdefault(key, []).append(row)

        text_ax.axis("off")
        summary_lines = [
            f"Cube: {self.cube_path.name}",
            f"Panels with cuts: {sum(1 for panel in self.panels if panel.cut_id is not None)}",
            f"Events total: {len(rows)} | counted: {len(counted_rows)} | flagged: {len(flagged_rows)} | "
            f"locked: {len(locked_rows)} | linked: {len(linked_rows)}",
            f"Generated: {self._timestamp_now()}",
            "",
        ]
        if grouped:
            for (panel_name, cut_name), items in sorted(grouped.items()):
                periods = [
                    float(item["peak_period_s"])
                    for item in items
                    if np.isfinite(float(item["peak_period_s"]))
                ]
                amps = [
                    float(item["fit_amp_arcsec"])
                    for item in items
                    if np.isfinite(float(item["fit_amp_arcsec"]))
                ]
                vels = [
                    float(item["velocity_amp_km_s"])
                    for item in items
                    if np.isfinite(float(item["velocity_amp_km_s"]))
                ]
                energies = [
                    float(item["specific_energy_j_kg"])
                    for item in items
                    if np.isfinite(float(item["specific_energy_j_kg"]))
                ]
                summary_lines.append(
                    f"{panel_name}/{cut_name or '-'}: n={len(items)} | "
                    f"Pmed={np.nanmedian(periods) if periods else float('nan'):.2f}s | "
                    f"Amed={np.nanmedian(amps) if amps else float('nan'):.3f}'' | "
                    f"vmed={np.nanmedian(vels) if vels else float('nan'):.2f} km/s | "
                    f"Emed={np.nanmedian(energies) if energies else float('nan'):.3e} J/kg"
                )
        else:
            summary_lines.append("No counted curated events available.")
        text_ax.text(
            0.0,
            1.0,
            "\n".join(summary_lines[:18]),
            ha="left",
            va="top",
            fontsize=9,
            family="monospace",
            transform=text_ax.transAxes,
        )

        metric_specs = [
            ("peak_period_s", "Period [s]"),
            ("fit_amp_arcsec", "Amplitude ['']"),
            ("velocity_amp_km_s", "Velocity [km/s]"),
            ("specific_energy_j_kg", "Energy/m [J/kg]"),
        ]
        for axis, (key, title) in zip(axes, metric_specs):
            values = [
                float(row[key]) for row in counted_rows if np.isfinite(float(row[key]))
            ]
            if values:
                axis.hist(values, bins=min(max(len(values), 5), 20), color="tab:blue", alpha=0.82)
            else:
                axis.text(
                    0.5,
                    0.5,
                    "No counted events.",
                    ha="center",
                    va="center",
                    transform=axis.transAxes,
                )
            axis.set_title(title, fontsize=10)
            axis.set_ylabel("count")
        fig.tight_layout()
        fig.savefig(save_path_obj, bbox_inches="tight")
        self._set_status(f"Curated report exported to {save_path_obj}")

    def _collect_propagation_group_rows(
        self, observation_rows: list[dict[str, Any]] | None = None
    ) -> list[dict[str, Any]]:
        rows = observation_rows if observation_rows is not None else self._collect_curated_event_rows()
        grouped: dict[str, list[dict[str, Any]]] = {}
        for row in rows:
            group_key = self._curated_group_key(
                row.get("cut_id"),
                row.get("event_id"),
                row.get("link_group_id"),
            )
            grouped.setdefault(group_key, []).append(row)

        group_rows: list[dict[str, Any]] = []
        for group_key, members in sorted(grouped.items()):
            representative_amp = max(
                members,
                key=lambda row: (
                    self._curated_row_rank_value(row.get("fit_amp_arcsec")),
                    self._curated_row_rank_value(row.get("confidence_score")),
                    self._curated_row_rank_value(row.get("duration_s")),
                ),
            )
            representative_conf = max(
                members,
                key=lambda row: (
                    self._curated_row_rank_value(row.get("confidence_score")),
                    self._curated_row_rank_value(row.get("fit_amp_arcsec")),
                    self._curated_row_rank_value(row.get("duration_s")),
                ),
            )
            unique_classes = sorted(
                {
                    str(member.get("propagation_class") or "").strip()
                    for member in members
                    if str(member.get("propagation_class") or "").strip()
                }
            )
            resolved_class = (
                unique_classes[0]
                if len(unique_classes) == 1
                else ",".join(unique_classes)
                if unique_classes
                else ("local" if len(members) == 1 else "same-wave")
            )
            cut_ids = sorted({int(member["cut_id"]) for member in members if member.get("cut_id") is not None})
            stack_ids = sorted(
                {
                    int(stack_id)
                    for member in members
                    for stack_id in (member.get("stack_ids") or [])
                }
            )
            periods = [
                float(member["peak_period_s"])
                for member in members
                if np.isfinite(float(member.get("peak_period_s", float("nan"))))
            ]
            velocities = [
                float(member["velocity_amp_km_s"])
                for member in members
                if np.isfinite(float(member.get("velocity_amp_km_s", float("nan"))))
            ]
            energies = [
                float(member["specific_energy_j_kg"])
                for member in members
                if np.isfinite(float(member.get("specific_energy_j_kg", float("nan"))))
            ]
            amps = [
                float(member["fit_amp_arcsec"])
                for member in members
                if np.isfinite(float(member.get("fit_amp_arcsec", float("nan"))))
            ]
            confidences = [
                float(member["confidence_score"])
                for member in members
                if np.isfinite(float(member.get("confidence_score", float("nan"))))
            ]
            group_rows.append(
                {
                    "group_key": group_key,
                    "link_group_id": representative_amp.get("link_group_id"),
                    "synthetic_group": not bool(str(representative_amp.get("link_group_id") or "").strip()),
                    "classification": resolved_class,
                    "class_labels": unique_classes,
                    "member_count": int(len(members)),
                    "cut_count": int(len(cut_ids)),
                    "counted_count": int(sum(1 for member in members if member.get("counted"))),
                    "locked_count": int(sum(1 for member in members if member.get("review_locked"))),
                    "qa_flagged_count": int(sum(1 for member in members if member.get("qa_flags"))),
                    "cut_ids": cut_ids,
                    "cut_names": sorted({str(member["cut_name"]) for member in members}),
                    "stack_ids": stack_ids,
                    "stack_names": sorted(
                        {
                            str(stack_name)
                            for member in members
                            for stack_name in (member.get("stack_names") or [])
                        }
                    ),
                    "representative_cut_id": representative_amp.get("cut_id"),
                    "representative_cut_name": representative_amp.get("cut_name"),
                    "representative_event_id": representative_amp.get("event_id"),
                    "representative_amp_arcsec": representative_amp.get("fit_amp_arcsec"),
                    "best_conf_cut_id": representative_conf.get("cut_id"),
                    "best_conf_cut_name": representative_conf.get("cut_name"),
                    "best_conf_event_id": representative_conf.get("event_id"),
                    "best_confidence_score": representative_conf.get("confidence_score"),
                    "max_amp_arcsec": float(np.nanmax(amps)) if amps else float("nan"),
                    "median_period_s": float(np.nanmedian(periods)) if periods else float("nan"),
                    "median_velocity_km_s": float(np.nanmedian(velocities)) if velocities else float("nan"),
                    "median_specific_energy_j_kg": (
                        float(np.nanmedian(energies)) if energies else float("nan")
                    ),
                    "mean_confidence_score": (
                        float(np.nanmean(confidences)) if confidences else float("nan")
                    ),
                    "members": self._clone_wavelet_payload(members),
                }
            )
        return group_rows

    def _export_propagation_tables(self) -> None:
        observation_rows = self._collect_curated_event_rows()
        group_rows = self._collect_propagation_group_rows(observation_rows)
        default_name = self.cube_path.stem + "_propagation_tables.json"
        save_path = self.filedialog.asksaveasfilename(
            title="Export propagation tables",
            initialdir=str(Path(__file__).resolve().parent.parent),
            initialfile=default_name,
            defaultextension=".json",
            filetypes=[("JSON", "*.json"), ("CSV", "*.csv"), ("All files", "*.*")],
        )
        if not save_path:
            return

        save_path_obj = Path(save_path).expanduser().resolve()
        save_path_obj.parent.mkdir(parents=True, exist_ok=True)

        if save_path_obj.suffix.lower() == ".json":
            payload = {
                "cube_path": str(self.cube_path),
                "observations": self._json_safe(observation_rows),
                "groups": self._json_safe(group_rows),
                "summary": {
                    "observation_count": len(observation_rows),
                    "group_count": len(group_rows),
                    "linked_group_count": sum(
                        1 for row in group_rows if not bool(row.get("synthetic_group"))
                    ),
                },
            }
            with open(save_path_obj, "w", encoding="utf-8") as f:
                json.dump(payload, f, indent=2)
            self._set_status(f"Propagation tables exported to {save_path_obj}")
            return

        observations_path = save_path_obj
        groups_path = save_path_obj.with_name(save_path_obj.stem + "_groups.csv")

        observation_fields = list(observation_rows[0].keys()) if observation_rows else [
            "cut_id",
            "cut_name",
            "event_id",
            "group_key",
            "classification",
        ]
        with open(observations_path, "w", encoding="utf-8", newline="") as f:
            writer = csv.DictWriter(f, fieldnames=observation_fields)
            writer.writeheader()
            for row in observation_rows:
                out_row = dict(row)
                for key, value in list(out_row.items()):
                    if isinstance(value, (list, dict)):
                        out_row[key] = json.dumps(self._json_safe(value), ensure_ascii=False)
                writer.writerow(out_row)

        group_fields = list(group_rows[0].keys()) if group_rows else [
            "group_key",
            "classification",
            "member_count",
            "cut_count",
        ]
        with open(groups_path, "w", encoding="utf-8", newline="") as f:
            writer = csv.DictWriter(f, fieldnames=group_fields)
            writer.writeheader()
            for row in group_rows:
                out_row = dict(row)
                for key, value in list(out_row.items()):
                    if isinstance(value, (list, dict)):
                        out_row[key] = json.dumps(self._json_safe(value), ensure_ascii=False)
                writer.writerow(out_row)

        self._set_status(
            f"Propagation tables exported to {observations_path} and {groups_path}"
        )

    def _metrics_field_specs(self) -> list[tuple[str, str]]:
        return [
            ("peak_period_s", "Period [s]"),
            ("fit_amp_arcsec", "Amplitude [arcsec]"),
            ("fit_amp_km", "Amplitude [km]"),
            ("velocity_amp_km_s", "Velocity amplitude [km s^-1]"),
            ("accel_amp_km_s2", "Acceleration amplitude [km s^-2]"),
            ("specific_energy_j_kg", "Specific energy [J kg^-1]"),
            ("energy_flux_w_m2", "Energy flux [W m^-2]"),
            ("power_ratio", "Power ratio"),
            ("confidence_score", "Confidence score"),
            ("duration_s", "Duration [s]"),
            ("link_count", "Link count"),
        ]

    def _metrics_group_specs(self) -> list[tuple[str, str]]:
        return [
            ("cut_name", "Cut"),
            ("status", "Status"),
            ("resolved_propagation_class", "Propagation class"),
            ("panel_name", "Panel"),
            ("group_key", "Link group"),
        ]

    def _metrics_field_label(self, key: str) -> str:
        mapping = dict(self._metrics_field_specs())
        return mapping.get(str(key), str(key))

    def _metrics_key_from_label(
        self,
        label: str,
        specs: list[tuple[str, str]],
        default_key: str,
    ) -> str:
        mapping = {display: key for key, display in specs}
        return mapping.get(str(label), str(default_key))

    def _metrics_label_from_key(
        self,
        key: str,
        specs: list[tuple[str, str]],
        default_label: str,
    ) -> str:
        mapping = {item_key: display for item_key, display in specs}
        return mapping.get(str(key), str(default_label))

    def _metrics_scope_specs(self) -> list[tuple[str, str]]:
        scopes = [
            ("counted_all", "All counted waves"),
            ("all_events", "All events"),
        ]
        stack = self._selected_stack()
        if stack is not None:
            stack_name = str(stack.get("name") or f"Stack {int(stack['stack_id'])}")
            scopes.extend(
                [
                    ("active_stack_counted", f"Active stack counted: {stack_name}"),
                    ("active_stack_all", f"Active stack all: {stack_name}"),
                ]
            )
        cut = self._selected_cut()
        if cut is not None:
            scopes.extend(
                [
                    ("selected_cut_counted", f"Selected cut counted: {cut.name}"),
                    ("selected_cut_all", f"Selected cut all: {cut.name}"),
                ]
            )
        return scopes

    def _metrics_scope_rows(self, scope_key: str) -> list[dict[str, Any]]:
        rows = list(self._collect_curated_event_rows())
        scope_key = str(scope_key or "counted_all")
        if scope_key.endswith("_counted"):
            rows = [row for row in rows if bool(row.get("counted"))]
        if scope_key.startswith("active_stack"):
            stack = self._selected_stack()
            if stack is None:
                return []
            stack_id = int(stack["stack_id"])
            rows = [
                row
                for row in rows
                if stack_id in {int(item) for item in (row.get("stack_ids") or [])}
            ]
        elif scope_key.startswith("selected_cut"):
            cut = self._selected_cut()
            if cut is None:
                return []
            rows = [row for row in rows if int(row.get("cut_id", -1)) == int(cut.cut_id)]
        return rows

    def _metrics_numeric_values(
        self, rows: list[dict[str, Any]], field_key: str
    ) -> tuple[np.ndarray, list[dict[str, Any]]]:
        values: list[float] = []
        kept_rows: list[dict[str, Any]] = []
        for row in rows:
            try:
                value = float(row.get(field_key, float("nan")))
            except Exception:
                continue
            if not np.isfinite(value):
                continue
            values.append(value)
            kept_rows.append(row)
        return np.asarray(values, dtype=np.float64), kept_rows

    def _style_metrics_axis(self, axis: Any) -> None:
        axis.set_facecolor("white")
        axis.grid(True, color="0.86", linewidth=0.7)
        axis.spines["top"].set_visible(False)
        axis.spines["right"].set_visible(False)
        axis.spines["left"].set_linewidth(0.9)
        axis.spines["bottom"].set_linewidth(0.9)

    def _export_metrics_table(self) -> None:
        existing = self.metrics_window
        if existing is None:
            return
        rows = list(existing.get("current_rows") or [])
        if not rows:
            self._set_status("No rows available in the current statistics scope.")
            return
        scope_key = self._metrics_key_from_label(
            existing["scope_var"].get(),
            self._metrics_scope_specs(),
            "counted_all",
        )
        default_name = f"{self.cube_path.stem}_{scope_key}_master_table.csv"
        save_path = self.filedialog.asksaveasfilename(
            title="Export master table",
            initialdir=str(Path(__file__).resolve().parent.parent),
            initialfile=default_name,
            defaultextension=".csv",
            filetypes=[("CSV", "*.csv"), ("JSON", "*.json"), ("All files", "*.*")],
        )
        if not save_path:
            return
        save_path_obj = Path(save_path).expanduser().resolve()
        save_path_obj.parent.mkdir(parents=True, exist_ok=True)
        if save_path_obj.suffix.lower() == ".json":
            payload = {
                "cube_path": str(self.cube_path),
                "scope": scope_key,
                "rows": self._json_safe(rows),
            }
            with open(save_path_obj, "w", encoding="utf-8") as f:
                json.dump(payload, f, indent=2)
        else:
            fieldnames = list(rows[0].keys())
            with open(save_path_obj, "w", encoding="utf-8", newline="") as f:
                writer = csv.DictWriter(f, fieldnames=fieldnames)
                writer.writeheader()
                for row in rows:
                    out_row = dict(row)
                    for key, value in list(out_row.items()):
                        if isinstance(value, (list, dict)):
                            out_row[key] = json.dumps(self._json_safe(value), ensure_ascii=False)
                    writer.writerow(out_row)
        self._set_status(f"Exported master table to {save_path_obj}")

    def _export_metrics_figure(self) -> None:
        existing = self.metrics_window
        if existing is None:
            return
        fig = existing.get("figure")
        if fig is None:
            return
        scope_key = self._metrics_key_from_label(
            existing["scope_var"].get(),
            self._metrics_scope_specs(),
            "counted_all",
        )
        plot_mode = str(existing["plot_mode_var"].get() or "histogram").lower()
        default_name = f"{self.cube_path.stem}_{scope_key}_{plot_mode}.png"
        save_path = self.filedialog.asksaveasfilename(
            title="Export statistics figure",
            initialdir=str(Path(__file__).resolve().parent.parent),
            initialfile=default_name,
            defaultextension=".png",
            filetypes=[("PNG", "*.png"), ("PDF", "*.pdf"), ("SVG", "*.svg"), ("All files", "*.*")],
        )
        if not save_path:
            return
        save_path_obj = Path(save_path).expanduser().resolve()
        save_path_obj.parent.mkdir(parents=True, exist_ok=True)
        fig.savefig(save_path_obj, bbox_inches="tight")
        self._set_status(f"Exported statistics figure to {save_path_obj}")

    def _open_metrics_window(self) -> None:
        existing = self.metrics_window
        if existing is not None:
            top = existing.get("top")
            if top is not None and top.winfo_exists():
                self._refresh_metrics_window()
                top.deiconify()
                top.lift()
                return
            self.metrics_window = None

        top = self.tk.Toplevel(self.root)
        top.title("Wave Statistics")
        top.geometry("1280x900")
        top.rowconfigure(2, weight=1)
        top.columnconfigure(0, weight=1)

        header = self.ttk.Frame(top, padding=8)
        header.grid(row=0, column=0, sticky="ew")
        header.columnconfigure(0, weight=1)
        summary_var = self.tk.StringVar(value="")
        detail_var = self.tk.StringVar(value="")
        self.ttk.Label(
            header, textvariable=summary_var, justify="left", wraplength=1220
        ).grid(row=0, column=0, sticky="w")
        self.ttk.Label(
            header, textvariable=detail_var, justify="left", wraplength=1220
        ).grid(row=1, column=0, sticky="w", pady=(4, 0))

        controls = self.ttk.LabelFrame(top, text="Plot Controls", padding=8)
        controls.grid(row=1, column=0, sticky="ew", padx=8, pady=(0, 8))
        for idx in range(12):
            controls.columnconfigure(idx, weight=1)

        scope_specs = self._metrics_scope_specs()
        field_specs = self._metrics_field_specs()
        group_specs = self._metrics_group_specs()
        scope_var = self.tk.StringVar(
            value=scope_specs[0][1] if scope_specs else "All counted waves"
        )
        plot_mode_var = self.tk.StringVar(value="histogram")
        x_var = self.tk.StringVar(
            value=self._metrics_label_from_key("fit_amp_km", field_specs, "Amplitude [km]")
        )
        y_var = self.tk.StringVar(
            value=self._metrics_label_from_key("peak_period_s", field_specs, "Period [s]")
        )
        color_var = self.tk.StringVar(
            value=self._metrics_label_from_key(
                "confidence_score", field_specs, "Confidence score"
            )
        )
        group_var = self.tk.StringVar(
            value=self._metrics_label_from_key("cut_name", group_specs, "Cut")
        )
        bins_var = self.tk.StringVar(value="18")
        log_x_var = self.tk.BooleanVar(value=False)
        log_y_var = self.tk.BooleanVar(value=False)

        self.ttk.Label(controls, text="Scope").grid(row=0, column=0, sticky="w")
        scope_box = self.ttk.Combobox(
            controls,
            textvariable=scope_var,
            values=[label for _key, label in scope_specs],
            state="readonly",
            width=24,
        )
        scope_box.grid(row=0, column=1, sticky="ew", padx=(6, 8))
        self.ttk.Label(controls, text="Mode").grid(row=0, column=2, sticky="w")
        mode_box = self.ttk.Combobox(
            controls,
            textvariable=plot_mode_var,
            values=["histogram", "scatter", "bar"],
            state="readonly",
            width=12,
        )
        mode_box.grid(row=0, column=3, sticky="ew", padx=(6, 8))
        self.ttk.Label(controls, text="X").grid(row=0, column=4, sticky="w")
        x_box = self.ttk.Combobox(
            controls,
            textvariable=x_var,
            values=[label for _key, label in field_specs],
            state="readonly",
            width=18,
        )
        x_box.grid(row=0, column=5, sticky="ew", padx=(6, 8))
        self.ttk.Label(controls, text="Y").grid(row=0, column=6, sticky="w")
        y_box = self.ttk.Combobox(
            controls,
            textvariable=y_var,
            values=[label for _key, label in field_specs],
            state="readonly",
            width=18,
        )
        y_box.grid(row=0, column=7, sticky="ew", padx=(6, 8))
        self.ttk.Label(controls, text="Bins").grid(row=0, column=8, sticky="w")
        bins_entry = self.ttk.Entry(controls, textvariable=bins_var, width=8)
        bins_entry.grid(row=0, column=9, sticky="ew", padx=(6, 0))

        self.ttk.Label(controls, text="Color").grid(row=1, column=0, sticky="w", pady=(8, 0))
        color_box = self.ttk.Combobox(
            controls,
            textvariable=color_var,
            values=["none"] + [label for _key, label in field_specs],
            state="readonly",
            width=18,
        )
        color_box.grid(row=1, column=1, sticky="ew", padx=(6, 8), pady=(8, 0))
        self.ttk.Label(controls, text="Group").grid(row=1, column=2, sticky="w", pady=(8, 0))
        group_box = self.ttk.Combobox(
            controls,
            textvariable=group_var,
            values=[label for _key, label in group_specs],
            state="readonly",
            width=18,
        )
        group_box.grid(row=1, column=3, sticky="ew", padx=(6, 8), pady=(8, 0))
        self.ttk.Checkbutton(
            controls,
            text="log X",
            variable=log_x_var,
            command=self._refresh_metrics_window,
        ).grid(row=1, column=4, sticky="w", pady=(8, 0))
        self.ttk.Checkbutton(
            controls,
            text="log Y",
            variable=log_y_var,
            command=self._refresh_metrics_window,
        ).grid(row=1, column=5, sticky="w", pady=(8, 0))
        self.ttk.Button(
            controls,
            text="Export Figure",
            command=self._export_metrics_figure,
        ).grid(row=1, column=10, sticky="ew", padx=(6, 4), pady=(8, 0))
        self.ttk.Button(
            controls,
            text="Export Master Table",
            command=self._export_metrics_table,
        ).grid(row=1, column=11, sticky="ew", padx=(4, 0), pady=(8, 0))

        body = self.ttk.Frame(top, padding=(8, 0, 8, 8))
        body.grid(row=2, column=0, sticky="nsew")
        body.rowconfigure(0, weight=1)
        body.columnconfigure(0, weight=1)
        fig = self.Figure(figsize=(10.0, 7.2), dpi=130)
        axis = fig.add_subplot(111)
        canvas = self.FigureCanvasTkAgg(fig, master=body)
        canvas.get_tk_widget().grid(row=0, column=0, sticky="nsew")

        self.metrics_window = {
            "top": top,
            "summary_var": summary_var,
            "detail_var": detail_var,
            "figure": fig,
            "axis": axis,
            "canvas": canvas,
            "scope_var": scope_var,
            "plot_mode_var": plot_mode_var,
            "x_var": x_var,
            "y_var": y_var,
            "color_var": color_var,
            "group_var": group_var,
            "bins_var": bins_var,
            "log_x_var": log_x_var,
            "log_y_var": log_y_var,
            "scope_box": scope_box,
            "current_rows": [],
        }
        for widget in (scope_box, mode_box, x_box, y_box, color_box, group_box):
            widget.bind("<<ComboboxSelected>>", lambda _event: self._refresh_metrics_window())
        bins_entry.bind("<Return>", lambda _event: self._refresh_metrics_window())
        bins_entry.bind("<FocusOut>", lambda _event: self._refresh_metrics_window())
        top.protocol("WM_DELETE_WINDOW", self._close_metrics_window)
        self._refresh_metrics_window()

    def _close_metrics_window(self) -> None:
        existing = self.metrics_window
        if existing is None:
            return
        top = existing.get("top")
        if top is not None and top.winfo_exists():
            top.destroy()
        self.metrics_window = None

    def _refresh_metrics_window(self) -> None:
        existing = self.metrics_window
        if existing is None:
            return
        top = existing.get("top")
        if top is None or not top.winfo_exists():
            self.metrics_window = None
            return

        scope_specs = self._metrics_scope_specs()
        scope_values = [label for _key, label in scope_specs]
        scope_var = existing["scope_var"]
        if scope_var.get() not in scope_values:
            scope_var.set(scope_values[0] if scope_values else "All counted waves")
        existing["scope_box"].configure(values=scope_values)

        scope_key = self._metrics_key_from_label(
            scope_var.get(),
            scope_specs,
            "counted_all",
        )
        rows = self._metrics_scope_rows(scope_key)
        existing["current_rows"] = list(rows)
        fig = existing["figure"]
        canvas = existing["canvas"]
        fig.clear()
        axis = fig.add_subplot(111)
        existing["axis"] = axis
        self._style_metrics_axis(axis)

        plot_mode = str(existing["plot_mode_var"].get() or "histogram").lower()
        field_specs = self._metrics_field_specs()
        x_key = self._metrics_key_from_label(
            existing["x_var"].get(),
            field_specs,
            "fit_amp_km",
        )
        y_key = self._metrics_key_from_label(
            existing["y_var"].get(),
            field_specs,
            "peak_period_s",
        )
        group_specs = self._metrics_group_specs()
        group_key = self._metrics_key_from_label(
            existing["group_var"].get(),
            group_specs,
            "cut_name",
        )
        color_label = str(existing["color_var"].get() or "")
        color_key = self._metrics_key_from_label(
            color_label,
            field_specs,
            "confidence_score",
        )
        if color_label == "none":
            color_key = ""
        bins = max(self._safe_int_text(existing["bins_var"].get(), 18), 4)
        log_x = bool(existing["log_x_var"].get())
        log_y = bool(existing["log_y_var"].get())

        x_values, x_rows = self._metrics_numeric_values(rows, x_key)
        summary_scope = scope_var.get()
        existing["summary_var"].set(
            f"Scope: {summary_scope} | rows: {len(rows)} | finite X values: {x_values.size}"
        )

        if plot_mode == "scatter":
            y_values, y_rows = self._metrics_numeric_values(rows, y_key)
            row_pairs = [
                row
                for row in rows
                if row in x_rows and row in y_rows
            ]
            x_plot, row_pairs = self._metrics_numeric_values(row_pairs, x_key)
            y_plot, row_pairs = self._metrics_numeric_values(row_pairs, y_key)
            if x_plot.size and y_plot.size and x_plot.size == y_plot.size:
                color_values = None
                cmap = None
                if color_key:
                    color_values, color_rows = self._metrics_numeric_values(row_pairs, color_key)
                    if color_values.size != x_plot.size or color_rows != row_pairs:
                        color_values = None
                    else:
                        cmap = "viridis"
                scatter = axis.scatter(
                    x_plot,
                    y_plot,
                    c=color_values if color_values is not None else "#2E5FA7",
                    cmap=cmap,
                    s=44,
                    alpha=0.86,
                    edgecolors="white",
                    linewidths=0.5,
                )
                if color_values is not None:
                    cbar = fig.colorbar(scatter, ax=axis, pad=0.02)
                    cbar.set_label(self._metrics_field_label(color_key))
                axis.set_xlabel(self._metrics_field_label(x_key))
                axis.set_ylabel(self._metrics_field_label(y_key))
                axis.set_title(
                    f"{self._metrics_field_label(y_key)} vs {self._metrics_field_label(x_key)}",
                    fontsize=12,
                    fontweight="bold",
                    family="serif",
                )
                existing["detail_var"].set(
                    f"Scatter plot | n={x_plot.size} | "
                    f"median X={float(np.nanmedian(x_plot)):.3g} | "
                    f"median Y={float(np.nanmedian(y_plot)):.3g}"
                )
            else:
                axis.text(
                    0.5,
                    0.5,
                    "No finite rows for the selected scatter variables.",
                    ha="center",
                    va="center",
                    transform=axis.transAxes,
                )
                existing["detail_var"].set("Scatter plot unavailable for the selected variables.")
        elif plot_mode == "bar":
            y_values, y_rows = self._metrics_numeric_values(rows, y_key)
            grouped_values: dict[str, list[float]] = {}
            for row in y_rows:
                group_label = str(row.get(group_key, "-") or "-").strip() or "-"
                grouped_values.setdefault(group_label, []).append(float(row[y_key]))
            grouped_items = [
                (label, np.asarray(values, dtype=np.float64))
                for label, values in grouped_values.items()
                if values
            ]
            grouped_items.sort(
                key=lambda item: (-int(item[1].size), str(item[0]).lower())
            )
            grouped_items = grouped_items[:20]
            if grouped_items:
                labels: list[str] = []
                centers: list[float] = []
                lower_err: list[float] = []
                upper_err: list[float] = []
                for label, values in grouped_items:
                    median = float(np.nanmedian(values))
                    p16 = float(np.nanpercentile(values, 16))
                    p84 = float(np.nanpercentile(values, 84))
                    labels.append(label)
                    centers.append(median)
                    lower_err.append(max(median - p16, 0.0))
                    upper_err.append(max(p84 - median, 0.0))
                x_pos = np.arange(len(labels), dtype=np.float64)
                axis.bar(
                    x_pos,
                    centers,
                    color="#2E5FA7",
                    alpha=0.88,
                    edgecolor="white",
                    linewidth=0.8,
                )
                axis.errorbar(
                    x_pos,
                    centers,
                    yerr=np.vstack(
                        [
                            np.asarray(lower_err, dtype=np.float64),
                            np.asarray(upper_err, dtype=np.float64),
                        ]
                    ),
                    fmt="none",
                    ecolor="#1F1F1F",
                    elinewidth=1.0,
                    capsize=4,
                    capthick=1.0,
                )
                axis.set_xticks(x_pos)
                axis.set_xticklabels(labels, rotation=28, ha="right")
                axis.set_xlabel(
                    self._metrics_label_from_key(group_key, group_specs, group_key)
                )
                axis.set_ylabel(self._metrics_field_label(y_key))
                axis.set_title(
                    f"{self._metrics_field_label(y_key)} by "
                    f"{self._metrics_label_from_key(group_key, group_specs, group_key)}",
                    fontsize=12,
                    fontweight="bold",
                    family="serif",
                )
                existing["detail_var"].set(
                    f"Bar plot | groups={len(grouped_items)} | finite Y values={y_values.size} | "
                    "error bars = p16-p84"
                )
            else:
                axis.text(
                    0.5,
                    0.5,
                    "No finite rows for the selected bar metric.",
                    ha="center",
                    va="center",
                    transform=axis.transAxes,
                )
                existing["detail_var"].set("Bar plot unavailable for the selected metric/group.")
        else:
            if x_values.size:
                axis.hist(
                    x_values,
                    bins=min(max(int(bins), 4), max(12, min(48, x_values.size))),
                    color="#2E5FA7",
                    alpha=0.88,
                    edgecolor="white",
                    linewidth=0.8,
                )
                median = float(np.nanmedian(x_values))
                axis.axvline(median, color="#B04A3A", linewidth=1.4, linestyle="--")
                axis.set_xlabel(self._metrics_field_label(x_key))
                axis.set_ylabel("Count")
                axis.set_title(
                    f"Distribution of {self._metrics_field_label(x_key)}",
                    fontsize=12,
                    fontweight="bold",
                    family="serif",
                )
                existing["detail_var"].set(
                    f"Histogram | n={x_values.size} | median={median:.3g} | "
                    f"p16={float(np.nanpercentile(x_values, 16)):.3g} | "
                    f"p84={float(np.nanpercentile(x_values, 84)):.3g}"
                )
            else:
                axis.text(
                    0.5,
                    0.5,
                    "No finite rows for the selected histogram variable.",
                    ha="center",
                    va="center",
                    transform=axis.transAxes,
                )
                existing["detail_var"].set("Histogram unavailable for the selected variable.")

        if log_x and plot_mode != "bar":
            try:
                axis.set_xscale("log")
            except Exception:
                pass
        if log_y:
            try:
                axis.set_yscale("log")
            except Exception:
                pass

        fig.tight_layout()
        canvas.draw_idle()

    def _focus_metrics_window_scope(
        self,
        scope_key: str,
        *,
        plot_mode: str = "scatter",
        group_key: str | None = None,
    ) -> None:
        self._open_metrics_window()
        existing = self.metrics_window
        if existing is None:
            return
        scope_specs = self._metrics_scope_specs()
        group_specs = self._metrics_group_specs()
        scope_label = self._metrics_label_from_key(
            scope_key,
            scope_specs,
            existing["scope_var"].get(),
        )
        existing["scope_var"].set(scope_label)
        if str(plot_mode) in {"histogram", "scatter", "bar"}:
            existing["plot_mode_var"].set(str(plot_mode))
        if group_key is not None:
            existing["group_var"].set(
                self._metrics_label_from_key(group_key, group_specs, existing["group_var"].get())
            )
        self._refresh_metrics_window()

    def _open_propagation_window(self) -> None:
        existing = self.propagation_window
        if existing is not None:
            top = existing.get("top")
            if top is not None and top.winfo_exists():
                top.deiconify()
                top.lift()
                self._refresh_propagation_window()
                return
            self.propagation_window = None

        top = self.tk.Toplevel(self.root)
        top.title("Propagation Groups")
        top.geometry("1520x860")
        top.rowconfigure(1, weight=1)
        top.columnconfigure(0, weight=1)

        header = self.ttk.Frame(top, padding=8)
        header.grid(row=0, column=0, sticky="ew")
        header.columnconfigure(0, weight=1)
        summary_var = self.tk.StringVar(value="")
        detail_var = self.tk.StringVar(value="")
        self.ttk.Label(
            header, textvariable=summary_var, justify="left", wraplength=1480
        ).grid(row=0, column=0, sticky="w")
        self.ttk.Label(
            header, textvariable=detail_var, justify="left", wraplength=1480
        ).grid(row=1, column=0, sticky="w", pady=(4, 0))

        body = self.ttk.Frame(top, padding=(8, 0, 8, 8))
        body.grid(row=1, column=0, sticky="nsew")
        body.rowconfigure(0, weight=1)
        body.columnconfigure(0, weight=1)
        body.columnconfigure(1, weight=1)

        groups_frame = self.ttk.LabelFrame(body, text="Groups", padding=6)
        groups_frame.grid(row=0, column=0, sticky="nsew", padx=(0, 6))
        groups_frame.rowconfigure(0, weight=1)
        groups_frame.columnconfigure(0, weight=1)
        groups_tree = self.ttk.Treeview(
            groups_frame,
            columns=("group", "class", "members", "cuts", "rep", "best", "amp", "period", "conf"),
            show="headings",
            height=18,
        )
        groups_tree.grid(row=0, column=0, sticky="nsew")
        groups_y = self.ttk.Scrollbar(groups_frame, orient="vertical", command=groups_tree.yview)
        groups_y.grid(row=0, column=1, sticky="ns")
        groups_x = self.ttk.Scrollbar(groups_frame, orient="horizontal", command=groups_tree.xview)
        groups_x.grid(row=1, column=0, sticky="ew")
        groups_tree.configure(yscrollcommand=groups_y.set, xscrollcommand=groups_x.set)
        for column, label, width in (
            ("group", "Group", 140),
            ("class", "Class", 110),
            ("members", "Members", 70),
            ("cuts", "Cuts", 55),
            ("rep", "Rep Amp", 95),
            ("best", "Best Conf", 95),
            ("amp", "Max A ['']", 85),
            ("period", "Pmed [s]", 85),
            ("conf", "Mean Conf", 85),
        ):
            groups_tree.heading(column, text=label)
            groups_tree.column(column, width=width, stretch=(column == "group"))

        members_frame = self.ttk.LabelFrame(body, text="Observations", padding=6)
        members_frame.grid(row=0, column=1, sticky="nsew", padx=(6, 0))
        members_frame.rowconfigure(0, weight=1)
        members_frame.columnconfigure(0, weight=1)
        members_tree = self.ttk.Treeview(
            members_frame,
            columns=("cut", "event", "status", "class", "period", "amp", "conf", "stack", "note"),
            show="headings",
            height=18,
        )
        members_tree.grid(row=0, column=0, sticky="nsew")
        members_y = self.ttk.Scrollbar(members_frame, orient="vertical", command=members_tree.yview)
        members_y.grid(row=0, column=1, sticky="ns")
        members_x = self.ttk.Scrollbar(members_frame, orient="horizontal", command=members_tree.xview)
        members_x.grid(row=1, column=0, sticky="ew")
        members_tree.configure(yscrollcommand=members_y.set, xscrollcommand=members_x.set)
        for column, label, width in (
            ("cut", "Cut", 120),
            ("event", "Event", 55),
            ("status", "Status", 115),
            ("class", "Class", 95),
            ("period", "P [s]", 70),
            ("amp", "A ['']", 70),
            ("conf", "Conf", 60),
            ("stack", "Stack", 120),
            ("note", "Note", 220),
        ):
            members_tree.heading(column, text=label)
            members_tree.column(column, width=width, stretch=(column in {"cut", "stack", "note"}))

        actions = self.ttk.Frame(top, padding=(8, 0, 8, 8))
        actions.grid(row=2, column=0, sticky="ew")
        for idx in range(5):
            actions.columnconfigure(idx, weight=1)
        self.ttk.Button(
            actions,
            text="Open Representative",
            command=self._focus_selected_propagation_representative,
        ).grid(row=0, column=0, sticky="ew", padx=(0, 4))
        self.ttk.Button(
            actions,
            text="Open Member",
            command=self._focus_selected_propagation_member,
        ).grid(row=0, column=1, sticky="ew", padx=4)
        self.ttk.Button(
            actions,
            text="Export Tables",
            command=self._export_propagation_tables,
        ).grid(row=0, column=2, sticky="ew", padx=4)
        self.ttk.Button(
            actions,
            text="Refresh",
            command=self._refresh_propagation_window,
        ).grid(row=0, column=3, sticky="ew", padx=4)
        self.ttk.Button(
            actions,
            text="Close",
            command=self._close_propagation_window,
        ).grid(row=0, column=4, sticky="ew", padx=(4, 0))

        self.propagation_window = {
            "top": top,
            "summary_var": summary_var,
            "detail_var": detail_var,
            "groups_tree": groups_tree,
            "members_tree": members_tree,
            "group_lookup": {},
            "member_lookup": {},
            "selected_group_key": None,
            "selected_member_ref": None,
            "tree_updating": False,
        }
        groups_tree.bind(
            "<<TreeviewSelect>>", lambda _event: self._on_propagation_group_select()
        )
        members_tree.bind(
            "<<TreeviewSelect>>", lambda _event: self._on_propagation_member_select()
        )
        top.protocol("WM_DELETE_WINDOW", self._close_propagation_window)
        self._refresh_propagation_window()

    def _close_propagation_window(self) -> None:
        existing = self.propagation_window
        if existing is None:
            return
        top = existing.get("top")
        if top is not None and top.winfo_exists():
            top.destroy()
        self.propagation_window = None

    def _refresh_propagation_window(self) -> None:
        existing = self.propagation_window
        if existing is None:
            return
        top = existing.get("top")
        if top is None or not top.winfo_exists():
            self.propagation_window = None
            return

        observation_rows = self._collect_curated_event_rows()
        group_rows = self._collect_propagation_group_rows(observation_rows)
        existing["group_lookup"] = {
            str(group["group_key"]): group for group in group_rows
        }
        groups_tree = existing["groups_tree"]
        selected_group_key = (
            existing.get("selected_group_key")
            if existing.get("selected_group_key") in existing["group_lookup"]
            else (group_rows[0]["group_key"] if group_rows else None)
        )

        existing["tree_updating"] = True
        try:
            children = groups_tree.get_children()
            if children:
                groups_tree.delete(*children)
            for group in group_rows:
                group_key = str(group["group_key"])
                groups_tree.insert(
                    "",
                    "end",
                    iid=f"grp-{group_key}",
                    values=(
                        group_key,
                        str(group["classification"]),
                        str(int(group["member_count"])),
                        str(int(group["cut_count"])),
                        (
                            f"{int(group['representative_cut_id'])}:{int(group['representative_event_id'])}"
                            if group.get("representative_cut_id") is not None
                            else "-"
                        ),
                        (
                            f"{int(group['best_conf_cut_id'])}:{int(group['best_conf_event_id'])}"
                            if group.get("best_conf_cut_id") is not None
                            else "-"
                        ),
                        (
                            f"{float(group['max_amp_arcsec']):.3f}"
                            if np.isfinite(float(group["max_amp_arcsec"]))
                            else "-"
                        ),
                        (
                            f"{float(group['median_period_s']):.2f}"
                            if np.isfinite(float(group["median_period_s"]))
                            else "-"
                        ),
                        (
                            f"{float(group['mean_confidence_score']):.1f}"
                            if np.isfinite(float(group["mean_confidence_score"]))
                            else "-"
                        ),
                    ),
                )
            existing["selected_group_key"] = selected_group_key
            if selected_group_key is not None:
                target_iid = f"grp-{selected_group_key}"
                groups_tree.selection_set(target_iid)
                groups_tree.focus(target_iid)
            else:
                groups_tree.selection_remove(groups_tree.selection())
        finally:
            existing["tree_updating"] = False

        linked_count = sum(1 for group in group_rows if not bool(group.get("synthetic_group")))
        existing["summary_var"].set(
            f"Propagation groups: {len(group_rows)} | linked groups: {linked_count} | observations: {len(observation_rows)}"
        )
        self._refresh_propagation_members()

    def _refresh_propagation_members(self) -> None:
        existing = self.propagation_window
        if existing is None:
            return
        members_tree = existing["members_tree"]
        group = existing.get("group_lookup", {}).get(existing.get("selected_group_key"))
        members = [] if group is None else list(group.get("members", []))
        existing["member_lookup"] = {
            (int(member["cut_id"]), int(member["event_id"])): member for member in members
        }
        selected_member_ref = (
            existing.get("selected_member_ref")
            if existing.get("selected_member_ref") in existing["member_lookup"]
            else (
                (int(members[0]["cut_id"]), int(members[0]["event_id"]))
                if members
                else None
            )
        )
        existing["tree_updating"] = True
        try:
            children = members_tree.get_children()
            if children:
                members_tree.delete(*children)
            for member in members:
                cut_id = int(member["cut_id"])
                event_id = int(member["event_id"])
                iid = f"mem-{cut_id}-{event_id}"
                members_tree.insert(
                    "",
                    "end",
                    iid=iid,
                    values=(
                        f"{cut_id:02d} {member['cut_name']}",
                        str(event_id),
                        str(member["status"]),
                        str(member.get("resolved_propagation_class") or member.get("propagation_class") or "-"),
                        (
                            f"{float(member['peak_period_s']):.2f}"
                            if np.isfinite(float(member["peak_period_s"]))
                            else "-"
                        ),
                        (
                            f"{float(member['fit_amp_arcsec']):.3f}"
                            if np.isfinite(float(member["fit_amp_arcsec"]))
                            else "-"
                        ),
                        (
                            f"{float(member['confidence_score']):.1f}"
                            if np.isfinite(float(member["confidence_score"]))
                            else "-"
                        ),
                        ",".join(member.get("stack_positions") or []) or "-",
                        str(member.get("review_notes") or "-"),
                    ),
                )
            existing["selected_member_ref"] = selected_member_ref
            if selected_member_ref is not None:
                target_iid = f"mem-{selected_member_ref[0]}-{selected_member_ref[1]}"
                members_tree.selection_set(target_iid)
                members_tree.focus(target_iid)
            else:
                members_tree.selection_remove(members_tree.selection())
        finally:
            existing["tree_updating"] = False

        if group is None:
            existing["detail_var"].set("Select a propagation group to inspect its observations.")
            return
        existing["detail_var"].set(
            f"Group {group['group_key']} | class={group['classification']} | cuts={','.join(str(cut_id) for cut_id in group['cut_ids'])} | "
            f"rep={group['representative_cut_id']}:{group['representative_event_id']} | "
            f"best conf={group['best_conf_cut_id']}:{group['best_conf_event_id']}"
        )

    def _on_propagation_group_select(self) -> None:
        existing = self.propagation_window
        if existing is None or existing.get("tree_updating"):
            return
        selection = existing["groups_tree"].selection()
        if not selection:
            existing["selected_group_key"] = None
        else:
            iid = str(selection[0])
            existing["selected_group_key"] = iid[4:] if iid.startswith("grp-") else None
        self._refresh_propagation_members()

    def _on_propagation_member_select(self) -> None:
        existing = self.propagation_window
        if existing is None or existing.get("tree_updating"):
            return
        selection = existing["members_tree"].selection()
        if not selection:
            existing["selected_member_ref"] = None
            return
        iid = str(selection[0])
        if iid.startswith("mem-"):
            try:
                _prefix, cut_id_text, event_id_text = iid.split("-", 2)
                existing["selected_member_ref"] = (
                    int(cut_id_text),
                    int(event_id_text),
                )
            except Exception:
                existing["selected_member_ref"] = None

    def _selected_propagation_member(self) -> dict[str, Any] | None:
        existing = self.propagation_window
        if existing is None:
            return None
        member_ref = existing.get("selected_member_ref")
        if member_ref is None:
            return None
        return existing.get("member_lookup", {}).get(member_ref)

    def _focus_wavelet_event_for_cut(self, cut_id: int, event_id: int) -> None:
        if cut_id not in self.cuts:
            self._set_status("Invalid cut target.")
            return
        if self._wavelet_event_ref_by_cut(cut_id, event_id) is None:
            self._set_status(f"Cut {cut_id} event {event_id} is no longer available.")
            return
        self.selected_cut_id = cut_id
        self._open_cut_in_td_window(cut_id)
        panel = self._primary_panel_for_cut(cut_id)
        if panel is None:
            return
        existing = self.td_windows.get(panel.panel_id)
        if existing is None:
            return
        existing["wavelet_selected_event_id"] = int(event_id)
        self._refresh_td_window_wavelet_views(panel.panel_id, redraw_td=True)
        self._set_status(f"Focused cut {cut_id} event {event_id}.")

    def _focus_selected_propagation_member(self) -> None:
        member = self._selected_propagation_member()
        if member is None:
            self._set_status("Select an observation first.")
            return
        self._focus_wavelet_event_for_cut(int(member["cut_id"]), int(member["event_id"]))

    def _focus_selected_propagation_representative(self) -> None:
        existing = self.propagation_window
        if existing is None:
            return
        group = existing.get("group_lookup", {}).get(existing.get("selected_group_key"))
        if group is None:
            self._set_status("Select a propagation group first.")
            return
        cut_id = group.get("representative_cut_id")
        event_id = group.get("representative_event_id")
        if cut_id is None or event_id is None:
            self._set_status("This group has no representative event.")
            return
        self._focus_wavelet_event_for_cut(int(cut_id), int(event_id))

    def _collect_wavelet_link_groups(self) -> list[dict[str, Any]]:
        groups: dict[str, dict[str, Any]] = {}
        for row in self._collect_curated_event_rows():
            group_id = str(row.get("link_group_id") or "").strip()
            if not group_id:
                continue
            member = {
                "panel_id": row.get("primary_panel_id"),
                "panel_name": row.get("primary_panel_name") or "-",
                "cut_id": row.get("cut_id"),
                "cut_name": row.get("cut_name") or "",
                "event_id": row.get("event_id"),
                "status": row.get("status"),
                "counted": bool(row.get("counted")),
                "confidence_score": row.get("confidence_score"),
                "review_locked": bool(row.get("review_locked")),
                "review_notes": str(row.get("review_notes", "")),
                "qa_flags_text": str(row.get("qa_flags_text", "")),
            }
            group = groups.setdefault(
                group_id,
                {
                    "group_id": group_id,
                    "members": [],
                },
            )
            group["members"].append(member)

        output: list[dict[str, Any]] = []
        for group_id, group in sorted(groups.items()):
            members = sorted(
                group["members"],
                key=lambda item: (
                    int(item["cut_id"]) if item.get("cut_id") is not None else -1,
                    int(item["event_id"]),
                ),
            )
            scores = [
                float(item["confidence_score"])
                for item in members
                if np.isfinite(float(item["confidence_score"]))
            ]
            cut_names = sorted({str(item["cut_name"] or "-") for item in members})
            statuses = sorted({str(item["status"]) for item in members})
            output.append(
                {
                    "group_id": group_id,
                    "members": members,
                    "event_count": len(members),
                    "panel_count": len(
                        {
                            int(item["panel_id"])
                            for item in members
                            if item.get("panel_id") is not None
                        }
                    ),
                    "cut_count": len(
                        {
                            int(item["cut_id"])
                            for item in members
                            if item.get("cut_id") is not None
                        }
                    ),
                    "counted_count": sum(1 for item in members if item["counted"]),
                    "locked_count": sum(1 for item in members if item["review_locked"]),
                    "mean_confidence": (
                        float(np.nanmean(scores)) if scores else float("nan")
                    ),
                    "cuts_text": ",".join(cut_names),
                    "status_text": ",".join(statuses),
                }
            )
        return output

    def _open_link_groups_window(
        self,
        *,
        initial_group_id: str | None = None,
        initial_member_ref: tuple[int, int] | None = None,
    ) -> None:
        existing = self.link_groups_window
        if existing is not None:
            top = existing.get("top")
            if top is not None and top.winfo_exists():
                if initial_group_id is not None:
                    existing["pending_group_id"] = str(initial_group_id)
                if initial_member_ref is not None:
                    existing["pending_member_ref"] = (
                        int(initial_member_ref[0]),
                        int(initial_member_ref[1]),
                    )
                top.deiconify()
                top.lift()
                self._refresh_link_groups_window()
                return
            self.link_groups_window = None

        top = self.tk.Toplevel(self.root)
        top.title("Linked Wavelet Groups")
        top.geometry("1420x780")
        top.rowconfigure(1, weight=1)
        top.columnconfigure(0, weight=1)

        header = self.ttk.Frame(top, padding=8)
        header.grid(row=0, column=0, sticky="ew")
        header.columnconfigure(0, weight=1)
        summary_var = self.tk.StringVar(value="")
        detail_var = self.tk.StringVar(value="")
        self.ttk.Label(
            header, textvariable=summary_var, justify="left", wraplength=1380
        ).grid(row=0, column=0, sticky="w")
        self.ttk.Label(
            header, textvariable=detail_var, justify="left", wraplength=1380
        ).grid(row=1, column=0, sticky="w", pady=(4, 0))

        body = self.ttk.Frame(top, padding=(8, 0, 8, 8))
        body.grid(row=1, column=0, sticky="nsew")
        body.rowconfigure(0, weight=1)
        body.columnconfigure(0, weight=1)
        body.columnconfigure(1, weight=1)

        groups_frame = self.ttk.LabelFrame(body, text="Groups", padding=6)
        groups_frame.grid(row=0, column=0, sticky="nsew", padx=(0, 6))
        groups_frame.rowconfigure(0, weight=1)
        groups_frame.columnconfigure(0, weight=1)
        groups_tree = self.ttk.Treeview(
            groups_frame,
            columns=("group", "members", "panels", "counted", "locked", "conf", "status"),
            show="headings",
            height=16,
        )
        groups_tree.grid(row=0, column=0, sticky="nsew")
        groups_y = self.ttk.Scrollbar(groups_frame, orient="vertical", command=groups_tree.yview)
        groups_y.grid(row=0, column=1, sticky="ns")
        groups_x = self.ttk.Scrollbar(groups_frame, orient="horizontal", command=groups_tree.xview)
        groups_x.grid(row=1, column=0, sticky="ew")
        groups_tree.configure(yscrollcommand=groups_y.set, xscrollcommand=groups_x.set)
        for column, label, width in (
            ("group", "Group", 90),
            ("members", "Events", 60),
            ("panels", "Cuts", 60),
            ("counted", "Counted", 70),
            ("locked", "Locked", 65),
            ("conf", "Mean Conf", 85),
            ("status", "Statuses", 220),
        ):
            groups_tree.heading(column, text=label)
            groups_tree.column(column, width=width, stretch=(column == "status"))

        members_frame = self.ttk.LabelFrame(body, text="Members", padding=6)
        members_frame.grid(row=0, column=1, sticky="nsew", padx=(6, 0))
        members_frame.rowconfigure(0, weight=1)
        members_frame.columnconfigure(0, weight=1)
        members_tree = self.ttk.Treeview(
            members_frame,
            columns=("panel", "cut", "event", "status", "conf", "lock", "qa", "note"),
            show="headings",
            height=16,
        )
        members_tree.grid(row=0, column=0, sticky="nsew")
        members_y = self.ttk.Scrollbar(
            members_frame, orient="vertical", command=members_tree.yview
        )
        members_y.grid(row=0, column=1, sticky="ns")
        members_x = self.ttk.Scrollbar(
            members_frame, orient="horizontal", command=members_tree.xview
        )
        members_x.grid(row=1, column=0, sticky="ew")
        members_tree.configure(yscrollcommand=members_y.set, xscrollcommand=members_x.set)
        for column, label, width in (
            ("panel", "Panel", 90),
            ("cut", "Cut", 110),
            ("event", "Event", 55),
            ("status", "Status", 120),
            ("conf", "Conf", 60),
            ("lock", "Lock", 55),
            ("qa", "QA", 120),
            ("note", "Note", 220),
        ):
            members_tree.heading(column, text=label)
            members_tree.column(column, width=width, stretch=(column in {"note", "qa"}))

        actions = self.ttk.Frame(top, padding=(8, 0, 8, 8))
        actions.grid(row=2, column=0, sticky="ew")
        for idx in range(4):
            actions.columnconfigure(idx, weight=1)
        self.ttk.Button(
            actions,
            text="Open Member",
            command=self._focus_selected_link_group_member,
        ).grid(row=0, column=0, sticky="ew", padx=(0, 4))
        self.ttk.Button(
            actions,
            text="Sync Group From Member",
            command=self._sync_selected_link_group_member,
        ).grid(row=0, column=1, sticky="ew", padx=4)
        self.ttk.Button(
            actions,
            text="Refresh",
            command=self._refresh_link_groups_window,
        ).grid(row=0, column=2, sticky="ew", padx=4)
        self.ttk.Button(
            actions,
            text="Close",
            command=self._close_link_groups_window,
        ).grid(row=0, column=3, sticky="ew", padx=(4, 0))

