    def _build_figure(self) -> None:
        self.canvas = self.FigureCanvasTkAgg(self.figure, master=self.figure_frame)
        self.canvas.get_tk_widget().grid(row=0, column=0, sticky="nsew")
        self.canvas.get_tk_widget().configure(takefocus=True)

        if self.main_toolbar is not None:
            try:
                self.main_toolbar.destroy()
            except Exception:
                pass
        if self.main_toolbar_frame is None:
            self.main_toolbar_frame = self.tk.Frame(self.figure_frame)
            self.main_toolbar_frame.grid(row=1, column=0, sticky="ew", pady=(6, 0))
        else:
            for child in self.main_toolbar_frame.winfo_children():
                child.destroy()
        self.main_toolbar = self.NavigationToolbar2Tk(
            self.canvas,
            self.main_toolbar_frame,
        )
        self.main_toolbar.update()

        self.canvas.mpl_connect("button_press_event", self._on_canvas_press)
        self.canvas.mpl_connect("button_release_event", self._on_canvas_release)
        self.canvas.mpl_connect("motion_notify_event", self._on_canvas_motion)

    def _bind_shortcuts(self) -> None:
        self.root.bind("<Left>", self._on_global_left_shortcut)
        self.root.bind("<Right>", self._on_global_right_shortcut)
        self.root.bind("<Delete>", lambda _event: self._delete_selected_cut())
        self.root.bind("<Control-c>", lambda _event: self._copy_selected_cut())
        self.root.bind("<Control-v>", lambda _event: self._paste_cut())
        self.root.bind("<Escape>", lambda _event: self._cancel_pending_cut())
        self.root.bind("r", lambda _event: self._rotate_selected_cut(5.0))
        self.root.bind("R", lambda _event: self._rotate_selected_cut(-5.0))
        self.root.bind("n", lambda _event: self._start_draw_cut())
        self.root.bind("g", lambda _event: self._start_draw_feature_axis("line"))
        self.root.bind("G", lambda _event: self._start_draw_feature_axis("curve"))

    def _widget_blocks_timeline_shortcuts(self, widget: Any) -> bool:
        blocked_classes = {"Entry", "TEntry", "Spinbox", "TCombobox", "Text"}
        current = widget
        visited: set[int] = set()
        while current is not None:
            current_id = id(current)
            if current_id in visited:
                break
            visited.add(current_id)
            try:
                if str(current.winfo_class()) in blocked_classes:
                    return True
            except Exception:
                pass
            current = getattr(current, "master", None)
        return False

    def _on_global_left_shortcut(self, event: Any) -> str | None:
        if self._widget_blocks_timeline_shortcuts(getattr(event, "widget", None)):
            return None
        self._step_t_visual(-1)
        return "break"

    def _on_global_right_shortcut(self, event: Any) -> str | None:
        if self._widget_blocks_timeline_shortcuts(getattr(event, "widget", None)):
            return None
        self._step_t_visual(1)
        return "break"

    def _apply_layout(self) -> None:
        rows, cols = LAYOUT_PRESETS[self.layout_var.get()]
        self.visible_panels = rows * cols

        if self.active_panel_id > self.visible_panels:
            self.active_panel_id = 1

        self.figure.clear()
        grid = self.figure.add_gridspec(
            1, 2, width_ratios=[1.0, 1.15], wspace=0.18
        )
        self.map_ax = self.figure.add_subplot(grid[0, 0])
        mosaic_grid = grid[0, 1].subgridspec(rows, cols, hspace=0.28, wspace=0.22)

        self.panel_axes.clear()
        self.axis_to_panel_id.clear()
        for index in range(self.visible_panels):
            row = index // cols
            col = index % cols
            ax = self.figure.add_subplot(mosaic_grid[row, col])
            panel_id = index + 1
            self.panel_axes[panel_id] = ax
            self.axis_to_panel_id[ax] = panel_id

        with warnings.catch_warnings():
            warnings.filterwarnings(
                "ignore",
                message="This figure includes Axes that are not compatible with tight_layout",
                category=UserWarning,
            )
            self.figure.tight_layout()
        self._refresh_panel_list()
        self._sync_controls_from_active_panel()

    def _save_session(self) -> None:
        default_name = self.cube_path.stem + "_td_session.json"
        save_path = self.filedialog.asksaveasfilename(
            title="Save session",
            initialdir=str(Path(__file__).resolve().parent.parent),
            initialfile=default_name,
            defaultextension=".json",
            filetypes=[("JSON", "*.json"), ("All files", "*.*")],
        )
        if not save_path:
            return
        save_path_obj = Path(save_path)
        self._write_session_file(save_path_obj, autosave=False)
        self._set_status(f"Session saved to {save_path_obj}")

    def _refresh_panel_list(self) -> None:
        self.panel_listbox.delete(0, self.tk.END)
        for panel in self.panels[: self.visible_panels]:
            cut = self.cuts.get(panel.cut_id) if panel.cut_id is not None else None
            params = self._panel_td_params(panel)
            label = (
                f"{panel.name} | no cut"
                if cut is None
                else f"{panel.name} | {cut.name} | "
                f"t={int(params['t_ini'])}:{int(params['t_fin'])}:{int(params['stride'])} | "
                f"w={int(params['width'])} {params['weighting']}"
            )
            self.panel_listbox.insert(self.tk.END, label)

        if self.visible_panels > 0:
            self.panel_listbox.selection_clear(0, self.tk.END)
            self.panel_listbox.selection_set(self.active_panel_id - 1)
            self.panel_listbox.activate(self.active_panel_id - 1)

    def _refresh_cut_list(self) -> None:
        self.cut_listbox.delete(0, self.tk.END)
        ordered = sorted(self.cuts.values(), key=lambda cut: cut.cut_id)
        for cut in ordered:
            preview_cut = self._cut_preview(cut.cut_id) or cut
            marker = "L" if cut.locked else " "
            dynamic_marker = f"D{len(self._cut_dynamic_keyframes(cut.cut_id))}" if self._cut_dynamic_enabled(cut.cut_id) else "--"
            label = (
                f"{cut.cut_id:02d} {cut.name} {marker} {dynamic_marker} "
                f"[{self._cut_curve_mode_label(preview_cut)}] "
                f"({preview_cut.p0[0]:.1f},{preview_cut.p0[1]:.1f}) -> ({preview_cut.p1[0]:.1f},{preview_cut.p1[1]:.1f})"
            )
            self.cut_listbox.insert(self.tk.END, label)

        if self.selected_cut_id is None:
            return

        index = next(
            (i for i, cut in enumerate(ordered) if cut.cut_id == self.selected_cut_id),
            None,
        )
        if index is not None:
            self.cut_listbox.selection_clear(0, self.tk.END)
            self.cut_listbox.selection_set(index)
            self.cut_listbox.activate(index)

    def _feature_axis_label(self, axis: FeatureAxis) -> str:
        total_length = polyline_length(axis.points)
        return (
            f"{axis.axis_id:02d} {axis.name} | {axis.mode} | "
            f"pts={len(axis.points)} | L={total_length:.1f}"
        )

    def _selected_feature_axis(self) -> FeatureAxis | None:
        if self.selected_feature_axis_id is None:
            return None
        return self.feature_axes.get(self.selected_feature_axis_id)

    def _refresh_feature_axis_list(self) -> None:
        if not hasattr(self, "feature_axis_listbox"):
            return
        self.feature_axis_listbox.delete(0, self.tk.END)
        ordered = sorted(self.feature_axes.values(), key=lambda axis: axis.axis_id)
        for axis in ordered:
            self.feature_axis_listbox.insert(self.tk.END, self._feature_axis_label(axis))
        if self.selected_feature_axis_id not in self.feature_axes:
            self.selected_feature_axis_id = ordered[0].axis_id if ordered else None
        if self.selected_feature_axis_id is not None:
            index = next(
                (
                    idx
                    for idx, axis in enumerate(ordered)
                    if int(axis.axis_id) == int(self.selected_feature_axis_id)
                ),
                None,
            )
            if index is not None:
                self.feature_axis_listbox.selection_clear(0, self.tk.END)
                self.feature_axis_listbox.selection_set(index)
                self.feature_axis_listbox.activate(index)
        self._sync_feature_axis_controls()

    def _sync_feature_axis_controls(self) -> None:
        axis = self._selected_feature_axis()
        if self.feature_draw_mode == "curve" and not self.feature_pending_points:
            self.selected_feature_axis_name_var.set(
                "Drawing curve axis: left-click to add points. Finish Curve or right-click closes it."
            )
            return
        if self.feature_draw_mode == "curve" and self.feature_pending_points:
            self.selected_feature_axis_name_var.set(
                f"Drawing curve axis: {len(self.feature_pending_points)} point(s). "
                "Left-click adds points, Finish Curve or right-click closes it."
            )
            return
        if self.feature_draw_mode == "line" and not self.feature_pending_points:
            self.selected_feature_axis_name_var.set(
                "Drawing line axis: click the first point on the map."
            )
            return
        if self.feature_draw_mode == "line" and self.feature_pending_points:
            self.selected_feature_axis_name_var.set(
                "Drawing line axis: choose the second point on the map."
            )
            return
        if axis is None:
            self.selected_feature_axis_name_var.set(
                "No feature axis selected. Draw a line or curve to define the feature spine."
            )
            return
        self.selected_feature_axis_name_var.set(
            f"Selected: {axis.name} | mode={axis.mode} | points={len(axis.points)} | "
            f"length={polyline_length(axis.points):.1f} px"
        )

    def _stack_label(self, stack: dict[str, Any]) -> str:
        return f"{int(stack['stack_id']):02d} {stack['name']} ({len(stack.get('cut_ids') or [])})"

    def _selected_stack(self) -> dict[str, Any] | None:
        if self.active_stack_id is None:
            return None
        return self.stacks.get(self.active_stack_id)

    def _refresh_stack_list(self) -> None:
        if not hasattr(self, "stack_listbox"):
            return
        self.stack_listbox.delete(0, self.tk.END)
        ordered = sorted(self.stacks.values(), key=lambda item: int(item["stack_id"]))
        for stack in ordered:
            self.stack_listbox.insert(self.tk.END, self._stack_label(stack))
        if self.active_stack_id not in self.stacks:
            self.active_stack_id = ordered[0]["stack_id"] if ordered else None
        if self.active_stack_id is None:
            return
        index = next(
            (
                idx
                for idx, stack in enumerate(ordered)
                if int(stack["stack_id"]) == int(self.active_stack_id)
            ),
            None,
        )
        if index is not None:
            self.stack_listbox.selection_clear(0, self.tk.END)
            self.stack_listbox.selection_set(index)
            self.stack_listbox.activate(index)

    def _refresh_stack_member_list(self) -> None:
        if not hasattr(self, "stack_member_listbox"):
            return
        self.stack_member_listbox.delete(0, self.tk.END)
        stack = self._selected_stack()
        if stack is None:
            self.selected_stack_cut_id = None
            return
        cut_ids = [
            int(cut_id) for cut_id in stack.get("cut_ids", []) if int(cut_id) in self.cuts
        ]
        stack["cut_ids"] = cut_ids
        for index, cut_id in enumerate(cut_ids, start=1):
            cut = self.cuts[cut_id]
            state = self._cut_analysis(cut_id)
            event_count = len(state.get("wavelet_events") or [])
            cell_status = ""
            for experiment in self.experiments.values():
                for cell in experiment.get("cells") or []:
                    if int(cell.get("cut_id", -1)) == int(cut_id):
                        cell_status = str(cell.get("status") or "")
                        break
                if cell_status:
                    break
            tracking_done = (
                "T"
                if state.get("crest_tracking_result")
                or cell_status in {"nuwt_completed", "wavelet_completed", "completed"}
                else "-"
            )
            wavelet_done = (
                "W"
                if state.get("wavelet_filter_result")
                or cell_status in {"wavelet_completed", "completed"}
                else "-"
            )
            dynamic_tag = f"D{len(self._cut_dynamic_keyframes(cut_id))}" if self._cut_dynamic_enabled(cut_id) else "--"
            self.stack_member_listbox.insert(
                self.tk.END,
                f"{index:02d} | {cut.cut_id:02d} {cut.name} | {dynamic_tag} | {tracking_done}{wavelet_done} | events={event_count}",
            )
        if self.selected_stack_cut_id not in cut_ids:
            self.selected_stack_cut_id = cut_ids[0] if cut_ids else None
        if self.selected_stack_cut_id is None:
            return
        member_index = next(
            (
                idx
                for idx, cut_id in enumerate(cut_ids)
                if int(cut_id) == int(self.selected_stack_cut_id)
            ),
            None,
        )
        if member_index is not None:
            self.stack_member_listbox.selection_clear(0, self.tk.END)
            self.stack_member_listbox.selection_set(member_index)
            self.stack_member_listbox.activate(member_index)

    def _refresh_experiment_list(self) -> None:
        if not hasattr(self, "experiment_listbox"):
            return
        for experiment in self.experiments.values():
            self._sync_experiment_state_from_disk(experiment)
        self.experiment_listbox.delete(0, self.tk.END)
        ordered = sorted(
            self.experiments.values(),
            key=lambda item: int(item.get("experiment_id", 0)),
        )
        for experiment in ordered:
            self.experiment_listbox.insert(self.tk.END, self._experiment_label(experiment))
        if self.active_experiment_id not in self.experiments:
            self.active_experiment_id = ordered[0]["experiment_id"] if ordered else None
        if self.active_experiment_id is not None:
            index = next(
                (
                    idx
                    for idx, experiment in enumerate(ordered)
                    if int(experiment["experiment_id"]) == int(self.active_experiment_id)
                ),
                None,
            )
            if index is not None:
                self.experiment_listbox.selection_clear(0, self.tk.END)
                self.experiment_listbox.selection_set(index)
                self.experiment_listbox.activate(index)
        experiment = self._selected_experiment()
        if experiment is None:
            self.experiment_progress_global_var.set("Idle.")
            self.experiment_progress_outer_var.set("Stacks: 0/0")
            self.experiment_progress_inner_var.set("Members: 0/0")
            self.experiment_progress_stage_var.set("Stage: idle")
            self.experiment_view_mode_var.set("displacement")
            self._refresh_experiment_output_info(None)
            self._refresh_experiment_run_button(None)
            if hasattr(self, "experiment_view_displacement_button"):
                self.experiment_view_displacement_button.configure(state="normal")
            if hasattr(self, "experiment_view_rotation_button"):
                self.experiment_view_rotation_button.configure(state="normal")
            return
        self.experiment_output_dir_var.set(
            str(experiment.get("export_root") or self.experiment_output_dir_var.get()).strip()
        )
        self._refresh_experiment_output_info(experiment)
        self._refresh_experiment_run_button(experiment)
        available_modes = self._experiment_available_stack_modes(experiment)
        current_view_mode = self._normalize_experiment_stack_mode(
            experiment.get("view_mode") or self._experiment_stack_mode(experiment)
        )
        if available_modes and current_view_mode not in available_modes:
            current_view_mode = self._experiment_stack_mode(experiment)
            experiment["view_mode"] = current_view_mode
        self.experiment_view_mode_var.set(current_view_mode)
        if hasattr(self, "experiment_view_displacement_button"):
            self.experiment_view_displacement_button.configure(
                state=("normal" if "displacement" in available_modes or not available_modes else "disabled")
            )
        if hasattr(self, "experiment_view_rotation_button"):
            self.experiment_view_rotation_button.configure(
                state=("normal" if "rotation" in available_modes or not available_modes else "disabled")
            )
        cells = len(self._experiment_cells(experiment))
        stack_count = len(self._experiment_stack_specs(experiment))
        stack_mode = self._experiment_stack_mode(experiment)
        self.experiment_progress_global_var.set(
            f"{experiment['name']} | status={experiment.get('status', 'created')} "
            f"| stacks={stack_mode} "
            f"| study={'full-cube-angle' if bool(experiment.get('full_cube_angles', False)) else 'standard'} "
            f"| coverage={'full-frame' if bool(experiment.get('dynamic_length', False)) else 'base-length'} "
            f"| w={int(experiment.get('td_width', 1))} {str(experiment.get('td_weighting') or 'uniform')} "
            f"| cells={cells}"
        )
        self.experiment_progress_outer_var.set(f"Stacks: {stack_count}")
        self.experiment_progress_inner_var.set(f"Members: {cells}")
        self.experiment_progress_stage_var.set(
            "Stage: "
            f"NUWT={experiment.get('nuwt_status', 'pending')} | "
            f"Wavelet={experiment.get('wavelet_status', 'pending')} | "
            f"Tables={experiment.get('tables_status', 'pending')} | "
            f"{experiment.get('last_run_summary') or experiment.get('status', 'idle')}"
        )

    def _on_experiment_list_select(self, _event: Any) -> None:
        if not hasattr(self, "experiment_listbox"):
            return
        selection = self.experiment_listbox.curselection()
        if not selection:
            return
        ordered = sorted(
            self.experiments.values(),
            key=lambda item: int(item.get("experiment_id", 0)),
        )
        index = int(selection[0])
        if not (0 <= index < len(ordered)):
            return
        self.active_experiment_id = int(ordered[index]["experiment_id"])
        self._refresh_experiment_list()

    def _experiment_td_sampling_params(self) -> tuple[int, str]:
        width_default = max(
            self._safe_int_text(
                self.panel_width_var.get() if hasattr(self, "panel_width_var") else 1,
                1,
            ),
            1,
        )
        width = max(
            self._safe_int_text(
                self.experiment_width_var.get() if hasattr(self, "experiment_width_var") else width_default,
                width_default,
            ),
            1,
        )
        weighting = str(
            self.experiment_weighting_var.get()
            if hasattr(self, "experiment_weighting_var")
            else "uniform"
        ).strip() or "uniform"
        if weighting not in {"uniform", "gaussian"}:
            weighting = "uniform"
        if hasattr(self, "experiment_width_var"):
            self.experiment_width_var.set(str(width))
        if hasattr(self, "experiment_weighting_var"):
            self.experiment_weighting_var.set(weighting)
        return width, weighting

    def _activate_selected_experiment_view(self, mode: str) -> None:
        experiment = self._selected_experiment()
        if experiment is None:
            self._set_status("Select a study first.")
            return
        normalized_mode = self._normalize_experiment_stack_mode(mode)
        available_modes = self._experiment_available_stack_modes(experiment)
        if available_modes and normalized_mode not in available_modes:
            fallback_mode = self._experiment_stack_mode(experiment)
            experiment["view_mode"] = fallback_mode
            self.refresh_all()
            self._set_status(
                f"{experiment['name']}: only {fallback_mode} stacks are available for this study."
            )
            return
        experiment["view_mode"] = normalized_mode
        stack_ids = (
            experiment.get("rotation_stack_ids")
            if normalized_mode == "rotation"
            else experiment.get("displacement_stack_ids")
        ) or []
        valid_stack_ids = [int(stack_id) for stack_id in stack_ids if int(stack_id) in self.stacks]
        if valid_stack_ids:
            self.active_stack_id = int(valid_stack_ids[0])
            stack = self.stacks[int(valid_stack_ids[0])]
            cut_ids = [int(cut_id) for cut_id in (stack.get("cut_ids") or []) if int(cut_id) in self.cuts]
            self.selected_stack_cut_id = cut_ids[0] if cut_ids else None
        self._record_session_change()
        self.refresh_all()
        self._set_status(
            f"{experiment['name']}: viewing stacks by {normalized_mode}."
        )

    def _series_from_range(self, start_value: float, end_value: float, step_value: float) -> list[float]:
        step_value = abs(float(step_value))
        if step_value <= 0.0:
            return [float(start_value)]
        if end_value < start_value:
            start_value, end_value = end_value, start_value
        count = int(math.floor((end_value - start_value) / step_value + 1e-9)) + 1
        values = [float(start_value + idx * step_value) for idx in range(max(count, 1))]
        if not values or values[-1] < end_value - 1e-6:
            values.append(float(end_value))
        rounded = [round(value, 6) for value in values]
        out: list[float] = []
        for value in rounded:
            if not out or abs(value - out[-1]) > 1e-6:
                out.append(float(value))
        return out

    def _symmetric_series(self, limit_value: float, step_value: float) -> list[float]:
        limit_value = abs(float(limit_value))
        values = self._series_from_range(-limit_value, limit_value, step_value)
        if not any(abs(value) <= 1e-6 for value in values):
            values.append(0.0)
            values.sort()
        return values

    def _offset_series(
        self, min_value: float, max_value: float, step_value: float
    ) -> list[float]:
        start_value = float(min(min_value, max_value))
        end_value = float(max(min_value, max_value))
        values = self._series_from_range(start_value, end_value, step_value)
        if start_value <= 0.0 <= end_value and not any(abs(value) <= 1e-6 for value in values):
            values.append(0.0)
            values.sort()
        return values

    def _cut_normal_and_displacement_limits(
        self, cut: Cut
    ) -> tuple[float, float, float, float] | None:
        dx = float(cut.p1[0] - cut.p0[0])
        dy = float(cut.p1[1] - cut.p0[1])
        norm = math.hypot(dx, dy)
        if norm <= 1e-6:
            return None
        normal_x = -dy / norm
        normal_y = dx / norm
        positive_limit = min(
            ray_limit(cut.p0, (normal_x, normal_y), self.nx, self.ny),
            ray_limit(cut.p1, (normal_x, normal_y), self.nx, self.ny),
        )
        negative_limit = min(
            ray_limit(cut.p0, (-normal_x, -normal_y), self.nx, self.ny),
            ray_limit(cut.p1, (-normal_x, -normal_y), self.nx, self.ny),
        )
        return (
            float(normal_x),
            float(normal_y),
            -float(max(negative_limit, 0.0)),
            float(max(positive_limit, 0.0)),
        )

    def _experiment_output_root(self, experiment: dict[str, Any]) -> Path:
        configured = str(experiment.get("export_root") or "").strip()
        if configured:
            target = Path(configured).expanduser().resolve()
        else:
            base_dir = self._resolved_export_dir()
            target = base_dir / (
                f"{self._safe_export_slug(self.cube_path.stem)}"
                f"_cut{int(experiment.get('base_cut_id') or 0):03d}"
                f"_study{int(experiment.get('experiment_id') or 0):03d}"
                f"_{self._safe_export_slug(str(experiment.get('name') or 'study'))}"
            )
        target.mkdir(parents=True, exist_ok=True)
        experiment["export_root"] = str(target)
        return target

    def _experiment_output_display_path(
        self, experiment: dict[str, Any] | None = None
    ) -> Path:
        if experiment is not None:
            configured = str(experiment.get("export_root") or "").strip()
            if configured:
                return Path(configured).expanduser().resolve()
            return self._resolved_export_dir() / (
                f"{self._safe_export_slug(self.cube_path.stem)}"
                f"_cut{int(experiment.get('base_cut_id') or 0):03d}"
                f"_study{int(experiment.get('experiment_id') or 0):03d}"
                f"_{self._safe_export_slug(str(experiment.get('name') or 'study'))}"
            )
        configured = str(self.experiment_output_dir_var.get()).strip()
        if configured:
            return Path(configured).expanduser().resolve()
        return self._resolved_export_dir()

    def _refresh_experiment_output_info(
        self, experiment: dict[str, Any] | None = None
    ) -> None:
        if not hasattr(self, "experiment_output_info_var"):
            return
        label = "Output"
        if experiment is not None:
            label = f"Output for {str(experiment.get('name') or 'study')}"
        self.experiment_output_info_var.set(
            f"{label}: {self._experiment_output_display_path(experiment)}"
        )

    def _ensure_experiment_output_structure(
        self, root_dir: Path, experiment: dict[str, Any] | None = None
    ) -> None:
        root_dir.mkdir(parents=True, exist_ok=True)
        (root_dir / "cells").mkdir(parents=True, exist_ok=True)
        # Create both stack families so a folder change cannot break later saves.
        (root_dir / "displacements").mkdir(parents=True, exist_ok=True)
        (root_dir / "rotates").mkdir(parents=True, exist_ok=True)
        if experiment is not None and bool(
            experiment.get("save_options", {}).get("save_important_images", True)
        ):
            (root_dir / "important_zones_images").mkdir(parents=True, exist_ok=True)

    def _sync_experiment_state_from_disk(self, experiment: dict[str, Any] | None) -> None:
        if experiment is None:
            return
        configured_root = str(experiment.get("export_root") or "").strip()
        root_dir = (
            Path(configured_root).expanduser().resolve()
            if configured_root
            else self._experiment_output_display_path(experiment)
        )
        status_path = Path(
            str(experiment.get("status_path") or (root_dir / "status.json"))
        ).expanduser()
        manifest_path = Path(
            str(experiment.get("manifest_path") or (root_dir / "manifest.json"))
        ).expanduser()
        experiment["status_path"] = str(status_path.resolve())
        experiment["manifest_path"] = str(manifest_path.resolve())

        status_payload: dict[str, Any] = {}
        status_mtime_ns = (
            status_path.stat().st_mtime_ns if status_path.exists() else None
        )
        if status_mtime_ns != experiment.get("_status_mtime_ns") and status_path.exists():
            try:
                loaded_status = self._read_json_file(status_path)
            except Exception:
                loaded_status = None
            if isinstance(loaded_status, dict):
                status_payload = loaded_status
                for key in (
                    "status",
                    "nuwt_status",
                    "wavelet_status",
                    "tables_status",
                    "updated_at",
                    "completed_at",
                ):
                    value = loaded_status.get(key)
                    if value not in {None, ""}:
                        experiment[key] = value
                summary_text = str(loaded_status.get("summary") or "").strip()
                if summary_text:
                    experiment["last_run_summary"] = summary_text
        experiment["_status_mtime_ns"] = status_mtime_ns

        manifest_payload: dict[str, Any] = {}
        manifest_mtime_ns = (
            manifest_path.stat().st_mtime_ns if manifest_path.exists() else None
        )
        need_manifest_sync = bool(
            not experiment.get("stack_outputs")
            or manifest_mtime_ns != experiment.get("_manifest_mtime_ns")
        )
        if need_manifest_sync and manifest_path.exists():
            try:
                loaded_manifest = self._read_json_file(manifest_path)
            except Exception:
                loaded_manifest = None
            if isinstance(loaded_manifest, dict):
                manifest_payload = loaded_manifest
                stack_outputs = loaded_manifest.get("stack_outputs")
                if isinstance(stack_outputs, dict):
                    experiment["stack_outputs"] = dict(stack_outputs)
                disk_experiment = loaded_manifest.get("experiment")
                if isinstance(disk_experiment, dict):
                    for key in (
                        "export_root",
                        "completed_at",
                        "study_td_params",
                        "study_crest_params",
                        "study_wavelet_params",
                        "save_options",
                        "important_zone_rules",
                        "stack_group_mode",
                        "view_mode",
                        "td_width",
                        "td_weighting",
                        "dynamic_length",
                        "full_cube_angles",
                    ):
                        if key in disk_experiment and disk_experiment.get(key) is not None:
                            experiment[key] = self._json_safe(disk_experiment.get(key))
        experiment["_manifest_mtime_ns"] = manifest_mtime_ns

        if not status_payload:
            next_stage = str(
                ((manifest_payload.get("summary") or {}).get("next_stage") or "")
            ).strip().lower()
            if next_stage == "tables":
                experiment["status"] = str(experiment.get("status") or "finalizing")
                experiment["nuwt_status"] = "completed"
                experiment["wavelet_status"] = "completed"
                experiment["tables_status"] = str(
                    experiment.get("tables_status") or "pending"
                )
            elif next_stage == "wavelet":
                experiment["nuwt_status"] = "completed"
                experiment["wavelet_status"] = str(
                    experiment.get("wavelet_status") or "pending"
                )
            elif next_stage == "nuwt":
                experiment["nuwt_status"] = str(
                    experiment.get("nuwt_status") or "pending"
                )

    def _write_experiment_metadata_files(self, experiment: dict[str, Any]) -> None:
        root_dir = self._experiment_output_root(experiment)
        self._ensure_experiment_output_structure(root_dir, experiment)
        stack_outputs = experiment.get("stack_outputs") or {}
        manifest_path = root_dir / "manifest.json"
        existing_manifest: dict[str, Any] = {}
        if manifest_path.exists():
            try:
                loaded_manifest = self._read_json_file(manifest_path)
            except Exception:
                loaded_manifest = None
            if isinstance(loaded_manifest, dict):
                existing_manifest = dict(loaded_manifest)
        summary_payload = {
            **dict(existing_manifest.get("summary") or {}),
            "cell_count": int(len(self._experiment_cells(experiment))),
            "stack_count": int(len(self._experiment_stack_specs(experiment))),
            "next_stage": self._experiment_next_stage(experiment),
        }
        self._write_json_file(
            manifest_path,
            {
                **existing_manifest,
                "experiment": experiment,
                "stack_outputs": stack_outputs,
                "summary": summary_payload,
            },
        )
        self._write_json_file(
            root_dir / "status.json",
            {
                "experiment_id": int(experiment["experiment_id"]),
                "status": str(experiment.get("status") or "created"),
                "nuwt_status": str(experiment.get("nuwt_status") or "pending"),
                "wavelet_status": str(experiment.get("wavelet_status") or "pending"),
                "tables_status": str(experiment.get("tables_status") or "pending"),
                "updated_at": self._timestamp_now(),
                "completed_at": experiment.get("completed_at"),
                "summary": str(experiment.get("last_run_summary") or ""),
            },
        )

    def _browse_experiment_output_dir(self) -> None:
        raw = str(self.experiment_output_dir_var.get()).strip()
        initial_dir = str(
            Path(raw).expanduser()
            if raw
            else self._resolved_export_dir()
        )
        selected = self.filedialog.askdirectory(
            title="Select study folder",
            initialdir=initial_dir,
            mustexist=False,
        )
        if not selected:
            return
        resolved = str(Path(selected).expanduser().resolve())
        Path(resolved).mkdir(parents=True, exist_ok=True)
        self.experiment_output_dir_var.set(resolved)
        experiment = self._selected_experiment()
        _job_id, running_job = self._background_experiment_job()
        if experiment is not None and running_job is None:
            experiment["export_root"] = resolved
            experiment["updated_at"] = self._timestamp_now()
            self._ensure_experiment_output_structure(Path(resolved), experiment)
            self._write_experiment_metadata_files(experiment)
            self._record_session_change()
            self._refresh_experiment_list()
        self._refresh_experiment_output_info(experiment)
        self._set_status(f"Study folder set to {resolved}.")

    def _refresh_experiment_run_button(self, experiment: dict[str, Any] | None) -> None:
        if not hasattr(self, "experiment_nuwt_button"):
            return
        has_experiment = experiment is not None
        _job_id, running_job = self._background_experiment_job()
        busy = running_job is not None
        next_stage = self._experiment_next_stage(experiment)
        nuwt_status = str((experiment or {}).get("nuwt_status") or "pending")
        wavelet_status = str((experiment or {}).get("wavelet_status") or "pending")

        nuwt_enabled = has_experiment and not busy
        wavelet_enabled = (
            has_experiment
            and not busy
            and nuwt_status == "completed"
        )
        rebuild_enabled = (
            has_experiment
            and not busy
            and wavelet_status == "completed"
        )

        self.experiment_nuwt_button.configure(
            state=("normal" if nuwt_enabled else "disabled")
        )
        self.experiment_wavelet_button.configure(
            state=("normal" if wavelet_enabled else "disabled")
        )
        self.experiment_rebuild_button.configure(
            state=("normal" if rebuild_enabled else "disabled")
        )

        if next_stage == "nuwt":
            self.experiment_nuwt_button.configure(text="Run NUWT")
            self.experiment_wavelet_button.configure(text="Run Wavelet")
            self.experiment_rebuild_button.configure(text="Rebuild Tables")
        elif next_stage == "wavelet":
            self.experiment_nuwt_button.configure(text="Run NUWT")
            self.experiment_wavelet_button.configure(text="Run Wavelet")
            self.experiment_rebuild_button.configure(text="Rebuild Tables")
        else:
            self.experiment_nuwt_button.configure(text="Run NUWT")
            self.experiment_wavelet_button.configure(text="Run Wavelet")
            self.experiment_rebuild_button.configure(text="Rebuild Tables")

    def _experiment_stage_summary_text(
        self, experiment: dict[str, Any], stage_name: str
    ) -> str:
        stack_specs = self._experiment_stack_specs(experiment)
        td_params = self._experiment_study_td_params(experiment)
        crest_params = self._experiment_study_crest_params(experiment)
        lines = [
            f"Study: {str(experiment.get('name') or '')}",
            f"Stage: {str(stage_name).upper()}",
            f"Folder: {self._experiment_output_root(experiment)}",
            f"Stacks: {len(stack_specs)} | cells: {len(self._experiment_cells(experiment))}",
            (
                f"TD: t={int(td_params['t_ini'])}:{int(td_params['t_fin'])}:{int(td_params['stride'])} "
                f"| width={int(td_params['width'])} | weighting={str(td_params['weighting'])}"
            ),
            (
                f"NUWT: cad={float(crest_params['cad']):.3f} | res={float(crest_params['res']):.3f} "
                f"| grad={float(crest_params['grad']):.3f} | min_tlen={int(crest_params['min_tlen'])}"
            ),
        ]
        if str(stage_name) == "wavelet":
            wavelet_params = self._experiment_study_wavelet_params(experiment)
            lines.append(
                (
                    f"Wavelet: P=[{float(wavelet_params['p_min']):.2f}, {float(wavelet_params['p_max']):.2f}] s "
                    f"| ratio={float(wavelet_params['power_ratio_thresh']):.2f} "
                    f"| min amp={float(wavelet_params['min_amp_arcsec']):.3f}"
                )
            )
        return "\n".join(lines)

    def _prompt_experiment_nuwt_settings(
        self, experiment: dict[str, Any]
    ) -> tuple[dict[str, Any], dict[str, Any]] | None:
        td_params = self._experiment_study_td_params(experiment)
        crest_params = self._experiment_study_crest_params(experiment)
        top = self.tk.Toplevel(self.root)
        top.title("NUWT Study Conditions")
        top.transient(self.root)
        top.grab_set()
        top.resizable(True, True)

        frame = self.ttk.Frame(top, padding=14)
        frame.grid(row=0, column=0, sticky="nsew")
        frame.columnconfigure(1, weight=1)
        frame.columnconfigure(3, weight=1)

        self.ttk.Label(
            frame,
            text=self._experiment_stage_summary_text(experiment, "nuwt"),
            justify="left",
            wraplength=520,
        ).grid(row=0, column=0, columnspan=4, sticky="w")

        row = 1
        self.ttk.Label(frame, text="TD conditions").grid(
            row=row, column=0, columnspan=4, sticky="w", pady=(10, 0)
        )
        row += 1

        td_vars = {
            "t_ini": self.tk.StringVar(value=str(int(td_params["t_ini"]))),
            "t_fin": self.tk.StringVar(value=str(int(td_params["t_fin"]))),
            "stride": self.tk.StringVar(value=str(int(td_params["stride"]))),
            "width": self.tk.StringVar(value=str(int(td_params["width"]))),
            "weighting": self.tk.StringVar(value=str(td_params["weighting"])),
        }
        td_fields = [
            ("t_ini", "t ini"),
            ("t_fin", "t fin"),
            ("stride", "stride"),
            ("width", "TD width"),
        ]
        for key, label in td_fields:
            self.ttk.Label(frame, text=label).grid(
                row=row, column=0 if key in {"t_ini", "stride"} else 2, sticky="w", pady=(6, 0)
            )
            self.ttk.Entry(frame, textvariable=td_vars[key], width=10).grid(
                row=row,
                column=1 if key in {"t_ini", "stride"} else 3,
                sticky="ew",
                pady=(6, 0),
                padx=(6, 8 if key in {"t_ini", "stride"} else 0),
            )
            if key in {"t_fin", "width"}:
                row += 1

        self.ttk.Label(frame, text="weighting").grid(row=row, column=0, sticky="w", pady=(6, 0))
        self.ttk.Combobox(
            frame,
            textvariable=td_vars["weighting"],
            values=["uniform", "gaussian"],
            state="readonly",
            width=12,
        ).grid(row=row, column=1, sticky="ew", pady=(6, 0), padx=(6, 8))
        row += 1

        self.ttk.Label(frame, text="NUWT conditions").grid(
            row=row, column=0, columnspan=4, sticky="w", pady=(10, 0)
        )
        row += 1

        crest_vars = {
            "cad": self.tk.StringVar(value=f"{float(crest_params['cad']):.3f}"),
            "res": self.tk.StringVar(value=f"{float(crest_params['res']):.3f}"),
            "grad": self.tk.StringVar(value=f"{float(crest_params['grad']):.3f}"),
            "min_tlen": self.tk.StringVar(value=str(int(crest_params["min_tlen"]))),
            "max_dist_jump": self.tk.StringVar(value=str(int(crest_params["max_dist_jump"]))),
            "max_time_skip": self.tk.StringVar(value=str(int(crest_params["max_time_skip"]))),
        }
        crest_fields = [
            ("cad", "cad"),
            ("res", "res"),
            ("grad", "grad"),
            ("min_tlen", "min tlen"),
            ("max_dist_jump", "max dist jump"),
            ("max_time_skip", "max time skip"),
        ]
        for index, (key, label) in enumerate(crest_fields):
            local_row = row + index // 2
            local_col = 0 if index % 2 == 0 else 2
            self.ttk.Label(frame, text=label).grid(
                row=local_row, column=local_col, sticky="w", pady=(6, 0)
            )
            self.ttk.Entry(frame, textvariable=crest_vars[key], width=10).grid(
                row=local_row,
                column=local_col + 1,
                sticky="ew",
                pady=(6, 0),
                padx=(6, 8 if local_col == 0 else 0),
            )
        row += (len(crest_fields) + 1) // 2

        invert_var = self.tk.BooleanVar(value=bool(crest_params.get("invert", False)))
        gauss_var = self.tk.BooleanVar(value=bool(crest_params.get("gauss", False)))
        checks = self.ttk.Frame(frame)
        checks.grid(row=row, column=0, columnspan=4, sticky="w", pady=(8, 0))
        self.ttk.Checkbutton(checks, text="invert", variable=invert_var).grid(
            row=0, column=0, sticky="w"
        )
        self.ttk.Checkbutton(checks, text="gauss", variable=gauss_var).grid(
            row=0, column=1, sticky="w", padx=(12, 0)
        )
        row += 1

        result: dict[str, Any] = {"value": None}

        def close_with(value: Any) -> None:
            result["value"] = value
            if top.winfo_exists():
                top.destroy()

        def confirm() -> None:
            try:
                updated_td = {
                    "t_ini": clamp_int(int(float(td_vars["t_ini"].get())), 0, self.nt - 1),
                    "t_fin": clamp_int(int(float(td_vars["t_fin"].get())), 0, self.nt - 1),
                    "stride": max(int(float(td_vars["stride"].get())), 1),
                    "width": max(int(float(td_vars["width"].get())), 1),
                    "weighting": (
                        "gaussian"
                        if str(td_vars["weighting"].get() or "") == "gaussian"
                        else "uniform"
                    ),
                }
                if int(updated_td["t_fin"]) < int(updated_td["t_ini"]):
                    raise ValueError("t fin must be >= t ini.")
                updated_crest = {
                    "cad": float(crest_vars["cad"].get()),
                    "res": float(crest_vars["res"].get()),
                    "grad": float(crest_vars["grad"].get()),
                    "min_tlen": max(int(float(crest_vars["min_tlen"].get())), 1),
                    "max_dist_jump": max(int(float(crest_vars["max_dist_jump"].get())), 1),
                    "max_time_skip": max(int(float(crest_vars["max_time_skip"].get())), 0),
                    "invert": bool(invert_var.get()),
                    "gauss": bool(gauss_var.get()),
                }
            except Exception as exc:
                self.messagebox.showerror(
                    "Invalid NUWT settings",
                    f"Could not parse the study settings:\n\n{exc}",
                    parent=top,
                )
                return
            close_with((updated_td, updated_crest))

        buttons = self.ttk.Frame(frame)
        buttons.grid(row=row, column=0, columnspan=4, sticky="ew", pady=(12, 0))
        buttons.columnconfigure(0, weight=1)
        buttons.columnconfigure(1, weight=1)
        self.ttk.Button(buttons, text="Run NUWT", command=confirm).grid(
            row=0, column=0, sticky="ew", padx=(0, 4)
        )
        self.ttk.Button(buttons, text="Cancel", command=lambda: close_with(None)).grid(
            row=0, column=1, sticky="ew", padx=(4, 0)
        )

        top.protocol("WM_DELETE_WINDOW", lambda: close_with(None))
        top.bind("<Escape>", lambda _event: close_with(None))
        top.bind("<Return>", lambda _event: confirm())
        top.update_idletasks()
        top.focus_set()
        self.root.wait_window(top)
        return result["value"]

    def _prompt_experiment_wavelet_settings(
        self, experiment: dict[str, Any]
    ) -> dict[str, Any] | None:
        wavelet_params = self._experiment_study_wavelet_params(experiment)
        top = self.tk.Toplevel(self.root)
        top.title("Wavelet Study Conditions")
        top.transient(self.root)
        top.grab_set()
        top.resizable(True, True)

        frame = self.ttk.Frame(top, padding=14)
        frame.grid(row=0, column=0, sticky="nsew")
        for col in range(4):
            frame.columnconfigure(col, weight=1 if col in {1, 3} else 0)

        self.ttk.Label(
            frame,
            text=self._experiment_stage_summary_text(experiment, "wavelet"),
            justify="left",
            wraplength=560,
        ).grid(row=0, column=0, columnspan=4, sticky="w")

        vars_map = {
            "p_min": self.tk.StringVar(value=f"{float(wavelet_params['p_min']):.2f}"),
            "p_max": self.tk.StringVar(value=f"{float(wavelet_params['p_max']):.2f}"),
            "power_ratio_thresh": self.tk.StringVar(
                value=f"{float(wavelet_params['power_ratio_thresh']):.2f}"
            ),
            "segment_power_frac": self.tk.StringVar(
                value=f"{float(wavelet_params['segment_power_frac']):.2f}"
            ),
            "min_points_segment": self.tk.StringVar(
                value=str(int(wavelet_params["min_points_segment"]))
            ),
            "min_amp_arcsec": self.tk.StringVar(
                value=f"{float(wavelet_params['min_amp_arcsec']):.3f}"
            ),
            "max_jump_pix": self.tk.StringVar(
                value=f"{float(wavelet_params['max_jump_pix']):.2f}"
            ),
            "min_points_cut_seg": self.tk.StringVar(
                value=str(int(wavelet_params["min_points_cut_seg"]))
            ),
            "rms_amp_ratio_max": self.tk.StringVar(
                value=f"{float(wavelet_params['rms_amp_ratio_max']):.2f}"
            ),
            "km_per_arcsec": self.tk.StringVar(
                value=f"{float(wavelet_params['km_per_arcsec']):.2f}"
            ),
            "density_kg_m3": self.tk.StringVar(
                value=""
                if not np.isfinite(float(wavelet_params["density_kg_m3"]))
                else f"{float(wavelet_params['density_kg_m3']):.3e}"
            ),
            "phase_speed_km_s": self.tk.StringVar(
                value=""
                if not np.isfinite(float(wavelet_params["phase_speed_km_s"]))
                else f"{float(wavelet_params['phase_speed_km_s']):.2f}"
            ),
            "min_prominence": self.tk.StringVar(
                value=f"{float(wavelet_params['min_prominence']):.3f}"
            ),
            "min_snr": self.tk.StringVar(value=f"{float(wavelet_params['min_snr']):.2f}"),
            "continuity_weight": self.tk.StringVar(
                value=f"{float(wavelet_params['continuity_weight']):.2f}"
            ),
            "time_weight": self.tk.StringVar(
                value=f"{float(wavelet_params['time_weight']):.2f}"
            ),
            "quality_weight": self.tk.StringVar(
                value=f"{float(wavelet_params['quality_weight']):.2f}"
            ),
            "error_weight": self.tk.StringVar(
                value=f"{float(wavelet_params['error_weight']):.2f}"
            ),
        }
        labels = [
            ("p_min", "P min [s]"),
            ("p_max", "P max [s]"),
            ("power_ratio_thresh", "power ratio"),
            ("segment_power_frac", "segment frac"),
            ("min_points_segment", "min pts seg"),
            ("min_amp_arcsec", "min amp [arcsec]"),
            ("max_jump_pix", "max jump [px]"),
            ("min_points_cut_seg", "min pts cut"),
            ("rms_amp_ratio_max", "rms/amp max"),
            ("km_per_arcsec", "km/arcsec"),
            ("density_kg_m3", "density [kg/m3]"),
            ("phase_speed_km_s", "phase speed [km/s]"),
            ("min_prominence", "min prominence"),
            ("min_snr", "min snr"),
            ("continuity_weight", "continuity w"),
            ("time_weight", "time w"),
            ("quality_weight", "quality w"),
            ("error_weight", "error w"),
        ]
        for index, (key, label) in enumerate(labels, start=1):
            local_row = index
            local_col = 0 if index % 2 == 1 else 2
            if local_col == 0 and index > 1:
                local_row = (index + 1) // 2
            elif local_col == 2:
                local_row = index // 2
            self.ttk.Label(frame, text=label).grid(
                row=local_row, column=local_col, sticky="w", pady=(6, 0)
            )
            self.ttk.Entry(frame, textvariable=vars_map[key], width=12).grid(
                row=local_row,
                column=local_col + 1,
                sticky="ew",
                pady=(6, 0),
                padx=(6, 8 if local_col == 0 else 0),
            )
        row = max((len(labels) + 1) // 2, 1) + 1

        result: dict[str, Any] = {"value": None}

        def close_with(value: Any) -> None:
            result["value"] = value
            if top.winfo_exists():
                top.destroy()

        def parse_optional_float(text: str) -> float:
            clean = str(text).strip()
            if not clean:
                return float("nan")
            return float(clean)

        def confirm() -> None:
            try:
                updated = {
                    "p_min": float(vars_map["p_min"].get()),
                    "p_max": float(vars_map["p_max"].get()),
                    "power_ratio_thresh": float(vars_map["power_ratio_thresh"].get()),
                    "segment_power_frac": float(vars_map["segment_power_frac"].get()),
                    "min_points_segment": max(int(float(vars_map["min_points_segment"].get())), 1),
                    "min_amp_arcsec": float(vars_map["min_amp_arcsec"].get()),
                    "max_jump_pix": float(vars_map["max_jump_pix"].get()),
                    "min_points_cut_seg": max(int(float(vars_map["min_points_cut_seg"].get())), 1),
                    "rms_amp_ratio_max": float(vars_map["rms_amp_ratio_max"].get()),
                    "km_per_arcsec": float(vars_map["km_per_arcsec"].get()),
                    "density_kg_m3": parse_optional_float(vars_map["density_kg_m3"].get()),
                    "phase_speed_km_s": parse_optional_float(vars_map["phase_speed_km_s"].get()),
                    "min_prominence": float(vars_map["min_prominence"].get()),
                    "min_snr": float(vars_map["min_snr"].get()),
                    "continuity_weight": float(vars_map["continuity_weight"].get()),
                    "time_weight": float(vars_map["time_weight"].get()),
                    "quality_weight": float(vars_map["quality_weight"].get()),
                    "error_weight": float(vars_map["error_weight"].get()),
                }
                if float(updated["p_max"]) <= float(updated["p_min"]):
                    raise ValueError("P max must be greater than P min.")
            except Exception as exc:
                self.messagebox.showerror(
                    "Invalid wavelet settings",
                    f"Could not parse the wavelet settings:\n\n{exc}",
                    parent=top,
                )
                return
            close_with(updated)

        buttons = self.ttk.Frame(frame)
        buttons.grid(row=row, column=0, columnspan=4, sticky="ew", pady=(12, 0))
        buttons.columnconfigure(0, weight=1)
        buttons.columnconfigure(1, weight=1)
        self.ttk.Button(buttons, text="Run Wavelet", command=confirm).grid(
            row=0, column=0, sticky="ew", padx=(0, 4)
        )
        self.ttk.Button(buttons, text="Cancel", command=lambda: close_with(None)).grid(
            row=0, column=1, sticky="ew", padx=(4, 0)
        )

        top.protocol("WM_DELETE_WINDOW", lambda: close_with(None))
        top.bind("<Escape>", lambda _event: close_with(None))
        top.bind("<Return>", lambda _event: confirm())
        top.update_idletasks()
        top.focus_set()
        self.root.wait_window(top)
        return result["value"]

    def _drop_cut_from_experiments(self, cut_id: int) -> None:
        for experiment in self.experiments.values():
            experiment["cut_ids"] = [
                int(member_cut_id)
                for member_cut_id in (experiment.get("cut_ids") or [])
                if int(member_cut_id) != int(cut_id)
            ]
            experiment["cells"] = [
                dict(cell)
                for cell in (experiment.get("cells") or [])
                if int(cell.get("cut_id", -1)) != int(cut_id)
            ]

    def _drop_stack_from_experiments(self, stack_id: int) -> None:
        for experiment in self.experiments.values():
            experiment["displacement_stack_ids"] = [
                int(current_stack_id)
                for current_stack_id in (experiment.get("displacement_stack_ids") or [])
                if int(current_stack_id) != int(stack_id)
            ]
            experiment["rotation_stack_ids"] = [
                int(current_stack_id)
                for current_stack_id in (experiment.get("rotation_stack_ids") or [])
                if int(current_stack_id) != int(stack_id)
            ]

    def _generate_exhaustive_experiment(self) -> None:
        base_cut = self._selected_cut()
        if base_cut is None:
            self._set_status("Select a base cut first.")
            return
        if self._cut_is_curve(base_cut):
            self._set_status("Exhaustive studies currently require a straight base cut.")
            return
        full_sweep = bool(self.experiment_full_sweep_var.get())
        step_value = self._parse_float_var(
            self.experiment_displacement_step_var.get(), "displacement step"
        )
        angle_min = self._parse_float_var(self.experiment_angle_min_var.get(), "angle min")
        angle_max = self._parse_float_var(self.experiment_angle_max_var.get(), "angle max")
        angle_step = self._parse_float_var(self.experiment_angle_step_var.get(), "angle step")
        if None in {step_value, angle_min, angle_max, angle_step}:
            return
        step_value = max(float(step_value), 1.0)
        angle_step = max(abs(float(angle_step)), 0.1)

        base_preview = (
            self._cut_preview(base_cut.cut_id, int(self.t_visual_var.get())) or base_cut
        )
        displacement_geometry = self._cut_normal_and_displacement_limits(base_preview)
        if displacement_geometry is None:
            self._set_status("Base cut is too short for a study.")
            return
        normal_x, normal_y, allowed_min, allowed_max = displacement_geometry
        angle_values = self._series_from_range(float(angle_min), float(angle_max), angle_step)
        if not angle_values:
            self._set_status("The study definition produced no valid angles.")
            return

        base_name = str(self.experiment_name_var.get()).strip() or f"Study {self.next_experiment_id}"
        full_cube_angles = self._warn_experiment_full_cube_angles(base_name)
        if full_cube_angles is None:
            self._set_status("Study generation cancelled.")
            return

        displacement_min: float
        displacement_max: float
        offset_values: list[float] = []
        angle_offset_values: list[list[float]] = []
        stack_group_mode: str
        total_cells = 0

        if bool(full_cube_angles):
            base_center = cut_center(base_preview)
            base_directed_angle = float(cut_directed_angle_deg(base_preview))
            global_offset_min = float("inf")
            global_offset_max = -float("inf")
            max_offset_series: list[float] = []
            for angle_value in angle_values:
                target_angle = base_directed_angle - float(angle_value)
                family_offsets = self._full_cube_angle_offset_values(
                    base_center,
                    target_angle,
                    step_value,
                )
                if not family_offsets:
                    family_offsets = [0.0]
                angle_offset_values.append([float(value) for value in family_offsets])
                total_cells += len(family_offsets)
                if len(family_offsets) > len(max_offset_series):
                    max_offset_series = list(family_offsets)
                global_offset_min = min(global_offset_min, float(min(family_offsets)))
                global_offset_max = max(global_offset_max, float(max(family_offsets)))
            if not np.isfinite(global_offset_min) or not np.isfinite(global_offset_max):
                global_offset_min = float(allowed_min)
                global_offset_max = float(allowed_max)
            displacement_min = float(global_offset_min)
            displacement_max = float(global_offset_max)
            offset_values = [float(value) for value in max_offset_series]
            stack_group_mode = "rotation"
        else:
            displacement_min_in = None
            displacement_max_in = None
            if not full_sweep:
                displacement_min_in = self._parse_float_var(
                    self.experiment_displacement_min_var.get(), "displacement min"
                )
                displacement_max_in = self._parse_float_var(
                    self.experiment_displacement_max_var.get(), "displacement max"
                )
                if None in {displacement_min_in, displacement_max_in}:
                    return
            if full_sweep:
                displacement_min = float(allowed_min)
                displacement_max = float(allowed_max)
            else:
                displacement_min = clamp_value(
                    float(displacement_min_in), allowed_min, allowed_max
                )
                displacement_max = clamp_value(
                    float(displacement_max_in), allowed_min, allowed_max
                )
            offset_values = self._offset_series(
                float(displacement_min),
                float(displacement_max),
                step_value,
            )
            total_cells = len(offset_values) * len(angle_values)
            stack_group_mode = self._prompt_experiment_stack_mode(
                base_name,
                len(offset_values),
                len(angle_values),
            ) or ""
            if not stack_group_mode:
                self._set_status("Study generation cancelled.")
                return

        td_width, td_weighting = self._experiment_td_sampling_params()
        if total_cells <= 0:
            self._set_status("The study definition produced no cells.")
            return
        if total_cells > MAX_EXPERIMENT_CUTS_HARD:
            self._set_status(
                f"Study would generate {total_cells} cuts. Hard limit is {MAX_EXPERIMENT_CUTS_HARD}; reduce the ranges first."
            )
            return
        if total_cells > MAX_EXPERIMENT_CUTS_WARN:
            continue_large = self.messagebox.askyesno(
                "Large Study",
                (
                    f"This study will generate {total_cells} cuts.\n\n"
                    f"The recommended limit is {MAX_EXPERIMENT_CUTS_WARN} because larger studies can be slow and heavy.\n"
                    "Do you want to continue anyway?"
                ),
                parent=self.root,
            )
            if not continue_large:
                self._set_status("Study generation cancelled.")
                return
        dynamic_length = self._warn_experiment_full_frame_rotations(base_name)
        if dynamic_length is None:
            self._set_status("Study generation cancelled.")
            return
        experiment_id = int(self.next_experiment_id)
        self.next_experiment_id += 1
        experiment = self._make_default_experiment_state(
            experiment_id,
            base_name,
            base_cut_id=base_cut.cut_id,
        )
        experiment["base_cut_name"] = str(base_cut.name)
        experiment["base_frame_idx"] = int(self.t_visual_var.get())
        experiment["base_angle_deg"] = float(cut_display_angle_deg(base_preview))
        experiment["base_length_px"] = float(cut_length(base_preview))
        experiment["displacement_step"] = float(step_value)
        experiment["displacement_min"] = float(displacement_min)
        experiment["displacement_max"] = float(displacement_max)
        experiment["displacement_limit"] = max(
            abs(float(displacement_min)),
            abs(float(displacement_max)),
        )
        experiment["full_sweep"] = bool(full_sweep)
        experiment["full_cube_angles"] = bool(full_cube_angles)
        experiment["offset_values"] = [float(value) for value in offset_values]
        experiment["angle_offset_values"] = self._json_safe(angle_offset_values)
        experiment["angle_min"] = float(min(angle_values))
        experiment["angle_max"] = float(max(angle_values))
        experiment["angle_step"] = float(angle_step)
        experiment["angle_values"] = [float(value) for value in angle_values]
        experiment["td_width"] = int(td_width)
        experiment["td_weighting"] = str(td_weighting)
        experiment["dynamic_length"] = bool(dynamic_length)
        experiment["min_cut_length_px"] = float(MIN_EXPERIMENT_CUT_LENGTH_PX)
        experiment["stack_group_mode"] = str(stack_group_mode)
        experiment["view_mode"] = str(stack_group_mode)
        base_state = self._cut_analysis_snapshot(base_cut.cut_id)
        base_td_params = self._cut_td_params(base_cut.cut_id)
        crest_params, wavelet_params = self._merge_crest_and_wavelet_params(
            base_state.get("crest_params"), base_state.get("wavelet_params")
        )
        experiment["study_td_params"] = {
            "t_ini": int(base_td_params["t_ini"]),
            "t_fin": int(base_td_params["t_fin"]),
            "stride": int(base_td_params["stride"]),
            "width": int(td_width),
            "weighting": str(td_weighting),
        }
        experiment["study_crest_params"] = dict(crest_params)
        experiment["study_wavelet_params"] = dict(wavelet_params)
        requested_output_dir = str(self.experiment_output_dir_var.get()).strip()
        if requested_output_dir:
            experiment["export_root"] = str(Path(requested_output_dir).expanduser().resolve())
        else:
            default_root = self._resolved_export_dir() / (
                f"{self._safe_export_slug(self.cube_path.stem)}"
                f"_cut{int(base_cut.cut_id):03d}"
                f"_study{int(experiment_id):03d}"
                f"_{self._safe_export_slug(base_name)}"
            )
            experiment["export_root"] = str(default_root.resolve())
            self.experiment_output_dir_var.set(str(default_root.resolve()))
        experiment["save_options"] = {
            "save_td_fits": bool(self.experiment_save_td_fits_var.get()),
            "save_stack_json": bool(self.experiment_save_stack_json_var.get()),
            "save_important_images": bool(self.experiment_save_important_images_var.get()),
        }
        experiment_root = self._experiment_output_root(experiment)
        output_folders = [
            "rotates" if str(stack_group_mode) == "rotation" else "displacements",
            "cells",
        ]
        if bool(experiment["save_options"].get("save_important_images", True)):
            output_folders.append("important_zones_images")
        for folder_name in output_folders:
            (experiment_root / folder_name).mkdir(parents=True, exist_ok=True)
        experiment["status_path"] = str(experiment_root / "status.json")
        experiment["manifest_path"] = str(experiment_root / "manifest.json")

        generated_cut_ids: list[int] = []
        cells: list[dict[str, Any]] = []
        displacement_stack_specs: list[tuple[float, list[int]]] = []
        displacement_stack_ids: list[int] = []
        rotation_stack_map: dict[int, list[int]] = {
            idx: [] for idx in range(len(angle_values))
        }
        template_panel = self.active_panel
        base_length_px = max(float(cut_length(base_preview)), 1.0)
        min_cut_length_px = float(experiment["min_cut_length_px"])
        if bool(full_cube_angles):
            base_center = cut_center(base_preview)
            base_directed_angle = float(cut_directed_angle_deg(base_preview))
            for angle_idx, angle_value in enumerate(angle_values):
                row_cut_ids: list[int] = []
                target_angle = base_directed_angle - float(angle_value)
                ux, uy = vector_from_vertical_angle(target_angle)
                normal_x = -uy
                normal_y = ux
                family_offsets = (
                    angle_offset_values[angle_idx]
                    if angle_idx < len(angle_offset_values)
                    else [0.0]
                )
                for offset_idx, offset_value in enumerate(family_offsets):
                    point_on_line = (
                        float(base_center[0] + float(offset_value) * normal_x),
                        float(base_center[1] + float(offset_value) * normal_y),
                    )
                    frame_segment = self._line_segment_through_frame(
                        point_on_line,
                        target_angle,
                    )
                    if frame_segment is None:
                        continue
                    if bool(dynamic_length):
                        p0, p1, shifted_length = frame_segment
                    else:
                        frame_p0, frame_p1, _frame_length = frame_segment
                        frame_center = (
                            0.5 * (float(frame_p0[0]) + float(frame_p1[0])),
                            0.5 * (float(frame_p0[1]) + float(frame_p1[1])),
                        )
                        p0, p1, shifted_length = segment_from_angle_length(
                            target_angle,
                            base_length_px,
                            "center",
                            None,
                            frame_center,
                            self.nx,
                            self.ny,
                        )
                    if float(shifted_length) < min_cut_length_px:
                        continue
                    cut = self._create_cut(p0, p1)
                    cut.name = f"{base_name} a{angle_idx:02d} d{offset_idx:02d}"
                    self._seed_cut_td_params_from_panel(cut.cut_id, template_panel)
                    cut_state = self._cut_analysis(cut.cut_id)
                    cut_state["td_params"] = {
                        **dict(cut_state.get("td_params") or {}),
                        "width": int(td_width),
                        "weighting": str(td_weighting),
                    }
                    self._sync_panels_from_cut_td_params(cut.cut_id)
                    row_cut_ids.append(int(cut.cut_id))
                    rotation_stack_map[int(angle_idx)].append(int(cut.cut_id))
                    generated_cut_ids.append(int(cut.cut_id))
                    cell_id = f"ang_{angle_idx:03d}_off_{offset_idx:03d}"
                    cell_dir = str(experiment_root / "cells" / cell_id)
                    cells.append(
                        {
                            "cell_id": cell_id,
                            "cut_id": int(cut.cut_id),
                            "cut_name": str(cut.name),
                            "offset_idx": int(offset_idx),
                            "offset_value": float(offset_value),
                            "angle_idx": int(angle_idx),
                            "angle_deg": float(angle_value),
                            "cell_dir": cell_dir,
                            "status": "created",
                            "td_fits_path": "",
                            "nuwt_result_path": "",
                            "wavelet_result_path": "",
                        }
                    )
        else:
            for offset_idx, offset_value in enumerate(offset_values):
                row_cut_ids: list[int] = []
                for angle_idx, angle_value in enumerate(angle_values):
                    shifted = Cut(
                        cut_id=-1,
                        name="template",
                        color=base_preview.color,
                        p0=base_preview.p0,
                        p1=base_preview.p1,
                    )
                    shifted.p0, shifted.p1 = shift_cut(
                        shifted,
                        float(offset_value * normal_x),
                        float(offset_value * normal_y),
                        self.nx,
                        self.ny,
                    )
                    target_angle = (
                        float(cut_directed_angle_deg(shifted)) - float(angle_value)
                    )
                    shifted_center = cut_center(shifted)
                    shifted.p0, shifted.p1, shifted_length = (
                        self._build_experiment_cut_segment(
                            shifted_center,
                            target_angle,
                            base_length_px,
                            bool(dynamic_length),
                        )
                    )
                    if float(shifted_length) < min_cut_length_px:
                        continue
                    cut = self._create_cut(shifted.p0, shifted.p1)
                    cut.name = f"{base_name} d{offset_idx:02d} a{angle_idx:02d}"
                    self._seed_cut_td_params_from_panel(cut.cut_id, template_panel)
                    cut_state = self._cut_analysis(cut.cut_id)
                    cut_state["td_params"] = {
                        **dict(cut_state.get("td_params") or {}),
                        "width": int(td_width),
                        "weighting": str(td_weighting),
                    }
                    self._sync_panels_from_cut_td_params(cut.cut_id)
                    row_cut_ids.append(int(cut.cut_id))
                    rotation_stack_map[int(angle_idx)].append(int(cut.cut_id))
                    generated_cut_ids.append(int(cut.cut_id))
                    cell_id = f"off_{offset_idx:03d}_ang_{angle_idx:03d}"
                    cell_dir = str(experiment_root / "cells" / cell_id)
                    cells.append(
                        {
                            "cell_id": cell_id,
                            "cut_id": int(cut.cut_id),
                            "cut_name": str(cut.name),
                            "offset_idx": int(offset_idx),
                            "offset_value": float(offset_value),
                            "angle_idx": int(angle_idx),
                            "angle_deg": float(angle_value),
                            "cell_dir": cell_dir,
                            "status": "created",
                            "td_fits_path": "",
                            "nuwt_result_path": "",
                            "wavelet_result_path": "",
                        }
                    )
                displacement_stack_specs.append((float(offset_value), list(row_cut_ids)))

        rotation_stack_ids: list[int] = []
        if str(stack_group_mode) == "displacement":
            for offset_value, row_cut_ids in displacement_stack_specs:
                if not row_cut_ids:
                    continue
                displacement_stack = self._create_stack_state(
                    name=f"{base_name} | d={float(offset_value):+.1f}px",
                    cut_ids=row_cut_ids,
                )
                displacement_stack_ids.append(int(displacement_stack["stack_id"]))
        else:
            for angle_idx, angle_value in enumerate(angle_values):
                cut_ids = [
                    int(cut_id)
                    for cut_id in rotation_stack_map.get(int(angle_idx), [])
                    if int(cut_id) in self.cuts
                ]
                if not cut_ids:
                    continue
                rotation_stack = self._create_stack_state(
                    name=f"{base_name} | a={float(angle_value):+.1f}deg",
                    cut_ids=cut_ids,
                )
                rotation_stack_ids.append(int(rotation_stack["stack_id"]))

        if not generated_cut_ids:
            for stack_id in displacement_stack_ids + rotation_stack_ids:
                self.stacks.pop(int(stack_id), None)
            self.next_experiment_id = max(self.next_experiment_id - 1, 1)
            self._set_status("Study generation produced no valid cuts.")
            return

        experiment["cut_ids"] = generated_cut_ids
        experiment["cells"] = cells
        experiment["displacement_stack_ids"] = displacement_stack_ids
        experiment["rotation_stack_ids"] = rotation_stack_ids
        experiment["status"] = "generated"
        experiment["nuwt_status"] = "pending"
        experiment["wavelet_status"] = "pending"
        experiment["tables_status"] = "pending"
        experiment["stack_outputs"] = {}
        experiment["updated_at"] = self._timestamp_now()
        experiment["last_run_summary"] = "Generated geometry. Study folder ready."
        self.experiments[experiment_id] = experiment
        self._apply_experiment_params_to_cuts(experiment)
        self._write_experiment_metadata_files(experiment)
        self.active_experiment_id = experiment_id
        self.selected_cut_id = int(generated_cut_ids[0])
        primary_stack_ids = (
            displacement_stack_ids
            if str(stack_group_mode) == "displacement"
            else rotation_stack_ids
        )
        self.active_stack_id = (
            int(primary_stack_ids[0]) if primary_stack_ids else self.active_stack_id
        )
        self.selected_stack_cut_id = int(generated_cut_ids[0])
        self._record_session_change()
        self.refresh_all()
        self._set_status(
            f"Generated {len(generated_cut_ids)} exhaustive cuts for {base_name} "
            f"(d={float(displacement_min):+.1f}..{float(displacement_max):+.1f}px, "
            f"{'variable displacements per angle' if bool(full_cube_angles) else f'{len(offset_values)} displacements x {len(angle_values)} angles'}, "
            f"stacked by {stack_group_mode}, "
            f"study={'full cube' if bool(full_cube_angles) else 'standard'}, "
            f"length={'dynamic' if bool(dynamic_length) else 'fixed'}). "
            f"Folder: {experiment_root}"
        )

    def _delete_selected_experiment(self) -> None:
        experiment = self._selected_experiment()
        if experiment is None:
            self._set_status("Select a study first.")
            return
        if not self.messagebox.askyesno(
            "Delete Study",
            "Delete the study metadata and its generated view stacks?\n\n"
            "Generated cuts will be kept so you can still inspect them manually.",
            parent=self.root,
        ):
            return
        for stack_id in (
            list(experiment.get("displacement_stack_ids") or [])
            + list(experiment.get("rotation_stack_ids") or [])
        ):
            self.stacks.pop(int(stack_id), None)
        experiment_id = int(experiment["experiment_id"])
        self.experiments.pop(experiment_id, None)
        if self.active_experiment_id == experiment_id:
            self.active_experiment_id = next(iter(sorted(self.experiments.keys())), None)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Deleted study {experiment_id}.")

    def _create_stack(
        self, *, name: str | None = None, cut_ids: list[int] | None = None
    ) -> dict[str, Any]:
        stack = self._create_stack_state(name=name, cut_ids=cut_ids)
        self.active_stack_id = int(stack["stack_id"])
        self.selected_stack_cut_id = (cut_ids or [None])[0]
        self._record_session_change()
        self.refresh_all()
        return stack

    def _create_stack_state(
        self, *, name: str | None = None, cut_ids: list[int] | None = None
    ) -> dict[str, Any]:
        stack_id = int(self.next_stack_id)
        self.next_stack_id += 1
        stack = self._make_default_stack_state(
            stack_id,
            name or f"Stack {stack_id}",
            cut_ids or [],
        )
        self.stacks[stack_id] = stack
        return stack

    def _new_empty_stack(self) -> None:
        self._create_stack()
        self._set_status("Created an empty TD stack.")

    def _new_stack_from_all_cuts(self) -> None:
        ordered_cut_ids = sorted(self.cuts.keys())
        if not ordered_cut_ids:
            self._set_status("Create one or more cuts first.")
            return
        self._create_stack(cut_ids=ordered_cut_ids)
        self._set_status(f"Created a stack with {len(ordered_cut_ids)} cut(s).")

    def _rename_selected_stack(self) -> None:
        stack = self._selected_stack()
        if stack is None:
            self._set_status("Select a stack first.")
            return
        name = self.simpledialog.askstring(
            "Rename Stack",
            "Stack name:",
            initialvalue=str(stack["name"]),
            parent=self.root,
        )
        if name is None:
            return
        stack["name"] = str(name).strip() or str(stack["name"])
        self._record_session_change()
        self.refresh_all()

    def _delete_selected_stack(self) -> None:
        stack = self._selected_stack()
        if stack is None:
            self._set_status("Select a stack first.")
            return
        stack_id = int(stack["stack_id"])
        self.stacks.pop(stack_id, None)
        self._drop_stack_from_experiments(stack_id)
        if self.active_stack_id == stack_id:
            self.active_stack_id = next(iter(sorted(self.stacks.keys())), None)
        self.selected_stack_cut_id = None
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Deleted stack {stack_id}.")

    def _add_cut_to_stack(self, stack_id: int, cut_id: int) -> None:
        stack = self.stacks.get(stack_id)
        if stack is None or cut_id not in self.cuts:
            return
        cut_ids = list(stack.get("cut_ids") or [])
        if cut_id not in cut_ids:
            cut_ids.append(cut_id)
            stack["cut_ids"] = cut_ids
            self.selected_stack_cut_id = cut_id
            self._record_session_change()
            self.refresh_all()

    def _add_selected_cut_to_stack(self) -> None:
        stack = self._selected_stack()
        cut = self._selected_cut()
        if stack is None:
            self._set_status("Select a stack first.")
            return
        if cut is None:
            self._set_status("Select a cut first.")
            return
        self._add_cut_to_stack(int(stack["stack_id"]), int(cut.cut_id))
        self._set_status(f"Added {cut.name} to {stack['name']}.")

    def _add_all_cuts_to_stack(self) -> None:
        stack = self._selected_stack()
        if stack is None:
            self._set_status("Select a stack first.")
            return
        added = 0
        for cut_id in sorted(self.cuts.keys()):
            before = len(stack.get("cut_ids") or [])
            self._add_cut_to_stack(int(stack["stack_id"]), int(cut_id))
            if len(stack.get("cut_ids") or []) > before:
                added += 1
        if added == 0:
            self._set_status(f"{stack['name']} already contains all cuts.")
        else:
            self._set_status(f"Added {added} cut(s) to {stack['name']}.")

    def _selected_stack_cut_ids(self) -> list[int]:
        stack = self._selected_stack()
        if stack is None:
            return []
        cut_ids = [
            int(cut_id)
            for cut_id in (stack.get("cut_ids") or [])
            if int(cut_id) in self.cuts
        ]
        stack["cut_ids"] = cut_ids
        return cut_ids

    def _stack_template_cut_id(self, cut_ids: list[int]) -> int | None:
        normalized = [int(cut_id) for cut_id in cut_ids if int(cut_id) in self.cuts]
        if not normalized:
            return None
        preferred = [
            self.selected_stack_cut_id,
            self.selected_cut_id,
            self.active_panel.cut_id if getattr(self, "panels", None) else None,
        ]
        for candidate in preferred:
            if candidate is not None and int(candidate) in normalized:
                return int(candidate)
        return int(normalized[0])

    def _remove_selected_cut_from_stack(self) -> None:
        stack = self._selected_stack()
        if stack is None:
            self._set_status("Select a stack first.")
            return
        if self.selected_stack_cut_id is None:
            self._set_status("Select a stack member first.")
            return
        cut_ids = [int(cut_id) for cut_id in stack.get("cut_ids") or []]
        if self.selected_stack_cut_id not in cut_ids:
            self._set_status("Select a valid stack member first.")
            return
        cut_ids.remove(int(self.selected_stack_cut_id))
        stack["cut_ids"] = cut_ids
        self.selected_stack_cut_id = cut_ids[0] if cut_ids else None
        self._record_session_change()
        self.refresh_all()

    def _move_selected_stack_member(self, direction: int) -> None:
        stack = self._selected_stack()
        if stack is None or self.selected_stack_cut_id is None:
            self._set_status("Select a stack member first.")
            return
        cut_ids = [int(cut_id) for cut_id in stack.get("cut_ids") or []]
        if self.selected_stack_cut_id not in cut_ids:
            self._set_status("Select a valid stack member first.")
            return
        index = cut_ids.index(int(self.selected_stack_cut_id))
        target = index + int(direction)
        if target < 0 or target >= len(cut_ids):
            return
        cut_ids[index], cut_ids[target] = cut_ids[target], cut_ids[index]
        stack["cut_ids"] = cut_ids
        self._record_session_change()
        self.refresh_all()

    def _on_stack_list_select(self, _event: Any) -> None:
        if not hasattr(self, "stack_listbox"):
            return
        selection = self.stack_listbox.curselection()
        if not selection:
            return
        ordered = sorted(self.stacks.values(), key=lambda item: int(item["stack_id"]))
        if selection[0] >= len(ordered):
            return
        self.active_stack_id = int(ordered[selection[0]]["stack_id"])
        self.selected_stack_cut_id = None
        self.refresh_all()

    def _on_stack_member_select(self, _event: Any) -> None:
        stack = self._selected_stack()
        if stack is None or not hasattr(self, "stack_member_listbox"):
            return
        selection = self.stack_member_listbox.curselection()
        if not selection:
            return
        cut_ids = [int(cut_id) for cut_id in stack.get("cut_ids") or [] if int(cut_id) in self.cuts]
        if selection[0] >= len(cut_ids):
            return
        self.selected_stack_cut_id = cut_ids[selection[0]]
        self.selected_cut_id = self.selected_stack_cut_id
        self.refresh_all()

    def _sync_controls_from_active_panel(self) -> None:
        panel = self.active_panel
        params = self._panel_td_params(panel)
        self.control_update_guard = True
        self.panel_t_ini_var.set(int(params["t_ini"]))
        self.panel_t_fin_var.set(int(params["t_fin"]))
        self.panel_stride_var.set(int(params["stride"]))
        self.panel_width_var.set(int(params["width"]))
        self.panel_weighting_var.set(str(params["weighting"]))
        self.control_update_guard = False

    def _cut_option_label(self, cut: Cut) -> str:
        return f"{cut.cut_id}: {cut.name}"

    def _cut_from_option(self, value: str) -> Cut | None:
        if not value:
            return None
        try:
            cut_id = int(str(value).split(":", 1)[0].strip())
        except Exception:
            return None
        return self.cuts.get(cut_id)

    def _refresh_measurement_selectors(self) -> None:
        ordered = sorted(self.cuts.values(), key=lambda cut: cut.cut_id)
        values = [self._cut_option_label(cut) for cut in ordered]
        self.reference_cut_box["values"] = values
        self.target_cut_box["values"] = values

        ref_cut = self._cut_from_option(self.reference_cut_var.get())
        target_cut = self._cut_from_option(self.target_cut_var.get())

        if ref_cut is None and ordered:
            ref_cut = ordered[0]

        if target_cut is None:
            if self.selected_cut_id is not None and self.selected_cut_id in self.cuts:
                target_cut = self.cuts[self.selected_cut_id]
            elif len(ordered) > 1:
                target_cut = ordered[1]
            elif ordered:
                target_cut = ordered[0]

        if (
            ref_cut is not None
            and target_cut is not None
            and ref_cut.cut_id == target_cut.cut_id
            and len(ordered) > 1
        ):
            for candidate in ordered:
                if candidate.cut_id != ref_cut.cut_id:
                    target_cut = candidate
                    break

        self.reference_cut_var.set("" if ref_cut is None else self._cut_option_label(ref_cut))
        self.target_cut_var.set("" if target_cut is None else self._cut_option_label(target_cut))

    def _refresh_panel_cut_selector(self) -> None:
        ordered = sorted(self.cuts.values(), key=lambda cut: cut.cut_id)
        values = [self._cut_option_label(cut) for cut in ordered]
        self.panel_selector_update_guard = True
        self.panel_cut_box["values"] = values

        panel = self.active_panel
        cut = self.cuts.get(panel.cut_id) if panel.cut_id is not None else None
        if cut is None:
            self.panel_cut_var.set("")
        else:
            self.panel_cut_var.set(self._cut_option_label(cut))
        self.panel_selector_update_guard = False

    def _refresh_measurements(self) -> None:
        ref_cut = self._cut_from_option(self.reference_cut_var.get())
        target_cut = self._cut_from_option(self.target_cut_var.get())

        if ref_cut is None or target_cut is None:
            self.measure_center_var.set("Center distance: n/a")
            self.measure_min_var.set("Min distance: n/a")
            self.measure_angle_var.set("Angle difference: n/a")
            return

        ref_preview = self._cut_preview(ref_cut.cut_id) or ref_cut
        target_preview = self._cut_preview(target_cut.cut_id) or target_cut
        center_dist = distance(cut_center(ref_preview), cut_center(target_preview))
        min_dist = min_segment_distance(ref_preview, target_preview)
        angle_diff = angle_difference_deg(ref_preview, target_preview)

        self.measure_center_var.set(f"Center distance: {center_dist:.2f} px")
        self.measure_min_var.set(f"Min distance: {min_dist:.2f} px")
        self.measure_angle_var.set(f"Angle difference: {angle_diff:.2f} deg")

    def _sync_geometry_controls_from_selected_cut(self) -> None:
        cut = self._selected_cut()
        self.geometry_update_guard = True
        if cut is None:
            self.selected_cut_name_var.set("No cut selected")
            self.geometry_angle_var.set("")
            self.geometry_length_var.set("")
            self.geometry_x1_var.set("")
            self.geometry_y1_var.set("")
            self.geometry_x2_var.set("")
            self.geometry_y2_var.set("")
        else:
            preview_cut = self._cut_preview(cut.cut_id) or cut
            dynamic_label = " | dynamic" if self._cut_dynamic_enabled(cut.cut_id) else ""
            curve_label = ""
            if self._cut_is_curve(cut):
                curve_label = f" | {self._cut_curve_mode_label(preview_cut)}"
            self.selected_cut_name_var.set(f"Selected: {cut.name}{curve_label}{dynamic_label}")
            self.geometry_angle_var.set(f"{cut_display_angle_deg(preview_cut):.2f}")
            self.geometry_length_var.set(f"{cut_length(preview_cut):.2f}")
            self.geometry_x1_var.set(f"{preview_cut.p0[0]:.2f}")
            self.geometry_y1_var.set(f"{preview_cut.p0[1]:.2f}")
            self.geometry_x2_var.set(f"{preview_cut.p1[0]:.2f}")
            self.geometry_y2_var.set(f"{preview_cut.p1[1]:.2f}")
        self.geometry_update_guard = False
        self._refresh_dynamic_cut_controls()
        self._sync_function_cut_controls_from_selected_cut()

    def _refresh_dynamic_cut_controls(self) -> None:
        if not hasattr(self, "dynamic_keyframe_listbox"):
            return
        cut = self._selected_cut()
        self.dynamic_keyframe_listbox.delete(0, self.tk.END)
        if cut is None:
            self.dynamic_cut_enabled_var.set(False)
            self.dynamic_reference_frame_var.set("")
            self.dynamic_keyframe_summary_var.set("Select a cut to enable dynamic geometry.")
            return

        enabled = self._cut_dynamic_enabled(cut.cut_id)
        reference_frame = self._cut_dynamic_reference_frame(cut.cut_id)
        keyframes = self._cut_dynamic_keyframes(cut.cut_id)
        current_t = int(self.t_visual_var.get())
        self.dynamic_cut_enabled_var.set(enabled)
        self.dynamic_reference_frame_var.set(str(reference_frame))
        for frame_idx in sorted(keyframes.keys()):
            marker = " <- t" if int(frame_idx) == current_t else ""
            self.dynamic_keyframe_listbox.insert(
                self.tk.END,
                f"t={int(frame_idx):04d}{marker}",
            )
        if keyframes:
            selected_index = next(
                (
                    idx
                    for idx, frame_idx in enumerate(sorted(keyframes.keys()))
                    if int(frame_idx) == current_t
                ),
                None,
            )
            if selected_index is not None:
                self.dynamic_keyframe_listbox.selection_clear(0, self.tk.END)
                self.dynamic_keyframe_listbox.selection_set(selected_index)
                self.dynamic_keyframe_listbox.activate(selected_index)
        mode_text = "enabled" if enabled else "disabled"
        self.dynamic_keyframe_summary_var.set(
            f"Dynamic geometry {mode_text}. Ref={reference_frame}. "
            f"Keyframes={len(keyframes)}. Editing at current t writes a keyframe."
        )

    def _toggle_selected_cut_dynamic(self) -> None:
        cut = self._selected_cut()
        if cut is None:
            self.dynamic_cut_enabled_var.set(False)
            self._set_status("Select a cut first.")
            return
        if self._cut_is_curve(cut):
            self.dynamic_cut_enabled_var.set(False)
            self._set_status("Dynamic geometry is not available for curved cuts yet.")
            return
        state = self._cut_analysis(cut.cut_id)
        enabled = bool(self.dynamic_cut_enabled_var.get())
        state["dynamic_enabled"] = enabled
        if enabled and not state.get("dynamic_keyframes"):
            state["dynamic_reference_frame"] = clamp_int(
                int(self.t_visual_var.get()), 0, self.nt - 1
            )
        self._invalidate_cut_dependents(cut.cut_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(
            f"{'Enabled' if enabled else 'Disabled'} dynamic geometry for {cut.name}."
        )

    def _capture_selected_cut_dynamic_keyframe(self) -> None:
        cut = self._selected_cut()
        if cut is None:
            self._set_status("Select a cut first.")
            return
        preview_cut = self._cut_preview(cut.cut_id) or cut
        frame_idx = int(self.t_visual_var.get())
        if not self._set_cut_dynamic_keyframe(
            cut.cut_id, frame_idx, preview_cut.p0, preview_cut.p1, enable_dynamic=True
        ):
            self._set_status("Could not capture dynamic keyframe.")
            return
        self._invalidate_cut_dependents(cut.cut_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Captured dynamic keyframe for {cut.name} at t={frame_idx}.")

    def _delete_selected_cut_dynamic_keyframe(self) -> None:
        cut = self._selected_cut()
        if cut is None:
            self._set_status("Select a cut first.")
            return
        frame_idx = int(self.t_visual_var.get())
        if not self._delete_cut_dynamic_keyframe(cut.cut_id, frame_idx):
            self._set_status(f"{cut.name} has no keyframe at t={frame_idx}.")
            return
        self._invalidate_cut_dependents(cut.cut_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Deleted dynamic keyframe for {cut.name} at t={frame_idx}.")

    def _clear_selected_cut_dynamic_keyframes(self) -> None:
        cut = self._selected_cut()
        if cut is None:
            self._set_status("Select a cut first.")
            return
        state = self._cut_analysis(cut.cut_id)
        if not state.get("dynamic_keyframes"):
            self._set_status(f"{cut.name} has no dynamic keyframes.")
            return
        state["dynamic_keyframes"] = {}
        self._invalidate_cut_dependents(cut.cut_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Cleared dynamic keyframes for {cut.name}.")

    def _set_selected_cut_dynamic_reference(self) -> None:
        cut = self._selected_cut()
        if cut is None:
            self._set_status("Select a cut first.")
            return
        frame_idx = int(self.t_visual_var.get())
        state = self._cut_analysis(cut.cut_id)
        old_reference_frame = int(state.get("dynamic_reference_frame", 0))
        current_geometry = self._cut_geometry_for_frame(cut.cut_id, frame_idx)
        old_reference_geometry = self._cut_geometry_for_frame(cut.cut_id, old_reference_frame)
        keyframes = dict(state.get("dynamic_keyframes") or {})
        if old_reference_frame != frame_idx:
            keyframes[old_reference_frame] = {
                "p0": [
                    float(old_reference_geometry[0][0]),
                    float(old_reference_geometry[0][1]),
                ],
                "p1": [
                    float(old_reference_geometry[1][0]),
                    float(old_reference_geometry[1][1]),
                ],
            }
        keyframes.pop(frame_idx, None)
        cut.p0 = clamp_point(current_geometry[0], self.nx, self.ny)
        cut.p1 = clamp_point(current_geometry[1], self.nx, self.ny)
        state["dynamic_reference_frame"] = frame_idx
        state["dynamic_enabled"] = True
        state["dynamic_keyframes"] = keyframes
        self._invalidate_cut_dependents(cut.cut_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Set dynamic reference frame of {cut.name} to t={frame_idx}.")

    def _on_dynamic_keyframe_select(self, _event: Any) -> None:
        cut = self._selected_cut()
        if cut is None or not hasattr(self, "dynamic_keyframe_listbox"):
            return
        selection = self.dynamic_keyframe_listbox.curselection()
        if not selection:
            return
        keyframe_frames = sorted(self._cut_dynamic_keyframes(cut.cut_id).keys())
        if selection[0] >= len(keyframe_frames):
            return
        self.t_visual_var.set(int(keyframe_frames[selection[0]]))
        self.refresh_all()

    def _editable_cut(self, cut: Cut | None, action: str) -> Cut | None:
        if cut is None:
            self._set_status(f"No cut selected to {action}.")
            return None
        if cut.locked:
            self._set_status(f"{cut.name} is locked.")
            return None
        return cut

    def _selected_editable_cut(self, action: str) -> Cut | None:
        return self._editable_cut(self._selected_cut(), action)

    def _cut_is_curve(self, cut: Cut | None) -> bool:
        return cut is not None and str(getattr(cut, "mode", "line")) == "curve"

    def _curve_cut_edit_supported(self, cut: Cut | None, action: str) -> bool:
        return True

    def _shift_curve_cut_geometry(self, cut: Cut, dx: float, dy: float) -> bool:
        points = cut_polyline_points(cut)
        if len(points) < 2:
            return False
        min_dx = -min(point[0] for point in points)
        max_dx = (self.nx - 1.0) - max(point[0] for point in points)
        min_dy = -min(point[1] for point in points)
        max_dy = (self.ny - 1.0) - max(point[1] for point in points)
        dx = clamp_value(float(dx), float(min_dx), float(max_dx))
        dy = clamp_value(float(dy), float(min_dy), float(max_dy))
        shifted_points = [
            (float(point[0] + dx), float(point[1] + dy)) for point in points
        ]
        updated, _limited = self._set_curve_cut_geometry(
            cut,
            shifted_points,
            curve_fit=self._curve_transform_fit_mode(cut),
        )
        return updated

    def _apply_cut_points(
        self, cut: Cut, p0: tuple[float, float], p1: tuple[float, float], status: str
    ) -> bool:
        p0 = clamp_point(p0, self.nx, self.ny)
        p1 = clamp_point(p1, self.nx, self.ny)
        if distance(p0, p1) < 1.0:
            self._set_status("Cut too short after the requested operation.")
            return False

        if self._cut_dynamic_enabled(cut.cut_id):
            if not self._set_cut_dynamic_keyframe(
                cut.cut_id,
                int(self.t_visual_var.get()),
                p0,
                p1,
                enable_dynamic=True,
            ):
                self._set_status("Could not update dynamic cut geometry.")
                return False
        else:
            cut.p0 = p0
            cut.p1 = p1
            cut.mode = "line"
            cut.curve_fit = "line"
            cut.curve_points = []
            self._clear_cut_function_metadata(cut)
        self.selected_cut_id = cut.cut_id
        self._invalidate_cut_dependents(cut.cut_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(status)
        return True

    def _normalize_anchor_mode(self, anchor_mode: str) -> str | None:
        value = str(anchor_mode).strip().lower()
        mapping = {
            "center": "center",
            "p0": "p0",
            "p1": "p1",
            "fix p0": "p0",
            "fix p1": "p1",
        }
        return mapping.get(value)

    def _normalize_length_mode(self, length_mode: str) -> str | None:
        value = str(length_mode).strip().lower()
        mapping = {
            "symmetric": "symmetric",
            "from p0": "p0",
            "from p1": "p1",
            "fix p0": "p0",
            "fix p1": "p1",
        }
        return mapping.get(value)

    def _set_cut_angle(
        self, cut: Cut, angle_deg: float, anchor_mode: str, status_prefix: str
    ) -> bool:
        preview_cut = self._cut_preview(cut.cut_id) or cut
        if self._cut_is_curve(preview_cut):
            normalized_anchor = self._normalize_anchor_mode(anchor_mode)
            if normalized_anchor == "center":
                anchor_point = cut_center(preview_cut)
            elif normalized_anchor == "p0":
                anchor_point = preview_cut.p0
            elif normalized_anchor == "p1":
                anchor_point = preview_cut.p1
            else:
                self._set_status(f"Unknown anchor mode: {anchor_mode}")
                return False
            delta_deg = float(angle_deg) - cut_display_angle_deg(preview_cut)
            rotated_points = [
                rotate_point(point, anchor_point, delta_deg)
                for point in cut_polyline_points(preview_cut)
            ]
            return self._apply_curve_cut_geometry(
                cut,
                rotated_points,
                status_prefix,
                curve_fit=self._curve_transform_fit_mode(cut),
            )

        desired_length = cut_length(preview_cut)
        normalized_anchor = self._normalize_anchor_mode(anchor_mode)
        if normalized_anchor == "center":
            p0, p1, actual_length = segment_from_angle_length(
                angle_deg,
                desired_length,
                "center",
                None,
                cut_center(preview_cut),
                self.nx,
                self.ny,
            )
        elif normalized_anchor == "p0":
            p0, p1, actual_length = segment_from_angle_length(
                angle_deg,
                desired_length,
                "p0",
                preview_cut.p0,
                None,
                self.nx,
                self.ny,
            )
        elif normalized_anchor == "p1":
            p0, p1, actual_length = segment_from_angle_length(
                angle_deg,
                desired_length,
                "p1",
                preview_cut.p1,
                None,
                self.nx,
                self.ny,
            )
        else:
            self._set_status(f"Unknown anchor mode: {anchor_mode}")
            return False

        limited = actual_length + 1e-6 < desired_length
        status = status_prefix
        if limited:
            status += " Limited by image bounds."
        return self._apply_cut_points(cut, p0, p1, status)

    def _set_cut_length(
        self, cut: Cut, length_value: float, length_mode: str, status_prefix: str
    ) -> bool:
        preview_cut = self._cut_preview(cut.cut_id) or cut
        if self._cut_is_curve(preview_cut):
            current_length = cut_length(preview_cut)
            if current_length <= 1e-9:
                self._set_status("Curved cut is too short to resize.")
                return False
            normalized_length = self._normalize_length_mode(length_mode)
            if normalized_length == "symmetric":
                anchor_point = cut_center(preview_cut)
            elif normalized_length == "p0":
                anchor_point = preview_cut.p0
            elif normalized_length == "p1":
                anchor_point = preview_cut.p1
            else:
                self._set_status(f"Unknown length mode: {length_mode}")
                return False
            scale = max(float(length_value), 1.0) / current_length
            scaled_points = [
                (
                    float(anchor_point[0] + scale * (point[0] - anchor_point[0])),
                    float(anchor_point[1] + scale * (point[1] - anchor_point[1])),
                )
                for point in cut_polyline_points(preview_cut)
            ]
            return self._apply_curve_cut_geometry(
                cut,
                scaled_points,
                status_prefix,
                curve_fit=self._curve_transform_fit_mode(cut),
            )

        angle_deg = cut_directed_angle_deg(preview_cut)
        requested_length = max(float(length_value), 1.0)

        normalized_length = self._normalize_length_mode(length_mode)
        if normalized_length == "symmetric":
            p0, p1, actual_length = segment_from_angle_length(
                angle_deg,
                requested_length,
                "center",
                None,
                cut_center(preview_cut),
                self.nx,
                self.ny,
            )
        elif normalized_length == "p0":
            p0, p1, actual_length = segment_from_angle_length(
                angle_deg,
                requested_length,
                "p0",
                preview_cut.p0,
                None,
                self.nx,
                self.ny,
            )
        elif normalized_length == "p1":
            p0, p1, actual_length = segment_from_angle_length(
                angle_deg,
                requested_length,
                "p1",
                preview_cut.p1,
                None,
                self.nx,
                self.ny,
            )
        else:
            self._set_status(f"Unknown length mode: {length_mode}")
            return False

        limited = actual_length + 1e-6 < requested_length
        status = status_prefix
        if limited:
            status += " Limited by image bounds."
        return self._apply_cut_points(cut, p0, p1, status)

    def _parse_float_var(self, value: str, field_name: str) -> float | None:
        try:
            return float(str(value).strip())
        except Exception:
            self._set_status(f"Invalid {field_name} value.")
            return None

    def _on_measurement_selection(self, _event: Any) -> None:
        self._refresh_measurements()

    def _on_panel_cut_selection(self, _event: Any) -> None:
        if self.panel_selector_update_guard:
            return
        self._assign_panel_cut_from_selector()

    def _on_geometry_entry_event(self, event: Any) -> None:
        widget = event.widget
        if widget == self.geometry_angle_entry:
            self._set_selected_cut_angle()
        elif widget == self.geometry_length_entry:
            self._set_selected_cut_length()
        elif widget == self.center_distance_entry:
            self._set_center_distance_between_cuts()
        elif widget in getattr(self, "geometry_coord_entries", []):
            self._apply_selected_cut_coords()
        elif widget in {
            getattr(self, "function_point_x_entry", None),
            getattr(self, "function_point_y_entry", None),
        }:
            self._apply_selected_function_control_point()

    def _on_function_expression_event(self, _event: Any) -> None:
        expression = str(self.function_cut_expression_var.get() or "").strip()
        current_params: dict[str, float] = {}
        for name, var in dict(getattr(self, "function_param_vars", {}) or {}).items():
            try:
                current_params[str(name)] = float(str(var.get()).strip())
            except Exception:
                continue
        cut = self._selected_cut()
        if cut is not None and self._cut_is_function_curve(cut):
            for name, value in dict(getattr(cut, "function_params", {}) or {}).items():
                current_params.setdefault(str(name), float(value))
        self._refresh_function_param_editor(expression, current_params)

    def _on_function_render_points_event(self, _event: Any) -> None:
        cut = self._selected_cut()
        if cut is None or not self._cut_is_function_curve(cut):
            return
        self._refit_selected_function_cut()

    def _on_function_param_entry_event(self, _event: Any) -> None:
        self._apply_function_params_to_selected_cut()

    def _on_angle_entry_event(self, _event: Any) -> None:
        self._set_selected_cut_angle()

    def _on_length_entry_event(self, _event: Any) -> None:
        self._set_selected_cut_length()

    def _on_coord_entry_event(self, _event: Any) -> None:
        self._apply_selected_cut_coords()

    def _on_center_distance_entry_event(self, _event: Any) -> None:
        self._set_center_distance_between_cuts()

    def _set_selected_cut_angle(self) -> None:
        if self.geometry_update_guard:
            return
        cut = self._selected_editable_cut("set angle")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "set angle"):
            return
        angle_deg = self._parse_float_var(self.geometry_angle_var.get(), "angle")
        if angle_deg is None:
            return
        anchor_mode = self.geometry_anchor_var.get()
        self._set_cut_angle(cut, angle_deg, anchor_mode, f"Set {cut.name} angle to {angle_deg:.2f} deg.")

    def _adjust_selected_cut_angle(self, delta_deg: float) -> None:
        cut = self._selected_editable_cut("adjust angle")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "adjust angle"):
            return
        new_angle = cut_display_angle_deg(cut) + delta_deg
        self._set_cut_angle(
            cut,
            new_angle,
            self.geometry_anchor_var.get(),
            f"Adjusted {cut.name} angle by {delta_deg:+.1f} deg.",
        )

    def _set_selected_cut_length(self) -> None:
        if self.geometry_update_guard:
            return
        cut = self._selected_editable_cut("set length")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "set length"):
            return
        length_value = self._parse_float_var(self.geometry_length_var.get(), "length")
        if length_value is None:
            return
        self._set_cut_length(
            cut,
            length_value,
            self.geometry_length_mode_var.get(),
            f"Set {cut.name} length to {length_value:.2f} px.",
        )

    def _adjust_selected_cut_length(self, delta_length: float) -> None:
        cut = self._selected_editable_cut("adjust length")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "adjust length"):
            return
        new_length = max(1.0, cut_length(cut) + delta_length)
        self._set_cut_length(
            cut,
            new_length,
            self.geometry_length_mode_var.get(),
            f"Adjusted {cut.name} length by {delta_length:+.1f} px.",
        )

    def _apply_selected_cut_coords(self) -> None:
        if self.geometry_update_guard:
            return
        cut = self._selected_editable_cut("apply coordinates")
        if cut is None:
            return

        x1 = self._parse_float_var(self.geometry_x1_var.get(), "x1")
        y1 = self._parse_float_var(self.geometry_y1_var.get(), "y1")
        x2 = self._parse_float_var(self.geometry_x2_var.get(), "x2")
        y2 = self._parse_float_var(self.geometry_y2_var.get(), "y2")
        if None in {x1, y1, x2, y2}:
            return

        if self._cut_is_curve(cut):
            self._apply_curve_cut_endpoint_mapping(
                cut,
                (float(x1), float(y1)),
                (float(x2), float(y2)),
                f"Applied coordinates to {cut.name}.",
            )
            return

        self._apply_cut_points(
            cut,
            (float(x1), float(y1)),
            (float(x2), float(y2)),
            f"Applied coordinates to {cut.name}.",
        )

    def _measurement_cuts(self, action: str | None = None) -> tuple[Cut | None, Cut | None]:
        ref_cut = self._cut_from_option(self.reference_cut_var.get())
        target_cut = self._cut_from_option(self.target_cut_var.get())
        if action is not None:
            if (
                ref_cut is not None
                and target_cut is not None
                and ref_cut.cut_id == target_cut.cut_id
            ):
                self._set_status("Reference and target must be different cuts.")
                return ref_cut, None
            target_cut = self._editable_cut(target_cut, action)
        return ref_cut, target_cut

    def _copy_reference_angle(self) -> None:
        ref_cut, target_cut = self._measurement_cuts("copy angle")
        if ref_cut is None or target_cut is None:
            self._set_status("Select reference and target cuts first.")
            return
        ref_preview = self._cut_preview(ref_cut.cut_id) or ref_cut
        self._set_cut_angle(
            target_cut,
            cut_display_angle_deg(ref_preview),
            "center",
            f"Copied angle from {ref_cut.name} to {target_cut.name}.",
        )

    def _copy_reference_length(self) -> None:
        ref_cut, target_cut = self._measurement_cuts("copy length")
        if ref_cut is None or target_cut is None:
            self._set_status("Select reference and target cuts first.")
            return
        ref_preview = self._cut_preview(ref_cut.cut_id) or ref_cut
        self._set_cut_length(
            target_cut,
            cut_length(ref_preview),
            "symmetric",
            f"Copied length from {ref_cut.name} to {target_cut.name}.",
        )

    def _make_parallel(self) -> None:
        ref_cut, target_cut = self._measurement_cuts("make parallel")
        if ref_cut is None or target_cut is None:
            self._set_status("Select reference and target cuts first.")
            return
        ref_preview = self._cut_preview(ref_cut.cut_id) or ref_cut
        self._set_cut_angle(
            target_cut,
            cut_display_angle_deg(ref_preview),
            "center",
            f"Made {target_cut.name} parallel to {ref_cut.name}.",
        )

    def _make_perpendicular(self) -> None:
        ref_cut, target_cut = self._measurement_cuts("make perpendicular")
        if ref_cut is None or target_cut is None:
            self._set_status("Select reference and target cuts first.")
            return
        ref_preview = self._cut_preview(ref_cut.cut_id) or ref_cut
        self._set_cut_angle(
            target_cut,
            cut_display_angle_deg(ref_preview) + 90.0,
            "center",
            f"Made {target_cut.name} perpendicular to {ref_cut.name}.",
        )

    def _match_centers(self) -> None:
        ref_cut, target_cut = self._measurement_cuts("match center")
        if ref_cut is None or target_cut is None:
            self._set_status("Select reference and target cuts first.")
            return

        ref_preview = self._cut_preview(ref_cut.cut_id) or ref_cut
        target_preview = self._cut_preview(target_cut.cut_id) or target_cut
        ref_center = cut_center(ref_preview)
        target_center = cut_center(target_preview)
        dx = ref_center[0] - target_center[0]
        dy = ref_center[1] - target_center[1]
        self._shift_cut_geometry(
            target_cut,
            dx,
            dy,
            f"Matched center of {target_cut.name} to {ref_cut.name}.",
        )

    def _match_vertices(self, vertex_name: str) -> None:
        ref_cut, target_cut = self._measurement_cuts(f"match {vertex_name}")
        if ref_cut is None or target_cut is None:
            self._set_status("Select reference and target cuts first.")
            return
        ref_preview = self._cut_preview(ref_cut.cut_id) or ref_cut
        target_preview = self._cut_preview(target_cut.cut_id) or target_cut

        if vertex_name == "p0":
            dx = ref_preview.p0[0] - target_preview.p0[0]
            dy = ref_preview.p0[1] - target_preview.p0[1]
            status = f"Matched p0 of {target_cut.name} to {ref_cut.name}."
        elif vertex_name == "p1":
            dx = ref_preview.p1[0] - target_preview.p1[0]
            dy = ref_preview.p1[1] - target_preview.p1[1]
            status = f"Matched p1 of {target_cut.name} to {ref_cut.name}."
        else:
            self._set_status(f"Unknown vertex selector: {vertex_name}")
            return

        self._shift_cut_geometry(target_cut, dx, dy, status)

    def _copy_reference_geometry(self) -> None:
        ref_cut, target_cut = self._measurement_cuts("copy geometry")
        if ref_cut is None or target_cut is None:
            self._set_status("Select reference and target cuts first.")
            return
        ref_preview = self._cut_preview(ref_cut.cut_id) or ref_cut

        self._apply_cut_geometry_copy(
            target_cut,
            ref_preview,
            f"Copied geometry from {ref_cut.name} to {target_cut.name}.",
        )

    def _set_center_distance_between_cuts(self) -> None:
        ref_cut, target_cut = self._measurement_cuts("set center distance")
        if ref_cut is None or target_cut is None:
            self._set_status("Select reference and target cuts first.")
            return

        desired = self._parse_float_var(
            self.center_distance_var.get(), "center distance"
        )
        if desired is None:
            return
        desired = max(0.0, desired)

        ref_preview = self._cut_preview(ref_cut.cut_id) or ref_cut
        target_preview = self._cut_preview(target_cut.cut_id) or target_cut
        ref_center = cut_center(ref_preview)
        target_center = cut_center(target_preview)
        dx = target_center[0] - ref_center[0]
        dy = target_center[1] - ref_center[1]
        current = math.hypot(dx, dy)

        if current < 1e-9:
            ux, uy = 1.0, 0.0
        else:
            ux, uy = dx / current, dy / current

        new_center = (ref_center[0] + desired * ux, ref_center[1] + desired * uy)
        move_dx = new_center[0] - target_center[0]
        move_dy = new_center[1] - target_center[1]
        self._shift_cut_geometry(
            target_cut,
            move_dx,
            move_dy,
            f"Set center distance between {ref_cut.name} and {target_cut.name} to {desired:.2f} px.",
        )

    def _assign_panel_cut_from_selector(self) -> None:
        cut = self._cut_from_option(self.panel_cut_var.get())
        if cut is None:
            self._set_status("Choose a cut in the TD tab first.")
            return

        panel = self.active_panel
        panel.cut_id = cut.cut_id
        self._seed_cut_td_params_from_panel(cut.cut_id, panel)
        self.selected_cut_id = cut.cut_id
        self._invalidate_panel_cache(panel.panel_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Assigned {cut.name} to {panel.name}.")

    def _clear_active_panel_cut(self) -> None:
        panel = self.active_panel
        if panel.cut_id is None:
            self._set_status(f"{panel.name} already has no cut assigned.")
            return

        panel.cut_id = None
        self._invalidate_panel_cache(panel.panel_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Cleared cut assignment from {panel.name}.")

    def _apply_controls_to_active_panel(self) -> None:
        if self.control_update_guard:
            return

        panel = self.active_panel
        t_ini = int(self.panel_t_ini_var.get())
        t_fin = int(self.panel_t_fin_var.get())

        if t_ini > t_fin:
            t_fin = t_ini
            self.control_update_guard = True
            self.panel_t_fin_var.set(t_fin)
            self.control_update_guard = False

        panel.t_ini = clamp_int(t_ini, 0, self.nt - 1)
        panel.t_fin = clamp_int(t_fin, panel.t_ini, self.nt - 1)
        panel.stride = max(int(self.panel_stride_var.get()), 1)
        panel.width = max(int(self.panel_width_var.get()), 1)
        panel.weighting = str(self.panel_weighting_var.get())
        if panel.cut_id is not None and panel.cut_id in self.cuts:
            state = self._cut_analysis(panel.cut_id)
            state["td_params"] = {
                "t_ini": int(panel.t_ini),
                "t_fin": int(panel.t_fin),
                "stride": int(panel.stride),
                "width": int(panel.width),
                "weighting": str(panel.weighting),
            }
            state["td_cache_key"] = None
            state["td_cache_td"] = None
            state["td_cache_meta"] = None
            self._sync_panels_from_cut_td_params(panel.cut_id)
            self._invalidate_cut_dependents(panel.cut_id)
        else:
            self._invalidate_panel_cache(panel.panel_id)
        self._record_session_change()
        self.refresh_all()

    def _clear_panel_analysis_results(
        self, panel_id: int, *, clear_tracking: bool, clear_wavelet: bool
    ) -> None:
        state = self._panel_analysis(panel_id)
        state["td_cache_key"] = None
        state["td_cache_td"] = None
        state["td_cache_meta"] = None
        if clear_tracking:
            state["crest_tracking_result"] = None
            state["crest_tracking_td_key"] = None
        if clear_tracking or clear_wavelet:
            state["wavelet_filter_result"] = None
            state["wavelet_events"] = []
            state["wavelet_next_event_id"] = 1
            state["wavelet_selected_event_id"] = None

    def _invalidate_panel_cache(self, panel_id: int) -> None:
        panel = self.panels[panel_id - 1]
        panel.cache_key = None
        panel.cache_td = None
        panel.cache_meta = None
        self._clear_panel_analysis_results(
            panel_id, clear_tracking=True, clear_wavelet=True
        )
        self._clear_td_window_crest_tracking(panel_id, stale=True)

    def _invalidate_cut_dependents(self, cut_id: int) -> None:
        for panel in self.panels:
            if panel.cut_id == cut_id:
                self._invalidate_panel_cache(panel.panel_id)

    def _set_status(self, text: str) -> None:
        self.status_var.set(text)

    def _on_axis_flip_change(self) -> None:
        self._record_session_change()
        self.refresh_all()

    def _on_axis_flip_event(self, _event: Any) -> None:
        self._on_axis_flip_change()

    def _zoom_limits(
        self, lo: float, hi: float, center: float, zoom_value: float
    ) -> tuple[float, float]:
        span = hi - lo
        if span <= 0 or zoom_value <= 1.0:
            return lo, hi

        window = span / zoom_value
        center = clamp_value(center, lo, hi)
        start = center - window / 2.0
        end = center + window / 2.0

        if start < lo:
            end += lo - start
            start = lo
        if end > hi:
            start -= end - hi
            end = hi

        start = max(start, lo)
        end = min(end, hi)
        return start, end

    def _map_data_to_display(self, x: float, y: float) -> tuple[float, float]:
        if self.map_swap_xy_var.get():
            return y, x
        return x, y

    def _map_display_to_data(self, u: float, v: float) -> tuple[float, float]:
        if self.map_swap_xy_var.get():
            return v, u
        return u, v

    def _map_display_shape(self) -> tuple[int, int]:
        if self.map_swap_xy_var.get():
            return self.ny, self.nx
        return self.nx, self.ny

    def _on_t_visual_change(self, _value: str) -> None:
        self._sync_geometry_controls_from_selected_cut()
        self._refresh_measurements()
        self._refresh_cut_list()
        self._refresh_export_controls()
        self.refresh_map()
        self.refresh_td_views()

    def _on_t_ini_change(self, value: str) -> None:
        if self.control_update_guard:
            return
        self.panel_t_ini_var.set(int(float(value)))
        self._apply_controls_to_active_panel()

    def _on_t_fin_change(self, value: str) -> None:
        if self.control_update_guard:
            return
        self.panel_t_fin_var.set(int(float(value)))
        self._apply_controls_to_active_panel()

    def _on_panel_param_commit(self) -> None:
        self._apply_controls_to_active_panel()

    def _on_panel_param_event(self, _event: Any) -> None:
        self._apply_controls_to_active_panel()

    def _on_layout_change(self, _event: Any) -> None:
        self._apply_layout()
        self._record_session_change()
        self.refresh_all()

    def _step_t_visual(self, step: int) -> None:
        new_value = clamp_int(self.t_visual_var.get() + step, 0, self.nt - 1)
        self.t_visual_var.set(new_value)
        self._on_t_visual_change(str(new_value))

    def _on_panel_list_select(self, _event: Any) -> None:
        selection = self.panel_listbox.curselection()
        if not selection:
            return
        panel_id = selection[0] + 1
        if panel_id > self.visible_panels:
            return
        self.active_panel_id = panel_id
        panel = self.active_panel
        self.selected_cut_id = panel.cut_id
        self._sync_controls_from_active_panel()
        self.refresh_all()

    def _on_cut_list_select(self, _event: Any) -> None:
        selection = self.cut_listbox.curselection()
        if not selection:
            return
        ordered = sorted(self.cuts.values(), key=lambda cut: cut.cut_id)
        if selection[0] >= len(ordered):
            return
        self.selected_cut_id = ordered[selection[0]].cut_id
        self.refresh_all()

    def _on_feature_axis_list_select(self, _event: Any) -> None:
        if not hasattr(self, "feature_axis_listbox"):
            return
        selection = self.feature_axis_listbox.curselection()
        if not selection:
            return
        ordered = sorted(self.feature_axes.values(), key=lambda axis: axis.axis_id)
        if selection[0] >= len(ordered):
            return
        self.selected_feature_axis_id = ordered[selection[0]].axis_id
        self._sync_feature_axis_controls()
        self.refresh_map()

    def _create_cut(self, p0: tuple[float, float], p1: tuple[float, float]) -> Cut:
        cut = Cut(
            cut_id=self.next_cut_id,
            name=f"Cut {self.next_cut_id}",
            color=COLOR_CYCLE[(self.next_cut_id - 1) % len(COLOR_CYCLE)],
            p0=p0,
            p1=p1,
        )
        self.cuts[cut.cut_id] = cut
        self.next_cut_id += 1
        return cut

    def _cut_is_function_curve(self, cut: Cut | None) -> bool:
        return (
            cut is not None
            and str(getattr(cut, "mode", "line")) == "curve"
            and str(getattr(cut, "curve_fit", "")).strip().lower() == "function"
            and bool(str(getattr(cut, "function_expr", "") or "").strip())
        )

    def _cut_curve_mode_label(self, cut: Cut | None) -> str:
        if cut is None:
            return "none"
        if not self._cut_is_curve(cut):
            return "line"
        fit_mode = str(getattr(cut, "curve_fit", "polyline") or "polyline").strip()
        if self._cut_is_function_curve(cut):
            fit_mode = "function"
        point_count = len(cut_polyline_points(cut))
        return f"curve:{fit_mode} | pts={point_count} | L={cut_length(cut):.1f}px"

    def _clear_cut_function_metadata(self, cut: Cut) -> None:
        cut.function_expr = ""
        cut.function_x_start = float(cut.p0[0])
        cut.function_x_end = float(cut.p1[0])
        cut.function_point_count = 0
        cut.function_control_points = []
        cut.function_params = {}

    def _cut_function_metadata_payload(
        self,
        cut: Cut,
    ) -> dict[str, Any] | None:
        if not self._cut_is_function_curve(cut):
            return None
        point_count = max(
            int(getattr(cut, "function_point_count", 0) or 0),
            len(cut_polyline_points(cut)),
            2,
        )
        return {
            "function_expr": str(getattr(cut, "function_expr", "") or ""),
            "function_x_start": float(getattr(cut, "function_x_start", cut.p0[0])),
            "function_x_end": float(getattr(cut, "function_x_end", cut.p1[0])),
            "function_point_count": point_count,
            "function_control_points": [
                (float(point[0]), float(point[1]))
                for point in (getattr(cut, "function_control_points", []) or [])
            ],
            "function_params": {
                str(key): float(value)
                for key, value in dict(getattr(cut, "function_params", {}) or {}).items()
            },
        }

    def _curve_transform_fit_mode(self, cut: Cut | None) -> str:
        if self._cut_is_function_curve(cut):
            return "polyline"
        fit_mode = str(getattr(cut, "curve_fit", "polyline") or "polyline").strip().lower()
        return fit_mode if fit_mode in {"polyline", "quadratic", "cubic"} else "polyline"

    def _clear_cut_dynamic_geometry(self, cut_id: int) -> None:
        state = self._cut_analysis(cut_id)
        state["dynamic_enabled"] = False
        state["dynamic_keyframes"] = {}
        state["dynamic_reference_frame"] = clamp_int(
            int(self.t_visual_var.get()),
            0,
            self.nt - 1,
        )

    def _normalize_curve_geometry_points(
        self,
        raw_points: list[tuple[float, float]],
    ) -> tuple[list[tuple[float, float]], bool]:
        normalized: list[tuple[float, float]] = []
        limited = False
        for point in raw_points:
            raw_point = (float(point[0]), float(point[1]))
            clamped = clamp_point(raw_point, self.nx, self.ny)
            if (
                abs(clamped[0] - raw_point[0]) > 1e-6
                or abs(clamped[1] - raw_point[1]) > 1e-6
            ):
                limited = True
            if normalized and distance(normalized[-1], clamped) < 0.35:
                continue
            normalized.append((float(clamped[0]), float(clamped[1])))
        if len(normalized) < 2 or polyline_length(normalized) < 1.0:
            raise ValueError("Curve geometry collapsed to a too-short cut.")
        return normalized, limited

    def _set_curve_cut_geometry(
        self,
        cut: Cut,
        points: list[tuple[float, float]],
        *,
        curve_fit: str = "polyline",
        function_meta: dict[str, Any] | None = None,
    ) -> tuple[bool, bool]:
        try:
            normalized, limited = self._normalize_curve_geometry_points(points)
        except ValueError as exc:
            self._set_status(str(exc))
            return False, False

        fit_mode = str(curve_fit or "polyline").strip().lower() or "polyline"
        if fit_mode == "function" and function_meta is None:
            fit_mode = "polyline"
        cut.mode = "curve"
        cut.curve_fit = fit_mode
        cut.curve_points = [
            (float(point[0]), float(point[1])) for point in normalized
        ]
        cut.p0 = cut.curve_points[0]
        cut.p1 = cut.curve_points[-1]
        if fit_mode == "function" and function_meta is not None:
            cut.function_expr = str(function_meta.get("function_expr", "") or "")
            cut.function_x_start = float(
                function_meta.get("function_x_start", cut.p0[0])
            )
            cut.function_x_end = float(
                function_meta.get("function_x_end", cut.p1[0])
            )
            cut.function_point_count = max(
                int(function_meta.get("function_point_count", len(cut.curve_points)) or 0),
                2,
            )
            cut.function_control_points = [
                (float(point[0]), float(point[1]))
                for point in (function_meta.get("function_control_points") or [])
            ]
            cut.function_params = {
                str(key): float(value)
                for key, value in dict(function_meta.get("function_params") or {}).items()
            }
        else:
            self._clear_cut_function_metadata(cut)
        return True, limited

    def _apply_curve_cut_geometry(
        self,
        cut: Cut,
        points: list[tuple[float, float]],
        status: str,
        *,
        curve_fit: str = "polyline",
        function_meta: dict[str, Any] | None = None,
    ) -> bool:
        had_dynamic = self._cut_dynamic_enabled(cut.cut_id)
        if had_dynamic:
            self._clear_cut_dynamic_geometry(cut.cut_id)
        updated, limited = self._set_curve_cut_geometry(
            cut,
            points,
            curve_fit=curve_fit,
            function_meta=function_meta,
        )
        if not updated:
            return False
        self.selected_cut_id = cut.cut_id
        self._invalidate_cut_dependents(cut.cut_id)
        self._record_session_change()
        self.refresh_all()
        suffix = ""
        if limited:
            suffix += " Limited by image bounds."
        if had_dynamic:
            suffix += " Dynamic geometry was disabled for this curved cut."
        self._set_status(f"{status}{suffix}")
        return True

    def _shift_cut_geometry(self, cut: Cut, dx: float, dy: float, status: str) -> bool:
        preview_cut = self._cut_preview(cut.cut_id) or cut
        if self._cut_is_curve(preview_cut):
            shifted_points = [
                (float(point[0] + dx), float(point[1] + dy))
                for point in cut_polyline_points(preview_cut)
            ]
            return self._apply_curve_cut_geometry(
                cut,
                shifted_points,
                status,
                curve_fit=self._curve_transform_fit_mode(cut),
            )
        p0, p1 = shift_cut(preview_cut, dx, dy, self.nx, self.ny)
        return self._apply_cut_points(cut, p0, p1, status)

    def _apply_cut_geometry_copy(
        self,
        target_cut: Cut,
        source_cut: Cut,
        status: str,
    ) -> bool:
        source_preview = self._cut_preview(source_cut.cut_id) or source_cut
        if self._cut_is_curve(source_preview):
            return self._apply_curve_cut_geometry(
                target_cut,
                cut_polyline_points(source_preview),
                status,
                curve_fit=str(getattr(source_preview, "curve_fit", "polyline")),
                function_meta=self._cut_function_metadata_payload(source_preview),
            )
        return self._apply_cut_points(
            target_cut,
            source_preview.p0,
            source_preview.p1,
            status,
        )

    def _apply_curve_cut_endpoint_mapping(
        self,
        cut: Cut,
        new_p0: tuple[float, float],
        new_p1: tuple[float, float],
        status: str,
    ) -> bool:
        preview_cut = self._cut_preview(cut.cut_id) or cut
        points = cut_polyline_points(preview_cut)
        if len(points) < 2:
            self._set_status("Curved cut has no valid geometry.")
            return False

        old_p0 = points[0]
        old_p1 = points[-1]
        old_dx = float(old_p1[0] - old_p0[0])
        old_dy = float(old_p1[1] - old_p0[1])
        old_len = math.hypot(old_dx, old_dy)
        if old_len <= 1e-9:
            self._set_status("Curved cut is too short to remap.")
            return False

        new_p0 = clamp_point(new_p0, self.nx, self.ny)
        new_p1 = clamp_point(new_p1, self.nx, self.ny)
        if distance(new_p0, new_p1) < 1.0:
            self._set_status("Cut too short after the requested operation.")
            return False

        new_dx = float(new_p1[0] - new_p0[0])
        new_dy = float(new_p1[1] - new_p0[1])
        new_len = math.hypot(new_dx, new_dy)
        angle_delta = math.atan2(new_dy, new_dx) - math.atan2(old_dy, old_dx)
        cos_a = math.cos(angle_delta)
        sin_a = math.sin(angle_delta)
        scale = new_len / old_len

        transformed_points = []
        for point in points:
            rel_x = float(point[0] - old_p0[0])
            rel_y = float(point[1] - old_p0[1])
            rot_x = scale * (cos_a * rel_x - sin_a * rel_y)
            rot_y = scale * (sin_a * rel_x + cos_a * rel_y)
            transformed_points.append(
                (float(new_p0[0] + rot_x), float(new_p0[1] + rot_y))
            )

        return self._apply_curve_cut_geometry(
            cut,
            transformed_points,
            status,
            curve_fit=self._curve_transform_fit_mode(cut),
        )

    def _function_cut_eval_env(self) -> dict[str, Any]:
        return {
            "sin": np.sin,
            "cos": np.cos,
            "tan": np.tan,
            "asin": np.arcsin,
            "acos": np.arccos,
            "atan": np.arctan,
            "arcsin": np.arcsin,
            "arccos": np.arccos,
            "arctan": np.arctan,
            "sinh": np.sinh,
            "cosh": np.cosh,
            "tanh": np.tanh,
            "exp": np.exp,
            "log": np.log,
            "log10": np.log10,
            "log2": np.log2,
            "log1p": np.log1p,
            "sqrt": np.sqrt,
            "abs": np.abs,
            "floor": np.floor,
            "ceil": np.ceil,
            "round": np.round,
            "sign": np.sign,
            "where": np.where,
            "clip": np.clip,
            "minimum": np.minimum,
            "maximum": np.maximum,
            "pi": float(np.pi),
            "e": float(np.e),
        }

    def _function_control_points(self, cut: Cut | None) -> list[tuple[float, float]]:
        if cut is None:
            return []
        raw_points = list(getattr(cut, "function_control_points", []) or [])
        normalized: list[tuple[float, float]] = []
        for point in raw_points:
            try:
                clamped = clamp_point((float(point[0]), float(point[1])), self.nx, self.ny)
            except Exception:
                continue
            normalized.append((float(clamped[0]), float(clamped[1])))
        if normalized:
            return sorted(normalized, key=lambda point: (point[0], point[1]))
        if self._cut_is_function_curve(cut):
            fallback = cut_polyline_points(cut)
            if fallback:
                step = max(len(fallback) // 6, 1)
                return [
                    (float(point[0]), float(point[1]))
                    for point in fallback[::step]
                ]
        return []

    def _normalize_function_cut_expression(self, expression: str) -> str:
        text = str(expression or "").strip()
        if not text:
            raise ValueError("Enter a function y = f(x) first.")
        if "=" in text:
            lhs, rhs = text.split("=", 1)
            lhs_key = lhs.strip().lower().replace(" ", "")
            if lhs_key in {"y", "f(x)", "y(x)"}:
                text = rhs.strip()
        for prefix in ("numpy.", "np.", "math."):
            text = text.replace(prefix, "")
        if not text:
            raise ValueError("Enter a valid function expression.")
        return text

    def _function_parameter_names_from_expression(self, expression: str) -> list[str]:
        normalized_expression = self._normalize_function_cut_expression(expression)
        ignored = set(self._function_cut_eval_env().keys()) | {"x"}
        names: list[str] = []
        for token in re.findall(r"[A-Za-z_][A-Za-z0-9_]*", normalized_expression):
            if token in ignored or token in names:
                continue
            names.append(str(token))
        return names

    def _validate_function_cut_ast(
        self,
        tree: ast.AST,
        allowed_names: set[str],
        callable_names: set[str],
    ) -> None:
        allowed_nodes = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Call,
            ast.Name,
            ast.Load,
            ast.Constant,
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.Pow,
            ast.Mod,
            ast.USub,
            ast.UAdd,
            ast.Compare,
            ast.Eq,
            ast.NotEq,
            ast.Lt,
            ast.LtE,
            ast.Gt,
            ast.GtE,
            ast.BitAnd,
            ast.BitOr,
        )
        for node in ast.walk(tree):
            if not isinstance(node, allowed_nodes):
                raise ValueError(
                    f"Unsupported syntax in function cut: {type(node).__name__}."
                )
            if isinstance(node, ast.Name) and node.id not in allowed_names:
                raise ValueError(f"Unsupported symbol in function cut: {node.id}")
            if isinstance(node, ast.Call):
                if not isinstance(node.func, ast.Name) or node.func.id not in callable_names:
                    raise ValueError("Only simple allowed functions can be used in y = f(x).")

    def _evaluate_parametric_function_cut_expression(
        self,
        expression: str,
        x_values: np.ndarray,
        params: dict[str, Any] | None = None,
    ) -> tuple[str, list[str], dict[str, float], np.ndarray]:
        normalized_expression = self._normalize_function_cut_expression(expression)
        param_names = self._function_parameter_names_from_expression(normalized_expression)
        env = self._function_cut_eval_env()
        callable_names = {
            name for name, value in env.items() if callable(value)
        }
        allowed_names = set(env.keys()) | {"x"} | set(param_names)
        tree = ast.parse(normalized_expression, mode="eval")
        self._validate_function_cut_ast(tree, allowed_names, callable_names)

        x_array = np.asarray(x_values, dtype=np.float64)
        local_env = dict(env)
        local_env["x"] = x_array
        resolved_params: dict[str, float] = {}
        params = dict(params or {})
        for name in param_names:
            default_value = 0.0
            if name.lower() in {"c", "offset", "y0"}:
                default_value = 1.0
            resolved_params[name] = float(params.get(name, default_value))
            local_env[name] = resolved_params[name]
        result = eval(compile(tree, "<function-cut>", "eval"), {"__builtins__": {}}, local_env)
        y_array = np.asarray(result, dtype=np.float64)
        if y_array.ndim == 0:
            y_array = np.full(x_array.shape, float(y_array), dtype=np.float64)
        elif y_array.shape != x_array.shape:
            if y_array.size != x_array.size:
                raise ValueError("Function result must be scalar or match the sampled x grid.")
            y_array = np.reshape(y_array, x_array.shape)
        if not np.all(np.isfinite(y_array)):
            raise ValueError("Function produced NaN/Inf values inside the requested x range.")
        return normalized_expression, param_names, resolved_params, y_array

    def _fit_function_params_to_points(
        self,
        expression: str,
        control_points: list[tuple[float, float]],
        initial_params: dict[str, Any] | None = None,
    ) -> tuple[str, list[str], dict[str, float], list[tuple[float, float]]]:
        normalized_points = [
            clamp_point((float(point[0]), float(point[1])), self.nx, self.ny)
            for point in control_points
        ]
        normalized_points = sorted(
            normalized_points,
            key=lambda point: (point[0], point[1]),
        )
        if len(normalized_points) < 2:
            raise ValueError("Function fit needs at least two clicked points.")

        x_values = np.asarray([float(point[0]) for point in normalized_points], dtype=np.float64)
        y_values = np.asarray([float(point[1]) for point in normalized_points], dtype=np.float64)
        if abs(float(np.nanmax(x_values)) - float(np.nanmin(x_values))) < 1e-9:
            raise ValueError("Function fit needs points with different x positions.")

        normalized_expression = self._normalize_function_cut_expression(expression)
        param_names = self._function_parameter_names_from_expression(normalized_expression)
        env = self._function_cut_eval_env()
        callable_names = {
            name for name, value in env.items() if callable(value)
        }
        allowed_names = set(env.keys()) | {"x"} | set(param_names)
        tree = ast.parse(normalized_expression, mode="eval")
        self._validate_function_cut_ast(tree, allowed_names, callable_names)
        if len(normalized_points) < max(len(param_names), 2):
            raise ValueError(
                f"Function fit needs at least {max(len(param_names), 2)} points for this expression."
            )
        if not param_names:
            return normalized_expression, [], {}, normalized_points

        initial_params = dict(initial_params or {})
        initial_values = []
        y_median = float(np.nanmedian(y_values))
        for name in param_names:
            if name in initial_params:
                initial_values.append(float(initial_params[name]))
            elif name.lower() in {"c", "offset", "y0"}:
                initial_values.append(y_median)
            else:
                initial_values.append(0.0)

        def residual(vector: np.ndarray) -> np.ndarray:
            params_map = {
                name: float(vector[index]) for index, name in enumerate(param_names)
            }
            _expr, _names, _resolved, modeled = self._evaluate_parametric_function_cut_expression(
                normalized_expression,
                x_values,
                params=params_map,
            )
            return np.asarray(modeled - y_values, dtype=np.float64)

        result = least_squares(
            residual,
            x0=np.asarray(initial_values, dtype=np.float64),
            max_nfev=4000,
        )
        fitted_params = {
            name: float(result.x[index]) for index, name in enumerate(param_names)
        }
        return normalized_expression, param_names, fitted_params, normalized_points

    def _build_function_curve_from_control_points(
        self,
        expression: str,
        control_points: list[tuple[float, float]],
        render_point_count: int,
        *,
        initial_params: dict[str, Any] | None = None,
        params_override: dict[str, Any] | None = None,
        move_control_points: bool = False,
    ) -> tuple[str, list[tuple[float, float]], dict[str, Any]]:
        sample_count = max(int(render_point_count), 2)
        if params_override is None:
            normalized_expression, param_names, fitted_params, normalized_points = (
                self._fit_function_params_to_points(
                    expression,
                    control_points,
                    initial_params=initial_params,
                )
            )
        else:
            normalized_points = [
                clamp_point((float(point[0]), float(point[1])), self.nx, self.ny)
                for point in control_points
            ]
            normalized_points = sorted(
                normalized_points,
                key=lambda point: (point[0], point[1]),
            )
            if len(normalized_points) < 2:
                raise ValueError("Function cut needs at least two clicked points.")
            x_points = np.asarray(
                [float(point[0]) for point in normalized_points],
                dtype=np.float64,
            )
            normalized_expression, param_names, fitted_params, modeled_points = (
                self._evaluate_parametric_function_cut_expression(
                    expression,
                    x_points,
                    params=params_override,
                )
            )
            if move_control_points:
                normalized_points = [
                    clamp_point((float(x_value), float(y_value)), self.nx, self.ny)
                    for x_value, y_value in zip(x_points.tolist(), modeled_points.tolist())
                ]
            fitted_params = dict(fitted_params)

        x_values_points = np.asarray(
            [float(point[0]) for point in normalized_points],
            dtype=np.float64,
        )
        start_value = float(np.nanmin(x_values_points))
        end_value = float(np.nanmax(x_values_points))
        if abs(end_value - start_value) < 1e-9:
            raise ValueError("Function cut needs points with a finite x span.")
        x_values = np.linspace(
            start_value,
            end_value,
            sample_count,
            dtype=np.float64,
        )
        _expr, _names, _params, y_values = self._evaluate_parametric_function_cut_expression(
            expression,
            x_values,
            params=fitted_params,
        )
        points, _limited = self._normalize_curve_geometry_points(
            list(zip(x_values.tolist(), y_values.tolist()))
        )
        return normalized_expression, points, {
            "function_expr": normalized_expression,
            "function_x_start": float(start_value),
            "function_x_end": float(end_value),
            "function_point_count": sample_count,
            "function_control_points": [
                (float(point[0]), float(point[1])) for point in normalized_points
            ],
            "function_params": {
                str(name): float(fitted_params.get(name, 0.0)) for name in param_names
            },
        }

    def _refresh_function_param_editor(
        self,
        expression: str | None = None,
        params: dict[str, Any] | None = None,
    ) -> None:
        if not hasattr(self, "function_param_frame"):
            return
        for child in self.function_param_frame.winfo_children():
            child.destroy()
        self.function_param_vars = {}

        expression_text = str(expression or self.function_cut_expression_var.get() or "").strip()
        if not expression_text:
            self.ttk.Label(
                self.function_param_frame,
                text="Write the function expression first.",
                justify="left",
                wraplength=300,
            ).grid(row=0, column=0, sticky="w")
            return

        try:
            param_names = self._function_parameter_names_from_expression(expression_text)
        except Exception as exc:
            self.ttk.Label(
                self.function_param_frame,
                text=f"Invalid function: {exc}",
                justify="left",
                wraplength=300,
            ).grid(row=0, column=0, sticky="w")
            return

        if not param_names:
            self.ttk.Label(
                self.function_param_frame,
                text="This expression has no free parameters to fit.",
                justify="left",
                wraplength=300,
            ).grid(row=0, column=0, sticky="w")
            return

        resolved_params = dict(params or {})
        for index, name in enumerate(param_names):
            self.ttk.Label(self.function_param_frame, text=name).grid(
                row=index, column=0, sticky="w", pady=(0 if index == 0 else 6, 0)
            )
            var = self.tk.StringVar(
                value=f"{float(resolved_params.get(name, 0.0)):.6g}"
            )
            self.function_param_vars[name] = var
            entry = self.ttk.Entry(self.function_param_frame, textvariable=var, width=14)
            entry.grid(
                row=index,
                column=1,
                sticky="ew",
                padx=(6, 0),
                pady=(0 if index == 0 else 6, 0),
            )
            entry.bind("<Return>", self._on_function_param_entry_event)

    def _sync_function_cut_controls_from_selected_cut(self) -> None:
        if not hasattr(self, "function_cut_mode_var"):
            return
        cut = self._selected_cut()
        if cut is None:
            self.function_cut_mode_var.set("Selected curve: none")
            self.function_fit_points_var.set(
                f"Fit points: {len(self.function_cut_pending_points)}"
            )
            self.function_point_summary_var.set("Function points: none")
            self.selected_function_point_index = None
            self.function_point_x_var.set("")
            self.function_point_y_var.set("")
            self._refresh_function_param_editor()
            if hasattr(self, "function_point_listbox"):
                self.function_point_listbox.delete(0, self.tk.END)
            return
        preview_cut = self._cut_preview(cut.cut_id) or cut
        self.function_cut_mode_var.set(
            f"Selected curve: {self._cut_curve_mode_label(preview_cut)}"
        )
        self.function_fit_points_var.set(
            f"Fit points: {len(self.function_cut_pending_points)}"
        )
        if self._cut_is_function_curve(preview_cut):
            self.function_cut_expression_var.set(
                str(getattr(preview_cut, "function_expr", "") or "")
            )
            point_count = max(
                int(getattr(preview_cut, "function_point_count", 0) or 0),
                len(cut_polyline_points(preview_cut)),
                2,
            )
            self.function_cut_points_var.set(str(point_count))
            self._refresh_function_param_editor(
                str(getattr(preview_cut, "function_expr", "") or ""),
                dict(getattr(preview_cut, "function_params", {}) or {}),
            )
        else:
            self._refresh_function_param_editor()
        self._refresh_function_point_editor()

    def _load_selected_cut_into_function_editor(self) -> None:
        cut = self._selected_cut()
        if cut is None:
            self._set_status("Select a cut first.")
            return
        preview_cut = self._cut_preview(cut.cut_id) or cut
        if self._cut_is_function_curve(preview_cut):
            self.function_cut_expression_var.set(
                str(getattr(preview_cut, "function_expr", "") or "")
            )
            self.function_cut_points_var.set(
                str(
                    max(
                        int(getattr(preview_cut, "function_point_count", 0) or 0),
                        len(cut_polyline_points(preview_cut)),
                        2,
                    )
                )
            )
            self._refresh_function_param_editor(
                str(getattr(preview_cut, "function_expr", "") or ""),
                dict(getattr(preview_cut, "function_params", {}) or {}),
            )
            self._refresh_function_point_editor()
            self._set_status(f"Loaded functional settings from {cut.name}.")
            return
        self._refresh_function_param_editor(
            str(self.function_cut_expression_var.get() or ""),
        )
        self._refresh_function_point_editor()
        self._set_status(
            "Loaded the selected cut into the function editor. Click fit points to create the functional fit."
        )

    def _start_draw_function_cut(self) -> None:
        expression = str(self.function_cut_expression_var.get() or "").strip()
        if not expression:
            self._set_status("Write the function expression before clicking fit points.")
            return
        self._refresh_function_param_editor(expression)
        self._cancel_curve_cut_draw()
        self._cancel_feature_axis_draw()
        self.draw_mode = False
        self.force_new_cut = False
        self.pending_point = None
        self.hover_point = None
        self.drag_state = None
        self.function_cut_draw_mode = True
        self.function_cut_pending_points = []
        self.function_cut_hover_point = None
        self.function_fit_points_var.set("Fit points: 0")
        self._set_status(
            "Function fit mode: left-click to add fit points. Finish Fit or right-click closes it."
        )
        self.refresh_map()

    def _cancel_function_cut_draw(self) -> None:
        if not self.function_cut_draw_mode and not self.function_cut_pending_points:
            return
        self.function_cut_draw_mode = False
        self.function_cut_pending_points = []
        self.function_cut_hover_point = None
        self.function_fit_points_var.set("Fit points: 0")
        self._set_status("Function fit point capture cancelled.")
        self.refresh_map()

    def _append_function_cut_point(self, x: float, y: float) -> None:
        point = clamp_point((x, y), self.nx, self.ny)
        if self.function_cut_pending_points and distance(self.function_cut_pending_points[-1], point) < 1.0:
            self._set_status("Choose a point farther away to define the function fit.")
            return
        self.function_cut_pending_points.append(point)
        self.function_cut_hover_point = point
        self.function_fit_points_var.set(
            f"Fit points: {len(self.function_cut_pending_points)}"
        )
        self._set_status(
            f"Added function-fit point {len(self.function_cut_pending_points)} at ({point[0]:.1f}, {point[1]:.1f})."
        )
        self.refresh_map()

    def _finish_pending_function_cut(self) -> None:
        expression = str(self.function_cut_expression_var.get() or "").strip()
        if not expression:
            self._set_status("Write the function expression before fitting.")
            return
        if not self.function_cut_draw_mode and not self.function_cut_pending_points:
            self._set_status("No function-fit points are being drawn.")
            return
        render_point_count = max(self._safe_int_text(self.function_cut_points_var.get(), 0), 2)
        target_cut = self._selected_cut() if self._cut_is_function_curve(self._selected_cut()) else None
        initial_params = (
            dict(getattr(target_cut, "function_params", {}) or {})
            if target_cut is not None
            else None
        )
        try:
            normalized_expression, curve_points, function_meta = (
                self._build_function_curve_from_control_points(
                    expression,
                    list(self.function_cut_pending_points),
                    render_point_count,
                    initial_params=initial_params,
                )
            )
        except Exception as exc:
            self._set_status(f"Could not fit the function to the clicked points: {exc}")
            return

        self.function_cut_draw_mode = False
        self.function_cut_pending_points = []
        self.function_cut_hover_point = None
        self.function_fit_points_var.set("Fit points: 0")

        if target_cut is None:
            cut = self._create_cut(curve_points[0], curve_points[-1])
            updated, limited = self._set_curve_cut_geometry(
                cut,
                curve_points,
                curve_fit="function",
                function_meta=function_meta,
            )
            if not updated:
                self.cuts.pop(cut.cut_id, None)
                self.next_cut_id = max(self.next_cut_id - 1, 1)
                return
            panel = self.active_panel
            panel.cut_id = cut.cut_id
            self._seed_cut_td_params_from_panel(cut.cut_id, panel)
            self.selected_cut_id = cut.cut_id
            status_prefix = f"Created function cut {cut.name} from {len(function_meta['function_control_points'])} fit point(s)."
        else:
            self._apply_curve_cut_geometry(
                target_cut,
                curve_points,
                f"Updated {target_cut.name} from {len(function_meta['function_control_points'])} fit point(s).",
                curve_fit="function",
                function_meta=function_meta,
            )
            limited = False
            status_prefix = ""

        if target_cut is None:
            self.refresh_all()
            limited_text = " Limited by image bounds." if limited else ""
            self._set_status(
                f"{status_prefix} y={normalized_expression}.{limited_text}"
            )

    def _refit_selected_function_cut(self) -> None:
        cut = self._selected_editable_cut("refit function cut")
        if cut is None or not self._cut_is_function_curve(cut):
            self._set_status("Select a function cut first.")
            return
        control_points = self._function_control_points(cut)
        if len(control_points) < 2:
            self._set_status("The selected function cut has no editable fit points.")
            return
        render_point_count = max(self._safe_int_text(self.function_cut_points_var.get(), 0), 2)
        try:
            normalized_expression, curve_points, function_meta = (
                self._build_function_curve_from_control_points(
                    str(self.function_cut_expression_var.get() or getattr(cut, "function_expr", "")),
                    control_points,
                    render_point_count,
                    initial_params=dict(getattr(cut, "function_params", {}) or {}),
                )
            )
        except Exception as exc:
            self._set_status(f"Could not refit the selected function cut: {exc}")
            return
        self._apply_curve_cut_geometry(
            cut,
            curve_points,
            f"Refit {cut.name} to its stored control points.",
            curve_fit="function",
            function_meta=function_meta,
        )
        self.function_cut_expression_var.set(normalized_expression)

    def _apply_function_params_to_selected_cut(self) -> None:
        cut = self._selected_editable_cut("apply function parameters")
        if cut is None or not self._cut_is_function_curve(cut):
            self._set_status("Select a function cut first.")
            return
        expression = str(self.function_cut_expression_var.get() or getattr(cut, "function_expr", "")).strip()
        if not expression:
            self._set_status("Write the function expression first.")
            return
        control_points = self._function_control_points(cut)
        if len(control_points) < 2:
            self._set_status("The selected function cut has no control points to move.")
            return
        params_override: dict[str, float] = {}
        try:
            for name in self._function_parameter_names_from_expression(expression):
                var = self.function_param_vars.get(name)
                params_override[name] = float(str(var.get() if var is not None else "0").strip())
        except Exception as exc:
            self._set_status(f"Invalid function parameter value: {exc}")
            return

        render_point_count = max(self._safe_int_text(self.function_cut_points_var.get(), 0), 2)
        try:
            normalized_expression, curve_points, function_meta = (
                self._build_function_curve_from_control_points(
                    expression,
                    control_points,
                    render_point_count,
                    params_override=params_override,
                    move_control_points=True,
                )
            )
        except Exception as exc:
            self._set_status(f"Could not apply function parameters: {exc}")
            return
        self._apply_curve_cut_geometry(
            cut,
            curve_points,
            f"Applied function parameters to {cut.name}.",
            curve_fit="function",
            function_meta=function_meta,
        )
        self.function_cut_expression_var.set(normalized_expression)

    def _refresh_function_point_editor(self) -> None:
        if not hasattr(self, "function_point_listbox"):
            return
        self.function_point_listbox.delete(0, self.tk.END)
        cut = self._selected_cut()
        if cut is None or not self._cut_is_function_curve(cut):
            self.function_point_summary_var.set("Function points: select a function cut.")
            self.selected_function_point_index = None
            self.function_point_x_var.set("")
            self.function_point_y_var.set("")
            return
        control_points = self._function_control_points(cut)
        self.function_point_summary_var.set(
            f"Function points: {len(control_points)} control point(s). Edit x/y to refit."
        )
        for index, point in enumerate(control_points, start=1):
            self.function_point_listbox.insert(
                self.tk.END,
                f"{index:02d}: ({float(point[0]):.2f}, {float(point[1]):.2f})",
            )
        if not control_points:
            self.selected_function_point_index = None
            self.function_point_x_var.set("")
            self.function_point_y_var.set("")
            return
        if (
            self.selected_function_point_index is None
            or self.selected_function_point_index >= len(control_points)
        ):
            self.selected_function_point_index = 0
        self.function_point_listbox.selection_clear(0, self.tk.END)
        self.function_point_listbox.selection_set(self.selected_function_point_index)
        self.function_point_listbox.activate(self.selected_function_point_index)
        point = control_points[self.selected_function_point_index]
        self.function_point_x_var.set(f"{float(point[0]):.3f}")
        self.function_point_y_var.set(f"{float(point[1]):.3f}")

    def _on_function_point_list_select(self, _event: Any) -> None:
        cut = self._selected_cut()
        if cut is None or not self._cut_is_function_curve(cut):
            return
        selection = self.function_point_listbox.curselection()
        if not selection:
            return
        control_points = self._function_control_points(cut)
        index = int(selection[0])
        if index >= len(control_points):
            return
        self.selected_function_point_index = index
        point = control_points[index]
        self.function_point_x_var.set(f"{float(point[0]):.3f}")
        self.function_point_y_var.set(f"{float(point[1]):.3f}")

    def _apply_selected_function_control_point(self) -> None:
        cut = self._selected_editable_cut("edit function point")
        if cut is None or not self._cut_is_function_curve(cut):
            return
        control_points = self._function_control_points(cut)
        index = self.selected_function_point_index
        if index is None or index < 0 or index >= len(control_points):
            self._set_status("Select a function point first.")
            return
        x_value = self._parse_float_var(self.function_point_x_var.get(), "function point x")
        y_value = self._parse_float_var(self.function_point_y_var.get(), "function point y")
        if x_value is None or y_value is None:
            return
        control_points[index] = clamp_point((float(x_value), float(y_value)), self.nx, self.ny)
        render_point_count = max(self._safe_int_text(self.function_cut_points_var.get(), 0), 2)
        try:
            normalized_expression, curve_points, function_meta = (
                self._build_function_curve_from_control_points(
                    str(self.function_cut_expression_var.get() or getattr(cut, "function_expr", "")),
                    control_points,
                    render_point_count,
                    initial_params=dict(getattr(cut, "function_params", {}) or {}),
                )
            )
        except Exception as exc:
            self._set_status(f"Could not refit after editing the point: {exc}")
            return
        self._apply_curve_cut_geometry(
            cut,
            curve_points,
            f"Updated function point {index + 1} of {cut.name}.",
            curve_fit="function",
            function_meta=function_meta,
        )
        self.function_cut_expression_var.set(normalized_expression)

    def _remove_selected_function_control_point(self) -> None:
        cut = self._selected_editable_cut("remove function point")
        if cut is None or not self._cut_is_function_curve(cut):
            return
        control_points = self._function_control_points(cut)
        index = self.selected_function_point_index
        if index is None or index < 0 or index >= len(control_points):
            self._set_status("Select a function point first.")
            return
        remaining = [point for idx, point in enumerate(control_points) if idx != index]
        param_count = len(
            self._function_parameter_names_from_expression(
                str(self.function_cut_expression_var.get() or getattr(cut, "function_expr", ""))
            )
        )
        if len(remaining) < max(param_count, 2):
            self._set_status(
                f"Need at least {max(param_count, 2)} point(s) to keep fitting this function."
            )
            return
        render_point_count = max(self._safe_int_text(self.function_cut_points_var.get(), 0), 2)
        try:
            normalized_expression, curve_points, function_meta = (
                self._build_function_curve_from_control_points(
                    str(self.function_cut_expression_var.get() or getattr(cut, "function_expr", "")),
                    remaining,
                    render_point_count,
                    initial_params=dict(getattr(cut, "function_params", {}) or {}),
                )
            )
        except Exception as exc:
            self._set_status(f"Could not refit after removing the point: {exc}")
            return
        self.selected_function_point_index = max(0, min(index, len(remaining) - 1))
        self._apply_curve_cut_geometry(
            cut,
            curve_points,
            f"Removed a function control point from {cut.name}.",
            curve_fit="function",
            function_meta=function_meta,
        )
        self.function_cut_expression_var.set(normalized_expression)

    def _prompt_curve_cut_fit_mode(self) -> str | None:
        top = self.tk.Toplevel(self.root)
        top.title("Curved Cut Fit")
        top.transient(self.root)
        top.grab_set()
        top.resizable(False, False)

        choice: dict[str, str | None] = {"mode": None}

        def close_with(mode: str | None) -> None:
            choice["mode"] = mode
            if top.winfo_exists():
                top.destroy()

        frame = self.ttk.Frame(top, padding=14)
        frame.grid(row=0, column=0, sticky="nsew")
        frame.columnconfigure(0, weight=1)
        frame.columnconfigure(1, weight=1)

        self.ttk.Label(
            frame,
            text="Como quieres ajustar los puntos del curved cut?",
            justify="left",
            wraplength=380,
        ).grid(row=0, column=0, columnspan=2, sticky="w")
        self.ttk.Label(
            frame,
            text=(
                "Polyline = sigue los puntos tal como fueron dibujados.\n"
                "Quadratic/Cubic = ajuste polinomico parametrico y sampling subpixel."
            ),
            justify="left",
            wraplength=380,
        ).grid(row=1, column=0, columnspan=2, sticky="w", pady=(8, 0))

        self.ttk.Button(
            frame,
            text="Polyline",
            command=lambda: close_with("polyline"),
        ).grid(row=2, column=0, sticky="ew", padx=(0, 6), pady=(12, 0))
        self.ttk.Button(
            frame,
            text="Quadratic",
            command=lambda: close_with("quadratic"),
        ).grid(row=2, column=1, sticky="ew", padx=(6, 0), pady=(12, 0))
        self.ttk.Button(
            frame,
            text="Cubic",
            command=lambda: close_with("cubic"),
        ).grid(row=3, column=0, sticky="ew", padx=(0, 6), pady=(8, 0))
        self.ttk.Button(
            frame,
            text="Cancelar",
            command=lambda: close_with(None),
        ).grid(row=3, column=1, sticky="ew", padx=(6, 0), pady=(8, 0))

        top.protocol("WM_DELETE_WINDOW", lambda: close_with(None))
        top.bind("<Escape>", lambda _event: close_with(None))
        top.bind("<Return>", lambda _event: close_with("cubic"))
        top.update_idletasks()
        top.focus_set()
        self.root.wait_window(top)
        return choice["mode"]

    def _build_curve_cut_points(
        self,
        control_points: list[tuple[float, float]],
        fit_mode: str,
    ) -> list[tuple[float, float]]:
        points = [clamp_point(point, self.nx, self.ny) for point in control_points]
        if len(points) < 2 or polyline_length(points) < 1.0:
            raise ValueError("Curved cut needs at least two separated points.")

        arc_lengths = polyline_arc_lengths(points)
        total_length = max(float(arc_lengths[-1]) if len(arc_lengths) else 0.0, 1.0)
        sample_count = max(int(round(total_length * 3.0)) + 1, 48)

        if str(fit_mode) == "polyline":
            sample_distances = np.linspace(0.0, total_length, sample_count, dtype=np.float64)
            sampled_points = [
                clamp_point(
                    polyline_point_at_length(points, arc_lengths, float(distance_value)),
                    self.nx,
                    self.ny,
                )
                for distance_value in sample_distances
            ]
        else:
            xs = np.asarray([float(point[0]) for point in points], dtype=np.float64)
            ys = np.asarray([float(point[1]) for point in points], dtype=np.float64)
            if total_length <= 1e-9:
                params = np.linspace(0.0, 1.0, len(points), dtype=np.float64)
            else:
                params = arc_lengths / total_length
            degree = 2 if str(fit_mode) == "quadratic" else 3
            degree = max(1, min(int(degree), len(points) - 1))
            x_coeff = np.polyfit(params, xs, deg=degree)
            y_coeff = np.polyfit(params, ys, deg=degree)
            sample_params = np.linspace(0.0, 1.0, sample_count, dtype=np.float64)
            sampled_points = [
                clamp_point(
                    (
                        float(np.polyval(x_coeff, param_value)),
                        float(np.polyval(y_coeff, param_value)),
                    ),
                    self.nx,
                    self.ny,
                )
                for param_value in sample_params
            ]

        normalized: list[tuple[float, float]] = []
        for point in sampled_points:
            if normalized and distance(normalized[-1], point) < 0.35:
                continue
            normalized.append((float(point[0]), float(point[1])))
        if len(normalized) < 2 or polyline_length(normalized) < 1.0:
            raise ValueError("Curved cut fit collapsed to a too-short geometry.")
        return normalized

    def _start_draw_curve_cut(self) -> None:
        self._cancel_function_cut_draw()
        self._cancel_feature_axis_draw()
        self.draw_mode = False
        self.force_new_cut = False
        self.pending_point = None
        self.hover_point = None
        self.drag_state = None
        self.curve_cut_draw_mode = True
        self.curve_cut_pending_points = []
        self.curve_cut_hover_point = None
        self._set_status(
            "Curved cut mode: left-click to add points. Finish Curved or right-click closes it."
        )
        self.refresh_map()

    def _cancel_curve_cut_draw(self) -> None:
        if not self.curve_cut_draw_mode and not self.curve_cut_pending_points:
            return
        self.curve_cut_draw_mode = False
        self.curve_cut_pending_points = []
        self.curve_cut_hover_point = None
        self._set_status("Curved cut drawing cancelled.")
        self.refresh_map()

    def _append_curve_cut_point(self, x: float, y: float) -> None:
        point = clamp_point((x, y), self.nx, self.ny)
        if self.curve_cut_pending_points and distance(self.curve_cut_pending_points[-1], point) < 1.0:
            self._set_status("Choose a point farther away to define the curved cut.")
            return
        self.curve_cut_pending_points.append(point)
        self.curve_cut_hover_point = point
        self._set_status(
            f"Added curved-cut point {len(self.curve_cut_pending_points)} at ({point[0]:.1f}, {point[1]:.1f})."
        )
        self.refresh_map()

    def _finish_pending_curve_cut(self) -> None:
        if not self.curve_cut_draw_mode and not self.curve_cut_pending_points:
            self._set_status("No curved cut is being drawn.")
            return
        normalized_points: list[tuple[float, float]] = []
        for point in self.curve_cut_pending_points:
            clamped = clamp_point(point, self.nx, self.ny)
            if normalized_points and distance(normalized_points[-1], clamped) < 1.0:
                continue
            normalized_points.append(clamped)
        if len(normalized_points) < 2 or polyline_length(normalized_points) < 1.0:
            self._set_status("Curved cut is too short; add at least two separated points.")
            return
        fit_mode = self._prompt_curve_cut_fit_mode()
        if fit_mode is None:
            self._set_status("Curved cut creation cancelled.")
            return
        try:
            sampled_points = self._build_curve_cut_points(normalized_points, fit_mode)
        except ValueError as exc:
            self._set_status(str(exc))
            return
        cut = self._create_cut(sampled_points[0], sampled_points[-1])
        cut.mode = "curve"
        cut.curve_fit = str(fit_mode)
        cut.curve_points = [(float(point[0]), float(point[1])) for point in sampled_points]
        self._clear_cut_function_metadata(cut)
        panel = self.active_panel
        panel.cut_id = cut.cut_id
        self._seed_cut_td_params_from_panel(cut.cut_id, panel)
        self.selected_cut_id = cut.cut_id
        self.curve_cut_draw_mode = False
        self.curve_cut_pending_points = []
        self.curve_cut_hover_point = None
        self._invalidate_cut_dependents(cut.cut_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(
            f"Created curved cut {cut.name} with fit={fit_mode} and {len(sampled_points)} sampled points."
        )

    def _create_feature_axis(
        self, points: list[tuple[float, float]], mode: str
    ) -> FeatureAxis:
        axis = FeatureAxis(
            axis_id=self.next_feature_axis_id,
            name=f"Axis {self.next_feature_axis_id}",
            color=COLOR_CYCLE[(self.next_feature_axis_id - 1) % len(COLOR_CYCLE)],
            points=[(float(point[0]), float(point[1])) for point in points],
            mode="line" if str(mode) == "line" else "curve",
        )
        self.feature_axes[axis.axis_id] = axis
        self.next_feature_axis_id += 1
        self.selected_feature_axis_id = axis.axis_id
        return axis

    def _start_draw_feature_axis(self, mode: str) -> None:
        self._cancel_function_cut_draw()
        self._cancel_curve_cut_draw()
        self.draw_mode = False
        self.force_new_cut = False
        self.pending_point = None
        self.hover_point = None
        self.drag_state = None
        self.feature_draw_mode = "line" if str(mode) == "line" else "curve"
        self.feature_pending_points = []
        self.feature_hover_point = None
        self._sync_feature_axis_controls()
        if self.feature_draw_mode == "line":
            self._set_status(
                "Feature line mode: click two points on the map to define the feature axis."
            )
        else:
            self._set_status(
                "Feature curve mode: left-click to add points. Finish Curve or right-click closes it."
            )
        self.refresh_map()

    def _cancel_feature_axis_draw(self) -> None:
        if self.feature_draw_mode is None and not self.feature_pending_points:
            return
        self.feature_draw_mode = None
        self.feature_pending_points = []
        self.feature_hover_point = None
        self._sync_feature_axis_controls()
        self._set_status("Feature axis drawing cancelled.")
        self.refresh_map()

    def _append_feature_axis_point(self, x: float, y: float) -> None:
        if self.feature_draw_mode is None:
            return
        point = clamp_point((x, y), self.nx, self.ny)
        if self.feature_pending_points:
            if distance(self.feature_pending_points[-1], point) < 1.0:
                self._set_status("Choose a point farther away to define the feature axis.")
                return
        self.feature_pending_points.append(point)
        self.feature_hover_point = point
        if self.feature_draw_mode == "line" and len(self.feature_pending_points) >= 2:
            self._finish_pending_feature_axis()
            return
        self._sync_feature_axis_controls()
        if self.feature_draw_mode == "curve":
            self._set_status(
                f"Added curve point {len(self.feature_pending_points)} at ({point[0]:.1f}, {point[1]:.1f})."
            )
        else:
            self._set_status(
                f"Feature line start set at ({point[0]:.1f}, {point[1]:.1f}). Choose the second point."
            )
        self.refresh_map()

    def _finish_pending_feature_axis(self) -> None:
        if self.feature_draw_mode is None:
            self._set_status("No feature axis is being drawn.")
            return
        normalized_points: list[tuple[float, float]] = []
        for point in self.feature_pending_points:
            clamped = clamp_point(point, self.nx, self.ny)
            if normalized_points and distance(normalized_points[-1], clamped) < 1.0:
                continue
            normalized_points.append(clamped)
        if len(normalized_points) < 2 or polyline_length(normalized_points) < 1.0:
            self._set_status("Feature axis is too short; add at least two separated points.")
            return
        axis_mode = self.feature_draw_mode
        axis = self._create_feature_axis(normalized_points, axis_mode)
        self.feature_draw_mode = None
        self.feature_pending_points = []
        self.feature_hover_point = None
        self._record_session_change()
        self.refresh_all()
        self._set_status(
            f"Saved {axis.mode} feature axis {axis.name} with {len(axis.points)} point(s)."
        )

    def _delete_selected_feature_axis(self) -> None:
        axis = self._selected_feature_axis()
        if axis is None:
            self._set_status("Select a feature axis first.")
            return
        self.feature_axes.pop(axis.axis_id, None)
        if self.selected_feature_axis_id == axis.axis_id:
            self.selected_feature_axis_id = None
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Deleted feature axis {axis.name}.")

    def _generate_cuts_from_selected_feature_axis(self) -> None:
        axis = self._selected_feature_axis()
        if axis is None:
            self._set_status("Select a feature axis first.")
            return

        spacing = self._parse_float_var(self.feature_spacing_var.get(), "feature spacing")
        length_value = self._parse_float_var(self.feature_length_var.get(), "feature length")
        angle_offset = self._parse_float_var(
            self.feature_angle_offset_var.get(), "feature angle"
        )
        if spacing is None or length_value is None or angle_offset is None:
            return

        spacing = max(float(spacing), 1.0)
        length_value = max(float(length_value), 1.0)
        points = [clamp_point(point, self.nx, self.ny) for point in axis.points]
        arc_lengths = polyline_arc_lengths(points)
        total_length = 0.0 if len(arc_lengths) == 0 else float(arc_lengths[-1])
        if total_length < 1.0:
            self._set_status(f"{axis.name} is too short to generate cuts.")
            return

        positions = feature_axis_sample_positions(total_length, spacing)
        if not positions:
            self._set_status(f"{axis.name} produced no valid sample positions.")
            return
        if len(positions) > MAX_FEATURE_AXIS_CUTS:
            self._set_status(
                f"{axis.name} would generate {len(positions)} cuts. Increase spacing and try again."
            )
            return

        template_panel = self.active_panel
        generated_cut_ids: list[int] = []
        clipped_count = 0
        tangent_delta = max(min(spacing * 0.35, max(total_length * 0.15, 1.0)), 1.0)
        for index, position in enumerate(positions, start=1):
            center = polyline_point_at_length(points, arc_lengths, position)
            tx, ty = polyline_tangent_at_length(
                points,
                arc_lengths,
                position,
                delta=tangent_delta,
            )
            normal_angle = float(math.degrees(math.atan2(-ty, tx)))
            p0, p1, actual_length = segment_from_angle_length(
                normal_angle + float(angle_offset),
                length_value,
                "center",
                None,
                center,
                self.nx,
                self.ny,
            )
            if actual_length < 1.0:
                continue
            cut = self._create_cut(p0, p1)
            cut.name = f"{axis.name} {index:02d}"
            self._seed_cut_td_params_from_panel(cut.cut_id, template_panel)
            generated_cut_ids.append(cut.cut_id)
            if actual_length + 1e-6 < length_value:
                clipped_count += 1

        if not generated_cut_ids:
            self._set_status(f"{axis.name} did not yield any valid cuts.")
            return

        template_panel.cut_id = generated_cut_ids[0]
        self.selected_cut_id = generated_cut_ids[0]
        self._invalidate_panel_cache(template_panel.panel_id)

        stack_name = ""
        if bool(self.feature_create_stack_var.get()):
            stack_id = int(self.next_stack_id)
            self.next_stack_id += 1
            stack_name = f"{axis.name} Stack"
            self.stacks[stack_id] = self._make_default_stack_state(
                stack_id,
                stack_name,
                generated_cut_ids,
            )
            self.active_stack_id = stack_id
            self.selected_stack_cut_id = generated_cut_ids[0]

        self._record_session_change()
        self.refresh_all()
        message = (
            f"Generated {len(generated_cut_ids)} cuts from {axis.name} "
            f"(spacing={spacing:.1f}, length={length_value:.1f}, angle={angle_offset:.1f} deg)."
        )
        if stack_name:
            message += f" Created {stack_name}."
        if clipped_count:
            message += f" {clipped_count} cut(s) were clipped by image bounds."
        self._set_status(message)

    def _start_draw_cut(self) -> None:
        self._cancel_function_cut_draw()
        self._cancel_curve_cut_draw()
        self._cancel_feature_axis_draw()
        self.draw_mode = True
        self.force_new_cut = False
        self.pending_point = None
        self.hover_point = None
        self.drag_state = None
        self._set_status(
            f"Draw mode for {self.active_panel.name}: click two points on the map."
        )
        self.refresh_map()

    def _start_add_cut(self) -> None:
        self._cancel_function_cut_draw()
        self._cancel_curve_cut_draw()
        self._cancel_feature_axis_draw()
        self.draw_mode = True
        self.force_new_cut = True
        self.pending_point = None
        self.hover_point = None
        self.drag_state = None
        self._set_status(
            f"Add Cut mode for {self.active_panel.name}: the next two clicks create a new cut."
        )
        self.refresh_map()

    def _begin_pending_cut(self, x: float, y: float) -> None:
        self.pending_point = (x, y)
        self.hover_point = (x, y)
        self.drag_state = None
        self._set_status(
            f"First point set at ({x:.1f}, {y:.1f}) for {self.active_panel.name}. "
            "Click second point to finish. Esc or right-click cancels."
        )
        self.refresh_map()

    def _finish_pending_cut(self, x: float, y: float) -> None:
        if self.pending_point is None:
            return

        p0 = self.pending_point
        p1 = (x, y)
        if distance(p0, p1) < 1.0:
            self._set_status("Cut too short; choose two distinct points.")
            return

        panel = self.active_panel
        if panel.cut_id is not None and panel.cut_id in self.cuts:
            if self.force_new_cut:
                cut = self._create_cut(p0, p1)
                panel.cut_id = cut.cut_id
                self._seed_cut_td_params_from_panel(cut.cut_id, panel)
            else:
                cut = self.cuts[panel.cut_id]
                if self._cut_dynamic_enabled(cut.cut_id):
                    self._set_cut_dynamic_keyframe(
                        cut.cut_id,
                        int(self.t_visual_var.get()),
                        p0,
                        p1,
                        enable_dynamic=True,
                    )
                else:
                    cut.p0 = p0
                    cut.p1 = p1
                    cut.mode = "line"
                    cut.curve_fit = "line"
                    cut.curve_points = []
                    self._clear_cut_function_metadata(cut)
        else:
            cut = self._create_cut(p0, p1)
            panel.cut_id = cut.cut_id
            self._seed_cut_td_params_from_panel(cut.cut_id, panel)

        self.selected_cut_id = cut.cut_id
        self.pending_point = None
        self.hover_point = None
        self.draw_mode = False
        self.force_new_cut = False
        self._invalidate_cut_dependents(cut.cut_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"{cut.name} assigned to {panel.name}.")

    def _cancel_pending_cut(self) -> None:
        if self.function_cut_draw_mode or self.function_cut_pending_points:
            self._cancel_function_cut_draw()
            return
        if self.curve_cut_draw_mode or self.curve_cut_pending_points:
            self._cancel_curve_cut_draw()
            return
        if self.feature_draw_mode is not None or self.feature_pending_points:
            self._cancel_feature_axis_draw()
            return
        if self.pending_point is None and not self.draw_mode:
            return
        self.pending_point = None
        self.hover_point = None
        self.draw_mode = False
        self.force_new_cut = False
        self.drag_state = None
        self._set_status("Cut creation cancelled.")
        self.refresh_map()

    def _assign_selected_cut(self) -> None:
        if self.selected_cut_id is None or self.selected_cut_id not in self.cuts:
            self._set_status("No cut selected to assign.")
            return
        panel = self.active_panel
        panel.cut_id = self.selected_cut_id
        self._seed_cut_td_params_from_panel(self.selected_cut_id, panel)
        self._invalidate_panel_cache(panel.panel_id)
        self._sync_controls_from_active_panel()
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Assigned Cut {self.selected_cut_id} to {panel.name}.")

    def _copy_selected_cut(self) -> None:
        cut = self._selected_cut()
        if cut is None:
            self._set_status("No cut selected to copy.")
            return
        preview_cut = self._cut_preview(cut.cut_id) or cut
        self.clipboard_cut = {
            "p0": preview_cut.p0,
            "p1": preview_cut.p1,
            "color": cut.color,
            "mode": str(getattr(preview_cut, "mode", "line")),
            "curve_fit": str(getattr(preview_cut, "curve_fit", "line")),
            "curve_points": [
                [float(point[0]), float(point[1])]
                for point in (getattr(preview_cut, "curve_points", []) or [])
            ],
            "function_expr": str(getattr(preview_cut, "function_expr", "") or ""),
            "function_x_start": float(
                getattr(preview_cut, "function_x_start", preview_cut.p0[0])
            ),
            "function_x_end": float(
                getattr(preview_cut, "function_x_end", preview_cut.p1[0])
            ),
            "function_point_count": max(
                int(getattr(preview_cut, "function_point_count", 0) or 0),
                0,
            ),
            "function_control_points": [
                [float(point[0]), float(point[1])]
                for point in (getattr(preview_cut, "function_control_points", []) or [])
            ],
            "function_params": {
                str(key): float(value)
                for key, value in dict(getattr(preview_cut, "function_params", {}) or {}).items()
            },
        }
        self._set_status(f"Copied {cut.name}.")

    def _paste_cut(self) -> None:
        if self.clipboard_cut is None:
            self._set_status("Clipboard is empty.")
            return

        p0 = self.clipboard_cut["p0"]
        p1 = self.clipboard_cut["p1"]
        new_cut = self._create_cut(
            clamp_point((p0[0] + 3.0, p0[1] + 3.0), self.nx, self.ny),
            clamp_point((p1[0] + 3.0, p1[1] + 3.0), self.nx, self.ny),
        )
        if str(self.clipboard_cut.get("mode", "line")) == "curve":
            curve_points = [
                clamp_point((float(point[0]) + 3.0, float(point[1]) + 3.0), self.nx, self.ny)
                for point in (self.clipboard_cut.get("curve_points") or [])
            ]
            if len(curve_points) >= 2:
                pasted_fit = str(self.clipboard_cut.get("curve_fit", "polyline"))
                if pasted_fit == "function":
                    shifted_control_points = [
                        clamp_point(
                            (float(point[0]) + 3.0, float(point[1]) + 3.0),
                            self.nx,
                            self.ny,
                        )
                        for point in (self.clipboard_cut.get("function_control_points") or [])
                    ]
                    function_expr = str(self.clipboard_cut.get("function_expr", "") or "")
                    function_params = dict(self.clipboard_cut.get("function_params") or {})
                    render_point_count = max(
                        int(self.clipboard_cut.get("function_point_count", len(curve_points)) or 0),
                        2,
                    )
                    if function_expr and len(shifted_control_points) >= 2:
                        try:
                            _expr, refit_curve_points, function_meta = (
                                self._build_function_curve_from_control_points(
                                    function_expr,
                                    shifted_control_points,
                                    render_point_count,
                                    initial_params=function_params,
                                )
                            )
                            updated, _limited = self._set_curve_cut_geometry(
                                new_cut,
                                refit_curve_points,
                                curve_fit="function",
                                function_meta=function_meta,
                            )
                            if not updated:
                                pasted_fit = "polyline"
                        except Exception:
                            pasted_fit = "polyline"
                    else:
                        pasted_fit = "polyline"
                if pasted_fit != "function":
                    new_cut.mode = "curve"
                    new_cut.curve_fit = pasted_fit
                    new_cut.curve_points = [(float(point[0]), float(point[1])) for point in curve_points]
                    new_cut.p0 = new_cut.curve_points[0]
                    new_cut.p1 = new_cut.curve_points[-1]
                    self._clear_cut_function_metadata(new_cut)
        panel = self.active_panel
        panel.cut_id = new_cut.cut_id
        self._seed_cut_td_params_from_panel(new_cut.cut_id, panel)
        self.selected_cut_id = new_cut.cut_id
        self._invalidate_panel_cache(panel.panel_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Pasted {new_cut.name} into {panel.name}.")

    def _rotate_selected_cut(self, angle_deg: float) -> None:
        self._adjust_selected_cut_angle(angle_deg)

    def _delete_selected_cut(self) -> None:
        cut = self._selected_cut()
        if cut is None:
            return
        cut_id = cut.cut_id
        for panel in self.panels:
            if panel.cut_id == cut_id:
                panel.cut_id = None
                self._invalidate_panel_cache(panel.panel_id)
        self.cut_analysis_state.pop(cut_id, None)
        for stack in self.stacks.values():
            stack["cut_ids"] = [
                int(member_cut_id)
                for member_cut_id in (stack.get("cut_ids") or [])
                if int(member_cut_id) != int(cut_id)
            ]
        self._drop_cut_from_experiments(cut_id)
        del self.cuts[cut_id]
        if self.selected_cut_id == cut_id:
            self.selected_cut_id = None
        if self.selected_stack_cut_id == cut_id:
            self.selected_stack_cut_id = None
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Deleted Cut {cut_id}.")

    def _selected_cut(self) -> Cut | None:
        if self.selected_cut_id is None:
            return None
        return self.cuts.get(self.selected_cut_id)

    def _panel_for_axis(self, axis: Any) -> int | None:
        return self.axis_to_panel_id.get(axis)

    def _find_cut_hit(
        self, x: float, y: float
    ) -> tuple[str, int] | None:
        ordered = []
        map_cut_ids, _map_note = self._main_map_cut_ids()
        map_cut_lookup = {int(cut_id) for cut_id in map_cut_ids}
        if (
            self.selected_cut_id is not None
            and self.selected_cut_id in self.cuts
            and int(self.selected_cut_id) in map_cut_lookup
        ):
            ordered.append(self.cuts[self.selected_cut_id])
        for cut_id in map_cut_ids:
            if self.selected_cut_id == cut_id:
                continue
            ordered.append(self.cuts[int(cut_id)])

        best: tuple[float, str, int] | None = None
        for cut in ordered:
            if not cut.visible:
                continue
            preview_cut = self._cut_preview(cut.cut_id) or cut
            if self._cut_is_curve(preview_cut):
                points = cut_polyline_points(preview_cut)
                best_curve_dist: float | None = None
                for idx in range(len(points) - 1):
                    dist_value = distance_point_to_segment(
                        (x, y),
                        points[idx],
                        points[idx + 1],
                    )
                    if best_curve_dist is None or dist_value < best_curve_dist:
                        best_curve_dist = float(dist_value)
                if best_curve_dist is not None and best_curve_dist <= 3.0:
                    if best is None or best_curve_dist < best[0]:
                        best = (best_curve_dist, "line", cut.cut_id)
                continue
            d0 = distance((x, y), preview_cut.p0)
            d1 = distance((x, y), preview_cut.p1)
            ds = distance_point_to_segment((x, y), preview_cut.p0, preview_cut.p1)

            candidates = [
                (d0, "p0"),
                (d1, "p1"),
                (ds, "line"),
            ]
            for dist_value, part in candidates:
                threshold = 5.0 if part in {"p0", "p1"} else 3.0
                if dist_value <= threshold:
                    if best is None or dist_value < best[0]:
                        best = (dist_value, part, cut.cut_id)

        if best is None:
            return None
        return best[1], best[2]

    def _on_canvas_press(self, event: Any) -> None:
        if self._main_toolbar_mode_active():
            return
        if event.inaxes is None or event.xdata is None or event.ydata is None:
            return

        if event.inaxes == self.map_ax:
            self._handle_map_press(
                float(event.xdata),
                float(event.ydata),
                int(getattr(event, "button", 1) or 1),
            )
            return

        panel_id = self._panel_for_axis(event.inaxes)
        if panel_id is not None:
            self.active_panel_id = panel_id
            self.selected_cut_id = self.panels[panel_id - 1].cut_id
            self._sync_controls_from_active_panel()
            self.refresh_all()
            if getattr(event, "dblclick", False):
                self._open_td_window(panel_id)

    def _handle_map_press(self, x: float, y: float, button: int = 1) -> None:
        x, y = self._map_display_to_data(x, y)
        x = clamp_value(x, 0.0, self.nx - 1.0)
        y = clamp_value(y, 0.0, self.ny - 1.0)

        if self.function_cut_draw_mode:
            if button == 3:
                if len(self.function_cut_pending_points) >= 2:
                    self._finish_pending_function_cut()
                else:
                    self._cancel_function_cut_draw()
                return
            if button == 1:
                self._append_function_cut_point(x, y)
            return

        if self.curve_cut_draw_mode:
            if button == 3:
                if len(self.curve_cut_pending_points) >= 2:
                    self._finish_pending_curve_cut()
                else:
                    self._cancel_curve_cut_draw()
                return
            if button == 1:
                self._append_curve_cut_point(x, y)
            return

        if self.feature_draw_mode is not None:
            if button == 3:
                if self.feature_draw_mode == "curve" and len(self.feature_pending_points) >= 2:
                    self._finish_pending_feature_axis()
                else:
                    self._cancel_feature_axis_draw()
                return
            if button == 1:
                self._append_feature_axis_point(x, y)
            return

        if button == 3:
            self._cancel_pending_cut()
            return

        if self.pending_point is not None:
            self._finish_pending_cut(x, y)
            return

        hit = None if self.draw_mode else self._find_cut_hit(x, y)
        if hit is None:
            self._begin_pending_cut(x, y)
            return

        part, cut_id = hit
        cut = self.cuts[cut_id]
        if cut.locked:
            self.selected_cut_id = cut_id
            self.refresh_all()
            return

        self.selected_cut_id = cut_id
        self.drag_state = {
            "part": part,
            "cut_id": cut_id,
            "last": (x, y),
            "dirty": False,
        }
        self.refresh_all()

    def _on_canvas_motion(self, event: Any) -> None:
        if self._main_toolbar_mode_active():
            return
        if event.inaxes != self.map_ax or event.xdata is None or event.ydata is None:
            return

        x, y = self._map_display_to_data(float(event.xdata), float(event.ydata))
        x = clamp_value(x, 0.0, self.nx - 1.0)
        y = clamp_value(y, 0.0, self.ny - 1.0)
        if self.function_cut_draw_mode:
            self.function_cut_hover_point = (x, y)
            self.refresh_map()
            return
        if self.curve_cut_draw_mode:
            self.curve_cut_hover_point = (x, y)
            self.refresh_map()
            return
        if self.feature_draw_mode is not None:
            self.feature_hover_point = (x, y)
            self.refresh_map()
            return
        if self.pending_point is not None:
            self.hover_point = (x, y)
            self.refresh_map()
            return

        if self.drag_state is None:
            return

        cut = self.cuts.get(self.drag_state["cut_id"])
        if cut is None:
            self.drag_state = None
            return

        part = self.drag_state["part"]
        if self._cut_is_curve(cut):
            last_x, last_y = self.drag_state["last"]
            dx = x - last_x
            dy = y - last_y
            if not self._shift_curve_cut_geometry(cut, dx, dy):
                return
            self.drag_state["last"] = (x, y)
            self.drag_state["dirty"] = True
            self._invalidate_cut_dependents(cut.cut_id)
            self.refresh_all()
            return
        preview_cut = self._cut_preview(cut.cut_id) or cut
        if part == "p0":
            new_p0, new_p1 = (x, y), preview_cut.p1
        elif part == "p1":
            new_p0, new_p1 = preview_cut.p0, (x, y)
        else:
            last_x, last_y = self.drag_state["last"]
            dx = x - last_x
            dy = y - last_y
            new_p0, new_p1 = shift_cut(preview_cut, dx, dy, self.nx, self.ny)
            self.drag_state["last"] = (x, y)

        if distance(new_p0, new_p1) < 1.0:
            return
        if self._cut_dynamic_enabled(cut.cut_id):
            self._set_cut_dynamic_keyframe(
                cut.cut_id,
                int(self.t_visual_var.get()),
                new_p0,
                new_p1,
                enable_dynamic=True,
            )
        else:
            cut.p0 = new_p0
            cut.p1 = new_p1

        self.drag_state["dirty"] = True
        self._invalidate_cut_dependents(cut.cut_id)
        self.refresh_all()

    def _on_canvas_release(self, _event: Any) -> None:
        if self._main_toolbar_mode_active():
            self.drag_state = None
            return
        if self.drag_state is not None and self.drag_state.get("dirty"):
            cut_id = int(self.drag_state.get("cut_id", -1))
            if cut_id in self.cuts:
                self._record_session_change()
                self._set_status(
                    f"Updated geometry of {self.cuts[cut_id].name} at t={int(self.t_visual_var.get())}."
                )
        self.drag_state = None

    def _main_toolbar_mode_active(self) -> bool:
        toolbar = getattr(self, "main_toolbar", None)
        if toolbar is None:
            return False
        return bool(str(getattr(toolbar, "mode", "") or "").strip())

    def _draw_map(self) -> None:
        frame = self.cube[int(self.t_visual_var.get())]
        if self.map_swap_xy_var.get():
            frame = frame.T
        vmin, vmax = frame_limits(frame)
        active_experiment = self._selected_experiment()
        active_experiment_cut_lookup = self._experiment_cut_lookup(active_experiment)

        ax = self.map_ax
        ax.clear()
        ax.imshow(
            frame,
            origin="lower",
            cmap="gray",
            vmin=vmin,
            vmax=vmax,
            interpolation="nearest",
        )

        for axis in self.feature_axes.values():
            if not axis.visible or len(axis.points) < 2:
                continue
            is_selected = axis.axis_id == self.selected_feature_axis_id
            display_points = [
                self._map_data_to_display(point[0], point[1]) for point in axis.points
            ]
            xs = [point[0] for point in display_points]
            ys = [point[1] for point in display_points]
            ax.plot(
                xs,
                ys,
                color=axis.color,
                linewidth=2.8 if is_selected else 1.6,
                alpha=0.95 if is_selected else 0.75,
                linestyle="-." if axis.mode == "curve" else ":",
            )
            ax.scatter(
                xs,
                ys,
                color=axis.color,
                s=32 if is_selected else 18,
                zorder=3,
                alpha=0.95 if is_selected else 0.8,
            )
            mid_index = len(display_points) // 2
            mid_point = display_points[mid_index]
            ax.text(
                mid_point[0],
                mid_point[1],
                axis.name,
                color=axis.color,
                fontsize=8,
                ha="center",
                va="bottom",
                bbox={"facecolor": "white", "alpha": 0.55, "edgecolor": "none"},
            )

        map_cut_ids, map_cut_note = self._main_map_cut_ids()
        for cut_id in map_cut_ids:
            cut = self.cuts.get(int(cut_id))
            if cut is None or not cut.visible:
                continue
            preview_cut = self._cut_preview(cut.cut_id) or cut
            is_selected = cut.cut_id == self.selected_cut_id
            lw = 3.0 if is_selected else 1.8
            alpha = 1.0 if is_selected else 0.85
            p0_disp = self._map_data_to_display(preview_cut.p0[0], preview_cut.p0[1])
            p1_disp = self._map_data_to_display(preview_cut.p1[0], preview_cut.p1[1])
            if self._cut_is_curve(preview_cut):
                display_points = [
                    self._map_data_to_display(point[0], point[1])
                    for point in cut_polyline_points(preview_cut)
                ]
                ax.plot(
                    [point[0] for point in display_points],
                    [point[1] for point in display_points],
                    color=cut.color,
                    linewidth=lw,
                    alpha=alpha,
                    linestyle="-",
                )
            else:
                ax.plot(
                    [p0_disp[0], p1_disp[0]],
                    [p0_disp[1], p1_disp[1]],
                    color=cut.color,
                    linewidth=lw,
                    alpha=alpha,
                    linestyle="--" if self._cut_dynamic_enabled(cut.cut_id) else "-",
                )
            ax.scatter(
                [p0_disp[0], p1_disp[0]],
                [p0_disp[1], p1_disp[1]],
                color=cut.color,
                s=36 if is_selected else 24,
                zorder=3,
            )
            mid_x = 0.5 * (p0_disp[0] + p1_disp[0])
            mid_y = 0.5 * (p0_disp[1] + p1_disp[1])
            if int(cut.cut_id) not in active_experiment_cut_lookup:
                ax.text(
                    mid_x,
                    mid_y,
                    cut.name + (" [dyn]" if self._cut_dynamic_enabled(cut.cut_id) else ""),
                    color=cut.color,
                    fontsize=8,
                    ha="center",
                    va="bottom",
                    bbox={"facecolor": "white", "alpha": 0.55, "edgecolor": "none"},
                    zorder=6,
                )
            if is_selected and self._cut_is_function_curve(preview_cut):
                function_points = self._function_control_points(preview_cut)
                if function_points:
                    display_function_points = [
                        self._map_data_to_display(point[0], point[1])
                        for point in function_points
                    ]
                    ax.scatter(
                        [point[0] for point in display_function_points],
                        [point[1] for point in display_function_points],
                        facecolors="white",
                        edgecolors=cut.color,
                        s=42,
                        linewidths=1.4,
                        zorder=5,
                    )

        if self.pending_point is not None:
            pending_disp = self._map_data_to_display(
                self.pending_point[0], self.pending_point[1]
            )
            ax.scatter(
                [pending_disp[0]],
                [pending_disp[1]],
                color="yellow",
                s=48,
                marker="x",
                zorder=4,
            )
            if self.hover_point is not None:
                hover_disp = self._map_data_to_display(
                    self.hover_point[0], self.hover_point[1]
                )
                ax.plot(
                    [pending_disp[0], hover_disp[0]],
                    [pending_disp[1], hover_disp[1]],
                    color="yellow",
                    linestyle="--",
                    linewidth=1.5,
                    alpha=0.9,
                )

        if self.function_cut_pending_points:
            function_display_points = [
                self._map_data_to_display(point[0], point[1])
                for point in self.function_cut_pending_points
            ]
            ax.scatter(
                [point[0] for point in function_display_points],
                [point[1] for point in function_display_points],
                color="limegreen",
                s=38,
                zorder=5,
            )
            if len(function_display_points) >= 2:
                ax.plot(
                    [point[0] for point in function_display_points],
                    [point[1] for point in function_display_points],
                    color="limegreen",
                    linewidth=1.4,
                    linestyle="--",
                    alpha=0.9,
                )
            if self.function_cut_hover_point is not None and function_display_points:
                hover_disp = self._map_data_to_display(
                    self.function_cut_hover_point[0],
                    self.function_cut_hover_point[1],
                )
                last_disp = function_display_points[-1]
                ax.plot(
                    [last_disp[0], hover_disp[0]],
                    [last_disp[1], hover_disp[1]],
                    color="limegreen",
                    linewidth=1.1,
                    linestyle=":",
                    alpha=0.9,
                )

        if self.feature_pending_points:
            pending_display_points = [
                self._map_data_to_display(point[0], point[1])
                for point in self.feature_pending_points
            ]
            pending_xs = [point[0] for point in pending_display_points]
            pending_ys = [point[1] for point in pending_display_points]
            ax.plot(
                pending_xs,
                pending_ys,
                color="deepskyblue",
                linewidth=2.0,
                linestyle="--",
                alpha=0.95,
            )
            ax.scatter(
                pending_xs,
                pending_ys,
                color="deepskyblue",
                s=40,
                marker="o",
                zorder=4,
            )
            if self.feature_hover_point is not None:
                hover_disp = self._map_data_to_display(
                    self.feature_hover_point[0], self.feature_hover_point[1]
                )
                last_disp = pending_display_points[-1]
                ax.plot(
                    [last_disp[0], hover_disp[0]],
                    [last_disp[1], hover_disp[1]],
                    color="deepskyblue",
                    linewidth=1.2,
                    linestyle=":",
                    alpha=0.9,
                )

        if self.curve_cut_pending_points:
            curve_display_points = [
                self._map_data_to_display(point[0], point[1])
                for point in self.curve_cut_pending_points
            ]
            ax.plot(
                [point[0] for point in curve_display_points],
                [point[1] for point in curve_display_points],
                color="gold",
                linewidth=2.1,
                linestyle="--",
                alpha=0.95,
            )
            ax.scatter(
                [point[0] for point in curve_display_points],
                [point[1] for point in curve_display_points],
                color="gold",
                s=34,
                zorder=4,
            )
            if self.curve_cut_hover_point is not None:
                hover_disp = self._map_data_to_display(
                    self.curve_cut_hover_point[0],
                    self.curve_cut_hover_point[1],
                )
                last_disp = curve_display_points[-1]
                ax.plot(
                    [last_disp[0], hover_disp[0]],
                    [last_disp[1], hover_disp[1]],
                    color="gold",
                    linewidth=1.1,
                    linestyle=":",
                    alpha=0.9,
                )

        disp_nx, disp_ny = self._map_display_shape()
        if self.map_flip_x_var.get():
            ax.set_xlim(disp_nx - 0.5, -0.5)
        else:
            ax.set_xlim(-0.5, disp_nx - 0.5)

        if self.map_flip_y_var.get():
            ax.set_ylim(disp_ny - 0.5, -0.5)
        else:
            ax.set_ylim(-0.5, disp_ny - 0.5)

        if self.map_swap_xy_var.get():
            ax.set_xlabel("y [pixel]")
            ax.set_ylabel("x [pixel]")
        else:
            ax.set_xlabel("x [pixel]")
            ax.set_ylabel("y [pixel]")
        ax.set_title(f"Map at t={int(self.t_visual_var.get())}{map_cut_note}")

    def _panel_td(self, panel: TDPanel) -> tuple[np.ndarray | None, dict[str, Any] | None]:
        if panel.cut_id is None or panel.cut_id not in self.cuts:
            return None, None

        cut = self.cuts[panel.cut_id]
        params = self._panel_td_params(panel)
        state = self._cut_analysis(cut.cut_id)
        key = cut_cache_key(cut, params) + self._cut_geometry_signature(cut.cut_id)
        if (
            state.get("td_cache_key") == key
            and state.get("td_cache_td") is not None
            and state.get("td_cache_meta") is not None
        ):
            return state["td_cache_td"], state["td_cache_meta"]

        try:
            td, meta = compute_td(
                self.cube,
                cut,
                int(params["t_ini"]),
                int(params["t_fin"]),
                int(params["stride"]),
                int(params["width"]),
                str(params["weighting"]),
                dynamic_geometry=self._dynamic_cut_geometry_samples(
                    cut.cut_id,
                    int(params["t_ini"]),
                    int(params["t_fin"]),
                    int(params["stride"]),
                ),
            )
        except ValueError as exc:
            state["td_cache_key"] = key
            state["td_cache_td"] = None
            state["td_cache_meta"] = {"error": str(exc)}
            panel.cache_key = key
            panel.cache_td = None
            panel.cache_meta = dict(state["td_cache_meta"])
            return None, state["td_cache_meta"]

        state["td_cache_key"] = key
        state["td_cache_td"] = td
        state["td_cache_meta"] = meta
        panel.cache_key = key
        panel.cache_td = td
        panel.cache_meta = meta
        return td, meta

    def _draw_td_axis(
        self,
        ax: Any,
        panel_id: int,
        use_zoom: bool = True,
        title_fontsize: float = 9.0,
        display_mode: str = "raw",
    ) -> None:
        display_mode = "raw"
        current_t = int(self.t_visual_var.get())
        td_aspect = "equal" if self.td_aspect_var.get() == "equal" else "auto"
        td_zoom = float(str(self.td_zoom_var.get()).rstrip("x") or "1")
        panel = self.panels[panel_id - 1]
        cut = self.cuts.get(panel.cut_id) if panel.cut_id is not None else None

        ax.clear()
        td, meta = self._panel_td(panel)
        if cut is None:
            ax.text(
                0.5,
                0.5,
                f"{panel.name}\nno cut assigned",
                ha="center",
                va="center",
                transform=ax.transAxes,
            )
            ax.set_xticks([])
            ax.set_yticks([])
            ax.set_title(panel.name)
        elif td is None or meta is None:
            error_text = "invalid TD"
            if meta is not None and "error" in meta:
                error_text = meta["error"]
            ax.text(
                0.5,
                0.5,
                f"{panel.name}\n{error_text}",
                ha="center",
                va="center",
                transform=ax.transAxes,
            )
            ax.set_xticks([])
            ax.set_yticks([])
            ax.set_title(panel_title(panel, cut))
        else:
            distances = meta["distances"]
            t_indices = meta["t_indices"]
            td_plot = td
            display_note = ""
            visual_fit = display_mode in {"visual spline", "visual spline fit"}
            if visual_fit:
                td_plot = td_visual_spline(td)
                display_note = " | visual spline fit"
            if len(t_indices) == 1:
                t_min = float(t_indices[0])
                t_max = float(t_indices[0]) + 1.0
            else:
                t_min = float(t_indices[0])
                t_max = float(t_indices[-1])

            vmin, vmax = frame_limits(td)
            dist_max = float(distances[-1])
            time_center = (
                float(current_t)
                if panel.t_ini <= current_t <= panel.t_fin
                else 0.5 * (t_min + t_max)
            )
            dist_center = 0.5 * dist_max

            if self.td_swap_axes_var.get():
                plot_x_size = td_plot.shape[0]
                plot_y_size = td_plot.shape[1]
                if visual_fit:
                    image_extent = [0.0, plot_x_size - 1.0, 0.0, plot_y_size - 1.0]
                    line_pos = map_value_to_display(current_t, t_min, t_max, plot_x_size)
                    x_center = map_value_to_display(time_center, t_min, t_max, plot_x_size)
                    y_center = map_value_to_display(dist_center, 0.0, dist_max, plot_y_size)
                else:
                    image_extent = [t_min, t_max, 0.0, dist_max]
                    line_pos = current_t
                    x_center = time_center
                    y_center = dist_center
                ax.imshow(
                    td_plot.T,
                    origin="lower",
                    aspect=td_aspect,
                    cmap="gray",
                    extent=image_extent,
                    vmin=vmin,
                    vmax=vmax,
                    interpolation="nearest",
                )
                if panel.t_ini <= current_t <= panel.t_fin:
                    ax.axvline(
                        line_pos,
                        color=cut.color,
                        linestyle="--",
                        linewidth=1.0,
                    )

                if use_zoom:
                    if visual_fit:
                        x0, x1 = self._zoom_limits(0.0, plot_x_size - 1.0, x_center, td_zoom)
                        y0, y1 = self._zoom_limits(0.0, plot_y_size - 1.0, y_center, td_zoom)
                    else:
                        x0, x1 = self._zoom_limits(t_min, t_max, time_center, td_zoom)
                        y0, y1 = self._zoom_limits(0.0, dist_max, dist_center, td_zoom)
                else:
                    if visual_fit:
                        x0, x1 = 0.0, plot_x_size - 1.0
                        y0, y1 = 0.0, plot_y_size - 1.0
                    else:
                        x0, x1 = t_min, t_max
                        y0, y1 = 0.0, dist_max

                if self.td_flip_x_var.get():
                    ax.set_xlim(x1, x0)
                else:
                    ax.set_xlim(x0, x1)
                if self.td_flip_y_var.get():
                    ax.set_ylim(y1, y0)
                else:
                    ax.set_ylim(y0, y1)
                ax.set_xlabel("time index")
                ax.set_ylabel("distance [pixel]")
                if visual_fit:
                    xticks, xticklabels = display_ticks(t_min, t_max, plot_x_size)
                    yticks, yticklabels = display_ticks(0.0, dist_max, plot_y_size)
                    ax.set_xticks(xticks)
                    ax.set_xticklabels(xticklabels)
                    ax.set_yticks(yticks)
                    ax.set_yticklabels(yticklabels)
            else:
                plot_x_size = td_plot.shape[1]
                plot_y_size = td_plot.shape[0]
                if visual_fit:
                    image_extent = [0.0, plot_x_size - 1.0, 0.0, plot_y_size - 1.0]
                    line_pos = map_value_to_display(current_t, t_min, t_max, plot_y_size)
                    x_center = map_value_to_display(dist_center, 0.0, dist_max, plot_x_size)
                    y_center = map_value_to_display(time_center, t_min, t_max, plot_y_size)
                else:
                    image_extent = [0.0, dist_max, t_min, t_max]
                    line_pos = current_t
                    x_center = dist_center
                    y_center = time_center
                ax.imshow(
                    td_plot,
                    origin="lower",
                    aspect=td_aspect,
                    cmap="gray",
                    extent=image_extent,
                    vmin=vmin,
                    vmax=vmax,
                    interpolation="nearest",
                )
                if panel.t_ini <= current_t <= panel.t_fin:
                    ax.axhline(
                        line_pos,
                        color=cut.color,
                        linestyle="--",
                        linewidth=1.0,
                    )

                if use_zoom:
                    if visual_fit:
                        x0, x1 = self._zoom_limits(0.0, plot_x_size - 1.0, x_center, td_zoom)
                        y0, y1 = self._zoom_limits(0.0, plot_y_size - 1.0, y_center, td_zoom)
                    else:
                        x0, x1 = self._zoom_limits(0.0, dist_max, dist_center, td_zoom)
                        y0, y1 = self._zoom_limits(t_min, t_max, time_center, td_zoom)
                else:
                    if visual_fit:
                        x0, x1 = 0.0, plot_x_size - 1.0
                        y0, y1 = 0.0, plot_y_size - 1.0
                    else:
                        x0, x1 = 0.0, dist_max
                        y0, y1 = t_min, t_max

                if self.td_flip_x_var.get():
                    ax.set_xlim(x1, x0)
                else:
                    ax.set_xlim(x0, x1)
                if self.td_flip_y_var.get():
                    ax.set_ylim(y1, y0)
                else:
                    ax.set_ylim(y0, y1)
                ax.set_xlabel("distance [pixel]")
                ax.set_ylabel("time index")
                if visual_fit:
                    xticks, xticklabels = display_ticks(0.0, dist_max, plot_x_size)
                    yticks, yticklabels = display_ticks(t_min, t_max, plot_y_size)
                    ax.set_xticks(xticks)
                    ax.set_xticklabels(xticklabels)
                    ax.set_yticks(yticks)
                    ax.set_yticklabels(yticklabels)

            ax.set_title(panel_title(panel, cut) + display_note, fontsize=title_fontsize)
            if display_note:
                ax.text(
                    0.99,
                    0.01,
                    "visual only",
                    ha="right",
                    va="bottom",
                    transform=ax.transAxes,
                    fontsize=max(title_fontsize - 2.0, 8.0),
                    color="tab:orange",
                    bbox={"facecolor": "white", "alpha": 0.7, "edgecolor": "none", "pad": 1.5},
                )

        for spine in ax.spines.values():
            spine.set_linewidth(2.5 if panel_id == self.active_panel_id else 1.0)
            if panel_id == self.active_panel_id:
                spine.set_edgecolor("crimson")
            elif cut is not None:
                spine.set_edgecolor(cut.color)
            else:
                spine.set_edgecolor("0.6")

    def _draw_td_panels(self) -> None:
        for panel_id, ax in self.panel_axes.items():
            self._draw_td_axis(ax, panel_id, use_zoom=True)

    def _td_window_panel(self, panel_id: int) -> TDPanel | None:
        if 1 <= panel_id <= len(self.panels):
            return self.panels[panel_id - 1]
        return None

    def _td_window_cut(self, panel_id: int, action: str) -> Cut | None:
        panel = self._td_window_panel(panel_id)
        if panel is None:
            self._set_status("Invalid TD window panel.")
            return None
        cut = self.cuts.get(panel.cut_id) if panel.cut_id is not None else None
        if cut is None:
            self._set_status(f"{panel.name} has no cut assigned.")
            return None
        return self._editable_cut(cut, action)

    def _td_window_tracking_key(self, panel_id: int) -> tuple[Any, ...] | None:
        panel = self._td_window_panel(panel_id)
        if panel is None or panel.cut_id is None or panel.cut_id not in self.cuts:
            return None
        return cut_cache_key(self.cuts[panel.cut_id], panel) + self._cut_geometry_signature(panel.cut_id)

    def _td_window_plot_to_td_coords(
        self, panel_id: int, event: Any
    ) -> tuple[float, float] | None:
        existing = self.td_windows.get(panel_id)
        if (
            existing is None
            or event.inaxes is not existing.get("ax")
            or event.xdata is None
            or event.ydata is None
        ):
            return None
        if self.td_swap_axes_var.get():
            return float(event.xdata), float(event.ydata)
        return float(event.ydata), float(event.xdata)

    def _build_velocity_trace_record(
        self,
        panel_id: int,
        trace_id: int,
        start_t: float,
        start_d: float,
        end_t: float,
        end_d: float,
    ) -> dict[str, Any]:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            raise ValueError("Velocity trace window is not available.")
        cad_s = self._safe_float_text(
            existing["crest_cad_var"].get(), DEFAULT_CREST_TRACKING["cad"]
        )
        res_arcsec_px = self._safe_float_text(
            existing["crest_res_var"].get(), DEFAULT_CREST_TRACKING["res"]
        )
        km_per_arcsec = self._safe_float_text(
            existing["wavelet_km_per_arcsec_var"].get(),
            DEFAULT_WAVELET_FILTER["km_per_arcsec"],
        )
        delta_frames = float(end_t) - float(start_t)
        if abs(delta_frames) <= 1e-6:
            raise ValueError("Velocity traces need a non-zero time span.")
        delta_dist_px = float(end_d) - float(start_d)
        duration_s = abs(delta_frames) * max(float(cad_s), 0.0)
        speed_px_frame = delta_dist_px / delta_frames
        speed_px_s = (
            float("nan") if cad_s <= 0.0 else delta_dist_px / (delta_frames * cad_s)
        )
        speed_arcsec_s = (
            float("nan")
            if not np.isfinite(speed_px_s) or res_arcsec_px <= 0.0
            else speed_px_s * res_arcsec_px
        )
        speed_km_s = (
            float("nan")
            if not np.isfinite(speed_arcsec_s) or km_per_arcsec <= 0.0
            else speed_arcsec_s * km_per_arcsec
        )
        return {
            "trace_id": int(trace_id),
            "label": f"V{int(trace_id):02d}",
            "t0": float(start_t),
            "d0": float(start_d),
            "t1": float(end_t),
            "d1": float(end_d),
            "delta_frames": float(delta_frames),
            "delta_dist_px": float(delta_dist_px),
            "duration_s": float(duration_s),
            "speed_px_frame": float(speed_px_frame),
            "speed_px_s": float(speed_px_s),
            "speed_arcsec_s": float(speed_arcsec_s),
            "speed_km_s": float(speed_km_s),
            "speed_km_s_abs": float(abs(speed_km_s)) if np.isfinite(speed_km_s) else float("nan"),
            "cad_s": float(cad_s),
            "res_arcsec_px": float(res_arcsec_px),
            "km_per_arcsec": float(km_per_arcsec),
        }

    def _refresh_td_window_velocity_trace_table(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        tree = existing.get("velocity_trace_tree")
        summary_var = existing.get("velocity_trace_summary_var")
        if tree is None or summary_var is None:
            return
        children = tree.get_children()
        if children:
            tree.delete(*children)
        traces = [
            dict(item) for item in (existing.get("velocity_traces") or []) if isinstance(item, dict)
        ]
        selected_id = existing.get("velocity_selected_trace_id")
        visible_ids: list[int] = []
        for trace in traces:
            trace_id = int(trace.get("trace_id", -1))
            visible_ids.append(trace_id)
            tree.insert(
                "",
                "end",
                iid=f"velocity-{trace_id}",
                values=(
                    str(trace_id),
                    str(trace.get("label") or f"V{trace_id:02d}"),
                    f"{float(trace.get('t0', float('nan'))):.2f}",
                    f"{float(trace.get('t1', float('nan'))):.2f}",
                    f"{float(trace.get('d0', float('nan'))):.2f}",
                    f"{float(trace.get('d1', float('nan'))):.2f}",
                    f"{float(trace.get('speed_px_frame', float('nan'))):.3f}",
                    f"{float(trace.get('speed_km_s', float('nan'))):.3f}",
                ),
            )
        if selected_id not in visible_ids:
            selected_id = visible_ids[0] if visible_ids else None
            existing["velocity_selected_trace_id"] = selected_id
        if selected_id is not None:
            iid = f"velocity-{int(selected_id)}"
            if iid in tree.get_children():
                tree.selection_set(iid)
                tree.focus(iid)
        draw_mode = bool(existing.get("velocity_trace_draw_mode"))
        pending = existing.get("velocity_trace_pending")
        summary_var.set(
            f"Velocity traces: {len(traces)} | draw mode={'on' if draw_mode else 'off'}"
            + (" | select two TD points" if draw_mode and pending is None else "")
            + (" | choose the second TD point" if draw_mode and pending is not None else "")
        )

    def _toggle_td_window_velocity_trace_mode(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        enabled = not bool(existing.get("velocity_trace_draw_mode", False))
        existing["velocity_trace_draw_mode"] = enabled
        existing["velocity_trace_pending"] = None
        existing["velocity_trace_hover"] = None
        button_var = existing.get("velocity_trace_button_var")
        if button_var is not None:
            button_var.set("Cancel draw" if enabled else "Draw velocity trace")
        self._refresh_td_window_velocity_trace_table(panel_id)
        self._refresh_td_window(panel_id)
        self._set_status(
            (
                f"{panel.name}: click two TD points to define a velocity trace."
                if enabled
                else f"{panel.name}: velocity trace draw mode cancelled."
            )
        )

    def _delete_td_window_selected_velocity_trace(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        selected_id = existing.get("velocity_selected_trace_id")
        if selected_id is None:
            self._set_status(f"Select a velocity trace first in {panel.name}.")
            return
        traces = [
            dict(item)
            for item in (existing.get("velocity_traces") or [])
            if isinstance(item, dict)
        ]
        new_traces = [
            trace for trace in traces if int(trace.get("trace_id", -1)) != int(selected_id)
        ]
        if len(new_traces) == len(traces):
            self._set_status(f"Selected velocity trace is no longer available in {panel.name}.")
            return
        existing["velocity_traces"] = new_traces
        existing["velocity_selected_trace_id"] = (
            int(new_traces[0]["trace_id"]) if new_traces else None
        )
        self._record_session_change()
        self._refresh_td_window_velocity_trace_table(panel_id)
        self._refresh_td_window(panel_id)
        self._set_status(f"Deleted velocity trace {int(selected_id)} from {panel.name}.")

    def _clear_td_window_velocity_traces(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        existing["velocity_traces"] = []
        existing["velocity_selected_trace_id"] = None
        existing["velocity_trace_draw_mode"] = False
        existing["velocity_trace_pending"] = None
        existing["velocity_trace_hover"] = None
        button_var = existing.get("velocity_trace_button_var")
        if button_var is not None:
            button_var.set("Draw velocity trace")
        self._record_session_change()
        self._refresh_td_window_velocity_trace_table(panel_id)
        self._refresh_td_window(panel_id)
        self._set_status(f"Cleared manual velocity traces for {panel.name}.")

    def _on_td_window_velocity_trace_select(self, panel_id: int, _event: Any = None) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        tree = existing.get("velocity_trace_tree")
        if tree is None:
            return
        selection = tree.selection()
        if not selection:
            existing["velocity_selected_trace_id"] = None
        else:
            try:
                existing["velocity_selected_trace_id"] = int(str(selection[0]).split("-", 1)[1])
            except Exception:
                existing["velocity_selected_trace_id"] = None
        self._refresh_td_window(panel_id)

    def _draw_td_window_velocity_traces(self, ax: Any, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        selected_id = existing.get("velocity_selected_trace_id")
        for trace in existing.get("velocity_traces") or []:
            if not isinstance(trace, dict):
                continue
            trace_id = int(trace.get("trace_id", -1))
            color = "gold" if trace_id == selected_id else "deepskyblue"
            linewidth = 2.5 if trace_id == selected_id else 1.8
            alpha = 0.95 if trace_id == selected_id else 0.8
            t0 = float(trace.get("t0", float("nan")))
            t1 = float(trace.get("t1", float("nan")))
            d0 = float(trace.get("d0", float("nan")))
            d1 = float(trace.get("d1", float("nan")))
            if not all(np.isfinite(value) for value in (t0, t1, d0, d1)):
                continue
            if self.td_swap_axes_var.get():
                ax.plot([t0, t1], [d0, d1], color=color, linewidth=linewidth, alpha=alpha)
                ax.text(t1, d1, str(trace.get("label") or f"V{trace_id:02d}"), color=color, fontsize=8)
            else:
                ax.plot([d0, d1], [t0, t1], color=color, linewidth=linewidth, alpha=alpha)
                ax.text(d1, t1, str(trace.get("label") or f"V{trace_id:02d}"), color=color, fontsize=8)

        pending = existing.get("velocity_trace_pending")
        hover = existing.get("velocity_trace_hover")
        if pending is not None and hover is not None:
            start_t, start_d = pending
            end_t, end_d = hover
            if self.td_swap_axes_var.get():
                ax.plot([start_t, end_t], [start_d, end_d], color="yellow", linewidth=1.4, linestyle="--", alpha=0.95)
            else:
                ax.plot([start_d, end_d], [start_t, end_t], color="yellow", linewidth=1.4, linestyle="--", alpha=0.95)

    def _clear_td_window_wavelet_filter(
        self, panel_id: int, stale: bool = False, refresh: bool = False
    ) -> None:
        self._clear_panel_analysis_results(
            panel_id, clear_tracking=False, clear_wavelet=True
        )
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return

        existing["wavelet_filter_result"] = None
        existing["wavelet_events"] = []
        existing["wavelet_next_event_id"] = 1
        existing["wavelet_selected_event_id"] = None
        summary_var = existing.get("wavelet_summary_var")
        physics_var = existing.get("wavelet_physics_var")
        events_summary_var = existing.get("wavelet_events_summary_var")
        selected_var = existing.get("wavelet_selected_var")
        diag_var = existing.get("wavelet_diag_var")
        if summary_var is not None:
            if stale:
                summary_var.set("Wavelet filter cleared because tracking changed.")
            else:
                summary_var.set("No wavelet filter results.")
        if physics_var is not None:
            physics_var.set("")
        if events_summary_var is not None:
            events_summary_var.set("")
        if selected_var is not None:
            selected_var.set("")
        if diag_var is not None:
            diag_var.set("")
        tree = existing.get("wavelet_events_tree")
        if tree is not None:
            existing["wavelet_table_updating"] = True
            try:
                children = tree.get_children()
                if children:
                    tree.delete(*children)
            finally:
                existing["wavelet_table_updating"] = False
        self._refresh_td_window_wavelet_diagnostics(panel_id)
        if not stale:
            self._record_session_change()
        if refresh:
            self._refresh_td_window(panel_id)

    def _clear_td_window_crest_tracking(
        self, panel_id: int, stale: bool = False, refresh: bool = False
    ) -> None:
        self._clear_panel_analysis_results(
            panel_id, clear_tracking=True, clear_wavelet=True
        )
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return

        existing["crest_tracking_result"] = None
        existing["crest_tracking_td_key"] = None
        summary_var = existing.get("crest_summary_var")
        if summary_var is None:
            return
        if stale:
            summary_var.set("Crest tracking cleared because the TD map changed.")
        else:
            summary_var.set("No crest tracking results.")
        self._clear_td_window_wavelet_filter(panel_id, stale=stale, refresh=False)
        if not stale:
            self._record_session_change()
        if refresh:
            self._refresh_td_window(panel_id)

    def _sync_td_window_crest_tracking(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return

        tracking_result = existing.get("crest_tracking_result")
        if tracking_result is None:
            return

        current_key = self._td_window_tracking_key(panel_id)
        if self._normalized_tracking_key(existing.get("crest_tracking_td_key")) != self._normalized_tracking_key(current_key):
            self._clear_td_window_crest_tracking(panel_id, stale=True)

    def _refresh_td_window_crest_summary(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        tracking_result = existing.get("crest_tracking_result")
        summary_var = existing.get("crest_summary_var")
        if summary_var is None:
            return
        if not tracking_result:
            summary_var.set("No crest tracking results.")
            return
        threads = tracking_result.get("threads") or []
        located = tracking_result.get("located") or {}
        located_count = int(np.count_nonzero(np.asarray(located.get("errs", [])) > 0))
        thread_count = len(threads)
        longest = max((int(th.get("length", 0)) for th in threads), default=0)
        summary_var.set(
            f"Located {located_count} crest bins. Threads: {thread_count}. Longest: {longest}."
        )

    def _parse_td_window_crest_tracking_params(
        self, panel_id: int
    ) -> dict[str, Any] | None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return None

        try:
            cad = float(str(existing["crest_cad_var"].get()).strip())
            res = float(str(existing["crest_res_var"].get()).strip())
            grad = float(str(existing["crest_grad_var"].get()).strip())
            min_tlen = int(float(str(existing["crest_min_tlen_var"].get()).strip()))
            max_dist_jump = int(
                float(str(existing["crest_max_dist_jump_var"].get()).strip())
            )
            max_time_skip = int(
                float(str(existing["crest_max_time_skip_var"].get()).strip())
            )
        except Exception:
            self._set_status(f"Invalid crest-tracking parameter for {panel.name}.")
            return None

        if cad <= 0.0 or res <= 0.0 or grad < 0.0:
            self._set_status(f"Crest-tracking cadence, resolution and gradient must be valid for {panel.name}.")
            return None
        if min_tlen < 1 or max_dist_jump < 0 or max_time_skip < 1:
            self._set_status(f"Crest-tracking integer limits are invalid for {panel.name}.")
            return None

        params = {
            "cad": cad,
            "res": res,
            "grad": grad,
            "min_tlen": min_tlen,
            "max_dist_jump": max_dist_jump,
            "max_time_skip": max_time_skip,
            "invert": bool(existing["crest_invert_var"].get()),
            "gauss": bool(existing["crest_gauss_var"].get()),
        }
        self._panel_analysis(panel_id)["crest_params"] = dict(params)
        self._update_td_window_preset_from_values(panel_id)
        return params

    def _run_td_window_crest_tracking(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return

        api, import_error = load_local_nuwt_api()
        if api is None:
            existing["crest_summary_var"].set(f"NUWT unavailable: {import_error}")
            self._set_status(f"NUWT import failed for {panel.name}.")
            return

        params = self._parse_td_window_crest_tracking_params(panel_id)
        if params is None:
            return

        td, meta = self._panel_td(panel)
        if td is None or meta is None:
            existing["crest_summary_var"].set("No valid TD map available for crest tracking.")
            self._set_status(f"{panel.name} has no valid TD map for crest tracking.")
            return

        td_nuwt = np.asarray(td, dtype=np.float64).T
        finite = np.isfinite(td_nuwt)
        if not np.any(finite):
            existing["crest_summary_var"].set("TD map contains no finite values.")
            self._set_status(f"{panel.name} has no finite TD values for crest tracking.")
            return
        fill_value = float(np.nanmin(td_nuwt[finite]))
        if not np.all(finite):
            td_nuwt = np.where(finite, td_nuwt, fill_value)

        tracking_mode = "gauss fit" if params["gauss"] else "nearest pixel"
        self._set_status(
            f"Running crest tracking for {panel.name} ({tracking_mode})..."
        )
        self.root.update_idletasks()

        try:
            located = api["locate_things"](
                td_nuwt,
                invert=params["invert"],
                grad=params["grad"],
                res=params["res"],
                cad=params["cad"],
                nearest_pixel=not params["gauss"],
            )
            threads, _ = api["follow_threads"](
                located,
                min_tlen=params["min_tlen"],
                max_dist_jump=params["max_dist_jump"],
                max_time_skip=params["max_time_skip"],
            )
            threads = api["patch_up_threads"](
                threads, fit_flag=0, simp_fill=False, debug=False
            )
        except Exception as exc:
            existing["crest_tracking_result"] = None
            existing["crest_tracking_td_key"] = None
            existing["crest_summary_var"].set(
                f"Crest tracking failed: {type(exc).__name__}: {exc}"
            )
            self._set_status(f"Crest tracking failed for {panel.name}.")
            self._refresh_td_window(panel_id)
            return

        located_count = int(np.count_nonzero(np.asarray(located["errs"]) > 0))
        thread_count = len(threads)
        longest = max((int(th.get("length", 0)) for th in threads), default=0)

        existing["crest_tracking_result"] = {
            "located": located,
            "threads": threads,
            "params": params,
        }
        existing["crest_tracking_td_key"] = self._td_window_tracking_key(panel_id)
        state = self._panel_analysis(panel_id)
        state["crest_tracking_result"] = self._clone_wavelet_payload(
            existing["crest_tracking_result"]
        )
        state["crest_tracking_td_key"] = self._clone_wavelet_payload(
            existing["crest_tracking_td_key"]
        )
        self._clear_td_window_wavelet_filter(panel_id, stale=True, refresh=False)
        existing["crest_summary_var"].set(
            f"Located {located_count} crest bins. Threads: {thread_count}. Longest: {longest}."
        )
        self._record_session_change()
        self._refresh_td_window(panel_id)
        self._set_status(
            f"Crest tracking completed for {panel.name} ({tracking_mode}): "
            f"{thread_count} thread(s)."
        )

    def _parse_td_window_wavelet_filter_params(
        self, panel_id: int
    ) -> dict[str, Any] | None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return None

        try:
            cad = float(str(existing["crest_cad_var"].get()).strip())
            res = float(str(existing["crest_res_var"].get()).strip())
            p_min = float(str(existing["wavelet_p_min_var"].get()).strip())
            p_max = float(str(existing["wavelet_p_max_var"].get()).strip())
            power_ratio_thresh = float(
                str(existing["wavelet_power_ratio_var"].get()).strip()
            )
            segment_power_frac = float(
                str(existing["wavelet_segment_frac_var"].get()).strip()
            )
            min_points_segment = int(
                float(str(existing["wavelet_min_points_seg_var"].get()).strip())
            )
            min_amp_arcsec = float(
                str(existing["wavelet_min_amp_var"].get()).strip()
            )
            max_jump_pix = float(str(existing["wavelet_max_jump_var"].get()).strip())
            min_points_cut_seg = int(
                float(str(existing["wavelet_min_points_cut_var"].get()).strip())
            )
            rms_amp_ratio_max = float(
                str(existing["wavelet_rms_amp_ratio_var"].get()).strip()
            )
            km_per_arcsec = float(
                str(existing["wavelet_km_per_arcsec_var"].get()).strip()
            )
            density_text = str(existing["wavelet_density_var"].get()).strip()
            phase_speed_text = str(existing["wavelet_phase_speed_var"].get()).strip()
            density_kg_m3 = float(density_text) if density_text else float("nan")
            phase_speed_km_s = (
                float(phase_speed_text) if phase_speed_text else float("nan")
            )
            min_prominence = float(
                str(existing["wavelet_min_prominence_var"].get()).strip()
            )
            min_snr = float(str(existing["wavelet_min_snr_var"].get()).strip())
            continuity_weight = float(
                str(existing["wavelet_continuity_weight_var"].get()).strip()
            )
            time_weight = float(str(existing["wavelet_time_weight_var"].get()).strip())
            quality_weight = float(
                str(existing["wavelet_quality_weight_var"].get()).strip()
            )
            error_weight = float(
                str(existing["wavelet_error_weight_var"].get()).strip()
            )
        except Exception:
            self._set_status(f"Invalid wavelet-filter parameter for {panel.name}.")
            return None

        if cad <= 0.0 or res <= 0.0:
            self._set_status(f"Wavelet cadence and pixel scale must be valid for {panel.name}.")
            return None
        if p_min <= 0.0 or p_max <= p_min:
            self._set_status(f"Wavelet period range is invalid for {panel.name}.")
            return None
        if power_ratio_thresh < 0.0 or not (0.0 < segment_power_frac <= 1.0):
            self._set_status(f"Wavelet power thresholds are invalid for {panel.name}.")
            return None
        if min_points_segment < 3 or min_points_cut_seg < 3 or max_jump_pix < 0.0:
            self._set_status(f"Wavelet point/jump limits are invalid for {panel.name}.")
            return None
        if min_amp_arcsec < 0.0 or rms_amp_ratio_max <= 0.0:
            self._set_status(f"Wavelet amplitude criteria are invalid for {panel.name}.")
            return None
        if km_per_arcsec <= 0.0:
            self._set_status(f"Wavelet km/arcsec conversion is invalid for {panel.name}.")
            return None
        if np.isfinite(density_kg_m3) and density_kg_m3 <= 0.0:
            self._set_status(f"Wavelet density must be positive for {panel.name}.")
            return None
        if np.isfinite(phase_speed_km_s) and phase_speed_km_s <= 0.0:
            self._set_status(f"Wavelet phase speed must be positive for {panel.name}.")
            return None
        if (
            min_prominence < 0.0
            or min_snr < 0.0
            or continuity_weight < 0.0
            or time_weight < 0.0
            or quality_weight < 0.0
            or error_weight < 0.0
        ):
            self._set_status(f"Wavelet tracking thresholds and weights must be non-negative for {panel.name}.")
            return None

        params = {
            "cad": cad,
            "res": res,
            "p_min": p_min,
            "p_max": p_max,
            "power_ratio_thresh": power_ratio_thresh,
            "segment_power_frac": segment_power_frac,
            "min_points_segment": min_points_segment,
            "min_amp_arcsec": min_amp_arcsec,
            "max_jump_pix": max_jump_pix,
            "min_points_cut_seg": min_points_cut_seg,
            "rms_amp_ratio_max": rms_amp_ratio_max,
            "km_per_arcsec": km_per_arcsec,
            "density_kg_m3": density_kg_m3,
            "phase_speed_km_s": phase_speed_km_s,
            "min_prominence": min_prominence,
            "min_snr": min_snr,
            "continuity_weight": continuity_weight,
            "time_weight": time_weight,
            "quality_weight": quality_weight,
            "error_weight": error_weight,
        }
        self._panel_analysis(panel_id)["wavelet_params"] = {
            key: value for key, value in params.items() if key not in {"cad", "res"}
        }
        self._update_td_window_preset_from_values(panel_id)
        return params

    def _set_td_window_selected_event_thread_filter(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if existing is None or panel is None or selected_event is None:
            self._set_status(f"Select a wavelet event first for P{panel_id}.")
            return
        thread_index = self._wavelet_event_thread_index(selected_event)
        if thread_index is None:
            self._set_status(f"The selected event in {panel.name} has no valid thread index.")
            return
        filter_text = self._format_wavelet_thread_filter_text([thread_index])
        existing["wavelet_thread_filter_var"].set(filter_text)
        self._panel_analysis(panel_id)["wavelet_thread_filter_text"] = filter_text
        self._record_session_change()
        self._set_status(f"Set wavelet thread filter to {filter_text} for {panel.name}.")

    def _apply_td_window_selected_event_thread_to_stack(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if existing is None or panel is None or panel.cut_id is None:
            return
        if selected_event is None:
            self._set_status(f"Select a wavelet event first for {panel.name}.")
            return
        stack_id = self._resolve_td_window_target_stack_id(panel_id)
        if stack_id is None or int(stack_id) not in self.stacks:
            self._set_status(
                f"{panel.name} is not tied to a unique stack. Use Stack Browser -> Thread->Stack."
            )
            return
        thread_index = self._wavelet_event_thread_index(selected_event)
        if thread_index is None:
            self._set_status(f"The selected event in {panel.name} has no valid thread index.")
            return
        stack = self.stacks[int(stack_id)]
        cut_ids = [
            int(cut_id)
            for cut_id in (stack.get("cut_ids") or [])
            if int(cut_id) in self.cuts
        ]
        applied_cut_ids, skipped_cut_ids = self._apply_wavelet_thread_filter_to_cuts(
            cut_ids,
            [thread_index],
        )
        filter_text = self._format_wavelet_thread_filter_text([thread_index])
        if not applied_cut_ids and skipped_cut_ids:
            self._set_status(
                f"Thread filter {filter_text} could not be applied in {stack['name']}; "
                "some cuts do not have that tracked thread."
            )
            return
        message = (
            f"Applied wavelet thread filter {filter_text} to {len(applied_cut_ids)} cut(s) in {stack['name']}."
        )
        if skipped_cut_ids:
            message += f" Skipped {len(skipped_cut_ids)} cut(s) without that thread."
        self._set_status(message)

    def _format_wavelet_segment_physics(
        self, segment: dict[str, Any], prefix: str
    ) -> str:
        return (
            f"{prefix} thread {int(segment.get('thread_index', -1)) + 1}, "
            f"seg {int(segment.get('seg_id', -1))}, "
            f"wseg {int(segment.get('wseg_id', -1))} | "
            f"A={float(segment.get('fit_amp_arcsec', float('nan'))):.3f}'' "
            f"({float(segment.get('fit_amp_km', float('nan'))):.1f} km) | "
            f"P={float(segment.get('peak_period_s', float('nan'))):.2f} s | "
            f"f={float(segment.get('freq_mhz', float('nan'))):.2f} mHz | "
            f"v={float(segment.get('velocity_amp_km_s', float('nan'))):.2f} km/s | "
            f"ratio={float(segment.get('power_ratio', float('nan'))):.2f}"
        )

    def _clone_wavelet_payload(self, payload: Any) -> Any:
        if isinstance(payload, np.ndarray):
            return np.asarray(payload, dtype=np.float64).copy()
        if isinstance(payload, dict):
            return {key: self._clone_wavelet_payload(value) for key, value in payload.items()}
        if isinstance(payload, list):
            return [self._clone_wavelet_payload(value) for value in payload]
        if isinstance(payload, tuple):
            return tuple(self._clone_wavelet_payload(value) for value in payload)
        return payload

    def _panel_wavelet_events_snapshot(self, panel_id: int) -> list[dict[str, Any]]:
        existing = self.td_windows.get(panel_id)
        if existing is not None:
            events = existing.get("wavelet_events") or []
        else:
            events = (self._panel_analysis(panel_id).get("wavelet_events") or [])
        out = events if isinstance(events, list) else []
        for event in out:
            self._ensure_wavelet_event_fields(event)
        return out

    def _cut_wavelet_events_snapshot(self, cut_id: int) -> list[dict[str, Any]]:
        state = self.cut_analysis_state.get(cut_id)
        events = [] if state is None else (state.get("wavelet_events") or [])
        out = events if isinstance(events, list) else []
        for event in out:
            self._ensure_wavelet_event_fields(event)
        return out

    def _wavelet_event_ref(
        self, panel_id: int, event_id: int | None
    ) -> dict[str, Any] | None:
        if event_id is None:
            return None
        for event in self._panel_wavelet_events_snapshot(panel_id):
            if int(event.get("event_id", -1)) == int(event_id):
                self._ensure_wavelet_event_fields(event)
                return event
        return None

    def _wavelet_event_ref_by_cut(
        self, cut_id: int, event_id: int | None
    ) -> dict[str, Any] | None:
        if event_id is None:
            return None
        for event in self._cut_wavelet_events_snapshot(cut_id):
            if int(event.get("event_id", -1)) == int(event_id):
                self._ensure_wavelet_event_fields(event)
                return event
        return None

    def _ensure_wavelet_event_fields(self, event: dict[str, Any]) -> None:
        event.setdefault("manual_decision", None)
        event.setdefault("customized", False)
        event.setdefault("split_children_ids", [])
        event.setdefault("review_locked", False)
        event.setdefault("review_notes", "")
        event.setdefault("history", [])
        event.setdefault("link_group_id", None)
        event.setdefault("propagation_class", "")
        event.setdefault("confidence_score", float("nan"))
        event.setdefault("confidence_label", "")
        if event.get("history") is None:
            event["history"] = []
        analysis = event.get("analysis")
        if isinstance(analysis, dict):
            analysis.setdefault("decision_warnings", [])
        source_t_idx = np.asarray(event.get("source_t_idx", []), dtype=np.float64)
        event.setdefault("base_source_fit_mask", np.ones(source_t_idx.shape, dtype=bool))
        event.setdefault(
            "source_fit_mask",
            np.asarray(event.get("base_source_fit_mask"), dtype=bool).copy(),
        )

    def _event_source_overlap_fraction(
        self, source_a: np.ndarray, source_b: np.ndarray
    ) -> float:
        if source_a.size == 0 or source_b.size == 0:
            return 0.0
        overlap = np.intersect1d(
            np.asarray(np.round(source_a), dtype=np.int64),
            np.asarray(np.round(source_b), dtype=np.int64),
        )
        denom = max(min(source_a.size, source_b.size), 1)
        return float(overlap.size / denom)

    def _wavelet_segment_matches_locked_event(
        self, segment: dict[str, Any], event: dict[str, Any]
    ) -> bool:
        if not bool(event.get("review_locked")):
            return False
        analysis_a = segment or {}
        analysis_b = event.get("analysis") or {}
        if (
            int(analysis_a.get("thread_index", -9999))
            != int(analysis_b.get("thread_index", -9999))
        ):
            return False
        source_a = np.asarray(segment.get("source_t_idx", []), dtype=np.float64)
        source_b = np.asarray(event.get("source_t_idx", []), dtype=np.float64)
        return self._event_source_overlap_fraction(source_a, source_b) >= 0.5

    def _append_wavelet_event_history(
        self,
        event: dict[str, Any],
        action: str,
        *,
        note: str = "",
        details: str = "",
    ) -> None:
        self._ensure_wavelet_event_fields(event)
        entry = {
            "timestamp": self._timestamp_now(),
            "action": str(action),
            "note": str(note),
            "details": str(details),
            "status": self._td_window_wavelet_event_status(event),
        }
        event["history"].append(entry)

    def _wavelet_event_confidence_details(
        self, event: dict[str, Any]
    ) -> tuple[float, str]:
        self._ensure_wavelet_event_fields(event)
        analysis = event.get("analysis") or {}
        params = dict(event.get("current_params") or event.get("base_params") or {})
        flags = self._td_window_wavelet_event_qa_flags(event)
        score = 45.0
        power_ratio = float(analysis.get("power_ratio", float("nan")))
        thresh = max(float(params.get("power_ratio_thresh", 1.0)), 1e-6)
        if np.isfinite(power_ratio):
            score += min(max((power_ratio - thresh) / thresh, 0.0), 2.0) * 15.0
        point_count = int(np.asarray(analysis.get("wave_t_idx", []), dtype=np.float64).size)
        target_points = max(int(params.get("min_points_segment", 3)), 3)
        score += min(point_count / target_points, 2.0) * 8.0
        peak_period = float(analysis.get("peak_period_s", float("nan")))
        duration = float(analysis.get("duration_s", float("nan")))
        if np.isfinite(duration) and np.isfinite(peak_period) and peak_period > 0.0:
            score += min(duration / (2.0 * peak_period), 1.5) * 8.0
        residual = float(
            analysis.get(
                "fit_rms_over_amp",
                analysis.get("rms_amp_ratio", float("nan")),
            )
        )
        rms_limit = float(params.get("rms_amp_ratio_max", float("nan")))
        if np.isfinite(residual) and np.isfinite(rms_limit) and rms_limit > 0.0:
            score -= min(residual / rms_limit, 2.0) * 10.0
        if "few_points" in flags:
            score -= 10.0
        if "period_edge" in flags:
            score -= 10.0
        if "high_residual" in flags:
            score -= 18.0
        status = self._td_window_wavelet_event_status(event)
        if status == "manual accepted":
            score += 6.0
        elif status == "manual rejected":
            score -= 20.0
        elif status == "custom accepted":
            score += 3.0
        elif status == "custom rejected":
            score -= 12.0
        if bool(event.get("review_locked")):
            score += 4.0
        score = float(max(0.0, min(100.0, score)))
        if score >= 80.0:
            label = "high"
        elif score >= 55.0:
            label = "medium"
        else:
            label = "low"
        event["confidence_score"] = score
        event["confidence_label"] = label
        return score, label

    def _wavelet_event_confidence_score(self, event: dict[str, Any]) -> float:
        score, _label = self._wavelet_event_confidence_details(event)
        return score

    def _wavelet_segment_confidence_score(
        self, segment: dict[str, Any], params: dict[str, Any] | None = None
    ) -> float:
        analysis = segment or {}
        ranking_params = dict(DEFAULT_WAVELET_FILTER)
        if params:
            ranking_params.update(params)

        score = 45.0
        power_ratio = float(analysis.get("power_ratio", float("nan")))
        thresh = max(float(ranking_params.get("power_ratio_thresh", 1.0)), 1e-6)
        if np.isfinite(power_ratio):
            score += min(max((power_ratio - thresh) / thresh, 0.0), 2.0) * 15.0
        point_count = int(
            analysis.get(
                "fit_point_count",
                np.asarray(analysis.get("wave_t_idx", []), dtype=np.float64).size,
            )
        )
        target_points = max(int(ranking_params.get("min_points_segment", 3)), 3)
        score += min(point_count / target_points, 2.0) * 8.0
        peak_period = float(analysis.get("peak_period_s", float("nan")))
        duration = float(analysis.get("duration_s", float("nan")))
        if np.isfinite(duration) and np.isfinite(peak_period) and peak_period > 0.0:
            score += min(duration / (2.0 * peak_period), 1.5) * 8.0
        residual = float(
            analysis.get(
                "fit_rms_over_amp",
                analysis.get("rms_amp_ratio", float("nan")),
            )
        )
        rms_limit = float(ranking_params.get("rms_amp_ratio_max", float("nan")))
        if np.isfinite(residual):
            if np.isfinite(rms_limit) and rms_limit > 0.0:
                score -= min(residual / rms_limit, 2.0) * 20.0
            else:
                score -= min(residual, 2.0) * 16.0
        if not bool(analysis.get("accepted")):
            score -= 15.0

        warnings = {
            str(item).strip()
            for item in (analysis.get("decision_warnings") or [])
            if str(item).strip()
        }
        if "low power ratio" in warnings:
            score -= 6.0
        if "borderline power ratio" in warnings:
            score -= 4.0
        if "high fit residual" in warnings:
            score -= 18.0
        if "segment fit failed" in warnings:
            score -= 20.0
        if "fit check unavailable" in warnings:
            score -= 6.0

        return float(max(0.0, min(100.0, score)))

    def _wavelet_event_link_refs(
        self, event: dict[str, Any]
    ) -> list[dict[str, Any]]:
        self._ensure_wavelet_event_fields(event)
        group_id = event.get("link_group_id")
        if not group_id:
            return []
        refs: list[dict[str, Any]] = []
        for panel in self.panels:
            panel_events = self._panel_wavelet_events_snapshot(panel.panel_id)
            cut = self.cuts.get(panel.cut_id) if panel.cut_id is not None else None
            for candidate in panel_events:
                self._ensure_wavelet_event_fields(candidate)
                if candidate.get("link_group_id") != group_id:
                    continue
                refs.append(
                    {
                        "panel_id": panel.panel_id,
                        "panel_name": panel.name,
                        "cut_name": "" if cut is None else cut.name,
                        "event_id": int(candidate.get("event_id", -1)),
                    }
                )
        refs.sort(key=lambda item: (item["panel_id"], item["event_id"]))
        return refs

    def _wavelet_event_link_count(self, event: dict[str, Any]) -> int:
        refs = self._wavelet_event_link_refs(event)
        if not refs:
            return 0
        return max(len(refs) - 1, 0)

    def _wavelet_edit_state_snapshot(self, panel_id: int) -> dict[str, Any]:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            state = self._panel_analysis(panel_id)
            return {
                "events": self._clone_wavelet_payload(state.get("wavelet_events") or []),
                "selected_event_id": state.get("wavelet_selected_event_id"),
                "next_event_id": int(state.get("wavelet_next_event_id", 1)),
            }
        return {
            "events": self._clone_wavelet_payload(existing.get("wavelet_events") or []),
            "selected_event_id": existing.get("wavelet_selected_event_id"),
            "next_event_id": int(existing.get("wavelet_next_event_id", 1)),
        }

    def _push_wavelet_undo_state(self, panel_id: int, label: str) -> None:
        snapshot = self._wavelet_edit_state_snapshot(panel_id)
        snapshot["label"] = str(label)
        state = self._panel_analysis(panel_id)
        undo_stack = state.setdefault("wavelet_undo_stack", [])
        undo_stack.append(self._clone_wavelet_payload(snapshot))
        if len(undo_stack) > MAX_WAVELET_HISTORY:
            del undo_stack[: len(undo_stack) - MAX_WAVELET_HISTORY]
        state["wavelet_redo_stack"] = []
        existing = self.td_windows.get(panel_id)
        if existing is not None:
            existing["wavelet_undo_stack"] = self._clone_wavelet_payload(undo_stack)
            existing["wavelet_redo_stack"] = []

    def _restore_wavelet_edit_state(
        self, panel_id: int, snapshot: dict[str, Any], *, clear_target_stack: bool = False
    ) -> None:
        state = self._panel_analysis(panel_id)
        state["wavelet_events"] = self._clone_wavelet_payload(snapshot.get("events") or [])
        state["wavelet_selected_event_id"] = snapshot.get("selected_event_id")
        state["wavelet_next_event_id"] = int(snapshot.get("next_event_id", 1))
        existing = self.td_windows.get(panel_id)
        if existing is not None:
            existing["wavelet_events"] = self._clone_wavelet_payload(state["wavelet_events"])
            existing["wavelet_selected_event_id"] = state["wavelet_selected_event_id"]
            existing["wavelet_next_event_id"] = state["wavelet_next_event_id"]
            if clear_target_stack:
                existing["wavelet_redo_stack"] = self._clone_wavelet_payload(
                    state.get("wavelet_redo_stack") or []
                )
            self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)

    def _undo_td_window_wavelet_edit(self, panel_id: int) -> None:
        state = self._panel_analysis(panel_id)
        undo_stack = state.setdefault("wavelet_undo_stack", [])
        if not undo_stack:
            self._set_status(f"No wavelet edits to undo for P{panel_id}.")
            return
        redo_stack = state.setdefault("wavelet_redo_stack", [])
        redo_stack.append(self._wavelet_edit_state_snapshot(panel_id))
        snapshot = undo_stack.pop()
        self._restore_wavelet_edit_state(panel_id, snapshot, clear_target_stack=True)
        existing = self.td_windows.get(panel_id)
        if existing is not None:
            existing["wavelet_undo_stack"] = self._clone_wavelet_payload(undo_stack)
            existing["wavelet_redo_stack"] = self._clone_wavelet_payload(redo_stack)
        self._record_session_change()
        self._set_status(f"Undid wavelet edit for P{panel_id}.")

    def _redo_td_window_wavelet_edit(self, panel_id: int) -> None:
        state = self._panel_analysis(panel_id)
        redo_stack = state.setdefault("wavelet_redo_stack", [])
        if not redo_stack:
            self._set_status(f"No wavelet edits to redo for P{panel_id}.")
            return
        undo_stack = state.setdefault("wavelet_undo_stack", [])
        undo_stack.append(self._wavelet_edit_state_snapshot(panel_id))
        snapshot = redo_stack.pop()
        self._restore_wavelet_edit_state(panel_id, snapshot, clear_target_stack=True)
        existing = self.td_windows.get(panel_id)
        if existing is not None:
            existing["wavelet_undo_stack"] = self._clone_wavelet_payload(undo_stack)
            existing["wavelet_redo_stack"] = self._clone_wavelet_payload(redo_stack)
        self._record_session_change()
        self._set_status(f"Redid wavelet edit for P{panel_id}.")

    def _best_wavelet_segment(
        self, segments: list[dict[str, Any]], params: dict[str, Any] | None = None
    ) -> dict[str, Any] | None:
        if not segments:
            return None
        accepted = [segment for segment in segments if segment.get("accepted")]
        pool = accepted or segments
        best = max(
            pool,
            key=lambda segment: (
                self._wavelet_segment_confidence_score(segment, params),
                float(segment.get("duration_s", float("-inf"))),
                float(segment.get("fit_amp_arcsec", float("-inf"))),
                float(segment.get("power_ratio", float("-inf"))),
                -float(segment.get("mode_rank", float("inf"))),
            ),
        )
        return best

    def _keep_best_wavelet_segment_per_source(
        self,
        segments: list[dict[str, Any]],
        params: dict[str, Any] | None = None,
    ) -> tuple[list[dict[str, Any]], int]:
        indexed_segments = [
            (idx, self._clone_wavelet_payload(segment))
            for idx, segment in enumerate(segments or [])
        ]
        grouped: dict[tuple[int, int], list[tuple[int, dict[str, Any]]]] = {}
        for idx, segment in indexed_segments:
            key = (
                int(segment.get("thread_index", -1)),
                int(segment.get("seg_id", -1)),
            )
            grouped.setdefault(key, []).append((idx, segment))

        kept_indices: set[int] = set()
        removed_count = 0
        for group_segments in grouped.values():
            if len(group_segments) == 1:
                kept_indices.add(group_segments[0][0])
                continue
            best_segment = self._best_wavelet_segment(
                [item[1] for item in group_segments],
                params=params,
            )
            best_idx = group_segments[0][0]
            if best_segment is not None:
                for idx, segment in group_segments:
                    if (
                        int(segment.get("thread_index", -999))
                        == int(best_segment.get("thread_index", -1))
                        and int(segment.get("seg_id", -999))
                        == int(best_segment.get("seg_id", -1))
                        and int(segment.get("wseg_id", -999))
                        == int(best_segment.get("wseg_id", -1))
                        and int(segment.get("mode_rank", -999))
                        == int(best_segment.get("mode_rank", -1))
                    ):
                        best_idx = idx
                        break
            kept_indices.add(best_idx)
            removed_count += len(group_segments) - 1

        kept_segments = [
            segment for idx, segment in indexed_segments if idx in kept_indices
        ]
        return kept_segments, removed_count

    def _compact_wavelet_segment_row(
        self, segment: dict[str, Any] | None
    ) -> dict[str, Any]:
        analysis = dict(segment or {})
        return {
            "thread_index": int(analysis.get("thread_index", -1)),
            "seg_id": int(analysis.get("seg_id", -1)),
            "wseg_id": int(analysis.get("wseg_id", -1)),
            "accepted": bool(analysis.get("accepted")),
            "has_segment": bool(analysis.get("has_segment")),
            "decision_reason": str(analysis.get("decision_reason", "") or ""),
            "decision_warnings": list(analysis.get("decision_warnings") or []),
            "peak_period_s": float(analysis.get("peak_period_s", float("nan"))),
            "freq_mhz": float(analysis.get("freq_mhz", float("nan"))),
            "fit_amp_arcsec": float(analysis.get("fit_amp_arcsec", float("nan"))),
            "fit_amp_km": float(analysis.get("fit_amp_km", float("nan"))),
            "velocity_amp_km_s": float(
                analysis.get("velocity_amp_km_s", float("nan"))
            ),
            "specific_energy_j_kg": float(
                analysis.get("specific_energy_j_kg", float("nan"))
            ),
            "energy_flux_w_m2": float(
                analysis.get("energy_flux_w_m2", float("nan"))
            ),
            "duration_s": float(analysis.get("duration_s", float("nan"))),
            "power_ratio": float(analysis.get("power_ratio", float("nan"))),
            "fit_rms_over_amp": float(
                analysis.get(
                    "fit_rms_over_amp",
                    analysis.get("rms_amp_ratio", float("nan")),
                )
            ),
            "fit_point_count": int(analysis.get("fit_point_count", 0) or 0),
            "interp_point_count": int(
                analysis.get("interp_point_count", 0) or 0
            ),
        }

    def _lightweight_wavelet_filter_result(
        self,
        *,
        segments: list[dict[str, Any]],
        params: dict[str, Any],
        best_segment: dict[str, Any] | None,
        preserved_locked_event_ids: list[int],
        warnings: list[str],
    ) -> dict[str, Any]:
        best_ref = None
        if best_segment is not None:
            best_ref = {
                "thread_index": int(best_segment.get("thread_index", -1)),
                "seg_id": int(best_segment.get("seg_id", -1)),
                "wseg_id": int(best_segment.get("wseg_id", -1)),
                "accepted": bool(best_segment.get("accepted")),
                "power_ratio": float(best_segment.get("power_ratio", float("nan"))),
                "duration_s": float(best_segment.get("duration_s", float("nan"))),
                "fit_amp_arcsec": float(best_segment.get("fit_amp_arcsec", float("nan"))),
            }
        return {
            "segment_count": int(len(segments)),
            "accepted_count": int(sum(1 for segment in segments if segment.get("accepted"))),
            "with_segment_count": int(sum(1 for segment in segments if segment.get("has_segment"))),
            "params": dict(params),
            "best_segment": best_ref,
            "warnings": [str(item) for item in warnings if str(item)],
            "preserved_locked_event_ids": [
                int(event_id) for event_id in preserved_locked_event_ids
            ],
            "segments": [
                self._compact_wavelet_segment_row(segment) for segment in segments
            ],
        }

    def _replacement_wavelet_run_payload(
        self,
        segments: list[dict[str, Any]],
        params: dict[str, Any],
        *,
        warnings: list[str] | None = None,
    ) -> dict[str, Any]:
        warning_messages = [str(item) for item in (warnings or []) if str(item)]
        filtered_segments, removed_count = self._keep_best_wavelet_segment_per_source(
            segments or [],
            params=params,
        )
        if removed_count > 0:
            warning_messages.append(
                f"kept only best fit per source segment: removed {int(removed_count)}"
            )
        next_event_id = 1
        events: list[dict[str, Any]] = []
        for segment in filtered_segments:
            events.append(self._make_td_window_wavelet_event(next_event_id, segment, params))
            next_event_id += 1
        best_segment = self._best_wavelet_segment(filtered_segments, params=params)
        best_event_id = None
        if best_segment is not None:
            for event in events:
                analysis = event.get("analysis") or {}
                if (
                    int(analysis.get("thread_index", -999)) == int(best_segment.get("thread_index", -1))
                    and int(analysis.get("seg_id", -999)) == int(best_segment.get("seg_id", -1))
                    and int(analysis.get("wseg_id", -999)) == int(best_segment.get("wseg_id", -1))
                ):
                    best_event_id = int(event["event_id"])
                    break
        return {
            "filtered_segments": filtered_segments,
            "events": events,
            "next_event_id": next_event_id,
            "best_segment": best_segment,
            "best_event_id": best_event_id,
            "accepted_count": int(
                sum(1 for segment in filtered_segments if segment.get("accepted"))
            ),
            "with_segment_count": int(
                sum(1 for segment in filtered_segments if segment.get("has_segment"))
            ),
            "result": self._lightweight_wavelet_filter_result(
                segments=filtered_segments,
                params=params,
                best_segment=best_segment,
                preserved_locked_event_ids=[],
                warnings=warning_messages,
            ),
            "warnings": warning_messages,
        }

    def _make_td_window_wavelet_event(
        self,
        event_id: int,
        segment: dict[str, Any],
        params: dict[str, Any],
        *,
        origin: str = "auto",
        parent_event_id: int | None = None,
    ) -> dict[str, Any]:
        base_segment = self._clone_wavelet_payload(segment)
        base_source_t_idx = np.asarray(
            segment.get("source_t_idx", segment.get("wave_t_idx", [])),
            dtype=np.float64,
        ).copy()
        base_source_y_idx = np.asarray(
            segment.get("source_y_idx", segment.get("wave_y_idx", [])),
            dtype=np.float64,
        ).copy()
        base_source_fit_mask = np.asarray(
            segment.get(
                "source_fit_mask",
                np.ones(base_source_t_idx.shape, dtype=bool),
            ),
            dtype=bool,
        ).copy()
        event = {
            "event_id": int(event_id),
            "parent_event_id": parent_event_id,
            "origin": origin,
            "manual_decision": None,
            "customized": False,
            "split_children_ids": [],
            "base_source_t_idx": base_source_t_idx,
            "base_source_y_idx": base_source_y_idx,
            "base_source_fit_mask": base_source_fit_mask,
            "source_t_idx": base_source_t_idx.copy(),
            "source_y_idx": base_source_y_idx.copy(),
            "source_fit_mask": base_source_fit_mask.copy(),
            "base_analysis": base_segment,
            "analysis": self._clone_wavelet_payload(base_segment),
            "base_params": dict(params),
            "current_params": dict(params),
            "diagnostic": None,
            "review_locked": False,
            "review_notes": "",
            "history": [],
            "link_group_id": None,
        }
        self._append_wavelet_event_history(
            event,
            "created",
            details=f"origin={origin}",
        )
        self._wavelet_event_confidence_details(event)
        return event

    def _td_window_wavelet_events(self, panel_id: int) -> list[dict[str, Any]]:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return []
        events = existing.get("wavelet_events")
        if not isinstance(events, list):
            return []
        for event in events:
            self._ensure_wavelet_event_fields(event)
            self._wavelet_event_confidence_details(event)
        return events

    def _td_window_wavelet_event_by_id(
        self, panel_id: int, event_id: int | None
    ) -> dict[str, Any] | None:
        if event_id is None:
            return None
        for event in self._td_window_wavelet_events(panel_id):
            if int(event.get("event_id", -1)) == int(event_id):
                return event
        return None

    def _td_window_wavelet_selected_event(
        self, panel_id: int
    ) -> dict[str, Any] | None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return None
        return self._td_window_wavelet_event_by_id(
            panel_id, existing.get("wavelet_selected_event_id")
        )

    def _selected_td_window_wavelet_event_editable(
        self, panel_id: int, action: str
    ) -> dict[str, Any] | None:
        panel = self._td_window_panel(panel_id)
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if panel is None:
            return None
        if selected_event is None:
            self._set_status(f"Select a wavelet event first for {panel.name}.")
            return None
        self._ensure_wavelet_event_fields(selected_event)
        if bool(selected_event.get("review_locked")):
            self._set_status(
                f"Unlock the selected wavelet event before trying to {action} in {panel.name}."
            )
            return None
        return selected_event

    def _toggle_td_window_selected_wavelet_lock(self, panel_id: int) -> None:
        panel = self._td_window_panel(panel_id)
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if panel is None or selected_event is None:
            self._set_status(f"Select a wavelet event first for P{panel_id}.")
            return
        self._push_wavelet_undo_state(panel_id, "toggle lock")
        self._ensure_wavelet_event_fields(selected_event)
        selected_event["review_locked"] = not bool(selected_event.get("review_locked"))
        self._append_wavelet_event_history(
            selected_event,
            "lock" if selected_event["review_locked"] else "unlock",
            details=f"panel={panel.name}",
        )
        self._wavelet_event_confidence_details(selected_event)
        self._record_session_change()
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)
        self._set_status(
            f"{'Locked' if selected_event['review_locked'] else 'Unlocked'} selected wavelet event in {panel.name}."
        )

    def _edit_td_window_selected_wavelet_note(self, panel_id: int) -> None:
        panel = self._td_window_panel(panel_id)
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if panel is None or selected_event is None:
            self._set_status(f"Select a wavelet event first for P{panel_id}.")
            return
        self._ensure_wavelet_event_fields(selected_event)
        current_note = str(selected_event.get("review_notes", ""))
        note = self.simpledialog.askstring(
            "Event Note",
            f"Reviewer note for {panel.name} event {int(selected_event.get('event_id', -1))}:",
            initialvalue=current_note,
            parent=self.td_windows.get(panel_id, {}).get("top"),
        )
        if note is None:
            return
        self._push_wavelet_undo_state(panel_id, "edit note")
        selected_event["review_notes"] = str(note)
        self._append_wavelet_event_history(
            selected_event,
            "note",
            note=str(note),
        )
        self._record_session_change()
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)
        self._set_status(f"Updated reviewer note for {panel.name}.")

    def _show_td_window_selected_wavelet_history(self, panel_id: int) -> None:
        panel = self._td_window_panel(panel_id)
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if panel is None or selected_event is None:
            self._set_status(f"Select a wavelet event first for P{panel_id}.")
            return
        self._ensure_wavelet_event_fields(selected_event)
        top = self.tk.Toplevel(self.td_windows.get(panel_id, {}).get("top", self.root))
        top.title(
            f"History - {panel.name} event {int(selected_event.get('event_id', -1))}"
        )
        top.geometry("760x420")
        top.rowconfigure(0, weight=1)
        top.columnconfigure(0, weight=1)
        text = self.tk.Text(top, wrap="word")
        text.grid(row=0, column=0, sticky="nsew")
        scroll = self.ttk.Scrollbar(top, orient="vertical", command=text.yview)
        scroll.grid(row=0, column=1, sticky="ns")
        text.configure(yscrollcommand=scroll.set)
        lines = [
            f"Event {int(selected_event.get('event_id', -1))} | panel {panel.name}",
            f"Status: {self._td_window_wavelet_event_status(selected_event)}",
            f"Link group: {selected_event.get('link_group_id') or '-'}",
            f"Locked: {bool(selected_event.get('review_locked'))}",
            f"Note: {selected_event.get('review_notes') or '-'}",
            "",
        ]
        history_entries = selected_event.get("history") or []
        if not history_entries:
            lines.append("No history entries.")
        else:
            for item in history_entries:
                lines.append(
                    f"{item.get('timestamp', '')} | {item.get('action', '')} | "
                    f"{item.get('status', '')} | {item.get('details', '')}"
                )
                if item.get("note"):
                    lines.append(f"note: {item.get('note')}")
                lines.append("")
        text.insert("1.0", "\n".join(lines))
        text.configure(state="disabled")

    def _copy_td_window_selected_wavelet_link_source(self, panel_id: int) -> None:
        panel = self._td_window_panel(panel_id)
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if panel is None or selected_event is None:
            self._set_status(f"Select a wavelet event first for P{panel_id}.")
            return
        self.link_source_event_ref = {
            "panel_id": panel_id,
            "event_id": int(selected_event.get("event_id", -1)),
        }
        self._set_status(
            f"Copied link source from {panel.name} event {int(selected_event.get('event_id', -1))}."
        )

    def _link_td_window_selected_wavelet_to_source(self, panel_id: int) -> None:
        panel = self._td_window_panel(panel_id)
        selected_event = self._selected_td_window_wavelet_event_editable(panel_id, "link")
        if panel is None or selected_event is None:
            return
        if self.link_source_event_ref is None:
            self._set_status("Copy a link source event first.")
            return
        src_panel_id = int(self.link_source_event_ref.get("panel_id", -1))
        src_event_id = int(self.link_source_event_ref.get("event_id", -1))
        if src_panel_id == panel_id and src_event_id == int(selected_event.get("event_id", -1)):
            self._set_status("Select a different target event to link.")
            return
        source_event = self._td_window_wavelet_event_by_id(src_panel_id, src_event_id)
        if source_event is None:
            source_events = self._panel_wavelet_events_snapshot(src_panel_id)
            source_event = next(
                (evt for evt in source_events if int(evt.get("event_id", -1)) == src_event_id),
                None,
            )
        if source_event is None:
            self._set_status("The copied link source no longer exists.")
            return
        self._ensure_wavelet_event_fields(source_event)
        self._push_wavelet_undo_state(panel_id, "link event")
        if src_panel_id != panel_id:
            src_state = self._panel_analysis(src_panel_id)
            src_undo = src_state.setdefault("wavelet_undo_stack", [])
            src_undo.append(self._clone_wavelet_payload(self._wavelet_edit_state_snapshot(src_panel_id)))
            if len(src_undo) > MAX_WAVELET_HISTORY:
                del src_undo[: len(src_undo) - MAX_WAVELET_HISTORY]
            src_state["wavelet_redo_stack"] = []
            existing_src = self.td_windows.get(src_panel_id)
            if existing_src is not None:
                existing_src["wavelet_undo_stack"] = self._clone_wavelet_payload(src_undo)
                existing_src["wavelet_redo_stack"] = []
        group_id = source_event.get("link_group_id") or selected_event.get("link_group_id")
        if not group_id:
            group_id = self._next_link_group_label()
        source_event["link_group_id"] = group_id
        selected_event["link_group_id"] = group_id
        self._append_wavelet_event_history(
            source_event,
            "link",
            details=f"group={group_id} target=P{panel_id}:{int(selected_event.get('event_id', -1))}",
        )
        self._append_wavelet_event_history(
            selected_event,
            "link",
            details=f"group={group_id} source=P{src_panel_id}:{src_event_id}",
        )
        self._record_session_change()
        self._refresh_all_open_td_window_wavelet_views(redraw_td=True)
        self._set_status(
            f"Linked {panel.name} event {int(selected_event.get('event_id', -1))} to group {group_id}."
        )

    def _clear_td_window_selected_wavelet_link(self, panel_id: int) -> None:
        panel = self._td_window_panel(panel_id)
        selected_event = self._selected_td_window_wavelet_event_editable(panel_id, "clear link")
        if panel is None or selected_event is None:
            return
        self._ensure_wavelet_event_fields(selected_event)
        if not selected_event.get("link_group_id"):
            self._set_status(f"Selected event in {panel.name} is not linked.")
            return
        self._push_wavelet_undo_state(panel_id, "clear link")
        group_id = str(selected_event.get("link_group_id"))
        selected_event["link_group_id"] = None
        self._append_wavelet_event_history(
            selected_event,
            "unlink",
            details=f"group={group_id}",
        )
        self._record_session_change()
        self._refresh_all_open_td_window_wavelet_views(redraw_td=True)
        self._set_status(f"Cleared link group {group_id} from selected event in {panel.name}.")

    def _show_td_window_selected_wavelet_links(self, panel_id: int) -> None:
        panel = self._td_window_panel(panel_id)
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if panel is None or selected_event is None:
            self._set_status(f"Select a wavelet event first for P{panel_id}.")
            return
        self._ensure_wavelet_event_fields(selected_event)
        group_id = str(selected_event.get("link_group_id") or "").strip() or None
        self._open_link_groups_window(
            initial_group_id=group_id,
            initial_member_ref=(
                int(panel.cut_id) if panel.cut_id is not None else int(panel_id),
                int(selected_event.get("event_id", -1)),
            ),
        )
        if group_id is None:
            self._set_status(
                f"Opened link group viewer. {panel.name} event {int(selected_event.get('event_id', -1))} is not linked yet."
            )

    def _sync_linked_wavelet_group_from_cut_event(
        self, cut_id: int, event_id: int
    ) -> None:
        source_event = self._wavelet_event_ref_by_cut(cut_id, event_id)
        cut = self.cuts.get(cut_id)
        if cut is None or source_event is None:
            self._set_status("The selected linked event source is no longer available.")
            return
        group_id = str(source_event.get("link_group_id") or "").strip()
        if not group_id:
            self._set_status(
                f"{cut.name} event {int(source_event.get('event_id', -1))} is not linked."
            )
            return

        group_members: list[tuple[int, dict[str, Any]]] = []
        for current_cut_id in sorted(self.cuts.keys()):
            for event in self._cut_wavelet_events_snapshot(current_cut_id):
                self._ensure_wavelet_event_fields(event)
                if str(event.get("link_group_id") or "") == group_id:
                    group_members.append((int(current_cut_id), event))
        if len(group_members) < 2:
            self._set_status(f"Link group {group_id} only has one event.")
            return

        affected_cut_ids = sorted({int(item[0]) for item in group_members})
        for affected_cut_id in affected_cut_ids:
            self._push_wavelet_undo_state_for_cut(
                affected_cut_id, f"sync linked group {group_id}"
            )

        source_manual_decision = source_event.get("manual_decision")
        source_locked = bool(source_event.get("review_locked"))
        source_note = str(source_event.get("review_notes", ""))
        source_status = self._td_window_wavelet_event_status(source_event)
        updated_count = 0
        for target_cut_id, target_event in group_members:
            if target_cut_id == cut_id and int(target_event.get("event_id", -1)) == int(event_id):
                continue
            target_event["manual_decision"] = source_manual_decision
            target_event["review_locked"] = source_locked
            target_event["review_notes"] = source_note
            self._append_wavelet_event_history(
                target_event,
                "sync-in",
                note=source_note,
                details=(
                    f"group={group_id} source=cut{cut_id}:{event_id} "
                    f"status={source_status}"
                ),
            )
            self._wavelet_event_confidence_details(target_event)
            updated_count += 1

        self._append_wavelet_event_history(
            source_event,
            "sync-out",
            note=source_note,
            details=f"group={group_id} targets={updated_count}",
        )
        self._wavelet_event_confidence_details(source_event)
        self._record_session_change()
        for affected_cut_id in affected_cut_ids:
            self._sync_open_td_windows_from_cut(affected_cut_id)
        self._set_status(
            f"Synced {cut.name} event {event_id} to {updated_count} linked event(s) in {group_id}."
        )

    def _sync_linked_wavelet_group_from_event(self, panel_id: int, event_id: int) -> None:
        panel = self._td_window_panel(panel_id)
        if panel is not None and panel.cut_id is not None and panel.cut_id in self.cuts:
            self._sync_linked_wavelet_group_from_cut_event(int(panel.cut_id), event_id)
            return
        source_event = self._wavelet_event_ref(panel_id, event_id)
        if panel is None or source_event is None:
            self._set_status("The selected linked event source is no longer available.")
            return
        group_id = str(source_event.get("link_group_id") or "").strip()
        if not group_id:
            self._set_status(
                f"{panel.name} event {int(source_event.get('event_id', -1))} is not linked."
            )
            return

        group_members: list[tuple[int, dict[str, Any]]] = []
        for candidate_panel in self.panels:
            for event in self._panel_wavelet_events_snapshot(candidate_panel.panel_id):
                self._ensure_wavelet_event_fields(event)
                if str(event.get("link_group_id") or "") == group_id:
                    group_members.append((candidate_panel.panel_id, event))
        if len(group_members) < 2:
            self._set_status(f"Link group {group_id} only has one event.")
            return

        for affected_panel_id in sorted({int(item[0]) for item in group_members}):
            self._push_wavelet_undo_state(
                affected_panel_id, f"sync linked group {group_id}"
            )

        source_manual_decision = source_event.get("manual_decision")
        source_locked = bool(source_event.get("review_locked"))
        source_note = str(source_event.get("review_notes", ""))
        source_status = self._td_window_wavelet_event_status(source_event)
        updated_count = 0
        for target_panel_id, target_event in group_members:
            if target_panel_id == panel_id and int(target_event.get("event_id", -1)) == int(event_id):
                continue
            target_event["manual_decision"] = source_manual_decision
            target_event["review_locked"] = source_locked
            target_event["review_notes"] = source_note
            self._append_wavelet_event_history(
                target_event,
                "sync-in",
                note=source_note,
                details=(
                    f"group={group_id} source=P{panel_id}:{event_id} "
                    f"status={source_status}"
                ),
            )
            self._wavelet_event_confidence_details(target_event)
            updated_count += 1

        self._append_wavelet_event_history(
            source_event,
            "sync-out",
            note=source_note,
            details=f"group={group_id} targets={updated_count}",
        )
        self._wavelet_event_confidence_details(source_event)
        self._record_session_change()
        self._refresh_all_open_td_window_wavelet_views(redraw_td=True)
        self._refresh_link_groups_window()
        self._set_status(
            f"Synced {panel.name} event {event_id} to {updated_count} linked event(s) in {group_id}."
        )

    def _sync_td_window_selected_wavelet_group(self, panel_id: int) -> None:
        panel = self._td_window_panel(panel_id)
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if panel is None or selected_event is None:
            self._set_status(f"Select a wavelet event first for P{panel_id}.")
            return
        self._sync_linked_wavelet_group_from_event(
            panel_id, int(selected_event.get("event_id", -1))
        )

    def _td_window_wavelet_event_status(self, event: dict[str, Any]) -> str:
        if event.get("split_children_ids"):
            return "split parent"
        manual_decision = event.get("manual_decision")
        if manual_decision == "accepted":
            return "manual accepted"
        if manual_decision == "rejected":
            return "manual rejected"
        analysis = event.get("analysis") or {}
        if event.get("customized"):
            return "custom accepted" if analysis.get("accepted") else "custom rejected"
        return "auto accepted" if analysis.get("accepted") else "auto rejected"

    def _td_window_wavelet_event_is_counted(self, event: dict[str, Any]) -> bool:
        return self._td_window_wavelet_event_status(event) in {
            "auto accepted",
            "custom accepted",
            "manual accepted",
        }

    def _set_readonly_text(self, widget: Any, text: str) -> None:
        if widget is None:
            return
        try:
            widget.configure(state="normal")
            widget.delete("1.0", "end")
            widget.insert("1.0", str(text))
            widget.configure(state="disabled")
        except Exception:
            return

    def _td_window_wavelet_event_reason(self, event: dict[str, Any]) -> str:
        status = self._td_window_wavelet_event_status(event)
        if status == "manual accepted":
            return "accepted manually"
        if status == "manual rejected":
            return "rejected manually"
        if status == "split parent":
            return "replaced by split children"
        analysis = event.get("analysis") or {}
        base_reason = str(analysis.get("decision_reason", "") or "")
        warnings = [
            str(item)
            for item in (analysis.get("decision_warnings") or [])
            if str(item).strip()
        ]
        if warnings and base_reason:
            return f"{base_reason} ({', '.join(warnings)})"
        if warnings:
            return ", ".join(warnings)
        return base_reason

    def _td_window_wavelet_advanced_filter_values(
        self, panel_id: int
    ) -> dict[str, Any]:
        defaults = self._default_wavelet_advanced_filters()
        return {
            "qa": str(defaults["qa"]),
            "locked": str(defaults["locked"]),
            "linked": str(defaults["linked"]),
            "score_min": self._safe_float_text(defaults["score_min"], float("nan")),
            "period_min": self._safe_float_text(defaults["period_min"], float("nan")),
            "period_max": self._safe_float_text(defaults["period_max"], float("nan")),
            "amp_min": self._safe_float_text(defaults["amp_min"], float("nan")),
            "amp_max": self._safe_float_text(defaults["amp_max"], float("nan")),
            "energy_min": self._safe_float_text(defaults["energy_min"], float("nan")),
            "energy_max": self._safe_float_text(defaults["energy_max"], float("nan")),
        }

    def _td_window_wavelet_advanced_filter_match(
        self, event: dict[str, Any], filters: dict[str, Any]
    ) -> bool:
        self._ensure_wavelet_event_fields(event)
        analysis = event.get("analysis") or {}
        flags = self._td_window_wavelet_event_qa_flags(event)
        qa_filter = str(filters.get("qa", "all"))
        if qa_filter == "flagged" and not flags:
            return False
        if qa_filter == "clean" and flags:
            return False
        if qa_filter in {"few_points", "period_edge", "high_residual"} and qa_filter not in flags:
            return False
        locked_filter = str(filters.get("locked", "all"))
        if locked_filter == "locked" and not bool(event.get("review_locked")):
            return False
        if locked_filter == "unlocked" and bool(event.get("review_locked")):
            return False
        linked_filter = str(filters.get("linked", "all"))
        link_count = self._wavelet_event_link_count(event)
        if linked_filter == "linked" and link_count <= 0:
            return False
        if linked_filter == "unlinked" and link_count > 0:
            return False
        confidence_score = self._wavelet_event_confidence_score(event)
        if np.isfinite(float(filters.get("score_min", float("nan")))):
            if confidence_score < float(filters["score_min"]):
                return False
        value_map = {
            "period_min": float(analysis.get("peak_period_s", float("nan"))),
            "period_max": float(analysis.get("peak_period_s", float("nan"))),
            "amp_min": float(analysis.get("fit_amp_arcsec", float("nan"))),
            "amp_max": float(analysis.get("fit_amp_arcsec", float("nan"))),
            "energy_min": float(analysis.get("specific_energy_j_kg", float("nan"))),
            "energy_max": float(analysis.get("specific_energy_j_kg", float("nan"))),
        }
        if np.isfinite(float(filters.get("period_min", float("nan")))) and (
            not np.isfinite(value_map["period_min"]) or value_map["period_min"] < float(filters["period_min"])
        ):
            return False
        if np.isfinite(float(filters.get("period_max", float("nan")))) and (
            not np.isfinite(value_map["period_max"]) or value_map["period_max"] > float(filters["period_max"])
        ):
            return False
        if np.isfinite(float(filters.get("amp_min", float("nan")))) and (
            not np.isfinite(value_map["amp_min"]) or value_map["amp_min"] < float(filters["amp_min"])
        ):
            return False
        if np.isfinite(float(filters.get("amp_max", float("nan")))) and (
            not np.isfinite(value_map["amp_max"]) or value_map["amp_max"] > float(filters["amp_max"])
        ):
            return False
        if np.isfinite(float(filters.get("energy_min", float("nan")))) and (
            not np.isfinite(value_map["energy_min"]) or value_map["energy_min"] < float(filters["energy_min"])
        ):
            return False
        if np.isfinite(float(filters.get("energy_max", float("nan")))) and (
            not np.isfinite(value_map["energy_max"]) or value_map["energy_max"] > float(filters["energy_max"])
        ):
            return False
        return True

    def _td_window_wavelet_event_filter_match(
        self, event: dict[str, Any], filter_name: str, filters: dict[str, Any]
    ) -> bool:
        status = self._td_window_wavelet_event_status(event)
        if filter_name == "all":
            base_match = True
        elif filter_name == "accepted":
            base_match = self._td_window_wavelet_event_is_counted(event)
        elif filter_name == "rejected":
            base_match = (not self._td_window_wavelet_event_is_counted(event)) and (
                status != "split parent"
            )
        elif filter_name == "manual":
            base_match = status.startswith("manual") or status.startswith("custom")
        elif filter_name == "split":
            base_match = status == "split parent"
        else:
            base_match = True
        if not base_match:
            return False
        return self._td_window_wavelet_advanced_filter_match(event, filters)

    def _td_window_wavelet_event_row(
        self, event: dict[str, Any]
    ) -> tuple[str, ...]:
        self._ensure_wavelet_event_fields(event)
        analysis = event.get("analysis") or {}
        confidence_score = self._wavelet_event_confidence_score(event)
        fit_point_count = int(analysis.get("fit_point_count", 0))
        interp_point_count = int(analysis.get("interp_point_count", 0))
        return (
            str(int(event.get("event_id", -1))),
            self._td_window_wavelet_event_status(event),
            str(event.get("origin", "")),
            str(int(analysis.get("thread_index", -1)) + 1),
            str(int(analysis.get("seg_id", -1))),
            str(int(analysis.get("wseg_id", -1))),
            str(int(analysis.get("mode_rank", -1)) + 1),
            f"{float(analysis.get('peak_period_s', float('nan'))):.2f}",
            f"{float(analysis.get('freq_mhz', float('nan'))):.2f}",
            f"{float(analysis.get('fit_amp_arcsec', float('nan'))):.3f}",
            f"{float(analysis.get('fit_amp_km', float('nan'))):.1f}",
            f"{float(analysis.get('velocity_amp_km_s', float('nan'))):.2f}",
            f"{float(analysis.get('accel_amp_km_s2', float('nan'))):.3f}",
            f"{float(analysis.get('specific_energy_j_kg', float('nan'))):.3e}",
            f"{float(analysis.get('duration_s', float('nan'))):.2f}",
            f"{float(analysis.get('power_ratio', float('nan'))):.2f}",
            f"{confidence_score:.1f}",
            f"{fit_point_count}/{interp_point_count}",
            "yes" if bool(event.get("review_locked")) else "no",
            str(self._wavelet_event_link_count(event)),
            ",".join(self._td_window_wavelet_event_qa_flags(event)),
            self._td_window_wavelet_event_reason(event),
        )

    def _td_window_wavelet_table_tag(self, event: dict[str, Any]) -> str:
        return self._td_window_wavelet_event_status(event).replace(" ", "_")

    def _td_window_visible_wavelet_event_ids(self, panel_id: int) -> list[int]:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return []
        filter_name = str(existing["wavelet_events_filter_var"].get() or "all")
        advanced_filters = self._td_window_wavelet_advanced_filter_values(panel_id)
        visible_ids: list[int] = []
        for event in self._td_window_wavelet_events(panel_id):
            if not self._td_window_wavelet_event_filter_match(
                event, filter_name, advanced_filters
            ):
                continue
            visible_ids.append(int(event.get("event_id", -1)))
        return visible_ids

    def _analyze_td_window_wavelet_event_source(
        self,
        panel_id: int,
        source_t_idx: np.ndarray,
        source_y_idx: np.ndarray,
        source_fit_mask: np.ndarray | None,
        params: dict[str, Any],
    ) -> dict[str, Any] | None:
        panel = self._td_window_panel(panel_id)
        if panel is None:
            return None
        api, import_error = load_local_wavelet_filter_api()
        if api is None:
            self._set_status(f"Wavelet filter import failed for {panel.name}: {import_error}")
            return None
        try:
            analysis = api["analyze_tracked_segment_with_wavelet"](
                source_t_idx,
                source_y_idx,
                cadence=params["cad"],
                pix_scale=params["res"],
                km_per_arcsec=params["km_per_arcsec"],
                p_min=params["p_min"],
                p_max=params["p_max"],
                power_ratio_thresh=params["power_ratio_thresh"],
                segment_power_frac=params["segment_power_frac"],
                min_points_segment=params["min_points_segment"],
                min_amp_arcsec=params["min_amp_arcsec"],
                rms_amp_ratio_max=params["rms_amp_ratio_max"],
                density_kg_m3=params["density_kg_m3"],
                phase_speed_km_s=params["phase_speed_km_s"],
                fit_mask=source_fit_mask,
            )
        except Exception as exc:
            self._set_status(
                f"Wavelet analysis failed for {panel.name}: {type(exc).__name__}: {exc}"
            )
            return None
        selected = self._best_wavelet_segment(
            analysis.get("candidates", []),
            params=params,
        )
        if selected is None:
            return None
        return {
            "selected": selected,
            "diag": self._clone_wavelet_payload(analysis.get("diag", {})),
            "candidates": self._clone_wavelet_payload(analysis.get("candidates", [])),
            "t_seg_s": self._clone_wavelet_payload(analysis.get("t_seg_s", np.array([], dtype=np.float64))),
            "y_arcsec": self._clone_wavelet_payload(analysis.get("y_arcsec", np.array([], dtype=np.float64))),
            "source_t_idx": np.asarray(source_t_idx, dtype=np.float64).copy(),
            "source_y_idx": np.asarray(source_y_idx, dtype=np.float64).copy(),
            "source_fit_mask": np.asarray(
                analysis.get(
                    "source_fit_mask",
                    source_fit_mask
                    if source_fit_mask is not None
                    else np.ones(np.asarray(source_t_idx).shape, dtype=bool),
                ),
                dtype=bool,
            ).copy(),
            "params": dict(params),
        }

    def _set_td_window_wavelet_event_analysis(
        self, event: dict[str, Any], diagnostic: dict[str, Any], *, customized: bool
    ) -> None:
        self._ensure_wavelet_event_fields(event)
        selected = self._clone_wavelet_payload(diagnostic["selected"])
        current_analysis = event.get("analysis") or event.get("base_analysis") or {}
        for key in ("thread_index", "seg_id"):
            if key not in selected:
                selected[key] = current_analysis.get(key, -1)
        event["analysis"] = selected
        event["diagnostic"] = self._clone_wavelet_payload(diagnostic)
        if "source_fit_mask" in diagnostic:
            event["source_fit_mask"] = np.asarray(
                diagnostic.get("source_fit_mask", []), dtype=bool
            ).copy()
        event["current_params"] = dict(diagnostic["params"])
        event["customized"] = bool(customized)
        self._wavelet_event_confidence_details(event)

    def _refresh_td_window_wavelet_table(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        tree = existing.get("wavelet_events_tree")
        if tree is None:
            return
        filter_name = str(existing["wavelet_events_filter_var"].get() or "all")
        advanced_filters = self._td_window_wavelet_advanced_filter_values(panel_id)
        selected_event_id = existing.get("wavelet_selected_event_id")
        existing["wavelet_table_updating"] = True
        try:
            children = tree.get_children()
            if children:
                tree.delete(*children)

            visible_ids: list[int] = []
            for event in self._td_window_wavelet_events(panel_id):
                if not self._td_window_wavelet_event_filter_match(
                    event, filter_name, advanced_filters
                ):
                    continue
                iid = f"evt-{int(event['event_id'])}"
                visible_ids.append(int(event["event_id"]))
                tree.insert(
                    "",
                    "end",
                    iid=iid,
                    values=self._td_window_wavelet_event_row(event),
                    tags=(self._td_window_wavelet_table_tag(event),),
                )

            target_iid: str | None = None
            if selected_event_id in visible_ids:
                target_iid = f"evt-{int(selected_event_id)}"
            elif visible_ids:
                existing["wavelet_selected_event_id"] = visible_ids[0]
                target_iid = f"evt-{visible_ids[0]}"
            else:
                existing["wavelet_selected_event_id"] = None

            if target_iid is not None:
                current_selection = tree.selection()
                if current_selection != (target_iid,):
                    tree.selection_set(target_iid)
                tree.focus(target_iid)
            else:
                tree.selection_remove(tree.selection())
        finally:
            existing["wavelet_table_updating"] = False

        self._refresh_td_window_wavelet_popup_table(panel_id)

        events = self._td_window_wavelet_events(panel_id)
        counted = sum(1 for event in events if self._td_window_wavelet_event_is_counted(event))
        rejected = sum(
            1
            for event in events
            if (not self._td_window_wavelet_event_is_counted(event))
            and self._td_window_wavelet_event_status(event) != "split parent"
        )
        manual = sum(
            1
            for event in events
            if self._td_window_wavelet_event_status(event).startswith("manual")
            or self._td_window_wavelet_event_status(event).startswith("custom")
        )
        split_parents = sum(
            1 for event in events if self._td_window_wavelet_event_status(event) == "split parent"
        )
        visible_count = len(tree.get_children())
        existing["wavelet_events_summary_var"].set(
            f"Events: {len(events)} | visible: {visible_count} | counted: {counted} | "
            f"rejected: {rejected} | manual/custom: {manual} | split parents: {split_parents}"
        )

    def _refresh_td_window_wavelet_diagnostics(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return

        def _update_detail_widgets() -> None:
            selected_text = str(existing["wavelet_selected_var"].get() or "").strip()
            diag_text = str(existing["wavelet_diag_var"].get() or "").strip()
            detail_text = "\n\n".join(
                item for item in (selected_text, diag_text) if item
            ).strip()
            if not detail_text:
                detail_text = "Select a wavelet event to inspect it."
            self._set_readonly_text(existing.get("wavelet_detail_text"), detail_text)
            self._set_readonly_text(existing.get("wavelet_table_detail_text"), detail_text)

        selected_event = self._td_window_wavelet_selected_event(panel_id)
        diag_canvas = existing.get("diag_canvas")
        diag_fig = existing.get("diag_figure")
        diag_axes = existing.get("diag_axes")
        plotting_enabled = (
            diag_fig is not None and diag_canvas is not None and diag_axes is not None
        )

        if plotting_enabled:
            for axis in diag_axes:
                axis.clear()

        if selected_event is None:
            existing["wavelet_selected_var"].set("Select a wavelet event to inspect it.")
            existing["wavelet_diag_var"].set("")
            _update_detail_widgets()
            if not plotting_enabled:
                return
            diag_axes[0].text(0.5, 0.5, "Select an event in the table.", ha="center", va="center", transform=diag_axes[0].transAxes)
            for axis in diag_axes[1:]:
                axis.axis("off")
            diag_canvas.draw_idle()
            return

        diagnostic = selected_event.get("diagnostic")
        if diagnostic is None:
            diagnostic = self._analyze_td_window_wavelet_event_source(
                panel_id,
                np.asarray(selected_event.get("source_t_idx", []), dtype=np.float64),
                np.asarray(selected_event.get("source_y_idx", []), dtype=np.float64),
                np.asarray(selected_event.get("source_fit_mask", []), dtype=bool),
                dict(selected_event.get("current_params") or selected_event.get("base_params") or {}),
            )
            if diagnostic is not None:
                selected_event["diagnostic"] = self._clone_wavelet_payload(diagnostic)
        if diagnostic is None:
            existing["wavelet_selected_var"].set("Could not build diagnostics for the selected event.")
            existing["wavelet_diag_var"].set("")
            _update_detail_widgets()
            if not plotting_enabled:
                return
            diag_axes[0].text(0.5, 0.5, "Diagnostics unavailable.", ha="center", va="center", transform=diag_axes[0].transAxes)
            for axis in diag_axes[1:]:
                axis.axis("off")
            diag_canvas.draw_idle()
            return

        analysis = selected_event.get("analysis") or {}
        confidence_score, confidence_label = self._wavelet_event_confidence_details(
            selected_event
        )
        link_refs = self._wavelet_event_link_refs(selected_event)
        linked_targets = [
            f"{item['panel_name']}:{item['event_id']}"
            for item in link_refs
            if not (
                int(item.get("panel_id", -1)) == int(panel_id)
                and int(item.get("event_id", -1))
                == int(selected_event.get("event_id", -1))
            )
        ]
        note_text = str(selected_event.get("review_notes") or "").strip()
        diag = diagnostic.get("diag") or {}
        selected_mode_rank = int(analysis.get("mode_rank", 0))
        mode_diag = next(
            (
                item
                for item in (diag.get("modes") or [])
                if int(item.get("mode_rank", -1)) == selected_mode_rank
            ),
            None,
        )
        t_seg = np.asarray(diagnostic.get("t_seg_s", []), dtype=np.float64)
        y_arc = np.asarray(diagnostic.get("y_arcsec", []), dtype=np.float64)
        trend = np.asarray(diag.get("trend", []), dtype=np.float64)
        y_detr = np.asarray(diag.get("y_detr", []), dtype=np.float64)
        wave_t = np.asarray(analysis.get("wave_t_s", []), dtype=np.float64)
        wave_y_arc = np.asarray(analysis.get("wave_y_arcsec", []), dtype=np.float64)
        wave_y_detr = np.asarray(analysis.get("wave_y_detr_arcsec", []), dtype=np.float64)
        wave_model = np.asarray(analysis.get("wave_model_arcsec", []), dtype=np.float64)
        model_detr = np.asarray(analysis.get("wave_model_detr_arcsec", []), dtype=np.float64)
        if model_detr.size == 0 and wave_model.size == wave_y_arc.size == wave_y_detr.size and wave_model.size > 0:
            model_detr = wave_model - (wave_y_arc - wave_y_detr)

        existing["wavelet_selected_var"].set(
            self._format_wavelet_segment_physics(
                analysis,
                f"Event {int(selected_event.get('event_id', -1))} [{self._td_window_wavelet_event_status(selected_event)}]:",
            )
            + f" | conf={confidence_score:.1f}/100 ({confidence_label})"
            + f" | lock={'yes' if bool(selected_event.get('review_locked')) else 'no'}"
            + f" | links={max(len(link_refs) - 1, 0)}"
            + (f" | linked_to={','.join(linked_targets[:4])}" if linked_targets else "")
            + (f" | note={note_text}" if note_text else "")
        )
        existing["wavelet_diag_var"].set(
            f"Reason: {self._td_window_wavelet_event_reason(selected_event)} | "
            f"QA: {','.join(self._td_window_wavelet_event_qa_flags(selected_event)) or '-'} | "
            f"Aspan={float(analysis.get('span_amp_arcsec', float('nan'))):.3f}'' | "
            f"E/m={float(analysis.get('specific_energy_j_kg', float('nan'))):.3e} J/kg | "
            f"a={float(analysis.get('accel_amp_km_s2', float('nan'))):.3f} km/s^2 | "
            f"rho={selected_event.get('current_params', {}).get('density_kg_m3', float('nan')):.3e} kg/m^3 | "
            f"F={float(analysis.get('energy_flux_w_m2', float('nan'))):.3e} W/m^2 | "
            "diag: drag-left=trim, right-click=split"
        )
        _update_detail_widgets()
        if not plotting_enabled:
            return

        raw_ax, detr_ax, scal_ax, spec_ax = diag_axes
        if t_seg.size and y_arc.size == t_seg.size:
            raw_ax.plot(t_seg, y_arc, color="0.3", linewidth=1.3, label="signal")
        if trend.size == t_seg.size and trend.size > 0:
            raw_ax.plot(t_seg, trend, color="tab:orange", linewidth=1.1, label="trend")
        if wave_t.size:
            raw_ax.axvspan(float(wave_t[0]), float(wave_t[-1]), color="tab:green", alpha=0.15)

        interaction = existing.get("diag_interaction")
        if interaction and interaction.get("mode") == "trim":
            left = min(
                float(interaction.get("start", 0.0)),
                float(interaction.get("current", interaction.get("start", 0.0))),
            )
            right = max(
                float(interaction.get("start", 0.0)),
                float(interaction.get("current", interaction.get("start", 0.0))),
            )
            raw_ax.axvspan(left, right, color="gold", alpha=0.18)
        raw_ax.set_title("Signal + Trend", fontsize=9)
        raw_ax.set_xlabel("time [s]")
        raw_ax.set_ylabel("disp. [arcsec]")
        raw_ax.legend(loc="best", fontsize=8)

        if t_seg.size and y_detr.size == t_seg.size:
            detr_ax.plot(t_seg, y_detr, color="0.4", linewidth=1.1, label="detrended")
        if wave_t.size and wave_y_detr.size == wave_t.size:
            detr_ax.plot(wave_t, wave_y_detr, color="tab:blue", linewidth=1.5, label="selected")
        if wave_t.size and model_detr.size == wave_t.size:
            detr_ax.plot(wave_t, model_detr, color="tab:red", linewidth=1.2, label="oscillation fit")
        if interaction and interaction.get("mode") == "trim":
            detr_ax.axvspan(left, right, color="gold", alpha=0.18)

        split_markers: list[float] = []
        split_text = str(existing["wavelet_split_frames_var"].get()).strip()
        if split_text:
            try:
                split_markers = sorted(
                    {
                        float(token.strip())
                        for token in split_text.split(",")
                        if token.strip()
                    }
                )
            except Exception:
                split_markers = []
        for split_marker in split_markers:
            raw_ax.axvline(split_marker, color="tab:purple", linestyle=":", linewidth=1.0)
            detr_ax.axvline(split_marker, color="tab:purple", linestyle=":", linewidth=1.0)
        detr_ax.set_title("Detrended Segment", fontsize=9)
        detr_ax.set_xlabel("time [s]")
        detr_ax.set_ylabel("disp. [arcsec]")
        detr_ax.legend(loc="best", fontsize=8)

        periods = np.asarray(diag.get("periods", []), dtype=np.float64)
        power = np.asarray(diag.get("power", []), dtype=np.float64)
        power_t = np.asarray(diag.get("power_t", t_seg), dtype=np.float64)
        ridge_periods = np.asarray(
            (mode_diag or {}).get("ridge_periods", diag.get("ridge_periods", [])),
            dtype=np.float64,
        )
        coi_boundary_period = np.asarray(
            (mode_diag or {}).get(
                "coi_boundary_period", diag.get("coi_boundary_period", [])
            ),
            dtype=np.float64,
        )
        diag_peak_period = float(
            (mode_diag or {}).get("peak_period", diag.get("peak_period", float("nan")))
        )
        if (
            power.ndim == 2
            and periods.size == power.shape[0]
            and power_t.size == power.shape[1]
            and power_t.size > 0
        ):
            scal_ax.imshow(
                power,
                aspect="auto",
                origin="lower",
                extent=[
                    float(power_t[0]),
                    float(power_t[-1]),
                    float(periods[0]),
                    float(periods[-1]),
                ],
                cmap="viridis",
            )
            if np.isfinite(diag_peak_period):
                scal_ax.axhline(diag_peak_period, color="w", linestyle="--", linewidth=1.0)
            if ridge_periods.size == power_t.size:
                scal_ax.plot(power_t, ridge_periods, color="white", linewidth=1.0, alpha=0.9)
            if coi_boundary_period.size == power_t.size:
                scal_ax.plot(
                    power_t,
                    coi_boundary_period,
                    color="tab:orange",
                    linewidth=1.0,
                    linestyle=":",
                    alpha=0.9,
                )
            if wave_t.size:
                scal_ax.axvspan(float(wave_t[0]), float(wave_t[-1]), color="tab:red", alpha=0.12)
        else:
            scal_ax.text(0.5, 0.5, "No scalogram available.", ha="center", va="center", transform=scal_ax.transAxes)
        scal_ax.set_title("Wavelet Power", fontsize=9)
        scal_ax.set_xlabel("time [s]")
        scal_ax.set_ylabel("period [s]")

        global_ws = np.asarray(diag.get("global_ws", []), dtype=np.float64)
        if periods.size and global_ws.size == periods.size:
            spec_ax.plot(periods, global_ws, color="tab:purple", linewidth=1.2)
            if np.isfinite(diag_peak_period):
                spec_ax.axvline(diag_peak_period, color="tab:red", linestyle="--", linewidth=1.0)
        else:
            spec_ax.text(0.5, 0.5, "No global spectrum.", ha="center", va="center", transform=spec_ax.transAxes)
        spec_ax.set_title("Global Spectrum", fontsize=9)
        spec_ax.set_xlabel("period [s]")
        spec_ax.set_ylabel("power")

        diag_fig.tight_layout()
        diag_canvas.draw_idle()

    def _refresh_td_window_wavelet_views(
        self, panel_id: int, *, redraw_td: bool = True
    ) -> None:
        _trace_stack_wavelet(
            f"refresh_td_window_wavelet_views start panel={panel_id} redraw_td={bool(redraw_td)}"
        )
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        self._refresh_td_window_wavelet_table(panel_id)
        events = self._td_window_wavelet_events(panel_id)
        _job_id, running_job = self._background_wavelet_job_for_panel(panel_id)
        if running_job is not None:
            existing["wavelet_summary_var"].set(
                str(running_job.get("message", "Running wavelet filter in background..."))
            )
        elif events:
            accepted_count = sum(1 for event in events if (event.get("analysis") or {}).get("accepted"))
            with_segment_count = sum(
                1 for event in events if (event.get("analysis") or {}).get("has_segment")
            )
            existing["wavelet_summary_var"].set(
                f"Wavelet accepted {accepted_count}/{len(events)} segment(s). "
                f"Selected by wavelet: {with_segment_count}."
            )
        elif existing.get("wavelet_filter_result"):
            existing["wavelet_summary_var"].set("Wavelet filter produced no events.")
        else:
            existing["wavelet_summary_var"].set("No wavelet filter results.")
        counted_events = [
            event for event in events if self._td_window_wavelet_event_is_counted(event)
        ]
        if counted_events:
            best_event = max(
                counted_events,
                key=lambda event: (
                    self._wavelet_event_confidence_score(event),
                    float((event.get("analysis") or {}).get("duration_s", float("-inf"))),
                    float((event.get("analysis") or {}).get("fit_amp_arcsec", float("-inf"))),
                ),
            )
            existing["wavelet_physics_var"].set(
                self._format_wavelet_segment_physics(
                    best_event.get("analysis") or {},
                    f"Best counted [{self._td_window_wavelet_event_status(best_event)}]:",
                )
            )
        else:
            params = (
                dict(events[0].get("current_params") or events[0].get("base_params") or {})
                if events
                else None
            )
            best_segment = self._best_wavelet_segment(
                [event.get("analysis") or {} for event in events],
                params=params,
            )
            existing["wavelet_physics_var"].set(
                self._format_wavelet_segment_physics(best_segment, "Best candidate:")
                if best_segment
                else ""
            )
        self._refresh_td_window_wavelet_diagnostics(panel_id)
        if redraw_td:
            _trace_stack_wavelet(f"refresh_td_window_wavelet_views before_refresh_td_window panel={panel_id}")
            self._refresh_td_window(panel_id)
        _trace_stack_wavelet(f"refresh_td_window_wavelet_views end panel={panel_id}")

    def _on_td_window_wavelet_filter_mode_change(self, panel_id: int) -> None:
        self._sync_panel_analysis_state_from_window(panel_id)
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=False)

    def _on_td_window_wavelet_event_select(self, panel_id: int, _event: Any = None) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        if existing.get("wavelet_table_updating"):
            return
        tree = existing.get("wavelet_events_tree")
        if tree is None:
            return
        previous_event_id = existing.get("wavelet_selected_event_id")
        selection = tree.selection()
        if not selection:
            existing["wavelet_selected_event_id"] = None
        else:
            iid = str(selection[0])
            if iid.startswith("evt-"):
                try:
                    existing["wavelet_selected_event_id"] = int(iid.split("-", 1)[1])
                except Exception:
                    existing["wavelet_selected_event_id"] = None
        if existing.get("wavelet_selected_event_id") == previous_event_id:
            return
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)

    def _recompute_td_window_selected_wavelet_event(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        selected_event = self._selected_td_window_wavelet_event_editable(
            panel_id, "recompute"
        )
        if selected_event is None:
            return
        if selected_event.get("split_children_ids"):
            self._set_status(f"Reset the split parent before recomputing it in {panel.name}.")
            return
        params = self._parse_td_window_wavelet_filter_params(panel_id)
        if params is None:
            return
        diagnostic = self._analyze_td_window_wavelet_event_source(
            panel_id,
            np.asarray(selected_event.get("source_t_idx", []), dtype=np.float64),
            np.asarray(selected_event.get("source_y_idx", []), dtype=np.float64),
            np.asarray(selected_event.get("source_fit_mask", []), dtype=bool),
            params,
        )
        if diagnostic is None:
            return
        self._push_wavelet_undo_state(panel_id, "recompute event")
        self._set_td_window_wavelet_event_analysis(
            selected_event, diagnostic, customized=True
        )
        self._append_wavelet_event_history(
            selected_event,
            "recompute",
            details=f"panel={panel.name}",
        )
        self._record_session_change()
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)
        self._set_status(f"Recomputed selected wavelet event for {panel.name}.")

    def _accept_td_window_selected_wavelet_event(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        selected_event = self._selected_td_window_wavelet_event_editable(
            panel_id, "accept"
        )
        if selected_event is None:
            return
        wave_t_idx = np.asarray(
            (selected_event.get("analysis") or {}).get("wave_t_idx", []),
            dtype=np.float64,
        )
        if wave_t_idx.size < 2:
            self._set_status(
                f"The selected event has no valid wave segment to accept in {panel.name}."
            )
            return
        self._push_wavelet_undo_state(panel_id, "accept event")
        selected_event["manual_decision"] = "accepted"
        self._append_wavelet_event_history(selected_event, "accept")
        self._wavelet_event_confidence_details(selected_event)
        self._record_session_change()
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)
        self._set_status(f"Marked selected wavelet event as accepted for {panel.name}.")

    def _reject_td_window_selected_wavelet_event(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        selected_event = self._selected_td_window_wavelet_event_editable(
            panel_id, "reject"
        )
        if selected_event is None:
            return
        self._push_wavelet_undo_state(panel_id, "reject event")
        selected_event["manual_decision"] = "rejected"
        self._append_wavelet_event_history(selected_event, "reject")
        self._wavelet_event_confidence_details(selected_event)
        self._record_session_change()
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)
        self._set_status(f"Marked selected wavelet event as rejected for {panel.name}.")

    def _reset_td_window_selected_wavelet_event(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        selected_event = self._selected_td_window_wavelet_event_editable(
            panel_id, "reset"
        )
        if selected_event is None:
            return
        self._push_wavelet_undo_state(panel_id, "reset event")
        if selected_event.get("split_children_ids"):
            child_ids = set(int(child_id) for child_id in selected_event["split_children_ids"])
            existing["wavelet_events"] = [
                event
                for event in self._td_window_wavelet_events(panel_id)
                if int(event.get("event_id", -1)) not in child_ids
            ]
            selected_event["split_children_ids"] = []
        selected_event["source_t_idx"] = np.asarray(
            selected_event.get("base_source_t_idx", []), dtype=np.float64
        ).copy()
        selected_event["source_y_idx"] = np.asarray(
            selected_event.get("base_source_y_idx", []), dtype=np.float64
        ).copy()
        selected_event["source_fit_mask"] = np.asarray(
            selected_event.get("base_source_fit_mask", []), dtype=bool
        ).copy()
        selected_event["analysis"] = self._clone_wavelet_payload(
            selected_event.get("base_analysis") or {}
        )
        selected_event["current_params"] = dict(
            selected_event.get("base_params") or {}
        )
        selected_event["manual_decision"] = None
        selected_event["customized"] = False
        selected_event["diagnostic"] = None
        self._append_wavelet_event_history(selected_event, "reset")
        self._wavelet_event_confidence_details(selected_event)
        self._record_session_change()
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)
        self._set_status(f"Reset selected wavelet event for {panel.name}.")

    def _bulk_update_td_window_visible_wavelet_events(
        self, panel_id: int, action: str
    ) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        visible_ids = self._td_window_visible_wavelet_event_ids(panel_id)
        if not visible_ids:
            self._set_status(f"No visible wavelet events to {action} in {panel.name}.")
            return

        changed = 0
        skipped_locked = 0
        skipped_invalid = 0
        undo_pushed = False

        for event_id in visible_ids:
            event = self._td_window_wavelet_event_by_id(panel_id, event_id)
            if event is None:
                continue
            self._ensure_wavelet_event_fields(event)
            if bool(event.get("review_locked")):
                skipped_locked += 1
                continue
            if event.get("split_children_ids") and action in {"accept", "reject"}:
                skipped_invalid += 1
                continue

            if action == "accept":
                wave_t_idx = np.asarray(
                    (event.get("analysis") or {}).get("wave_t_idx", []),
                    dtype=np.float64,
                )
                if wave_t_idx.size < 2:
                    skipped_invalid += 1
                    continue
                if not undo_pushed:
                    self._push_wavelet_undo_state(panel_id, f"{action} visible events")
                    undo_pushed = True
                event["manual_decision"] = "accepted"
                self._append_wavelet_event_history(event, "accept", details="bulk visible")
            elif action == "reject":
                if not undo_pushed:
                    self._push_wavelet_undo_state(panel_id, f"{action} visible events")
                    undo_pushed = True
                event["manual_decision"] = "rejected"
                self._append_wavelet_event_history(event, "reject", details="bulk visible")
            elif action == "reset":
                if not undo_pushed:
                    self._push_wavelet_undo_state(panel_id, f"{action} visible events")
                    undo_pushed = True
                if event.get("split_children_ids"):
                    child_ids = {
                        int(child_id) for child_id in event.get("split_children_ids") or []
                    }
                    existing["wavelet_events"] = [
                        candidate
                        for candidate in self._td_window_wavelet_events(panel_id)
                        if int(candidate.get("event_id", -1)) not in child_ids
                    ]
                    event["split_children_ids"] = []
                event["source_t_idx"] = np.asarray(
                    event.get("base_source_t_idx", []), dtype=np.float64
                ).copy()
                event["source_y_idx"] = np.asarray(
                    event.get("base_source_y_idx", []), dtype=np.float64
                ).copy()
                event["source_fit_mask"] = np.asarray(
                    event.get("base_source_fit_mask", []), dtype=bool
                ).copy()
                event["analysis"] = self._clone_wavelet_payload(
                    event.get("base_analysis") or {}
                )
                event["current_params"] = dict(event.get("base_params") or {})
                event["manual_decision"] = None
                event["customized"] = False
                event["diagnostic"] = None
                self._append_wavelet_event_history(event, "reset", details="bulk visible")
            else:
                return

            self._wavelet_event_confidence_details(event)
            changed += 1

        if changed <= 0:
            self._set_status(
                f"No visible wavelet events were updated in {panel.name}. "
                f"locked={skipped_locked}, skipped={skipped_invalid}."
            )
            return

        self._record_session_change()
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)
        self._set_status(
            f"{action.capitalize()} updated {changed} visible wavelet event(s) in {panel.name}. "
            f"locked={skipped_locked}, skipped={skipped_invalid}."
        )

    def _trim_td_window_selected_wavelet_event(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        selected_event = self._selected_td_window_wavelet_event_editable(
            panel_id, "trim"
        )
        if selected_event is None:
            return
        if selected_event.get("split_children_ids"):
            self._set_status(f"Reset the split parent before trimming it in {panel.name}.")
            return
        try:
            trim_start_text = str(existing["wavelet_trim_start_var"].get()).strip()
            trim_end_text = str(existing["wavelet_trim_end_var"].get()).strip()
            trim_start = float(trim_start_text) if trim_start_text else float("nan")
            trim_end = float(trim_end_text) if trim_end_text else float("nan")
        except Exception:
            self._set_status(f"Invalid trim range for {panel.name}.")
            return
        source_t_idx = np.asarray(selected_event.get("source_t_idx", []), dtype=np.float64)
        source_y_idx = np.asarray(selected_event.get("source_y_idx", []), dtype=np.float64)
        source_fit_mask = np.asarray(selected_event.get("source_fit_mask", []), dtype=bool)
        if source_t_idx.size < 3 or source_y_idx.size != source_t_idx.size:
            self._set_status(f"Selected event has no valid source segment in {panel.name}.")
            return
        if not np.isfinite(trim_start):
            trim_start = float(source_t_idx[0])
        if not np.isfinite(trim_end):
            trim_end = float(source_t_idx[-1])
        if trim_end <= trim_start:
            self._set_status(f"Trim end must be larger than trim start for {panel.name}.")
            return
        mask = (source_t_idx >= trim_start) & (source_t_idx <= trim_end)
        if np.count_nonzero(mask) < 3:
            self._set_status(f"Trimmed segment is too short for {panel.name}.")
            return
        params = self._parse_td_window_wavelet_filter_params(panel_id)
        if params is None:
            return
        diagnostic = self._analyze_td_window_wavelet_event_source(
            panel_id,
            source_t_idx[mask],
            source_y_idx[mask],
            source_fit_mask[mask] if source_fit_mask.size == source_t_idx.size else None,
            params,
        )
        if diagnostic is None:
            return
        self._push_wavelet_undo_state(panel_id, "trim event")
        selected_event["source_t_idx"] = np.asarray(source_t_idx[mask], dtype=np.float64).copy()
        selected_event["source_y_idx"] = np.asarray(source_y_idx[mask], dtype=np.float64).copy()
        if source_fit_mask.size == source_t_idx.size:
            selected_event["source_fit_mask"] = np.asarray(source_fit_mask[mask], dtype=bool).copy()
        selected_event["origin"] = "manual-trim"
        self._set_td_window_wavelet_event_analysis(
            selected_event, diagnostic, customized=True
        )
        self._append_wavelet_event_history(
            selected_event,
            "trim",
            details=f"{float(source_t_idx[mask][0]):.2f}-{float(source_t_idx[mask][-1]):.2f}",
        )
        self._record_session_change()
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)
        self._set_status(f"Trimmed selected wavelet event for {panel.name}.")

    def _split_td_window_selected_wavelet_event(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        selected_event = self._selected_td_window_wavelet_event_editable(
            panel_id, "split"
        )
        if selected_event is None:
            return
        if selected_event.get("split_children_ids"):
            self._set_status(f"Selected event is already split in {panel.name}.")
            return
        split_text = str(existing["wavelet_split_frames_var"].get()).strip()
        if not split_text:
            self._set_status(f"Enter one or more split frame indices for {panel.name}.")
            return
        try:
            split_frames = sorted(
                {float(token.strip()) for token in split_text.split(",") if token.strip()}
            )
        except Exception:
            self._set_status(f"Invalid split frame list for {panel.name}.")
            return
        source_t_idx = np.asarray(selected_event.get("source_t_idx", []), dtype=np.float64)
        source_y_idx = np.asarray(selected_event.get("source_y_idx", []), dtype=np.float64)
        source_fit_mask = np.asarray(selected_event.get("source_fit_mask", []), dtype=bool)
        if source_t_idx.size < 6 or source_y_idx.size != source_t_idx.size:
            self._set_status(f"Selected event is too short to split in {panel.name}.")
            return
        valid_splits = [
            value
            for value in split_frames
            if float(source_t_idx[0]) < value < float(source_t_idx[-1])
        ]
        if not valid_splits:
            self._set_status(f"No split points fall inside the selected event in {panel.name}.")
            return
        params = self._parse_td_window_wavelet_filter_params(panel_id)
        if params is None:
            return
        self._push_wavelet_undo_state(panel_id, "split event")
        boundaries = [float(source_t_idx[0])] + valid_splits + [float(source_t_idx[-1]) + 1e-9]
        next_event_id = int(existing.get("wavelet_next_event_id", 1))
        child_ids: list[int] = []
        new_events: list[dict[str, Any]] = []
        for idx in range(len(boundaries) - 1):
            left = boundaries[idx]
            right = boundaries[idx + 1]
            if idx == len(boundaries) - 2:
                mask = (source_t_idx >= left) & (source_t_idx <= right)
            else:
                mask = (source_t_idx >= left) & (source_t_idx < right)
            if np.count_nonzero(mask) < 3:
                continue
            diagnostic = self._analyze_td_window_wavelet_event_source(
                panel_id,
                source_t_idx[mask],
                source_y_idx[mask],
                source_fit_mask[mask] if source_fit_mask.size == source_t_idx.size else None,
                params,
            )
            if diagnostic is None:
                continue
            child_event = self._make_td_window_wavelet_event(
                next_event_id,
                diagnostic["selected"],
                params,
                origin="manual-split",
                parent_event_id=int(selected_event.get("event_id", -1)),
            )
            child_event["source_t_idx"] = np.asarray(source_t_idx[mask], dtype=np.float64).copy()
            child_event["source_y_idx"] = np.asarray(source_y_idx[mask], dtype=np.float64).copy()
            if source_fit_mask.size == source_t_idx.size:
                child_event["source_fit_mask"] = np.asarray(source_fit_mask[mask], dtype=bool).copy()
                child_event["base_source_fit_mask"] = child_event["source_fit_mask"].copy()
            child_event["base_source_t_idx"] = child_event["source_t_idx"].copy()
            child_event["base_source_y_idx"] = child_event["source_y_idx"].copy()
            parent_analysis = selected_event.get("analysis") or {}
            child_event["analysis"]["thread_index"] = parent_analysis.get("thread_index", -1)
            child_event["analysis"]["seg_id"] = parent_analysis.get("seg_id", -1)
            child_event["base_analysis"]["thread_index"] = parent_analysis.get("thread_index", -1)
            child_event["base_analysis"]["seg_id"] = parent_analysis.get("seg_id", -1)
            child_event["diagnostic"] = self._clone_wavelet_payload(diagnostic)
            self._append_wavelet_event_history(
                child_event,
                "split-child",
                details=f"parent={int(selected_event.get('event_id', -1))}",
            )
            child_ids.append(next_event_id)
            new_events.append(child_event)
            next_event_id += 1
        if not new_events:
            self._set_status(f"Could not create split child events for {panel.name}.")
            return
        selected_event["split_children_ids"] = child_ids
        self._append_wavelet_event_history(
            selected_event,
            "split",
            details=",".join(f"{value:.2f}" for value in valid_splits),
        )
        existing["wavelet_events"].extend(new_events)
        existing["wavelet_next_event_id"] = next_event_id
        existing["wavelet_selected_event_id"] = child_ids[0]
        self._record_session_change()
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)
        self._set_status(f"Split selected wavelet event into {len(new_events)} child event(s) for {panel.name}.")

    def _run_td_window_wavelet_filter(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        _trace_stack_wavelet(f"run_td_window_wavelet_filter start panel={panel_id} panel_name={panel.name}")

        _job_id, running_job = self._background_wavelet_job_for_panel(panel_id)
        if running_job is not None:
            self._set_status(f"Wavelet filter is already running for {panel.name}.")
            self._update_wavelet_job_widgets(panel_id)
            return

        tracking_result = existing.get("crest_tracking_result")
        if not tracking_result:
            existing["wavelet_summary_var"].set(
                "Run crest tracking first to use the wavelet filter."
            )
            existing["wavelet_physics_var"].set("")
            self._set_status(f"Run crest tracking before wavelet filtering {panel.name}.")
            return

        params = self._parse_td_window_wavelet_filter_params(panel_id)
        if params is None:
            return

        td, meta = self._panel_td(panel)
        if td is None or meta is None:
            existing["wavelet_summary_var"].set(
                "No valid TD map available for wavelet filtering."
            )
            existing["wavelet_physics_var"].set("")
            self._set_status(f"{panel.name} has no valid TD map for wavelet filtering.")
            return

        threads = tracking_result.get("threads") or []
        if not threads:
            existing["wavelet_summary_var"].set(
                "No tracked threads available for wavelet filtering."
            )
            existing["wavelet_physics_var"].set("")
            self._set_status(f"{panel.name} has no tracked threads for wavelet filtering.")
            return
        thread_filter_text = str(existing["wavelet_thread_filter_var"].get() or "").strip()
        selected_thread_indices, filter_error = self._parse_wavelet_thread_filter_text(
            thread_filter_text,
            max_threads=len(threads),
        )
        if filter_error is not None:
            existing["wavelet_summary_var"].set(filter_error)
            existing["wavelet_physics_var"].set("")
            self._set_status(f"{panel.name}: {filter_error}")
            return
        thread_entries = [
            {"thread_index": int(idx), "thread": thread}
            for idx, thread in enumerate(threads)
            if selected_thread_indices is None or int(idx) in selected_thread_indices
        ]
        if not thread_entries:
            existing["wavelet_summary_var"].set("Wavelet thread filter matched no tracked threads.")
            existing["wavelet_physics_var"].set("")
            self._set_status(f"{panel.name}: wavelet thread filter matched no tracked threads.")
            return

        job_id, job = self._new_background_job(
            kind="wavelet", panel_id=panel_id, panel_name=panel.name
        )
        filter_label = (
            self._format_wavelet_thread_filter_text(selected_thread_indices)
            if selected_thread_indices
            else "all"
        )
        existing["wavelet_summary_var"].set(
            f"Running wavelet filter in background... threads {filter_label}"
        )
        existing["wavelet_physics_var"].set("")
        job["stage"] = "starting"
        job["current"] = 0
        job["total"] = max(len(thread_entries), 1)
        job["message"] = (
            f"{panel.name}: queued wavelet filter "
            f"({len(thread_entries)} thread(s), filter={filter_label})"
        )
        thread = threading.Thread(
            target=self._wavelet_worker,
            args=(
                job_id,
                panel_id,
                panel.name,
                self._clone_wavelet_payload(thread_entries),
                np.asarray(meta["t_indices"], dtype=np.float64).copy(),
                dict(params),
                job["cancel_event"],
            ),
            daemon=True,
        )
        job["thread"] = thread
        thread.start()
        self._panel_analysis(panel_id)["wavelet_thread_filter_text"] = thread_filter_text
        self._update_wavelet_job_widgets(panel_id)
        self._set_status(
            f"Running wavelet filter in background for {panel.name} (threads {filter_label})..."
        )

    def _draw_td_window_crest_overlay(
        self, ax: Any, panel_id: int, meta: dict[str, Any] | None
    ) -> None:
        if meta is None:
            return

        existing = self.td_windows.get(panel_id)
        if existing is None:
            return

        tracking_result = existing.get("crest_tracking_result")
        if not tracking_result:
            return

        threads = tracking_result.get("threads") or []
        if not threads:
            return

        distances = np.asarray(meta["distances"], dtype=np.float64)
        t_indices = np.asarray(meta["t_indices"], dtype=np.float64)
        if distances.size == 0 or t_indices.size == 0:
            return

        dist_index = np.arange(distances.size, dtype=np.float64)
        dist_hi = dist_index[-1]

        for idx, thread in enumerate(threads):
            pos = np.asarray(thread.get("pos", []), dtype=np.float64)
            if pos.size != t_indices.size:
                continue
            mask = np.isfinite(pos) & (pos >= 0.0) & (pos <= dist_hi + 1e-9)
            if np.count_nonzero(mask) < 2:
                continue
            dist_vals = np.interp(pos[mask], dist_index, distances)
            time_vals = t_indices[mask]
            color = COLOR_CYCLE[idx % len(COLOR_CYCLE)]
            if self.td_swap_axes_var.get():
                ax.plot(time_vals, dist_vals, color=color, linewidth=1.5, alpha=0.85)
            else:
                ax.plot(dist_vals, time_vals, color=color, linewidth=1.5, alpha=0.85)

        events = existing.get("wavelet_events")
        if events:
            selected_event_id = existing.get("wavelet_selected_event_id")
            for event in events:
                is_selected = int(event.get("event_id", -1)) == int(selected_event_id or -1)
                if not self._td_window_wavelet_event_is_counted(event) and not is_selected:
                    continue
                wave_t_idx, wave_y_idx = self._wavelet_event_overlay_samples(
                    event,
                    allow_source_fallback=is_selected,
                )
                if wave_t_idx.size < 2 or wave_y_idx.size != wave_t_idx.size:
                    continue
                mask = np.isfinite(wave_y_idx) & (wave_y_idx >= 0.0) & (wave_y_idx <= dist_hi + 1e-9)
                if np.count_nonzero(mask) < 2:
                    continue
                dist_vals = np.interp(wave_y_idx[mask], dist_index, distances)
                time_vals = wave_t_idx[mask]
                status = self._td_window_wavelet_event_status(event)
                color = "lime"
                if status == "manual accepted":
                    color = "deepskyblue"
                elif status == "custom accepted":
                    color = "cyan"
                elif status not in {"auto accepted", "custom accepted", "manual accepted"}:
                    color = "darkorange"
                linewidth = 2.6 if self._td_window_wavelet_event_is_counted(event) else 1.6
                alpha = 0.95 if self._td_window_wavelet_event_is_counted(event) else 0.65
                if is_selected:
                    color = "gold"
                    linewidth = 3.0
                    alpha = 1.0
                if self.td_swap_axes_var.get():
                    ax.plot(time_vals, dist_vals, color=color, linewidth=linewidth, alpha=alpha)
                else:
                    ax.plot(dist_vals, time_vals, color=color, linewidth=linewidth, alpha=alpha)
            return

        wavelet_result = existing.get("wavelet_filter_result")
        if not wavelet_result:
            return

        for segment in wavelet_result.get("segments", []):
            if not segment.get("accepted"):
                continue
            wave_t_idx = np.asarray(segment.get("wave_t_idx", []), dtype=np.float64)
            wave_y_idx = np.asarray(segment.get("wave_y_idx", []), dtype=np.float64)
            if wave_t_idx.size < 2 or wave_y_idx.size != wave_t_idx.size:
                continue
            mask = np.isfinite(wave_y_idx) & (wave_y_idx >= 0.0) & (wave_y_idx <= dist_hi + 1e-9)
            if np.count_nonzero(mask) < 2:
                continue
            dist_vals = np.interp(wave_y_idx[mask], dist_index, distances)
            time_vals = wave_t_idx[mask]
            if self.td_swap_axes_var.get():
                ax.plot(time_vals, dist_vals, color="lime", linewidth=2.6, alpha=0.95)
            else:
                ax.plot(dist_vals, time_vals, color="lime", linewidth=2.6, alpha=0.95)

    def _toggle_td_window_editor(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return

        is_open = not bool(existing["edit_var"].get())
        existing["edit_var"].set(is_open)

        if is_open:
            existing["edit_frame"].grid()
            existing["editor_toggle_var"].set("Hide editor")
            self._set_status(
                f"Detached TD controls enabled for {self.panels[panel_id - 1].name}."
            )
        else:
            existing["edit_frame"].grid_remove()
            existing["editor_toggle_var"].set("Show editor")
            self._set_status(
                f"Detached TD controls hidden for {self.panels[panel_id - 1].name}."
            )

    def _on_td_window_display_mode_change(self, panel_id: int) -> None:
        self._refresh_td_window(panel_id)

    def _sync_td_window_controls(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return

        cut = self.cuts.get(panel.cut_id) if panel.cut_id is not None else None
        params = self._panel_td_params(panel)
        existing["control_guard"] = True
        existing["panel_info_var"].set(
            f"{panel.name} | no cut"
            if cut is None
            else f"{panel.name} | {cut.name} | "
            f"t={int(params['t_ini'])}:{int(params['t_fin'])}:{int(params['stride'])} | "
            f"w={int(params['width'])} {params['weighting']}"
        )
        existing["panel_t_ini_var"].set(str(int(params["t_ini"])))
        existing["panel_t_fin_var"].set(str(int(params["t_fin"])))
        existing["panel_stride_var"].set(str(int(params["stride"])))
        existing["panel_width_var"].set(str(int(params["width"])))
        existing["panel_weighting_var"].set(str(params["weighting"]))

        if cut is None:
            existing["cut_info_var"].set("No cut assigned to this panel.")
            existing["cut_angle_var"].set("")
            existing["cut_length_var"].set("")
            existing["center_x_var"].set("")
            existing["center_y_var"].set("")
            existing["cut_x1_var"].set("")
            existing["cut_y1_var"].set("")
            existing["cut_x2_var"].set("")
            existing["cut_y2_var"].set("")
        else:
            preview_cut = self._cut_preview(cut.cut_id) or cut
            center = cut_center(preview_cut)
            dynamic_label = " | dynamic" if self._cut_dynamic_enabled(cut.cut_id) else ""
            existing["cut_info_var"].set(
                f"{cut.name}{dynamic_label} | angle={cut_display_angle_deg(preview_cut):.2f} deg | "
                f"length={cut_length(preview_cut):.2f} px"
            )
            existing["cut_angle_var"].set(f"{cut_display_angle_deg(preview_cut):.2f}")
            existing["cut_length_var"].set(f"{cut_length(preview_cut):.2f}")
            existing["center_x_var"].set(f"{center[0]:.2f}")
            existing["center_y_var"].set(f"{center[1]:.2f}")
            existing["cut_x1_var"].set(f"{preview_cut.p0[0]:.2f}")
            existing["cut_y1_var"].set(f"{preview_cut.p0[1]:.2f}")
            existing["cut_x2_var"].set(f"{preview_cut.p1[0]:.2f}")
            existing["cut_y2_var"].set(f"{preview_cut.p1[1]:.2f}")
        existing["control_guard"] = False

    def _apply_td_window_panel_controls(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None or existing.get("control_guard"):
            return

        try:
            t_ini = int(float(str(existing["panel_t_ini_var"].get()).strip()))
            t_fin = int(float(str(existing["panel_t_fin_var"].get()).strip()))
            stride = int(float(str(existing["panel_stride_var"].get()).strip()))
            width = int(float(str(existing["panel_width_var"].get()).strip()))
        except Exception:
            self._set_status("Invalid detached TD control value.")
            return

        if t_ini > t_fin:
            t_fin = t_ini
            existing["control_guard"] = True
            existing["panel_t_fin_var"].set(str(t_fin))
            existing["control_guard"] = False

        panel.t_ini = clamp_int(t_ini, 0, self.nt - 1)
        panel.t_fin = clamp_int(t_fin, panel.t_ini, self.nt - 1)
        panel.stride = max(stride, 1)
        panel.width = max(width, 1)
        panel.weighting = str(existing["panel_weighting_var"].get() or "uniform")
        if panel.cut_id is not None and panel.cut_id in self.cuts:
            state = self._cut_analysis(panel.cut_id)
            state["td_params"] = {
                "t_ini": int(panel.t_ini),
                "t_fin": int(panel.t_fin),
                "stride": int(panel.stride),
                "width": int(panel.width),
                "weighting": str(panel.weighting),
            }
            state["td_cache_key"] = None
            state["td_cache_td"] = None
            state["td_cache_meta"] = None
            self._sync_panels_from_cut_td_params(panel.cut_id)
            self._invalidate_cut_dependents(panel.cut_id)
        else:
            self._invalidate_panel_cache(panel.panel_id)
        self._record_session_change()
        self.refresh_all()
        self._set_status(f"Updated detached TD controls for {panel.name}.")

    def _td_window_time_range(self, meta: dict[str, Any]) -> tuple[float, float]:
        t_indices = meta["t_indices"]
        if len(t_indices) == 1:
            return float(t_indices[0]), float(t_indices[0]) + 1.0
        return float(t_indices[0]), float(t_indices[-1])

    def _ensure_td_window_roi(self, panel_id: int, meta: dict[str, Any]) -> tuple[float, float, float, float]:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return 0.0, 1.0, 0.0, 1.0

        t_min, t_max = self._td_window_time_range(meta)
        dist_max = float(meta["distances"][-1])
        total_t = max(t_max - t_min, 1.0)
        total_d = max(dist_max, 1.0)

        try:
            t_span = float(str(existing["roi_t_span_var"].get()).strip())
        except Exception:
            t_span = max(5.0, 0.25 * total_t)
        try:
            d_span = float(str(existing["roi_d_span_var"].get()).strip())
        except Exception:
            d_span = max(2.0, 0.35 * total_d)

        t_span = clamp_value(t_span, min(1.0, total_t), total_t)
        d_span = clamp_value(d_span, min(1.0, total_d), total_d)

        if existing.get("roi_center_t") is None:
            current_t = float(self.t_visual_var.get())
            existing["roi_center_t"] = (
                current_t if t_min <= current_t <= t_max else 0.5 * (t_min + t_max)
            )
        if existing.get("roi_center_d") is None:
            existing["roi_center_d"] = 0.5 * dist_max

        roi_center_t = float(existing["roi_center_t"])
        roi_center_d = float(existing["roi_center_d"])

        if total_t <= t_span + 1e-9:
            roi_center_t = 0.5 * (t_min + t_max)
        else:
            roi_center_t = clamp_value(roi_center_t, t_min + 0.5 * t_span, t_max - 0.5 * t_span)
        if total_d <= d_span + 1e-9:
            roi_center_d = 0.5 * dist_max
        else:
            roi_center_d = clamp_value(roi_center_d, 0.5 * d_span, dist_max - 0.5 * d_span)

        existing["roi_center_t"] = roi_center_t
        existing["roi_center_d"] = roi_center_d
        existing["control_guard"] = True
        existing["roi_t_span_var"].set(f"{t_span:.2f}")
        existing["roi_d_span_var"].set(f"{d_span:.2f}")
        existing["control_guard"] = False

        return (
            roi_center_t - 0.5 * t_span,
            roi_center_t + 0.5 * t_span,
            roi_center_d - 0.5 * d_span,
            roi_center_d + 0.5 * d_span,
        )

    def _on_td_window_roi_toggle(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        existing["roi_dragging"] = False
        self._record_session_change()
        self._refresh_td_window(panel_id)
        if existing["roi_enabled_var"].get():
            self._set_status(f"ROI zoom enabled for {self.panels[panel_id - 1].name}.")
        else:
            self._set_status(f"ROI zoom hidden for {self.panels[panel_id - 1].name}.")

    def _apply_td_window_roi_settings(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None or existing.get("control_guard"):
            return
        td, meta = self._panel_td(panel)
        if td is None or meta is None:
            self._set_status(f"{panel.name} has no valid TD for ROI zoom.")
            return
        self._ensure_td_window_roi(panel_id, meta)
        self._record_session_change()
        self._refresh_td_window(panel_id)
        self._set_status(f"Updated ROI box for {panel.name}.")

    def _open_td_window_roi_window(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        top = existing.get("top")
        if top is None or not top.winfo_exists():
            return

        roi_top = existing.get("roi_top")
        if roi_top is not None and roi_top.winfo_exists():
            roi_top.deiconify()
            roi_top.lift()
            self._refresh_td_window(panel_id)
            return

        roi_top = self.tk.Toplevel(top)
        roi_top.title(f"ROI TD - {panel.name}")
        roi_top.geometry("980x420")
        roi_top.rowconfigure(0, weight=1)
        roi_top.columnconfigure(0, weight=1)
        frame = self.ttk.Frame(roi_top, padding=8)
        frame.grid(row=0, column=0, sticky="nsew")
        frame.rowconfigure(0, weight=1)
        frame.columnconfigure(0, weight=1)

        roi_fig = self.Figure(figsize=(8.6, 3.2), dpi=120)
        roi_ax = roi_fig.add_subplot(111)
        roi_canvas = self.FigureCanvasTkAgg(roi_fig, master=frame)
        roi_canvas.get_tk_widget().grid(row=0, column=0, sticky="nsew")

        existing["roi_top"] = roi_top
        existing["roi_figure"] = roi_fig
        existing["roi_ax"] = roi_ax
        existing["roi_canvas"] = roi_canvas
        existing["roi_window_toggle_var"].set("Close ROI window")
        roi_top.protocol(
            "WM_DELETE_WINDOW",
            lambda pid=panel_id: self._close_td_window_roi_window(pid),
        )
        self._refresh_td_window(panel_id)

    def _close_td_window_roi_window(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        roi_top = existing.get("roi_top")
        if roi_top is not None and roi_top.winfo_exists():
            roi_top.destroy()
        existing["roi_top"] = None
        existing["roi_figure"] = None
        existing["roi_ax"] = None
        existing["roi_canvas"] = None
        toggle_var = existing.get("roi_window_toggle_var")
        if toggle_var is not None:
            toggle_var.set("ROI window")

    def _toggle_td_window_roi_window(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        roi_top = existing.get("roi_top")
        if roi_top is not None and roi_top.winfo_exists():
            self._close_td_window_roi_window(panel_id)
        else:
            self._open_td_window_roi_window(panel_id)

    def _open_td_window_diag_window(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        top = existing.get("top")
        if top is None or not top.winfo_exists():
            return

        diag_top = existing.get("diag_top")
        if diag_top is not None and diag_top.winfo_exists():
            diag_top.deiconify()
            diag_top.lift()
            self._refresh_td_window_wavelet_diagnostics(panel_id)
            return

        diag_top = self.tk.Toplevel(top)
        diag_top.title(f"Wavelet Diagnostic - {panel.name}")
        diag_top.geometry("1080x760")
        diag_top.rowconfigure(0, weight=1)
        diag_top.columnconfigure(0, weight=1)
        frame = self.ttk.Frame(diag_top, padding=8)
        frame.grid(row=0, column=0, sticky="nsew")
        frame.rowconfigure(0, weight=1)
        frame.columnconfigure(0, weight=1)

        diag_fig = self.Figure(figsize=(9.2, 6.4), dpi=120)
        diag_axes = tuple(np.ravel(diag_fig.subplots(2, 2)))
        diag_canvas = self.FigureCanvasTkAgg(diag_fig, master=frame)
        diag_canvas.get_tk_widget().grid(row=0, column=0, sticky="nsew")
        diag_canvas.mpl_connect(
            "button_press_event",
            lambda event, pid=panel_id: self._on_td_window_diag_press(pid, event),
        )
        diag_canvas.mpl_connect(
            "motion_notify_event",
            lambda event, pid=panel_id: self._on_td_window_diag_motion(pid, event),
        )
        diag_canvas.mpl_connect(
            "button_release_event",
            lambda event, pid=panel_id: self._on_td_window_diag_release(pid, event),
        )

        existing["diag_top"] = diag_top
        existing["diag_figure"] = diag_fig
        existing["diag_axes"] = diag_axes
        existing["diag_canvas"] = diag_canvas
        existing["diag_window_toggle_var"].set("Close Wavelet diag")
        diag_top.protocol(
            "WM_DELETE_WINDOW",
            lambda pid=panel_id: self._close_td_window_diag_window(pid),
        )
        self._refresh_td_window_wavelet_diagnostics(panel_id)

    def _close_td_window_diag_window(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        diag_top = existing.get("diag_top")
        if diag_top is not None and diag_top.winfo_exists():
            diag_top.destroy()
        existing["diag_top"] = None
        existing["diag_figure"] = None
        existing["diag_axes"] = None
        existing["diag_canvas"] = None
        toggle_var = existing.get("diag_window_toggle_var")
        if toggle_var is not None:
            toggle_var.set("Wavelet diag window")

    def _open_td_window_wavelet_table_window(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None:
            return
        parent_top = existing.get("top")
        if parent_top is None or not parent_top.winfo_exists():
            return

        table_top = existing.get("wavelet_table_top")
        if table_top is not None and table_top.winfo_exists():
            table_top.deiconify()
            table_top.lift()
            self._refresh_td_window_wavelet_popup_table(panel_id)
            self._refresh_td_window_wavelet_diagnostics(panel_id)
            return

        table_top = self.tk.Toplevel(parent_top)
        table_top.title(f"Wavelet Event Table - {panel.name}")
        table_top.geometry("1760x720")
        table_top.rowconfigure(0, weight=1)
        table_top.columnconfigure(0, weight=1)

        frame = self.ttk.Frame(table_top, padding=8)
        frame.grid(row=0, column=0, sticky="nsew")
        frame.rowconfigure(1, weight=1)
        frame.columnconfigure(0, weight=1)

        self.ttk.Label(
            frame,
            text=(
                "Expanded event table. Selection stays synced with the main editor so "
                "reasons and candidates remain readable."
            ),
            justify="left",
        ).grid(row=0, column=0, sticky="w")

        tree_frame = self.ttk.Frame(frame)
        tree_frame.grid(row=1, column=0, sticky="nsew", pady=(8, 0))
        tree_frame.rowconfigure(0, weight=1)
        tree_frame.columnconfigure(0, weight=1)

        tree = self.ttk.Treeview(
            tree_frame,
            columns=WAVELET_EVENT_TABLE_COLUMNS,
            show="headings",
            height=22,
        )
        tree.grid(row=0, column=0, sticky="nsew")
        tree_y = self.ttk.Scrollbar(tree_frame, orient="vertical", command=tree.yview)
        tree_x = self.ttk.Scrollbar(tree_frame, orient="horizontal", command=tree.xview)
        tree.configure(yscrollcommand=tree_y.set, xscrollcommand=tree_x.set)
        tree_y.grid(row=0, column=1, sticky="ns")
        tree_x.grid(row=1, column=0, sticky="ew")
        for column, (label, width) in WAVELET_EVENT_TABLE_HEADINGS.items():
            tree.heading(column, text=label)
            tree.column(
                column,
                width=(360 if column == "reason" else width),
                stretch=(column in {"reason", "flags"}),
            )
        for tag_name, color in (
            ("auto_accepted", "green4"),
            ("auto_rejected", "firebrick"),
            ("custom_accepted", "darkcyan"),
            ("custom_rejected", "darkorange"),
            ("manual_accepted", "dodgerblue4"),
            ("manual_rejected", "red4"),
            ("split_parent", "gray45"),
        ):
            tree.tag_configure(tag_name, foreground=color)
        tree.bind(
            "<<TreeviewSelect>>",
            lambda _event, pid=panel_id: self._on_td_window_wavelet_popup_select(pid),
        )

        detail_frame = self.ttk.LabelFrame(
            frame, text="Selected event detail", padding=6
        )
        detail_frame.grid(row=2, column=0, sticky="nsew", pady=(8, 0))
        detail_frame.rowconfigure(0, weight=1)
        detail_frame.columnconfigure(0, weight=1)
        detail_text = self.tk.Text(detail_frame, height=8, wrap="word", state="disabled")
        detail_text.grid(row=0, column=0, sticky="nsew")
        detail_y = self.ttk.Scrollbar(
            detail_frame, orient="vertical", command=detail_text.yview
        )
        detail_text.configure(yscrollcommand=detail_y.set)
        detail_y.grid(row=0, column=1, sticky="ns")

        existing["wavelet_table_top"] = table_top
        existing["wavelet_table_tree"] = tree
        existing["wavelet_table_detail_text"] = detail_text
        existing["wavelet_popup_table_updating"] = False
        table_top.protocol(
            "WM_DELETE_WINDOW",
            lambda pid=panel_id: self._close_td_window_wavelet_table_window(pid),
        )
        self._refresh_td_window_wavelet_popup_table(panel_id)
        self._refresh_td_window_wavelet_diagnostics(panel_id)

    def _close_td_window_wavelet_table_window(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        table_top = existing.get("wavelet_table_top")
        if table_top is not None and table_top.winfo_exists():
            table_top.destroy()
        existing["wavelet_table_top"] = None
        existing["wavelet_table_tree"] = None
        existing["wavelet_table_detail_text"] = None
        existing["wavelet_popup_table_updating"] = False

    def _refresh_td_window_wavelet_popup_table(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        table_top = existing.get("wavelet_table_top")
        tree = existing.get("wavelet_table_tree")
        if (
            table_top is None
            or tree is None
            or not table_top.winfo_exists()
        ):
            return

        filter_name = str(existing["wavelet_events_filter_var"].get() or "all")
        advanced_filters = self._td_window_wavelet_advanced_filter_values(panel_id)
        selected_event_id = existing.get("wavelet_selected_event_id")
        existing["wavelet_popup_table_updating"] = True
        try:
            children = tree.get_children()
            if children:
                tree.delete(*children)

            visible_ids: list[int] = []
            for event in self._td_window_wavelet_events(panel_id):
                if not self._td_window_wavelet_event_filter_match(
                    event, filter_name, advanced_filters
                ):
                    continue
                iid = f"evt-popup-{int(event['event_id'])}"
                visible_ids.append(int(event["event_id"]))
                tree.insert(
                    "",
                    "end",
                    iid=iid,
                    values=self._td_window_wavelet_event_row(event),
                    tags=(self._td_window_wavelet_table_tag(event),),
                )

            target_iid: str | None = None
            if selected_event_id in visible_ids:
                target_iid = f"evt-popup-{int(selected_event_id)}"
            elif visible_ids:
                target_iid = f"evt-popup-{visible_ids[0]}"

            if target_iid is not None:
                current_selection = tree.selection()
                if current_selection != (target_iid,):
                    tree.selection_set(target_iid)
                tree.focus(target_iid)
                tree.see(target_iid)
            else:
                tree.selection_remove(tree.selection())
        finally:
            existing["wavelet_popup_table_updating"] = False

    def _on_td_window_wavelet_popup_select(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None or existing.get("wavelet_popup_table_updating"):
            return
        tree = existing.get("wavelet_table_tree")
        if tree is None:
            return
        previous_event_id = existing.get("wavelet_selected_event_id")
        selection = tree.selection()
        if not selection:
            existing["wavelet_selected_event_id"] = None
        else:
            iid = str(selection[0])
            if iid.startswith("evt-popup-"):
                try:
                    existing["wavelet_selected_event_id"] = int(iid.split("-", 2)[2])
                except Exception:
                    existing["wavelet_selected_event_id"] = None
        if existing.get("wavelet_selected_event_id") == previous_event_id:
            return
        self._refresh_td_window_wavelet_views(panel_id, redraw_td=True)

    def _toggle_td_window_diag_window(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        diag_top = existing.get("diag_top")
        if diag_top is not None and diag_top.winfo_exists():
            self._close_td_window_diag_window(panel_id)
        else:
            self._open_td_window_diag_window(panel_id)

    def _diag_edit_axes(self, panel_id: int) -> tuple[Any, Any] | tuple[None, None]:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return None, None
        diag_axes = existing.get("diag_axes")
        if not isinstance(diag_axes, tuple) or len(diag_axes) < 2:
            return None, None
        return diag_axes[0], diag_axes[1]

    def _on_td_window_diag_press(self, panel_id: int, event: Any) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is None or panel is None or event.xdata is None:
            return
        raw_ax, detr_ax = self._diag_edit_axes(panel_id)
        if event.inaxes not in {raw_ax, detr_ax}:
            return
        selected_event = self._td_window_wavelet_selected_event(panel_id)
        if selected_event is None:
            return
        source_t_idx = np.asarray(selected_event.get("source_t_idx", []), dtype=np.float64)
        if source_t_idx.size < 3:
            return
        clicked_t = float(event.xdata)
        if clicked_t < float(source_t_idx[0]) or clicked_t > float(source_t_idx[-1]):
            return
        button = int(getattr(event, "button", 1) or 1)
        if button == 1:
            existing["diag_interaction"] = {
                "mode": "trim",
                "start": clicked_t,
                "current": clicked_t,
            }
            self._refresh_td_window_wavelet_diagnostics(panel_id)
            return
        if button == 3:
            existing["wavelet_split_frames_var"].set(f"{clicked_t:.2f}")
            self._split_td_window_selected_wavelet_event(panel_id)

    def _on_td_window_diag_motion(self, panel_id: int, event: Any) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None or event.xdata is None:
            return
        interaction = existing.get("diag_interaction")
        if not interaction or interaction.get("mode") != "trim":
            return
        raw_ax, detr_ax = self._diag_edit_axes(panel_id)
        if event.inaxes not in {raw_ax, detr_ax}:
            return
        interaction["current"] = float(event.xdata)
        self._refresh_td_window_wavelet_diagnostics(panel_id)

    def _on_td_window_diag_release(self, panel_id: int, event: Any) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        interaction = existing.get("diag_interaction")
        if not interaction or interaction.get("mode") != "trim":
            return
        end_value = float(event.xdata) if event.xdata is not None else float(interaction.get("current", interaction.get("start", 0.0)))
        start_value = float(interaction.get("start", end_value))
        existing["diag_interaction"] = None
        left = min(start_value, end_value)
        right = max(start_value, end_value)
        if right - left < 1e-6:
            self._refresh_td_window_wavelet_diagnostics(panel_id)
            return
        existing["wavelet_trim_start_var"].set(f"{left:.2f}")
        existing["wavelet_trim_end_var"].set(f"{right:.2f}")
        self._trim_td_window_selected_wavelet_event(panel_id)

    def _draw_td_window_roi(
        self, panel_id: int, td: np.ndarray | None, meta: dict[str, Any] | None
    ) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return

        if td is None or meta is None or not existing["roi_enabled_var"].get():
            roi_ax = existing.get("roi_ax")
            if roi_ax is not None:
                roi_ax.clear()
                roi_ax.text(
                    0.5,
                    0.5,
                    "Enable ROI box to create a second TD panel.",
                    ha="center",
                    va="center",
                    transform=roi_ax.transAxes,
                )
                roi_ax.set_xticks([])
                roi_ax.set_yticks([])
                roi_ax.set_title("ROI TD", fontsize=10)
            return

        t0, t1, d0, d1 = self._ensure_td_window_roi(panel_id, meta)
        main_ax = existing["ax"]
        if self.td_swap_axes_var.get():
            rect_x, rect_y = t0, d0
            rect_w, rect_h = t1 - t0, d1 - d0
        else:
            rect_x, rect_y = d0, t0
            rect_w, rect_h = d1 - d0, t1 - t0

        main_ax.add_patch(
            self.Rectangle(
                (rect_x, rect_y),
                rect_w,
                rect_h,
                fill=False,
                linewidth=1.6,
                linestyle="--",
                edgecolor="tab:orange",
            )
        )

        roi_ax = existing.get("roi_ax")
        if roi_ax is None:
            return
        roi_ax.clear()

        t_min, t_max = self._td_window_time_range(meta)
        dist_max = float(meta["distances"][-1])
        vmin, vmax = frame_limits(td)
        td_aspect = "equal" if self.td_aspect_var.get() == "equal" else "auto"

        if self.td_swap_axes_var.get():
            roi_ax.imshow(
                td.T,
                origin="lower",
                aspect=td_aspect,
                cmap="gray",
                extent=[t_min, t_max, 0.0, dist_max],
                vmin=vmin,
                vmax=vmax,
                interpolation="nearest",
            )
            if self.td_flip_x_var.get():
                roi_ax.set_xlim(t1, t0)
            else:
                roi_ax.set_xlim(t0, t1)
            if self.td_flip_y_var.get():
                roi_ax.set_ylim(d1, d0)
            else:
                roi_ax.set_ylim(d0, d1)
            roi_ax.set_xlabel("time index")
            roi_ax.set_ylabel("distance [pixel]")
            self._draw_td_window_crest_overlay(roi_ax, panel_id, meta)
        else:
            roi_ax.imshow(
                td,
                origin="lower",
                aspect=td_aspect,
                cmap="gray",
                extent=[0.0, dist_max, t_min, t_max],
                vmin=vmin,
                vmax=vmax,
                interpolation="nearest",
            )
            if self.td_flip_x_var.get():
                roi_ax.set_xlim(d1, d0)
            else:
                roi_ax.set_xlim(d0, d1)
            if self.td_flip_y_var.get():
                roi_ax.set_ylim(t1, t0)
            else:
                roi_ax.set_ylim(t0, t1)
            roi_ax.set_xlabel("distance [pixel]")
            roi_ax.set_ylabel("time index")
            self._draw_td_window_crest_overlay(roi_ax, panel_id, meta)

        roi_ax.set_title("ROI TD", fontsize=10)
        roi_ax.tick_params(labelsize=8)
        for spine in roi_ax.spines.values():
            spine.set_edgecolor("tab:orange")
            spine.set_linewidth(1.4)

    def _on_td_window_press(self, panel_id: int, event: Any) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        coords = self._td_window_plot_to_td_coords(panel_id, event)
        if existing is not None and panel is not None and bool(existing.get("velocity_trace_draw_mode")):
            if coords is None:
                return
            clicked_t, clicked_d = coords
            pending = existing.get("velocity_trace_pending")
            if pending is None:
                existing["velocity_trace_pending"] = (float(clicked_t), float(clicked_d))
                existing["velocity_trace_hover"] = (float(clicked_t), float(clicked_d))
                self._refresh_td_window_velocity_trace_table(panel_id)
                self._refresh_td_window(panel_id)
                self._set_status(
                    f"{panel.name}: choose the second TD point for the velocity trace."
                )
                return
            start_t, start_d = pending
            try:
                trace = self._build_velocity_trace_record(
                    panel_id,
                    int(existing.get("velocity_next_trace_id", 1)),
                    float(start_t),
                    float(start_d),
                    float(clicked_t),
                    float(clicked_d),
                )
            except ValueError as exc:
                existing["velocity_trace_pending"] = None
                existing["velocity_trace_hover"] = None
                self._refresh_td_window_velocity_trace_table(panel_id)
                self._refresh_td_window(panel_id)
                self._set_status(str(exc))
                return
            traces = [
                dict(item)
                for item in (existing.get("velocity_traces") or [])
                if isinstance(item, dict)
            ]
            traces.append(trace)
            existing["velocity_traces"] = traces
            existing["velocity_next_trace_id"] = int(trace["trace_id"]) + 1
            existing["velocity_selected_trace_id"] = int(trace["trace_id"])
            existing["velocity_trace_draw_mode"] = False
            existing["velocity_trace_pending"] = None
            existing["velocity_trace_hover"] = None
            button_var = existing.get("velocity_trace_button_var")
            if button_var is not None:
                button_var.set("Draw velocity trace")
            self._record_session_change()
            self._refresh_td_window_velocity_trace_table(panel_id)
            self._refresh_td_window(panel_id)
            self._set_status(
                f"{panel.name}: saved velocity trace {int(trace['trace_id'])} "
                f"({float(trace['speed_km_s']):.3f} km/s)."
            )
            return
        if (
            existing is None
            or panel is None
            or not existing["roi_enabled_var"].get()
            or event.inaxes is not existing["ax"]
            or event.xdata is None
            or event.ydata is None
        ):
            return

        td, meta = self._panel_td(panel)
        if td is None or meta is None:
            return

        t0, t1, d0, d1 = self._ensure_td_window_roi(panel_id, meta)
        if self.td_swap_axes_var.get():
            clicked_t = float(event.xdata)
            clicked_d = float(event.ydata)
            inside = t0 <= clicked_t <= t1 and d0 <= clicked_d <= d1
        else:
            clicked_d = float(event.xdata)
            clicked_t = float(event.ydata)
            inside = d0 <= clicked_d <= d1 and t0 <= clicked_t <= t1

        if inside:
            existing["roi_drag_offset_t"] = clicked_t - float(existing["roi_center_t"])
            existing["roi_drag_offset_d"] = clicked_d - float(existing["roi_center_d"])
        else:
            existing["roi_center_t"] = clicked_t
            existing["roi_center_d"] = clicked_d
            existing["roi_drag_offset_t"] = 0.0
            existing["roi_drag_offset_d"] = 0.0

        existing["roi_dragging"] = True
        self._refresh_td_window(panel_id)

    def _on_td_window_motion(self, panel_id: int, event: Any) -> None:
        existing = self.td_windows.get(panel_id)
        panel = self._td_window_panel(panel_id)
        if existing is not None and bool(existing.get("velocity_trace_draw_mode")):
            coords = self._td_window_plot_to_td_coords(panel_id, event)
            if coords is None:
                return
            existing["velocity_trace_hover"] = (float(coords[0]), float(coords[1]))
            self._refresh_td_window(panel_id)
            return
        if (
            existing is None
            or panel is None
            or not existing.get("roi_dragging")
            or event.inaxes is not existing["ax"]
            or event.xdata is None
            or event.ydata is None
        ):
            return

        if self.td_swap_axes_var.get():
            clicked_t = float(event.xdata)
            clicked_d = float(event.ydata)
        else:
            clicked_d = float(event.xdata)
            clicked_t = float(event.ydata)

        existing["roi_center_t"] = clicked_t - float(existing.get("roi_drag_offset_t", 0.0))
        existing["roi_center_d"] = clicked_d - float(existing.get("roi_drag_offset_d", 0.0))
        self._refresh_td_window(panel_id)

    def _on_td_window_release(self, panel_id: int, _event: Any) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is not None:
            existing["roi_dragging"] = False

    def _set_td_window_cut_center(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None or existing.get("control_guard"):
            return
        cut = self._td_window_cut(panel_id, "set detached center")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "set detached center"):
            return
        center_x = self._parse_float_var(existing["center_x_var"].get(), "center x")
        center_y = self._parse_float_var(existing["center_y_var"].get(), "center y")
        if center_x is None or center_y is None:
            return

        old_center = cut_center(cut)
        dx = float(center_x) - old_center[0]
        dy = float(center_y) - old_center[1]
        self._shift_cut_geometry(
            cut,
            dx,
            dy,
            f"Moved center of {cut.name} from detached TD window.",
        )

    def _apply_td_window_cut_coords(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None or existing.get("control_guard"):
            return
        cut = self._td_window_cut(panel_id, "apply detached vertices")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "apply detached vertices"):
            return
        x1 = self._parse_float_var(existing["cut_x1_var"].get(), "x1")
        y1 = self._parse_float_var(existing["cut_y1_var"].get(), "y1")
        x2 = self._parse_float_var(existing["cut_x2_var"].get(), "x2")
        y2 = self._parse_float_var(existing["cut_y2_var"].get(), "y2")
        if None in {x1, y1, x2, y2}:
            return

        if self._cut_is_curve(cut):
            self._apply_curve_cut_endpoint_mapping(
                cut,
                (float(x1), float(y1)),
                (float(x2), float(y2)),
                f"Applied detached vertex coordinates to {cut.name}.",
            )
            return

        self._apply_cut_points(
            cut,
            (float(x1), float(y1)),
            (float(x2), float(y2)),
            f"Applied detached vertex coordinates to {cut.name}.",
        )

    def _set_td_window_cut_angle(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None or existing.get("control_guard"):
            return
        cut = self._td_window_cut(panel_id, "set detached angle")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "set detached angle"):
            return
        angle_deg = self._parse_float_var(existing["cut_angle_var"].get(), "angle")
        if angle_deg is None:
            return
        anchor_mode = str(existing["cut_anchor_var"].get()).strip()
        self._set_cut_angle(
            cut,
            angle_deg,
            anchor_mode,
            f"Set {cut.name} angle from detached TD window to {angle_deg:.2f} deg.",
        )

    def _adjust_td_window_cut_angle(self, panel_id: int, delta_deg: float) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        cut = self._td_window_cut(panel_id, "adjust detached angle")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "adjust detached angle"):
            return
        anchor_mode = str(existing["cut_anchor_var"].get()).strip()
        self._set_cut_angle(
            cut,
            cut_display_angle_deg(cut) + delta_deg,
            anchor_mode,
            f"Adjusted {cut.name} angle by {delta_deg:+.1f} deg from detached TD window.",
        )

    def _set_td_window_cut_length(self, panel_id: int) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None or existing.get("control_guard"):
            return
        cut = self._td_window_cut(panel_id, "set detached length")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "set detached length"):
            return
        length_value = self._parse_float_var(existing["cut_length_var"].get(), "length")
        if length_value is None:
            return
        length_mode = str(existing["cut_length_mode_var"].get()).strip()
        self._set_cut_length(
            cut,
            length_value,
            length_mode,
            f"Set {cut.name} length from detached TD window to {length_value:.2f} px.",
        )

    def _adjust_td_window_cut_length(self, panel_id: int, delta_length: float) -> None:
        existing = self.td_windows.get(panel_id)
        if existing is None:
            return
        cut = self._td_window_cut(panel_id, "adjust detached length")
        if cut is None:
            return
        if not self._curve_cut_edit_supported(cut, "adjust detached length"):
            return
        length_mode = str(existing["cut_length_mode_var"].get()).strip()
        self._set_cut_length(
            cut,
            max(1.0, cut_length(cut) + delta_length),
            length_mode,
            f"Adjusted {cut.name} length by {delta_length:+.1f} px from detached TD window.",
        )

    def _open_td_window(
        self,
        panel_id: int | None = None,
        *,
        source_stack_id: int | None = None,
    ) -> None:
        panel_id = self.active_panel_id if panel_id is None else panel_id
        if panel_id < 1 or panel_id > len(self.panels):
            return
        panel_state = self._panel_analysis(panel_id)

        existing = self.td_windows.get(panel_id)
        if existing is not None:
            existing["source_stack_id"] = (
                None if source_stack_id is None else int(source_stack_id)
            )
            top = existing["top"]
            if top.winfo_exists():
                top.deiconify()
                top.lift()
                self._refresh_td_window(panel_id)
                return
            del self.td_windows[panel_id]

        top = self.tk.Toplevel(self.root)
        top.title(f"TD Window - {self.panels[panel_id - 1].name}")
        top.geometry("1180x860")
        top.rowconfigure(2, weight=1)
        top.columnconfigure(0, weight=1)

        header_frame = self.ttk.Frame(top, padding=(8, 8, 8, 0))
        header_frame.grid(row=0, column=0, sticky="ew")
        header_frame.columnconfigure(0, weight=1)

        edit_var = self.tk.BooleanVar(value=False)
        roi_enabled_var = self.tk.BooleanVar(
            value=bool(panel_state.get("roi_enabled", False))
        )
        editor_toggle_var = self.tk.StringVar(value="Show editor")
        roi_window_toggle_var = self.tk.StringVar(value="ROI window")
        diag_window_toggle_var = self.tk.StringVar(value="Wavelet diag window")
